def _version_sort_key(ver: str) -> tuple:
    ver = str(ver or "").strip().lower()
    if ver.startswith("v"):
        ver = ver[1:]
    parts = []
    for token in ver.replace("-", ".").split("."):
        if token.isdigit():
            parts.append((0, int(token)))
        else:
            parts.append((1, token))
    return tuple(parts)
def _runtime_version_lock_is_live(payload: dict | None, now_ts: float | None = None) -> bool:
    payload = payload if isinstance(payload, dict) else {}
    ref_ts = float(now_ts if now_ts is not None else time.time())
    ts = safe_float(payload.get("ts", 0.0), 0.0)
    if ts <= 0:
        return False
    return (ref_ts - ts) <= RUNTIME_VERSION_LOCK_LEASE_SEC


def _is_non_authoritative_higher_runtime_lock(saved_ver: str, payload: dict | None) -> bool:
    payload = payload if isinstance(payload, dict) else {}
    saved_ver = str(saved_ver or "").strip()
    if not saved_ver:
        return False
    if _version_sort_key(saved_ver) <= _version_sort_key(BOT_VERSION):
        return False
    current_has_patch = "." in str(BOT_VERSION or "")
    saved_has_patch = "." in saved_ver
    lock_kind = str(payload.get("lock_kind", "") or "").strip().lower()
    return current_has_patch and (not saved_has_patch) and lock_kind != "authoritative"


def _enforce_runtime_version_lock(notify: bool = True) -> bool:
    """공유 볼륨에 살아 있는 더 최신 버전 잠금이 있으면 현재 구버전 런타임을 정지한다."""
    global _runtime_version_blocked
    try:
        now_ts = time.time()
        current = {
            "version": BOT_VERSION,
            "code_hash": _get_code_hash(),
            "updated_at": _now_kst().strftime("%Y-%m-%d %H:%M:%S"),
            "instance_id": _INSTANCE_ID,
            "ts": now_ts,
            "pid": os.getpid(),
            "host": os.getenv("HOSTNAME") or "",
            "railway_replica": os.getenv("RAILWAY_REPLICA_ID") or "",
            "lock_kind": "authoritative",
        }
        saved = _read_json_safe(RUNTIME_VERSION_LOCK_FILE, {}) or {}
        saved_ver = str(saved.get("version", "") or "")
        saved_live = _runtime_version_lock_is_live(saved, now_ts=now_ts)
        saved_instance = str(saved.get("instance_id", "") or "")
        non_authoritative_high_lock = _is_non_authoritative_higher_runtime_lock(saved_ver, saved)
        if non_authoritative_high_lock:
            stale_age = int(max(0, now_ts - safe_float(saved.get("ts", 0.0), 0.0)))
            _log_warn_msg(
                f"⚠️ 비정상 상위 잠금 자동 복구: instance={saved_instance or '-'} age={stale_age}s"
            )
            saved_ver = ""
            saved_live = False
            saved_instance = ""
        higher_live_lock = bool(
            saved_ver
            and _version_sort_key(saved_ver) > _version_sort_key(BOT_VERSION)
            and saved_live
            and saved_instance != _INSTANCE_ID
        )
        if higher_live_lock:
            _runtime_version_blocked = True
            msg = (
                f"⛔ <b>구버전 런타임 자동 정지</b>\n"
                f"현재 실행: <b>{BOT_VERSION}</b> / 상위 잠금 감지\n"
                f"인스턴스: <code>{_INSTANCE_ID}</code>\n"
                f"최신 버전이 이미 운영 중이므로 이 런타임은 스캔/알림을 중단합니다."
            )
            _log_info_msg(msg.replace("<b>", "").replace("</b>", "").replace("<code>", "").replace("</code>", ""))
            if notify:
                try:
                    send(msg)
                except Exception as e:
                    _swallow_exception(e)
            return False
        if saved_ver and _version_sort_key(saved_ver) > _version_sort_key(BOT_VERSION) and not saved_live:
            stale_age = int(max(0, now_ts - safe_float(saved.get("ts", 0.0), 0.0)))
            _log_warn_msg(
                f"⚠️ stale 상위 잠금 자동 복구: instance={saved_instance or '-'} age={stale_age}s"
            )
        should_write = False
        if not saved_ver:
            should_write = True
        elif saved_instance == _INSTANCE_ID:
            should_write = True
        elif not saved_live:
            should_write = True
        elif _version_sort_key(BOT_VERSION) >= _version_sort_key(saved_ver):
            should_write = True
        elif str(saved.get("code_hash", "")) != current["code_hash"] and saved_ver == BOT_VERSION:
            should_write = True
        if should_write:
            _write_json_atomic(RUNTIME_VERSION_LOCK_FILE, current, indent=2)
        _runtime_version_blocked = False
        return True
    except Exception as e:
        _log_warn_msg(f"⚠️ 운영 버전 잠금 확인 실패: {e}")
        return True

_leader_job_running: dict = {}  # v163.6: 동일 함수 동시 실행 방지
_leader_job_lock = threading.Lock()

def _leader_job(fn):
    def _wrapped(*args, **kwargs):
        if _runtime_version_blocked:
            return None
        was_leader = bool(_RUNTIME_IS_LEADER)
        if not _try_acquire_leader_lock():
            return None
        if not _enforce_runtime_version_lock(notify=False):
            return None
        # v163.6: 동일 함수 중복 실행 방지 (YT 스케줄러 2중 호출 차단)
        fn_key = getattr(fn, "__name__", str(fn))
        with _leader_job_lock:
            if _leader_job_running.get(fn_key):
                return None
            _leader_job_running[fn_key] = True
        try:
            if not was_leader:
                _send_startup_banner_once()
            return fn(*args, **kwargs)
        finally:
            with _leader_job_lock:
                _leader_job_running.pop(fn_key, None)
    return _wrapped

def _threaded_leader_job(fn):
    """v165.5: 선진입 등 시각 민감 job을 별도 스레드로 실행.
    schedule single-thread 특성상 run_scan 처리 중 job이 pending되는 문제 해소.
    _leader_job의 모든 가드(version_lock, leader_lock, 중복방지)를 스레드 내에서 동일 적용.
    """
    def _wrapped(*args, **kwargs):
        def _run():
            if _runtime_version_blocked:
                return
            was_leader = bool(_RUNTIME_IS_LEADER)
            if not _try_acquire_leader_lock():
                return
            if not _enforce_runtime_version_lock(notify=False):
                return
            fn_key = getattr(fn, "__name__", str(fn)) + "_threaded"
            with _leader_job_lock:
                if _leader_job_running.get(fn_key):
                    return
                _leader_job_running[fn_key] = True
            try:
                if not was_leader:
                    _send_startup_banner_once()
                fn(*args, **kwargs)
            except Exception as _e:
                _log_warn_msg(f"⚠️ threaded_leader_job 오류 [{getattr(fn,'__name__',str(fn))}]: {_e}")
            finally:
                with _leader_job_lock:
                    _leader_job_running.pop(fn_key, None)
        threading.Thread(target=_run, daemon=True).start()
    return _wrapped
def _ensure_dir(path: str):
    try:
        os.makedirs(path, exist_ok=True)
    except Exception as e:
        _log_warn_msg(f"⚠️ DATA_DIR 생성 실패: {path} ({e})")
def _snapshot_backup(file_path: str):
    """기존 파일이 있으면 backups로 스냅샷 백업(최근 N개 유지)"""
    try:
        if not os.path.isfile(file_path):
            return
        _ensure_dir(_BACKUP_DIR)
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        base = os.path.basename(file_path)
        backup_path = os.path.join(_BACKUP_DIR, f"{base}.{ts}.bak")
        # copy (binary safe)
        with open(file_path, "rb") as rf, open(backup_path, "wb") as wf:
            wf.write(rf.read())
        # prune old backups
        backups = sorted(
            [p for p in os.listdir(_BACKUP_DIR) if p.startswith(base + ".")],
            reverse=True,
        )
        for old in backups[MAX_STATE_BACKUPS:]:
            try:
                os.remove(os.path.join(_BACKUP_DIR, old))
            except Exception as e:
                _swallow_exception(e)
    except Exception as e:
        _log_warn_msg(f"⚠️ 백업 스냅샷 실패: {os.path.basename(file_path)} ({e})")
def _atomic_write_bytes(file_path: str, data: bytes):
    """tmp → fsync → os.replace 로 원자적 저장"""
    _ensure_dir(os.path.dirname(file_path))
    tmp_path = file_path + ".tmp"
    with open(tmp_path, "wb") as f:
        f.write(data)
        f.flush()
        os.fsync(f.fileno())
    os.replace(tmp_path, file_path)
def _write_json_atomic_unlocked(file_path: str, obj, indent: int = 2):
    try:
        _snapshot_backup(file_path)
        payload = json.dumps(obj, ensure_ascii=False, indent=indent).encode("utf-8")
        _atomic_write_bytes(file_path, payload)
    except Exception as e:
        _log_warn_msg(f"⚠️ JSON 저장 실패: {os.path.basename(file_path)} ({e})")
def _write_json_atomic(file_path: str, obj, indent: int = 2):
    with _file_lock:  # v38.3-P0-5
        _write_json_atomic_unlocked(file_path, obj, indent=indent)
def _read_json_unlocked(file_path: str, default=None):
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except FileNotFoundError:
        return default if default is not None else {}
    except Exception as e:
        _warn_json_default_once(file_path, e)
        return default if default is not None else {}
def _read_json_locked(file_path: str, default=None):
    """v38.3-P1-6: Lock 보호 JSON 읽기 (스레드 안전)"""
    with _file_lock:
        return _read_json_unlocked(file_path, default=default)
def _backup_runtime_json_file(file_path: str, tag: str = "manual") -> str:
    _ensure_dir(_BACKUP_DIR)
    stamp = _now_kst().strftime("%Y%m%d_%H%M%S")
    base = os.path.basename(file_path)
    backup = os.path.join(_BACKUP_DIR, f"{tag}_{stamp}_{base}")
    try:
        if os.path.exists(file_path):
            with open(file_path, "rb") as rf, open(backup, "wb") as wf:
                wf.write(rf.read())
    except Exception as e:
        _log_warn_msg(f"⚠️ 백업 실패: {base} ({e})")
        return ""
    return backup

def _parse_stats_scope_datetime(value: str | None) -> datetime | None:
    s = str(value or "").strip()
    if not s:
        return None
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y%m%d %H:%M:%S", "%Y%m%d%H%M%S", "%Y-%m-%dT%H:%M:%S"):
        try:
            return datetime.strptime(s, fmt).replace(tzinfo=_KST)
        except Exception:
            pass
    try:
        dt = datetime.fromisoformat(s)
        if dt.tzinfo is None:
            return dt.replace(tzinfo=_KST)
        return dt.astimezone(_KST)
    except Exception:
        return None

def _record_detected_datetime(rec: dict) -> datetime | None:
    if not isinstance(rec, dict):
        return None
    d = str(rec.get("detect_date") or rec.get("first_detect_date") or rec.get("exit_date") or "").strip()
    t = str(rec.get("detect_time") or rec.get("first_detect_time") or rec.get("exit_time") or "00:00:00").strip()
    if not d:
        return None
    if len(d) == 8 and d.isdigit():
        try:
            return datetime.strptime(f"{d} {t[:8]}", "%Y%m%d %H:%M:%S").replace(tzinfo=_KST)
        except Exception:
            return None
    try:
        dt = datetime.fromisoformat(f"{d} {t[:8]}")
        if dt.tzinfo is None:
            return dt.replace(tzinfo=_KST)
        return dt.astimezone(_KST)
    except Exception:
        return None

def _ensure_record_stats_meta(rec: dict) -> bool:
    if not isinstance(rec, dict):
        return False
    changed = False
    bot_version = str(rec.get("bot_version") or rec.get("version") or rec.get("signal_version") or "").strip()
    if not bot_version:
        rec["bot_version"] = "legacy"
        bot_version = "legacy"
        changed = True
    stats_cohort = str(rec.get("stats_cohort") or rec.get("structure_cohort") or "").strip()
    if not stats_cohort:
        rec["stats_cohort"] = _derive_stats_cohort(bot_version)
        stats_cohort = rec["stats_cohort"]
        changed = True
    if not str(rec.get("structure_cohort") or "").strip():
        rec["structure_cohort"] = stats_cohort
        changed = True
    return changed

def _normalize_signal_log_meta_fields(data: dict) -> int:
    if not isinstance(data, dict):
        return 0
    changed = 0
    for rec in data.values():
        if _ensure_record_stats_meta(rec):
            changed += 1
    return changed

def _load_stats_scope_state() -> dict:
    state = _read_json_locked(STATS_SCOPE_FILE, default={})
    if not isinstance(state, dict):
        state = {}
    cohorts = state.get("cohorts")
    if not isinstance(cohorts, dict):
        cohorts = {}
    state["cohorts"] = cohorts
    if not state.get("active_cohort"):
        state["active_cohort"] = BOT_STATS_COHORT
    if BOT_STATS_COHORT not in cohorts:
        cohorts[BOT_STATS_COHORT] = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
        _write_json_atomic(STATS_SCOPE_FILE, state, indent=2)
    return state

def _get_stats_scope_start(cohort: str | None = None) -> datetime | None:
    state = _load_stats_scope_state()
    target = str(cohort or BOT_STATS_COHORT or "").strip() or BOT_STATS_COHORT
    return _parse_stats_scope_datetime((state.get("cohorts") or {}).get(target))

def _record_matches_stats_scope(rec: dict, cohort: str | None = None) -> bool:
    if not isinstance(rec, dict):
        return False
    target = str(cohort or BOT_STATS_COHORT or "").strip() or BOT_STATS_COHORT
    rec_cohort = str(rec.get("stats_cohort") or rec.get("structure_cohort") or _derive_stats_cohort(rec.get("bot_version"))).strip()
    if rec_cohort != target:
        return False
    anchor = _get_stats_scope_start(target)
    if anchor is None:
        return True
    rec_dt = _record_detected_datetime(rec)
    if rec_dt is None:
        return False
    return rec_dt >= anchor

def _filter_records_by_stats_scope(records, cohort: str | None = None) -> list:
    return [rec for rec in (records or []) if _record_matches_stats_scope(rec, cohort=cohort)]

def _handle_reset_stats_command(raw: str):
    parts = raw.strip().split()
    if len(parts) < 2 or parts[1] not in ("확인", "confirm"):
        data = _load_signal_log_data()
        cohort_count = sum(1 for rec in data.values() if _record_matches_stats_scope(rec))
        send(
            f"⚠️ 현재 구조 cohort <b>{BOT_STATS_COHORT}</b> 승률을 초기화합니다.\n"
            f"대상 기록: {cohort_count}건\n"
            f"signal_log는 백업하고, 현재 cohort의 통계 시작 시각과 동적 기준을 baseline으로 복원합니다.\n"
            f"실행: <code>/reset_stats 확인</code>"
        )
        return
    backup = _backup_runtime_json_file(SIGNAL_LOG_FILE, tag="reset_stats")
    state = _load_stats_scope_state()
    stamp = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
    state["active_cohort"] = BOT_STATS_COHORT
    state.setdefault("cohorts", {})[BOT_STATS_COHORT] = stamp
    state.setdefault("last_reset", {})[BOT_STATS_COHORT] = stamp
    _write_json_atomic(STATS_SCOPE_FILE, state, indent=2)
    try:
        _history_cache["data"] = {}
        _history_cache["ts"] = 0
    except Exception:
        pass
    runtime_reset = _reset_stats_runtime_controls()
    send(
        f"♻️ <b>승률 초기화 완료</b>\n"
        f"cohort: <b>{BOT_STATS_COHORT}</b>\n"
        f"시작 시각: {stamp}\n"
        f"동적 기준: baseline 복원 (min_score/emergency/streak reset)\n"
        f"최소점수(일반/엄격): {runtime_reset['min_score_normal']}/{runtime_reset['min_score_strict']}점\n"
        f"백업: {os.path.basename(backup) if backup else '생략'}"
    )

def _migrate_legacy_files():
    """기존(현재 작업 디렉토리)에 있던 JSON이 있으면 DATA_DIR로 1회 복사"""
    try:
        cwd = os.getcwd()
        for fn in _PERSIST_FILES:
            legacy = os.path.join(cwd, fn)
            target = os.path.join(DATA_DIR, fn)
            if os.path.isfile(legacy) and not os.path.isfile(target):
                _ensure_dir(DATA_DIR)
                try:
                    with open(legacy, "rb") as rf, open(target, "wb") as wf:
                        wf.write(rf.read())
                    _log_info_msg(f"✅ 레거시 파일 이관: {fn} → {target}")
                except Exception as e:
                    _log_warn_msg(f"⚠️ 레거시 이관 실패: {fn} ({e})")
    except Exception as e:
        _log_warn_msg(f"⚠️ 레거시 이관 로직 오류: {e}")
def _storage_diagnostics_once():
    """시작 시 1회: DATA_DIR/볼륨/쓰기 가능 여부/파일 목록 출력"""
    try:
        _ensure_dir(DATA_DIR)
        _ensure_dir(_BACKUP_DIR)
        rp = os.getenv("RAILWAY_VOLUME_MOUNT_PATH", "")
        lines = [
            "=======================================================",
            "💾 Persistent Storage Check",
            f"   DATA_DIR: {DATA_DIR}",
        ]
        if rp:
            lines.append(f"   RAILWAY_VOLUME_MOUNT_PATH: {rp}")
        # writable test
        test_path = os.path.join(DATA_DIR, ".write_test")
        try:
            with open(test_path, "w", encoding="utf-8") as f:
                f.write(datetime.now().isoformat())
            os.remove(test_path)
            lines.append("   Writable: ✅ OK")
            # persistent probe file (kept) to prove writes survive redeploys
            probe_path = os.path.join(DATA_DIR, ".storage_ok")
            try:
                with open(probe_path, "w", encoding="utf-8") as f:
                    f.write(datetime.now().isoformat())
                lines.append(f"   Probe file: {probe_path} ✅ wrote")
            except Exception as pe:
                lines.append(f"   Probe file: ❌ FAIL ({pe})")
        except Exception as e:
            lines.append(f"   Writable: ❌ FAIL ({e})")
        # list key files
        existing = []
        for fn in _PERSIST_FILES:
            fp = os.path.join(DATA_DIR, fn)
            if os.path.isfile(fp):
                try:
                    size = os.path.getsize(fp)
                    existing.append(f"{fn}({size}B)")
                except Exception as e:
                    _swallow_exception(e)  # v105 structured silent-exception log
                    existing.append(fn)
        lines.append(f"   Files: {', '.join(existing) if existing else '(none)'}")
        lines.append("=======================================================")
        for line in lines:
            _log_info_msg(line)
    except Exception as e:
        _log_warn_msg(f"⚠️ 스토리지 진단 실패: {e}")
# ============================================================
# v40.0-#7: 메시지 차단 사유 내부 로그 (학습·개선 데이터)
# ============================================================
SUPPRESSED_LOG_FILE = _state_path("suppressed_alerts.json")
def _log_suppressed_alert(code: str, name: str, reason: str, signal_type: str = "", extra: dict = None):
    """알림 차단 시 내부 로그에 기록 (사용자 알림 없음, 학습용)."""
    try:
        data = _read_json_locked(SUPPRESSED_LOG_FILE) if os.path.exists(SUPPRESSED_LOG_FILE) else {}
        if not isinstance(data, dict):
            data = {}
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        key = f"{code}_{datetime.now().strftime('%Y%m%d%H%M%S')}"
        entry = {
            "code": code, "name": name, "reason": reason,
            "signal_type": signal_type, "time": now_s,
        }
        if extra and isinstance(extra, dict):
            entry.update(extra)
        data[key] = entry
        # 최대 500건 유지
        if len(data) > 500:
            sorted_keys = sorted(data.keys())
            for old_k in sorted_keys[:len(data) - 500]:
                data.pop(old_k, None)
        _write_json_atomic(SUPPRESSED_LOG_FILE, data, indent=2)
        _log_info_msg(f"  🚫 차단: {name}({code}) — {reason}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 차단 로그 기록 오류: {e}")
def _safe_feedback_theme_key(theme: str) -> str:
    theme = str(theme or "").strip()
    if theme in ("", "기타", "기타업종", "unknown", "미분류"):
        return ""
    return theme[:60]
def _feedback_reason_weight(reason: str) -> float:
    reason = str(reason or "")
    if reason == "candidate_miss":
        return 4.0
    if reason == "no_ask_liquidity":
        return COMMON_THRESHOLD_3P0
    if reason == "position_limit":
        return 2.5
    if reason == "sector_limit":
        return 2.0
    if reason == "blocked_other":
        return 1.8
    if reason == "external_suppressed":
        return 1.2
    return 1.0
def load_adaptive_capture_feedback() -> dict:
    global _adaptive_capture_feedback
    try:
        obj = _read_json_locked(ADAPTIVE_CAPTURE_FEEDBACK_FILE) if os.path.exists(ADAPTIVE_CAPTURE_FEEDBACK_FILE) else {}
        if not isinstance(obj, dict):
            obj = {}
        base = {"generated_date": "", "priority_codes": {}, "theme_bias": {}, "reason_counts": {}, "source_dates": []}
        base.update(obj)
        if not isinstance(base.get("priority_codes"), dict):
            base["priority_codes"] = {}
        if not isinstance(base.get("theme_bias"), dict):
            base["theme_bias"] = {}
        if not isinstance(base.get("reason_counts"), dict):
            base["reason_counts"] = {}
        if not isinstance(base.get("source_dates"), list):
            base["source_dates"] = []
        _adaptive_capture_feedback = base
    except Exception as e:
        _log_warn_msg(f"⚠️ adaptive feedback 로드 오류: {e}")
        _adaptive_capture_feedback = {"generated_date": "", "priority_codes": {}, "theme_bias": {}, "reason_counts": {}, "source_dates": []}
    return _adaptive_capture_feedback
def _build_adaptive_capture_feedback(lookback_days: int | None = None) -> dict:
    lookback_days = int(lookback_days or ADAPTIVE_FEEDBACK_LOOKBACK_DAYS or 5)
    try:
        raw = _read_json_locked(SELF_AUDIT_FILE) if os.path.exists(SELF_AUDIT_FILE) else {}
        raw = raw if isinstance(raw, dict) else {}
        rows = []
        for rec in raw.values():
            if isinstance(rec, dict):
                rows.append(rec)
        rows.sort(key=lambda x: str(x.get("date", "")))
        if lookback_days > 0:
            rows = rows[-lookback_days*2:]
        code_weights: dict[str, dict] = {}
        theme_weights: dict[str, dict] = {}
        reason_counts: dict[str, int] = {}
        source_dates: list[str] = []
        for rec in rows:
            date_key = str(rec.get("date", "") or "")
            if date_key and date_key not in source_dates:
                source_dates.append(date_key)
            for d in rec.get("leaders", []) or []:
                if not isinstance(d, dict):
                    continue
                cls = str(d.get("class", "") or "")
                if cls in ("", "detected"):
                    continue
                code = normalize_stock_code(d.get("code"))
                if not code:
                    continue
                chg = float(d.get("change_rate", 0) or 0)
                if chg < 5.0:
                    continue
                weight = _feedback_reason_weight(cls)
                reason_counts[cls] = reason_counts.get(cls, 0) + 1
                row = code_weights.setdefault(code, {
                    "code": code,
                    "name": str(d.get("name", code) or code),
                    "weight": 0.0,
                    "best_change": 0.0,
                    "reasons": set(),
                    "theme": _safe_feedback_theme_key(d.get("theme", "")),
                })
                row["weight"] += weight + min(max(chg - 5.0, 0.0) * 0.08, 1.6)
                row["best_change"] = max(row["best_change"], chg)
                row["reasons"].add(cls)
                theme_key = _safe_feedback_theme_key(d.get("theme", ""))
                if theme_key:
                    trow = theme_weights.setdefault(theme_key, {"theme": theme_key, "weight": 0.0, "codes": set(), "reasons": set()})
                    trow["weight"] += weight
                    trow["codes"].add(code)
                    trow["reasons"].add(cls)
        priority_codes = {}
        for code, row in sorted(code_weights.items(), key=lambda kv: (kv[1]["weight"], kv[1]["best_change"]), reverse=True)[:ADAPTIVE_FEEDBACK_MAX_CODES]:
            if float(row.get("weight", 0.0) or 0.0) < ADAPTIVE_FEEDBACK_CODE_MIN_WEIGHT:
                continue
            priority_codes[code] = {
                "name": row.get("name", code),
                "weight": round(float(row.get("weight", 0.0) or 0.0), 2),
                "best_change": round(float(row.get("best_change", 0.0) or 0.0), 2),
                "reasons": sorted(list(row.get("reasons") or [])),
                "theme": row.get("theme", ""),
            }
        theme_bias = {}
        for theme_key, row in sorted(theme_weights.items(), key=lambda kv: kv[1]["weight"], reverse=True):
            if float(row.get("weight", 0.0) or 0.0) < ADAPTIVE_FEEDBACK_THEME_MIN_WEIGHT:
                continue
            theme_bias[theme_key] = {
                "weight": round(float(row.get("weight", 0.0) or 0.0), 2),
                "codes": sorted(list(row.get("codes") or []))[:8],
                "reasons": sorted(list(row.get("reasons") or [])),
            }
        payload = {
            "generated_date": _now_kst().strftime("%Y%m%d"),
            "generated_at": _now_kst().strftime("%Y-%m-%d %H:%M:%S"),
            "version": BOT_VERSION,
            "source_dates": source_dates[-lookback_days:],
            "priority_codes": priority_codes,
            "theme_bias": theme_bias,
            "reason_counts": reason_counts,
        }
        _write_json_atomic(ADAPTIVE_CAPTURE_FEEDBACK_FILE, payload, indent=2)
        load_adaptive_capture_feedback()
        return payload
    except Exception as e:
        _log_error("_build_adaptive_capture_feedback", e)
        return {}
def load_stale_replay_penalty_profile() -> dict:
    global _stale_replay_penalty_profile
    try:
        obj = _read_json_locked(STALE_REPLAY_PENALTY_FILE) if os.path.exists(STALE_REPLAY_PENALTY_FILE) else {}
        if not isinstance(obj, dict):
            obj = {}
        base = {"generated_date": "", "code_penalty": {}, "theme_penalty": {}, "source_dates": [], "date_pressure": {}}
        base.update(obj)
        if not isinstance(base.get("code_penalty"), dict):
            base["code_penalty"] = {}
        if not isinstance(base.get("theme_penalty"), dict):
            base["theme_penalty"] = {}
        if not isinstance(base.get("source_dates"), list):
            base["source_dates"] = []
        if not isinstance(base.get("date_pressure"), dict):
            base["date_pressure"] = {}
        _stale_replay_penalty_profile = base
    except Exception as e:
        _log_warn_msg(f"⚠️ stale replay penalty 로드 오류: {e}")
        _stale_replay_penalty_profile = {"generated_date": "", "code_penalty": {}, "theme_penalty": {}, "source_dates": [], "date_pressure": {}}
    return _stale_replay_penalty_profile
def _load_stale_replay_penalty_sources() -> tuple[dict, dict]:
    raw_audit = _read_json_locked(SELF_AUDIT_FILE) if os.path.exists(SELF_AUDIT_FILE) else {}
    raw_shadow = _read_json_locked(SHADOW_CAPTURE_FILE) if os.path.exists(SHADOW_CAPTURE_FILE) else {}
    return (
        raw_audit if isinstance(raw_audit, dict) else {},
        raw_shadow if isinstance(raw_shadow, dict) else {},
    )
def _collect_stale_replay_date_pressure(raw_audit: dict, lookback_days: int) -> tuple[dict, list[str]]:
    audit_rows = [v for v in raw_audit.values() if isinstance(v, dict)]
    audit_rows.sort(key=lambda x: str(x.get("date", "")))
    if lookback_days > 0:
        audit_rows = audit_rows[-lookback_days * 2:]
    date_pressure: dict[str, float] = {}
    source_dates: list[str] = []
    for rec in audit_rows:
        date_key = str(rec.get("date", "") or "")
        if not date_key:
            continue
        summary = rec.get("summary") or {}
        pressure = (
            float(summary.get("candidate_miss", 0) or 0) * 1.0
            + float(summary.get("no_ask_liquidity", 0) or 0) * 0.8
            + float(summary.get("position_limit", 0) or 0) * 0.7
            + float(summary.get("blocked_other", 0) or 0) * 0.5
        )
        if pressure <= 0:
            continue
        date_pressure[date_key] = max(float(date_pressure.get(date_key, 0.0) or 0.0), round(pressure, 2))
        if date_key not in source_dates:
            source_dates.append(date_key)
    if lookback_days > 0:
        source_dates = source_dates[-lookback_days:]
    return date_pressure, source_dates
def _collect_stale_replay_penalty_rows(raw_shadow: dict, date_pressure: dict) -> tuple[dict, dict]:
    code_rows: dict[str, dict] = {}
    theme_rows: dict[str, dict] = {}
    for rec in raw_shadow.values():
        if not isinstance(rec, dict):
            continue
        date_key = str(rec.get("date", "") or "")
        if not date_key or date_key not in date_pressure:
            continue
        sig = str(rec.get("signal_type", "") or "").upper()
        reason = str(rec.get("reason", "") or "")
        if sig not in ("MID_PULLBACK", "ENTRY_POINT") or reason not in ("stale_pullback_quota", "stale_replay_penalty"):
            continue
        code = normalize_stock_code(rec.get("code"))
        if not code:
            continue
        pressure = float(date_pressure.get(date_key, 0.0) or 0.0)
        age_hours = safe_float(rec.get("tracking_replay_age_hours", 0.0), 0.0)
        miss_count = safe_int(rec.get("tracking_replay_miss_count", 0), 0)
        theme_key = _safe_feedback_theme_key(rec.get("sector_theme") or rec.get("theme") or rec.get("sector") or "")
        weight = 1.0 + min(COMMON_THRESHOLD_3P0, pressure * 0.14)
        if age_hours >= STALE_PULLBACK_MIN_HOURS:
            weight += min(1.8, (age_hours / max(STALE_PULLBACK_MIN_HOURS, 1.0)) * 0.55)
        if miss_count >= 2:
            weight += min(1.2, miss_count * 0.25)
        crow = code_rows.setdefault(code, {
            "code": code,
            "name": str(rec.get("name", code) or code),
            "weight": 0.0,
            "count": 0,
            "themes": set(),
            "reasons": set(),
            "max_age_hours": 0.0,
        })
        crow["weight"] += weight
        crow["count"] += 1
        crow["reasons"].add(reason)
        crow["max_age_hours"] = max(float(crow.get("max_age_hours", 0.0) or 0.0), age_hours)
        if theme_key:
            crow["themes"].add(theme_key)
            trow = theme_rows.setdefault(theme_key, {"theme": theme_key, "weight": 0.0, "count": 0, "codes": set(), "reasons": set()})
            trow["weight"] += weight
            trow["count"] += 1
            trow["codes"].add(code)
            trow["reasons"].add(reason)
    return code_rows, theme_rows
def _build_stale_replay_penalty_payload(date_pressure: dict, source_dates: list[str], code_rows: dict, theme_rows: dict) -> dict:
    code_penalty = {}
    for code, row in sorted(code_rows.items(), key=lambda kv: (kv[1]["weight"], kv[1]["count"]), reverse=True):
        if float(row.get("weight", 0.0) or 0.0) < STALE_REPLAY_CODE_MIN_WEIGHT:
            continue
        code_penalty[code] = {
            "name": row.get("name", code),
            "weight": round(float(row.get("weight", 0.0) or 0.0), 2),
            "count": safe_int(row.get("count", 0), 0),
            "themes": sorted(list(row.get("themes") or []))[:6],
            "reasons": sorted(list(row.get("reasons") or [])),
            "max_age_hours": round(float(row.get("max_age_hours", 0.0) or 0.0), 2),
        }
    theme_penalty = {}
    for theme_key, row in sorted(theme_rows.items(), key=lambda kv: (kv[1]["weight"], kv[1]["count"]), reverse=True):
        if float(row.get("weight", 0.0) or 0.0) < STALE_REPLAY_THEME_MIN_WEIGHT:
            continue
        theme_penalty[theme_key] = {
            "weight": round(float(row.get("weight", 0.0) or 0.0), 2),
            "count": safe_int(row.get("count", 0), 0),
            "codes": sorted(list(row.get("codes") or []))[:8],
            "reasons": sorted(list(row.get("reasons") or [])),
        }
    return {
        "generated_date": _now_kst().strftime("%Y%m%d"),
        "generated_at": _now_kst().strftime("%Y-%m-%d %H:%M:%S"),
        "version": BOT_VERSION,
        "source_dates": source_dates,
        "date_pressure": date_pressure,
        "code_penalty": code_penalty,
        "theme_penalty": theme_penalty,
    }
def _build_stale_replay_penalty_profile(lookback_days: int | None = None) -> dict:
    lookback_days = int(lookback_days or STALE_REPLAY_LOOKBACK_DAYS or 5)
    try:
        raw_audit, raw_shadow = _load_stale_replay_penalty_sources()
        date_pressure, source_dates = _collect_stale_replay_date_pressure(raw_audit, lookback_days)
        code_rows, theme_rows = _collect_stale_replay_penalty_rows(raw_shadow, date_pressure)
        payload = _build_stale_replay_penalty_payload(date_pressure, source_dates, code_rows, theme_rows)
        _write_json_atomic(STALE_REPLAY_PENALTY_FILE, payload, indent=2)
        load_stale_replay_penalty_profile()
        return payload
    except Exception as e:
        _log_error("_build_stale_replay_penalty_profile", e)
        return {}
def _get_stale_replay_code_entry(code: str) -> dict:
    code = normalize_stock_code(code)
    if not code or not isinstance(_stale_replay_penalty_profile, dict):
        return {}
    rows = _stale_replay_penalty_profile.get("code_penalty") or {}
    return dict(rows.get(code) or {}) if isinstance(rows, dict) else {}
def _get_stale_replay_theme_entry(theme: str) -> dict:
    theme = _safe_feedback_theme_key(theme)
    if not theme or not isinstance(_stale_replay_penalty_profile, dict):
        return {}
    rows = _stale_replay_penalty_profile.get("theme_penalty") or {}
    return dict(rows.get(theme) or {}) if isinstance(rows, dict) else {}
def _load_intraday_stale_shadow_counts(force: bool = False) -> dict:
    global _stale_shadow_intraday_cache
    now_ts = time.time()
    today = _now_kst().strftime("%Y%m%d")
    cache = _stale_shadow_intraday_cache if isinstance(_stale_shadow_intraday_cache, dict) else {"ts": 0.0, "date": "", "codes": {}, "themes": {}}
    if not force and cache.get("date") == today and (now_ts - float(cache.get("ts", 0.0) or 0.0)) < 60:
        return cache
    codes = {}
    themes = {}
    try:
        obj = _read_json_locked(SHADOW_CAPTURE_FILE) if os.path.exists(SHADOW_CAPTURE_FILE) else {}
        obj = obj if isinstance(obj, dict) else {}
        for rec in obj.values():
            if not isinstance(rec, dict):
                continue
            if str(rec.get("date", "") or "") != today:
                continue
            sig = str(rec.get("signal_type", "") or "").upper()
            reason = str(rec.get("reason", "") or "")
            if sig not in ("MID_PULLBACK", "ENTRY_POINT"):
                continue
            if reason not in ("stale_pullback_quota", "stale_replay_penalty"):
                continue
            code = normalize_stock_code(rec.get("code"))
            if code:
                codes[code] = codes.get(code, 0) + 1
            theme_key = _safe_feedback_theme_key(rec.get("sector_theme") or rec.get("theme") or rec.get("sector") or "")
            if theme_key:
                themes[theme_key] = themes.get(theme_key, 0) + 1
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        codes, themes = {}, {}
    cache = {"ts": now_ts, "date": today, "codes": codes, "themes": themes}
    _stale_shadow_intraday_cache = cache
    return cache
def _get_intraday_stale_shadow_count(code: str = "", theme: str = "") -> tuple[int, int]:
    cache = _load_intraday_stale_shadow_counts()
    codes = cache.get("codes") or {}
    themes = cache.get("themes") or {}
    code = normalize_stock_code(code)
    theme = _safe_feedback_theme_key(theme)
    return safe_int(codes.get(code, 0), 0), safe_int(themes.get(theme, 0), 0)
def _calc_stale_replay_penalty(code: str, theme: str = "", signal_type: str = "", age_hours: float = 0.0, miss_count: int = 0, leader_hit: bool = False, direct_like: bool = False, change_rate: float = 0.0, name: str = "", market: str = "") -> tuple[int, list[str]]:
    sig = str(signal_type or "").upper()
    if sig not in ("MID_PULLBACK", "ENTRY_POINT"):
        return 0, []
    if leader_hit or direct_like:
        return 0, []
    code_row = _get_stale_replay_code_entry(code)
    theme_row = _get_stale_replay_theme_entry(theme)
    intraday_code_hits, intraday_theme_hits = _get_intraday_stale_shadow_count(code, theme)
    penalty = 0
    notes = []
    if code_row:
        w = float(code_row.get("weight", 0.0) or 0.0)
        code_penalty = min(int(STALE_REPLAY_MAX_CODE_PENALTY or 6), max(2, int(round(w * 0.5))))
        penalty += code_penalty
        notes.append(f"🧯 stale 재노출 반복 감점 [{code_row.get('name', code)}] -{code_penalty}점")
    breadth = _get_theme_breadth_hint(code, name, theme=theme, market=market) if theme else {}
    if theme_row and change_rate < 18.0:
        tw = float(theme_row.get("weight", 0.0) or 0.0)
        theme_penalty = min(int(STALE_REPLAY_MAX_THEME_PENALTY or 4), max(1, int(round(tw * 0.28))))
        if breadth and bool(breadth.get("strong_breadth")) and safe_float(breadth.get("leader_change", 0.0), 0.0) >= max(8.0, change_rate):
            theme_penalty = max(0, theme_penalty - 1)
            if theme_penalty > 0:
                notes.append(f"🌱 stale 테마 breadth 방어 [{theme}] 감점완화")
        if theme_penalty > 0:
            penalty += theme_penalty
            notes.append(f"🧪 stale 테마 재노출 감점 [{theme}] -{theme_penalty}점")
        if breadth and bool(breadth.get("weak_breadth")) and change_rate < 18.0:
            extra = min(STALE_THEME_BREADTH_EXTRA_PENALTY, max(1, int(round(tw * 0.16)) + (1 if safe_float(breadth.get("breadth_ratio", 0.0), 0.0) < 0.25 else 0)))
            penalty += extra
            notes.append(f"📉 stale 테마 breadth 약세 [{theme}] -{extra}점")
    if intraday_code_hits >= 2:
        dyn = min(2, intraday_code_hits - 1)
        penalty += dyn
        notes.append(f"⏱ 당일 stale 재노출 누적 [{code}] -{dyn}점")
    if intraday_theme_hits >= 3 and change_rate < 16.0:
        dyn_theme = min(2, intraday_theme_hits - 2)
        penalty += dyn_theme
        notes.append(f"📉 당일 stale 테마 누적 [{theme}] -{dyn_theme}점")
    if penalty and age_hours >= STALE_PULLBACK_MIN_HOURS * 1.5:
        penalty += 1
    if penalty and miss_count >= 3:
        penalty += 1
    penalty = min(10, penalty)
    return penalty, notes
def _get_adaptive_feedback_code_entry(code: str) -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    if not isinstance(_adaptive_capture_feedback, dict):
        return {}
    rows = _adaptive_capture_feedback.get("priority_codes") or {}
    return dict(rows.get(code) or {}) if isinstance(rows, dict) else {}
def _get_adaptive_feedback_theme_entry(theme: str) -> dict:
    theme = _safe_feedback_theme_key(theme)
    if not theme:
        return {}
    if not isinstance(_adaptive_capture_feedback, dict):
        return {}
    rows = _adaptive_capture_feedback.get("theme_bias") or {}
    return dict(rows.get(theme) or {}) if isinstance(rows, dict) else {}
def _collect_adaptive_feedback_candidates(existing_codes=None) -> list:
    existing = {normalize_stock_code(c) for c in (existing_codes or []) if c}
    rows = []
    if not isinstance(_adaptive_capture_feedback, dict):
        return rows
    prio = _adaptive_capture_feedback.get("priority_codes") or {}
    if not isinstance(prio, dict) or not prio:
        return rows
    nxt_open = is_nxt_open()
    krx_open = is_market_open()
    for code, meta in list(sorted(prio.items(), key=lambda kv: float((kv[1] or {}).get("weight", 0.0) or 0.0), reverse=True))[:ADAPTIVE_FEEDBACK_MAX_CODES]:
        code = normalize_stock_code(code)
        if not code or code in existing:
            continue
        cur = {}
        try:
            if nxt_open and is_nxt_listed(code):
                cur = get_nxt_stock_price(code) or {}
            if (not cur or not cur.get("price")) and (krx_open or nxt_open):
                cur = get_stock_price(code) or {}
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            cur = {}
        price = safe_int(cur.get("price", 0), 0)
        change_rate = float(cur.get("change_rate", 0.0) or 0.0)
        vol_ratio = float(cur.get("volume_ratio", 0.0) or 0.0)
        if price <= 0:
            continue
        if change_rate < COMMON_THRESHOLD_3P0 and vol_ratio < 1.8:
            continue
        rows.append({
            "code": code,
            "name": _resolve_stock_name(code, meta.get("name", code)),
            "price": price,
            "change_rate": change_rate,
            "volume_ratio": vol_ratio,
            "today_vol": safe_int(cur.get("today_vol", 0), 0),
            "market": "NXT" if (nxt_open and is_nxt_listed(code)) else "KRX",
            "desc": "adaptive_feedback",
            "adaptive_feedback": True,
            "adaptive_feedback_weight": float(meta.get("weight", 0.0) or 0.0),
            "adaptive_feedback_theme": str(meta.get("theme", "") or ""),
        })
    return rows
def _calc_adaptive_feedback_bonus(code: str, theme: str = "", signal_type: str = "", change_rate: float = 0.0, vol_ratio: float = 0.0) -> tuple[int, list[str]]:
    bonus = 0
    notes = []
    code_row = _get_adaptive_feedback_code_entry(code)
    theme_row = _get_adaptive_feedback_theme_entry(theme)
    sig = str(signal_type or "")
    eligible_code = sig in ("SURGE", "EARLY_DETECT", "NEAR_UPPER", "STRONG_BUY", "UPPER_LIMIT")
    eligible_theme = sig in ("SURGE", "EARLY_DETECT", "NEAR_UPPER", "STRONG_BUY")
    if code_row and eligible_code:
        w = float(code_row.get("weight", 0.0) or 0.0)
        code_bonus = min(6, max(2, int(round(w * 0.8))))
        if change_rate >= 5.0 or vol_ratio >= 2.0:
            bonus += code_bonus
            notes.append(f"🔁 전일 miss 리더 재평가 [{code_row.get('name', code)}] +{code_bonus}점")
    if theme_row and eligible_theme:
        tw = float(theme_row.get("weight", 0.0) or 0.0)
        theme_bonus = min(4, max(1, int(round(tw * 0.45))))
        if change_rate >= 4.0 or vol_ratio >= 1.8:
            bonus += theme_bonus
            notes.append(f"🧪 self-audit 테마 보정 [{theme}] +{theme_bonus}점")
    return bonus, notes
def _parse_tracking_hint_datetime(date_str: str = "", time_str: str = "") -> datetime | None:
    date_str = str(date_str or "").strip()
    time_str = str(time_str or "").strip() or "00:00:00"
    if not date_str:
        return None
    try:
        if len(date_str) == 8 and date_str.isdigit():
            return datetime.strptime(f"{date_str} {time_str}", "%Y%m%d %H:%M:%S")
        return datetime.strptime(f"{date_str} {time_str}", "%Y-%m-%d %H:%M:%S")
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return None
def _load_tracking_priority_hints(force: bool = False) -> dict:
    now_ts = time.time()
    cache = _tracking_priority_hint_cache if isinstance(_tracking_priority_hint_cache, dict) else {"ts": 0.0, "rows": {}}
    if not force and cache.get("rows") and (now_ts - float(cache.get("ts", 0.0) or 0.0)) < 60:
        return cache.get("rows") or {}
    rows: dict = {}
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE) if os.path.exists(SIGNAL_LOG_FILE) else {}
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        data = {}
    if isinstance(data, dict):
        for _k, rec in data.items():
            if not isinstance(rec, dict):
                continue
            code = normalize_stock_code(rec.get("code", ""))
            if not code:
                continue
            first_dt = _parse_tracking_hint_datetime(rec.get("first_detect_date", rec.get("detect_date", "")), rec.get("first_detect_time", rec.get("detect_time", "")))
            last_dt = _parse_tracking_hint_datetime(rec.get("last_detect_date", rec.get("detect_date", "")), rec.get("last_detect_time", rec.get("detect_time", ""))) or first_dt
            cur = rows.get(code) or {}
            cur_last_dt = cur.get("last_dt")
            if cur and isinstance(cur_last_dt, datetime) and isinstance(last_dt, datetime) and last_dt <= cur_last_dt:
                continue
            rows[code] = {
                "first_dt": first_dt,
                "last_dt": last_dt,
                "signal_type": str(rec.get("signal_type", "") or ""),
                "status": str(rec.get("status", "") or ""),
                "miss_count": safe_int(rec.get("miss_count", 0), 0),
                "episode_candidate_count": safe_int(rec.get("episode_candidate_count", 0), 0),
            }
    _tracking_priority_hint_cache["ts"] = now_ts
    _tracking_priority_hint_cache["rows"] = rows
    return rows
def _get_tracking_priority_hint(code: str) -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    rows = _load_tracking_priority_hints()
    row = dict((rows or {}).get(code) or {})
    first_dt = row.get("first_dt")
    last_dt = row.get("last_dt")
    age_seconds = _kst_seconds_since(first_dt)
    last_seen_seconds = _kst_seconds_since(last_dt)
    row["age_hours"] = max(0.0, round(age_seconds / 3600.0, 2)) if age_seconds is not None else 0.0
    row["last_seen_hours"] = max(0.0, round(last_seen_seconds / 3600.0, 2)) if last_seen_seconds is not None else 0.0
    return row
def _empty_crossday_episode_context() -> dict:
    return {
        "episode_active": False,
        "prep": False,
        "confirmed": False,
        "near_upper_ready": False,
        "score_bonus": 0,
        "required_vol_cap": 0.0,
        "reclaim_ratio": 0.0,
        "pullback_pct": 0.0,
        "days_since_surge": 99,
        "hint_recent": False,
        "signal_hint_type": "",
        "reason": "",
    }
def _load_crossday_episode_history(code: str) -> list:
    try:
        items = get_daily_data(code, 8)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        items = []
    if len(items) < 4:
        return []
    hist = items[:-1] if len(items) >= 2 else items
    return hist if len(hist) >= 3 else []
def _select_crossday_episode_anchor(hist: list) -> dict:
    start_idx = max(1, len(hist) - 4)
    best_idx = -1
    best_score = -10**9
    best_gain = 0.0
    best_peak = 0
    for i in range(start_idx, len(hist)):
        row = hist[i] if isinstance(hist[i], dict) else {}
        prev_row = hist[i - 1] if i > 0 and isinstance(hist[i - 1], dict) else {}
        prev_close = safe_int(prev_row.get("close", 0), 0)
        close_p = safe_int(row.get("close", 0), 0)
        open_p = safe_int(row.get("open", close_p), close_p)
        high_p = safe_int(row.get("high", close_p), close_p)
        low_ref = min(open_p, close_p) if close_p else 0
        low_p = safe_int(row.get("low", low_ref), low_ref)
        if close_p <= 0 or high_p <= 0 or low_p <= 0:
            continue
        if prev_close <= 0:
            prev_close = open_p or close_p
        day_gain = ((close_p - prev_close) / prev_close * 100.0) if prev_close > 0 else 0.0
        day_range = ((high_p - low_p) / low_p * 100.0) if low_p > 0 else 0.0
        if day_gain < CROSSDAY_PRIOR_SURGE_MIN_PCT and day_range < CROSSDAY_PRIOR_RANGE_MIN_PCT:
            continue
        score = day_gain * COMMON_THRESHOLD_3P0 + day_range
        if score > best_score:
            best_idx = i
            best_score = score
            best_gain = day_gain
            best_peak = high_p
    return {
        "best_idx": best_idx,
        "best_gain": best_gain,
        "best_peak": best_peak,
    }
def _calc_crossday_episode_pullback(hist: list, best_idx: int, best_peak: int, current_price: int) -> dict:
    after_peak = [r for r in hist[best_idx + 1:] if isinstance(r, dict)]
    if not after_peak:
        after_peak = [hist[-1]] if hist and isinstance(hist[-1], dict) else []
    pullback_low = 0
    for row in after_peak:
        low_p = safe_int(row.get("low", 0), 0)
        if low_p <= 0:
            continue
        pullback_low = low_p if pullback_low <= 0 else min(pullback_low, low_p)
    if pullback_low <= 0:
        last_row = hist[-1] if hist and isinstance(hist[-1], dict) else {}
        pullback_low = safe_int(last_row.get("low", last_row.get("close", 0)), 0) or current_price
    if pullback_low <= 0 or best_peak <= 0 or best_peak <= pullback_low:
        return {}
    last_row = hist[-1] if hist and isinstance(hist[-1], dict) else {}
    current_ref_price = max(current_price, safe_int(last_row.get("high", current_price), current_price))
    reclaim_ratio = _calc_pullback_reclaim_ratio(best_peak, pullback_low, current_ref_price)
    return {
        "pullback_low": pullback_low,
        "pullback_pct": (best_peak - pullback_low) / best_peak * 100.0,
        "days_since_surge": max(0, len(hist) - 1 - best_idx),
        "reclaim_ratio": reclaim_ratio,
    }
def _build_crossday_episode_flags(hint_recent: bool, pullback_pct: float, change_rate: float, current_price: int, pullback_low: int, vol_ratio: float, reclaim_ratio: float) -> dict:
    prep = (
        hint_recent
        and pullback_pct >= CROSSDAY_PULLBACK_MIN_PCT
        and pullback_pct <= CROSSDAY_PULLBACK_MAX_PCT
        and change_rate >= CROSSDAY_RESURGE_PREP_MIN_CHANGE
        and current_price >= int(pullback_low * 1.02)
    )
    confirmed = (
        prep
        and change_rate >= CROSSDAY_RESURGE_SURGE_MIN_CHANGE
        and vol_ratio >= CROSSDAY_RESURGE_MIN_VOL_RATIO
        and reclaim_ratio >= CROSSDAY_RESURGE_MIN_RECLAIM_RATIO
    )
    near_upper_ready = bool(
        confirmed
        and change_rate >= CROSSDAY_RESURGE_NEAR_UPPER_MIN_CHANGE
        and reclaim_ratio >= 0.72
        and vol_ratio >= max(2.0, CROSSDAY_RESURGE_MIN_VOL_RATIO + 0.8)
    )
    return {
        "prep": bool(prep),
        "confirmed": bool(confirmed),
        "near_upper_ready": bool(near_upper_ready),
    }
def _get_crossday_episode_context(code: str, current_price: int = 0, change_rate: float = 0.0, vol_ratio: float = 0.0) -> dict:
    ctx = _empty_crossday_episode_context()
    code = normalize_stock_code(code)
    current_price = safe_int(current_price, 0)
    change_rate = safe_float(change_rate, 0.0)
    vol_ratio = safe_float(vol_ratio, 0.0)
    if not code or current_price <= 0:
        return ctx
    hint = _get_tracking_priority_hint(code)
    last_seen_hours = safe_float(hint.get("last_seen_hours", 999.0), 999.0)
    hint_recent = 0.0 <= last_seen_hours <= CROSSDAY_EPISODE_MAX_HOURS
    signal_hint_type = str(hint.get("signal_type", "") or "").upper()
    ctx["hint_recent"] = bool(hint_recent)
    ctx["signal_hint_type"] = signal_hint_type
    hist = _load_crossday_episode_history(code)
    if len(hist) < 3:
        return ctx
    anchor = _select_crossday_episode_anchor(hist)
    best_idx = safe_int(anchor.get("best_idx", -1), -1)
    best_gain = safe_float(anchor.get("best_gain", 0.0), 0.0)
    best_peak = safe_int(anchor.get("best_peak", 0), 0)
    if best_idx < 0 and not hint_recent:
        return ctx
    if best_idx < 0:
        best_idx = len(hist) - 1
        row = hist[best_idx] if isinstance(hist[best_idx], dict) else {}
        best_peak = safe_int(row.get("high", row.get("close", 0)), 0)
        best_gain = 0.0
    pullback = _calc_crossday_episode_pullback(hist, best_idx, best_peak, current_price)
    if not pullback:
        return ctx
    pullback_pct = safe_float(pullback.get("pullback_pct", 0.0), 0.0)
    days_since_surge = safe_int(pullback.get("days_since_surge", 99), 99)
    recent_cap = 4 if hint_recent else 3
    if days_since_surge > recent_cap:
        return ctx
    flags = _build_crossday_episode_flags(
        hint_recent,
        pullback_pct,
        change_rate,
        current_price,
        safe_int(pullback.get("pullback_low", 0), 0),
        vol_ratio,
        safe_float(pullback.get("reclaim_ratio", 0.0), 0.0),
    )
    if not (flags["prep"] or flags["confirmed"] or flags["near_upper_ready"]):
        return ctx
    reclaim_ratio = safe_float(pullback.get("reclaim_ratio", 0.0), 0.0)
    reason = (
        f"♻️ 전일 포함 연속 패턴: 1차상승 후 눌림 {pullback_pct:.1f}% / 회복률 {reclaim_ratio*100:.0f}% / "
        f"시차 {days_since_surge}일"
    )
    ctx.update({
        "episode_active": True,
        **flags,
        "score_bonus": 12 if flags["near_upper_ready"] else (10 if flags["confirmed"] else 6),
        "required_vol_cap": CROSSDAY_CONFIRM_REQUIRED_VOL_CAP if flags["confirmed"] else CROSSDAY_PREP_REQUIRED_VOL_CAP,
        "reclaim_ratio": round(reclaim_ratio, 3),
        "pullback_pct": round(pullback_pct, 1),
        "days_since_surge": int(days_since_surge),
        "prior_day_gain": round(best_gain, 1),
        "reason": reason,
    })
    return ctx
def _maybe_promote_signal_from_crossday_episode(signal_type: str, ctx: dict | None, change_rate: float = 0.0) -> str:
    ctx = ctx if isinstance(ctx, dict) else {}
    sig = str(signal_type or "").upper()
    change_rate = safe_float(change_rate, 0.0)
    if not ctx.get("episode_active"):
        return sig
    if ctx.get("near_upper_ready") and change_rate >= CROSSDAY_RESURGE_NEAR_UPPER_MIN_CHANGE:
        return "NEAR_UPPER"
    if ctx.get("confirmed") and change_rate >= CROSSDAY_RESURGE_SURGE_MIN_CHANGE:
        if sig in ("EARLY_DETECT", "SURGE"):
            return "SURGE"
    if ctx.get("prep") and sig in ("", "UNKNOWN") and change_rate >= CROSSDAY_RESURGE_PREP_MIN_CHANGE:
        return "EARLY_DETECT"
    return sig
def _should_require_execution_setup_from_crossday(signal_type: str, ctx: dict | None, change_rate: float = 0.0, vol_ratio: float = 0.0) -> bool:
    ctx = ctx if isinstance(ctx, dict) else {}
    sig = str(signal_type or "").upper()
    change_rate = safe_float(change_rate, 0.0)
    vol_ratio = safe_float(vol_ratio, 0.0)
    if not ctx.get("episode_active"):
        return False
    if sig == "EARLY_DETECT":
        return True
    if sig == "SURGE" and (ctx.get("prep") or ctx.get("confirmed")):
        if change_rate < CROSSDAY_EXECUTION_DIRECT_MIN_CHANGE or vol_ratio < max(2.0, CROSSDAY_RESURGE_MIN_VOL_RATIO + 0.6):
            return True
    return False
def _get_full_session_capture_stage(current_time: str = "", market: str = "") -> str:
    try:
        t = str(current_time or datetime.now().strftime("%H:%M:%S"))
        if " " in t:
            t = t.split(" ")[-1]
        hh, mm = int(t[:2]), int(t[3:5])
        mins = hh * 60 + mm
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        now_dt = datetime.now()
        mins = now_dt.hour * 60 + now_dt.minute
    market_name = str(market or "").upper()
    if 8 * 60 <= mins < 9 * 60 and market_name == "NXT":
        return "nxt_pre"
    if 9 * 60 <= mins < 10 * 60:
        return "opening"
    if 10 * 60 <= mins < 12 * 60:
        return "morning"
    if 12 * 60 <= mins < 14 * 60:
        return "afternoon"
    if 14 * 60 <= mins < 15 * 60 + 30:
        return "late"
    if 15 * 60 + 30 <= mins < 17 * 60 and market_name == "NXT":
        return "nxt_post_early"
    if 17 * 60 <= mins <= 20 * 60 and market_name == "NXT":
        return "nxt_post_late"
    return "other"
def _get_full_session_capture_profile(current_time: str = "", market: str = "") -> dict:
    stage = _get_full_session_capture_stage(current_time=current_time, market=market)
    profile = dict(FULL_SESSION_CAPTURE_PROFILES.get(stage, FULL_SESSION_CAPTURE_PROFILES.get("other", {})))
    profile["stage"] = stage
    return profile
def _promote_signal_from_full_session_flow(signal_type: str, stock: dict | None, change_rate: float = 0.0,
                                           vol_ratio: float = 0.0, current_time: str = "",
                                           crossday_ctx: dict | None = None) -> tuple[str, str, int]:
    stock = stock if isinstance(stock, dict) else {}
    ctx = crossday_ctx if isinstance(crossday_ctx, dict) else {}
    sig = str(signal_type or "").upper()
    market_name = str(stock.get("market", "") or "").upper()
    profile = _get_full_session_capture_profile(current_time=current_time, market=market_name)
    stage = str(profile.get("stage", "other") or "other")
    if stage == "other":
        return sig, "", 0
    cr = safe_float(change_rate, 0.0)
    vr = safe_float(vol_ratio, 0.0)
    desc = " ".join([str(stock.get("desc", "") or ""), str(stock.get("adaptive_feedback_theme", "") or "")])
    support_points = 0
    if ctx.get("episode_active"):
        support_points += 2
    if stock.get("theme_feedback") or stock.get("adaptive_feedback_hit") or stock.get("miss_theme_leader_hit") or stock.get("nxt_post_leader_hit"):
        support_points += 1
    if any(token in desc for token in ("랭킹후보", "자동편입", "feedback", "NXT장후리더", "theme_feedback", "theme_feedback[", "miss")):
        support_points += 1
    if cr >= 6.0:
        support_points += 1
    if vr >= COMMON_THRESHOLD_3P0:
        support_points += 1
    if market_name == "NXT" and not is_market_open():
        support_points += 1
    label = str(profile.get("label", "전시간대") or "전시간대")
    promo_bonus = profile.get("promo_bonus", {}) or {}
    near_ready = (
        cr >= float(profile.get("near_upper_min_change", UPPER_LIMIT_THRESHOLD - COMMON_THRESHOLD_3P0) or (UPPER_LIMIT_THRESHOLD - COMMON_THRESHOLD_3P0))
        and vr >= float(profile.get("near_upper_min_vol", 2.8) or 2.8)
        and (support_points >= 3 or ctx.get("near_upper_ready") or vr >= float(profile.get("near_upper_min_vol", 2.8) or 2.8) + 1.0)
    )
    surge_ready = (
        cr >= float(profile.get("surge_min_change", PRICE_SURGE_MIN) or PRICE_SURGE_MIN)
        and vr >= float(profile.get("surge_min_vol", 2.0) or 2.0)
        and (support_points >= 2 or ctx.get("confirmed") or vr >= float(profile.get("surge_min_vol", 2.0) or 2.0) + 1.0)
    )
    early_ready = (
        cr >= float(profile.get("early_min_change", max(1.6, CROSSDAY_RESURGE_PREP_MIN_CHANGE - 0.4)) or max(1.6, CROSSDAY_RESURGE_PREP_MIN_CHANGE - 0.4))
        and vr >= float(profile.get("early_min_vol", 1.4) or 1.4)
        and (support_points >= 1 or market_name == "NXT" or ctx.get("prep"))
    )
    if sig not in ("UPPER_LIMIT", "NEAR_UPPER") and near_ready and sig != "NEAR_UPPER":
        return "NEAR_UPPER", f"🕐 {label} 재가속 포착 — NEAR_UPPER 조기 승격", int(promo_bonus.get("NEAR_UPPER", 0) or 0)
    if sig in ("", "UNKNOWN", "EARLY_DETECT", "SURGE") and surge_ready and sig != "SURGE":
        return "SURGE", f"🕐 {label} 강세 지속 확인 — SURGE 조기 승격", int(promo_bonus.get("SURGE", 0) or 0)
    if sig in ("", "UNKNOWN") and early_ready:
        return "EARLY_DETECT", f"🕐 {label} 초기 강세 포착 — 내부추적 우선", int(promo_bonus.get("EARLY_DETECT", 0) or 0)
    return sig, "", 0
# ============================================================
# 🔥 F구간(광기구간) 감지 및 선진입 페널티 관리 (v162.3)
# 학술적 근거: 한국주식시장에서 거래대금 폭발 동반 급등 이후
#   t+1~t+3 거래일 내 평균회귀(reversal) 현상이 통계적으로 확인됨
#   (Kang & Chae 2019, Journal of Distribution Science 2023)
# 조건: 당일 거래대금비율 8배↑ AND 등락률 +10%↑ → F구간 마킹
# 해제: 3 거래일 경과 OR 해당 종목에 확인된 신규 재료(has_material) 등장
# ============================================================
def _trading_days_since(from_date_str: str) -> int:
    """from_date_str(YYYYMMDD) 기준 오늘까지 경과 거래일 수 (단순 달력일 기반 근사치, 주말 제외)."""
    try:
        from_date = datetime.strptime(from_date_str, "%Y%m%d").date()
        today = _now_kst().date()
        if today <= from_date:
            return 0
        count = 0
        cur = from_date
        while cur < today:
            cur += timedelta(days=1)
            if cur.weekday() < 5:  # 월~금
                count += 1
        return count
    except Exception:
        return 999  # 파싱 실패 시 충분히 큰 값 → 페널티 해제

def _save_f_zone_codes() -> None:
    """F구간 마킹 딕셔너리를 상태파일에 저장 (재시작 후 복원 보장)."""
    try:
        _write_json_atomic(F_ZONE_STATE_FILE, dict(_f_zone_codes))
    except Exception as e:
        _swallow_exception(e)

def _load_f_zone_codes() -> None:
    """봇 시작 시 F구간 마킹 딕셔너리 복원. 4 거래일 초과 항목은 즉시 폐기."""
    global _f_zone_codes
    try:
        data = _read_json_safe(F_ZONE_STATE_FILE, {})
        if not isinstance(data, dict):
            return
        cleaned = {}
        for code, info in data.items():
            if not isinstance(info, dict):
                continue
            elapsed = _trading_days_since(info.get("date", ""))
            if elapsed <= 3:
                cleaned[code] = info
        _f_zone_codes = cleaned
        if cleaned:
            _log_info_msg(f"[F구간] 재시작 복원: {len(cleaned)}종목 — {list(cleaned.keys())}")
    except Exception as e:
        _swallow_exception(e)

def _mark_f_zone(code: str, has_material: bool = False) -> None:
    """F구간 종목으로 마킹. has_material=True이면 재료 있음으로 기록 (페널티 면제 대상).
    v163.4: no_material_alert_sent 플래그 추가
      - 최초 마킹 시 has_material=False → no_material_alert_sent=False 세팅
      - 이후 재료-first 스캔에서 재료 발견 시 has_material=True 업데이트 + 후속 알람 트리거
    """
    global _f_zone_codes
    code = normalize_stock_code(code)
    if not code:
        return
    today_str = _now_kst().strftime("%Y%m%d")
    existing = _f_zone_codes.get(code, {})
    # 이미 오늘 마킹된 경우 has_material만 업데이트 (재료 새로 확인된 경우)
    if existing.get("date") == today_str:
        if has_material and not existing.get("has_material"):
            _f_zone_codes[code]["has_material"] = True
            # v163.4: 재료 새로 확인 → 후속 알람 트리거 플래그 세팅
            _f_zone_codes[code]["material_confirmed_pending"] = True
            _save_f_zone_codes()
            _log_info_msg(f"[F구간] {code} 재료 확인 → 후속 알람 트리거 예약")
        return
    _f_zone_codes[code] = {
        "date": today_str,
        "has_material": has_material,
        # v163.4: 무재료 포착 시 재료-first 스캔 우선 대상 플래그
        "no_material_alert_sent": not has_material,
        "material_confirmed_pending": False,
    }
    _save_f_zone_codes()
    _log_info_msg(f"[F구간] {code} 마킹 — date={today_str} has_material={has_material}")

def _is_f_zone_penalty(code: str, has_new_material: bool = False) -> tuple[bool, str]:
    """선진입 스코어링 시 F구간 페널티 적용 여부 반환.
    반환: (페널티 적용 여부, 사유 문자열)
    해제 조건: ① 3 거래일 초과 경과 ② has_material=True(기존) ③ has_new_material=True(현재)
    """
    global _f_zone_codes
    code = normalize_stock_code(code)
    if not code or code not in _f_zone_codes:
        return False, ""
    info = _f_zone_codes[code]
    # 재료 확인된 종목은 페널티 면제
    if info.get("has_material") or has_new_material:
        if has_new_material and not info.get("has_material"):
            _f_zone_codes[code]["has_material"] = True
        return False, ""
    mark_date = info.get("date", "")
    elapsed = _trading_days_since(mark_date)
    if elapsed > 3:
        # 3 거래일 초과 → 자동 해제 (메모리에서 제거)
        _f_zone_codes.pop(code, None)
        return False, ""
    reason = f"🚨 F구간 소진 종목 -15 (D+{elapsed}, {mark_date})"
    return True, reason


def _get_fzone_no_material_codes() -> list[str]:
    """v163.4: F구간 마킹 중 재료 미확인(has_material=False) 종목 코드 목록 반환.
    재료-first 스캔에서 이 종목들을 우선 뉴스/DART 검색 대상으로 활용.
    """
    today_str = _now_kst().strftime("%Y%m%d")
    result = []
    for code, info in dict(_f_zone_codes).items():
        if not isinstance(info, dict):
            continue
        if info.get("date") != today_str:
            continue
        if not info.get("has_material", False):
            result.append(code)
    return result


def _check_fzone_material_confirmed_and_alert() -> None:
    """v163.4: F구간 재료 확인 대기(material_confirmed_pending=True) 종목에 후속 알람 발송.
    run_material_first_scan() 내 또는 재료 발견 즉시 호출.
    흐름: F존 무재료 마킹 → 재료-first 스캔에서 뉴스/DART 확인
          → _mark_f_zone(code, has_material=True) → material_confirmed_pending=True
          → 이 함수가 후속 알람 발송 → pending 플래그 해제
    """
    if not _f_zone_codes:
        return
    today_str = _now_kst().strftime("%Y%m%d")
    for code, info in dict(_f_zone_codes).items():
        try:
            if not isinstance(info, dict):
                continue
            if info.get("date") != today_str:
                continue
            if not info.get("material_confirmed_pending", False):
                continue
            # 후속 알람 발송
            name = _resolve_stock_name(code, code)
            cur = get_stock_price(code)
            if not cur:
                continue
            price = safe_int(cur.get("price", 0), 0)
            chg = float(cur.get("change_rate", 0.0) or 0.0)
            chg_str = f"+{chg:.1f}%" if chg >= 0 else f"{chg:.1f}%"
            chart_url = f"https://m.stock.naver.com/domestic/stock/{code}/total"
            msg = (
                f"⚡ <b>[재료 확인됨]</b>\n"
                f"<b>{name}</b>  <b><code>{code}</code></b>\n"
                f"현재 {price:,}원 {chg_str}\n"
                f"F구간 포착 후 재료가 확인되었습니다."
            )
            send_with_chart_buttons(msg, code, name)
            _log_info_msg(f"[F구간] {name}({code}) 재료 확인 후속 알람 발송 완료")
            # pending 플래그 해제
            _f_zone_codes[code]["material_confirmed_pending"] = False
            _save_f_zone_codes()
        except Exception as e:
            _swallow_exception(e)

def _get_recent_avg_trade_amount(code: str, days: int | None = None) -> int:
    code = normalize_stock_code(code)
    if not code:
        return 0
    cache_key = f"{code}:{int(days or GLOBAL_PATTERN_TRADE_LOOKBACK_DAYS)}"
    cached = _global_pattern_trade_amount_cache.get(cache_key)
    if isinstance(cached, dict) and time.time() - float(cached.get("ts", 0) or 0) < 1800:
        return safe_int(cached.get("value", 0), 0)
    items = get_daily_data(code, days=max(int(days or 20) + 10, 40))
    if not items:
        return 0
    today = datetime.now().strftime("%Y%m%d")
    hist = [row for row in items if str(row.get("date", "") or "") < today]
    if not hist:
        hist = items[:-1] if len(items) > 1 else items
    values = [
        safe_int(row.get("close", 0), 0) * safe_int(row.get("vol", 0), 0)
        for row in hist[-max(5, int(days or 20)):]
        if safe_int(row.get("close", 0), 0) > 0 and safe_int(row.get("vol", 0), 0) > 0
    ]
    avg_value = int(sum(values) / len(values)) if values else 0
    _global_pattern_trade_amount_cache[cache_key] = {"ts": time.time(), "value": avg_value}
    return avg_value
def _calc_intraday_high_hold_metrics(stock: dict | None) -> dict:
    stock = stock if isinstance(stock, dict) else {}
    price = safe_int(stock.get("price", 0), 0)
    high = safe_int(stock.get("high", stock.get("day_high", 0)), 0)
    open_price = safe_int(stock.get("open", stock.get("open_price", 0)), 0)
    near_high_ratio = round((price / high), 4) if price > 0 and high > 0 else 0.0
    opening_drive_pct = round(((price - open_price) / open_price * 100.0), 2) if price > 0 and open_price > 0 else 0.0
    if price > 0 and high > open_price > 0:
        high_hold_ratio = max(0.0, min(1.2, (price - open_price) / max(high - open_price, 1)))
        opening_range_pct = round((high - open_price) / open_price * 100.0, 2)
    elif price > 0 and high > 0:
        high_hold_ratio = max(0.0, min(1.0, near_high_ratio))
        opening_range_pct = 0.0
    else:
        high_hold_ratio = 0.0
        opening_range_pct = 0.0
    return {
        "near_high_ratio": round(near_high_ratio, 4),
        "high_hold_ratio": round(high_hold_ratio, 4),
        "opening_drive_pct": round(opening_drive_pct, 2),
        "opening_range_pct": round(opening_range_pct, 2),
        "has_high": bool(high > 0),
    }
def _get_recent_high_breakout_context(code: str, current_price: int, lookback_days: int | None = None) -> dict:
    code = normalize_stock_code(code)
    price = safe_int(current_price, 0)
    if not code or price <= 0:
        return {}
    items = get_daily_data(code, days=max(int(lookback_days or 20) + 10, 50))
    if not items:
        return {}
    today = datetime.now().strftime("%Y%m%d")
    hist = [row for row in items if str(row.get("date", "") or "") < today]
    window = hist[-max(5, int(lookback_days or 20)):]
    highs = [safe_int(row.get("high", 0), 0) for row in window if safe_int(row.get("high", 0), 0) > 0]
    if not highs:
        return {}
    recent_high = max(highs)
    buffer_mult = max(0.95, 1.0 - GLOBAL_PATTERN_BREAKOUT_BUFFER_PCT / 100.0)
    breakout = bool(price >= int(recent_high * buffer_mult))
    distance_pct = round((price - recent_high) / recent_high * 100.0, 2) if recent_high > 0 else 0.0
    return {
        "recent_high": recent_high,
        "breakout": breakout,
        "distance_pct": distance_pct,
        "lookback_days": int(lookback_days or 20),
    }
def _build_global_pattern_context(stock: dict | None, current_time: str = "", change_rate: float = 0.0,
                                  vol_ratio: float = 0.0) -> dict:
    stock = stock if isinstance(stock, dict) else {}
    code = normalize_stock_code(stock.get("code", ""))
    price = safe_int(stock.get("price", 0), 0)
    today_vol = safe_int(stock.get("today_vol", 0), 0)
    trade_amount = safe_int(stock.get("trade_amount", 0), 0)
    if trade_amount <= 0 and price > 0 and today_vol > 0:
        trade_amount = int(price * today_vol)
    avg_trade_amount = _get_recent_avg_trade_amount(code)
    value_ratio = round((trade_amount / avg_trade_amount), 2) if trade_amount > 0 and avg_trade_amount > 0 else 0.0
    hold = _calc_intraday_high_hold_metrics(stock)
    breakout = _get_recent_high_breakout_context(code, price, lookback_days=GLOBAL_PATTERN_BREAKOUT_LOOKBACK_DAYS)
    market = str(stock.get("market", "") or "").upper()
    stage = _get_full_session_capture_stage(current_time=current_time, market=market)
    in_opening_stage = stage in ("opening", "nxt_pre", "nxt_post_early")
    recent_high_breakout = bool(
        breakout.get("breakout")
        and safe_float(change_rate, 0.0) >= GLOBAL_PATTERN_BREAKOUT_MIN_CHANGE
        and safe_float(vol_ratio, 0.0) >= GLOBAL_PATTERN_BREAKOUT_MIN_VOLUME
        and hold.get("near_high_ratio", 0.0) >= 0.985
    )
    value_hold_ready = bool(
        safe_float(change_rate, 0.0) >= GLOBAL_PATTERN_VALUE_MIN_CHANGE
        and safe_float(vol_ratio, 0.0) >= GLOBAL_PATTERN_VALUE_MIN_VOLUME
        and value_ratio >= GLOBAL_PATTERN_VALUE_RATIO_MIN
        and hold.get("high_hold_ratio", 0.0) >= GLOBAL_PATTERN_HIGH_HOLD_MIN
    )
    orb_breakout = bool(
        in_opening_stage
        and safe_float(change_rate, 0.0) >= GLOBAL_PATTERN_ORB_MIN_CHANGE
        and safe_float(vol_ratio, 0.0) >= GLOBAL_PATTERN_ORB_MIN_VOLUME
        and hold.get("high_hold_ratio", 0.0) >= GLOBAL_PATTERN_ORB_HIGH_HOLD_MIN
        and (
            hold.get("opening_range_pct", 0.0) >= GLOBAL_PATTERN_ORB_OPENING_RANGE_MIN_PCT
            or recent_high_breakout
            or hold.get("opening_drive_pct", 0.0) >= GLOBAL_PATTERN_ORB_OPENING_RANGE_MIN_PCT
        )
    )
    breakout_to_surge = bool(
        (orb_breakout or recent_high_breakout)
        and (
            value_ratio >= GLOBAL_PATTERN_VALUE_RATIO_STRONG
            or breakout.get("distance_pct", 0.0) >= 0.4
            or safe_float(change_rate, 0.0) >= 4.0
        )
    )
    breakout_to_early = bool(
        not breakout_to_surge and (orb_breakout or recent_high_breakout or value_hold_ready)
    )
    limit_distance_pct = max(0.0, round(UPPER_LIMIT_THRESHOLD - safe_float(change_rate, 0.0), 2))
    near_limit_lead = bool(
        safe_float(change_rate, 0.0) >= GLOBAL_PATTERN_NEAR_LIMIT_MIN_CHANGE
        and limit_distance_pct <= GLOBAL_PATTERN_NEAR_LIMIT_DISTANCE_PCT
        and value_ratio >= GLOBAL_PATTERN_NEAR_LIMIT_MIN_VALUE_RATIO
        and (
            hold.get("high_hold_ratio", 0.0) >= GLOBAL_PATTERN_NEAR_LIMIT_MIN_HOLD
            or recent_high_breakout
            or orb_breakout
        )
    )
    return {
        "trade_amount": trade_amount,
        "avg_trade_amount": avg_trade_amount,
        "value_ratio": value_ratio,
        "high_hold_ratio": float(hold.get("high_hold_ratio", 0.0) or 0.0),
        "near_high_ratio": float(hold.get("near_high_ratio", 0.0) or 0.0),
        "opening_drive_pct": float(hold.get("opening_drive_pct", 0.0) or 0.0),
        "opening_range_pct": float(hold.get("opening_range_pct", 0.0) or 0.0),
        "value_hold_ready": value_hold_ready,
        "value_hold_hit": bool(value_hold_ready and hold.get("near_high_ratio", 0.0) >= 0.986),
        "recent_high_breakout": recent_high_breakout,
        "recent_high": safe_int(breakout.get("recent_high", 0), 0),
        "recent_high_distance_pct": float(breakout.get("distance_pct", 0.0) or 0.0),
        "orb_breakout": orb_breakout,
        "breakout_to_surge": breakout_to_surge,
        "breakout_to_early": breakout_to_early,
        "near_limit_lead": near_limit_lead,
        "limit_distance_pct": limit_distance_pct,
        "stage": stage,
    }
def _is_leader_priority_signal(signal: dict | None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    sig = str(signal.get("signal_type", "") or "").upper()
    if sig in LEADER_PRIORITY_SIGNAL_TYPES:
        return True
    if bool(signal.get("direct_news_hit") or signal.get("theme_drive_hit") or signal.get("adaptive_feedback_hit") or signal.get("miss_theme_leader_hit")):
        return True
    change_rate = safe_float(signal.get("change_rate", 0.0), 0.0)
    vol_ratio = safe_float(signal.get("volume_ratio", 0.0), 0.0)
    score = safe_int(signal.get("score", 0), 0)
    if change_rate >= 12.0 and (vol_ratio >= 2.5 or score >= 95):
        return True
    if _extract_alert_sector_theme(signal) != "기타" and change_rate >= 8.0 and vol_ratio >= 1.8:
        return True
    return False
def _annotate_signal_priority(signal: dict | None) -> dict:
    signal = dict(signal or {})
    code = normalize_stock_code(signal.get("code", ""))
    hint = _get_tracking_priority_hint(code) if code else {}
    leader_hit = _is_leader_priority_signal(signal)
    sig = str(signal.get("signal_type", "") or "").upper()
    stale_hit = False
    if sig in ("MID_PULLBACK", "ENTRY_POINT"):
        age_hours = safe_float(hint.get("age_hours", 0.0), 0.0)
        miss_count = safe_int(hint.get("miss_count", 0), 0)
        last_seen_hours = safe_float(hint.get("last_seen_hours", 0.0), 0.0)
        is_intraday = bool(signal.get("is_intraday"))
        resurge_mode = bool(signal.get("resurge_mode"))
        theme_live = _extract_alert_sector_theme(signal) != "기타"
        direct_like = bool(signal.get("direct_news_hit") or signal.get("theme_drive_hit") or signal.get("adaptive_feedback_hit"))
        change_rate = safe_float(signal.get("change_rate", 0.0), 0.0)
        score = safe_int(signal.get("score", 0), 0)
        stale_hit = (
            age_hours >= STALE_PULLBACK_MIN_HOURS
            and last_seen_hours >= 0.25
            and not leader_hit
            and not direct_like
            and not theme_live
            and not is_intraday
            and not resurge_mode
            and change_rate < 12.0
            and score < 105
        )
        signal["tracking_replay_age_hours"] = age_hours
        signal["tracking_replay_miss_count"] = miss_count
        if not signal.get("_stale_replay_penalty_applied"):
            theme_key = _extract_alert_sector_theme(signal)
            penalty, notes = _calc_stale_replay_penalty(
                code=code,
                theme=theme_key,
                signal_type=sig,
                age_hours=age_hours,
                miss_count=miss_count,
                leader_hit=leader_hit,
                direct_like=direct_like,
                change_rate=change_rate,
                name=signal.get("name", ""),
                market=signal.get("market", ""),
            )
            signal["_priority_base_score"] = safe_int(signal.get("_priority_base_score", signal.get("score", 0)), 0)
            if penalty > 0:
                signal["score"] = max(0, safe_int(signal.get("_priority_base_score", signal.get("score", 0)), 0) - penalty)
                signal["stale_replay_penalty_points"] = penalty
                signal["stale_replay_penalty_hit"] = True
                signal.setdefault("reasons", []).extend(notes)
                if (
                    penalty >= STALE_REPLAY_FORCE_STALE_PENALTY
                    and not leader_hit
                    and not direct_like
                    and not theme_live
                    and not is_intraday
                    and not resurge_mode
                    and change_rate < 14.0
                ):
                    stale_hit = True
            signal["_stale_replay_penalty_applied"] = True
    signal["leader_priority_hit"] = bool(leader_hit)
    signal["stale_pullback_hit"] = bool(stale_hit)
    signal["stale_replay_penalty_hit"] = bool(signal.get("stale_replay_penalty_hit"))
    if stale_hit:
        signal.setdefault("reasons", []).append("🕰 기존 눌림목 재포착 성격 — 신규 리더 우선 구간에서는 후순위")
    return signal
def _apply_stale_pullback_quota(alerts: list, stage: str = "") -> list:
    if not alerts:
        return []
    staged = [_annotate_signal_priority(a) for a in alerts if isinstance(a, dict)]
    leader_present = any(a.get("leader_priority_hit") for a in staged)
    if not leader_present:
        return staged
    stale_limit = max(0, int(STALE_PULLBACK_MAX_PER_SCAN or 0))
    stale_kept = 0
    passed = []
    for a in staged:
        if a.get("stale_pullback_hit"):
            if safe_int(a.get("stale_replay_penalty_points", 0), 0) >= STALE_REPLAY_STRONG_DROP_POINTS:
                _record_shadow_capture(
                    a.get("code", ""), a.get("name", a.get("code", "")),
                    "stale_replay_penalty", a.get("signal_type", ""), stage=stage or "stale_replay_penalty",
                    extra={
                        "score": a.get("score", 0),
                        "grade": a.get("grade", ""),
                        "change_rate": a.get("change_rate", 0),
                        "market": a.get("market", ""),
                        "tracking_replay_age_hours": a.get("tracking_replay_age_hours", 0),
                        "tracking_replay_miss_count": a.get("tracking_replay_miss_count", 0),
                        "sector_theme": _extract_alert_sector_theme(a),
                    },
                )
                continue
            if stale_limit <= 0 or stale_kept >= stale_limit:
                _record_shadow_capture(
                    a.get("code", ""), a.get("name", a.get("code", "")),
                    "stale_pullback_quota", a.get("signal_type", ""), stage=stage or "stale_pullback_quota",
                    extra={
                        "score": a.get("score", 0),
                        "grade": a.get("grade", ""),
                        "change_rate": a.get("change_rate", 0),
                        "market": a.get("market", ""),
                        "tracking_replay_age_hours": a.get("tracking_replay_age_hours", 0),
                        "tracking_replay_miss_count": a.get("tracking_replay_miss_count", 0),
                        "sector_theme": _extract_alert_sector_theme(a),
                    },
                )
                continue
            stale_kept += 1
        passed.append(a)
    return passed
def _record_shadow_capture(code: str, name: str, reason: str, signal_type: str = "", stage: str = "", extra: dict | None = None):
    """외부 알림/실행으로 이어지지 못한 강세 후보를 내부 shadow 기록으로 남긴다."""
    try:
        data = _read_json_locked(SHADOW_CAPTURE_FILE) if os.path.exists(SHADOW_CAPTURE_FILE) else {}
        if not isinstance(data, dict):
            data = {}
        now = _now_kst()
        key = f"{normalize_stock_code(code) or code}_{now.strftime('%Y%m%d%H%M%S%f')}"
        rec = {
            "date": now.strftime('%Y%m%d'),
            "time": now.strftime('%Y-%m-%d %H:%M:%S'),
            "code": normalize_stock_code(code) or str(code or ""),
            "name": str(name or code or ""),
            "reason": str(reason or ""),
            "signal_type": str(signal_type or ""),
            "stage": str(stage or ""),
            "version": BOT_VERSION,
        }
        if isinstance(extra, dict):
            rec.update(extra)
        data[key] = rec
        if len(data) > 2000:
            for old_k in sorted(data.keys())[:len(data) - 2000]:
                data.pop(old_k, None)
        _write_json_atomic(SHADOW_CAPTURE_FILE, data, indent=2)
    except Exception as e:
        _log_warn_msg(f"⚠️ shadow capture 기록 오류: {e}")
def _iter_today_records(path: str, date_key: str) -> list:
    try:
        obj = _read_json_locked(path) if os.path.exists(path) else {}
        if not isinstance(obj, dict):
            return []
        rows = []
        for v in obj.values():
            if not isinstance(v, dict):
                continue
            d = str(v.get("date") or v.get("detect_date") or "")
            if d == date_key:
                rows.append(v)
        return rows
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return []
def _load_daily_self_audit_leaders(stage: str) -> list:
    leaders = list(_rank_from_universe("NXT" if stage == "nxt" else "KRX")[:15])
    uniq = []
    seen = set()
    for row in leaders:
        code = normalize_stock_code(row.get("code"))
        if code and code not in seen:
            seen.add(code)
            uniq.append(row)
    return uniq[:15]
def _load_daily_self_audit_detected(today: str) -> dict:
    signal_log = _read_json_locked(SIGNAL_LOG_FILE) if os.path.exists(SIGNAL_LOG_FILE) else {}
    signal_log = signal_log if isinstance(signal_log, dict) else {}
    today_detected = {}
    for rec in signal_log.values():
        if not isinstance(rec, dict) or str(rec.get("detect_date") or "") != today:
            continue
        code = normalize_stock_code(rec.get("code"))
        if code:
            today_detected.setdefault(code, rec)
    return today_detected
def _group_daily_self_audit_records(today: str) -> tuple[dict, dict]:
    by_code_supp, by_code_shadow = {}, {}
    for rec in _iter_today_records(SUPPRESSED_LOG_FILE, today):
        code = normalize_stock_code(rec.get("code"))
        if code:
            by_code_supp.setdefault(code, []).append(rec)
    for rec in _iter_today_records(SHADOW_CAPTURE_FILE, today):
        code = normalize_stock_code(rec.get("code"))
        if code:
            by_code_shadow.setdefault(code, []).append(rec)
    return by_code_supp, by_code_shadow
def _classify_daily_self_audit_leader(code: str, today_detected: dict, by_code_shadow: dict, by_code_supp: dict) -> str:
    if code in today_detected:
        return "detected"
    shadow = by_code_shadow.get(code, [])
    supp = by_code_supp.get(code, [])
    all_reasons = [str(r.get("reason", "")) for r in shadow + supp]
    if any("position_limit" in r for r in all_reasons):
        return "position_limit"
    if any("no_ask_liquidity" in r for r in all_reasons):
        return "no_ask_liquidity"
    if any("external_grade_suppressed" in r or "외부알림 억제" in r for r in all_reasons):
        return "external_suppressed"
    if all_reasons:
        return "blocked_other"
    return "candidate_miss"
def _summarize_daily_self_audit(leaders: list, today_detected: dict, by_code_shadow: dict, by_code_supp: dict) -> tuple[dict, list]:
    summary = {"detected": 0, "position_limit": 0, "no_ask_liquidity": 0, "external_suppressed": 0, "blocked_other": 0, "candidate_miss": 0}
    details = []
    for row in leaders:
        code = normalize_stock_code(row.get("code"))
        cls = _classify_daily_self_audit_leader(code, today_detected, by_code_shadow, by_code_supp)
        summary[cls] += 1
        details.append({
            "code": code,
            "name": row.get("name", code or ""),
            "change_rate": round(float(row.get("change_rate", 0) or 0), 2),
            "class": cls,
            "theme": row.get("theme", "") or row.get("sector", ""),
        })
    return summary, details
def _load_daily_self_audit_state() -> dict:
    audit_data = _read_json_locked(SELF_AUDIT_FILE) if os.path.exists(SELF_AUDIT_FILE) else {}
    return audit_data if isinstance(audit_data, dict) else {}
def _persist_daily_self_audit_entry(audit_key: str, today: str, stage: str, summary: dict, details: list) -> dict:
    audit_data = _load_daily_self_audit_state()
    audit_data[audit_key] = {
        "date": today,
        "stage": stage,
        "version": BOT_VERSION,
        "created_at": _now_kst().strftime("%Y-%m-%d %H:%M:%S"),
        "summary": summary,
        "leaders": details,
    }
    if len(audit_data) > 60:
        for old_k in sorted(audit_data.keys())[:len(audit_data) - 60]:
            audit_data.pop(old_k, None)
    _write_json_atomic(SELF_AUDIT_FILE, audit_data, indent=2)
    return audit_data[audit_key]
def _build_daily_self_audit_lines(stage: str, summary: dict, details: list) -> list:
    lines = [
        f"🧪 <b>장마감 self-audit</b> ({stage.upper()})  {BOT_VERSION}",
        f"━━━━━━━━━━━━━━━",
        f"상승 상위 {len(details)}종목 | 포착 {summary['detected']} | 제한 {summary['position_limit']} | 유동성 {summary['no_ask_liquidity']}",
        f"외부억제 {summary['external_suppressed']} | 기타차단 {summary['blocked_other']} | 후보미포착 {summary['candidate_miss']}",
    ]
    misses = [d for d in details if d["class"] != "detected"][:8]
    if misses:
        reason_map = {
            "position_limit": "동시보유 제한",
            "no_ask_liquidity": "유동성 차단",
            "external_suppressed": "외부알림 억제",
            "blocked_other": "기타 차단",
            "candidate_miss": "후보 미포착",
        }
        lines.append("━━━━━━━━━━━━━━━")
        for row in misses:
            lines.append(f"• {row['name']} {row['change_rate']:+.1f}% — {reason_map.get(row['class'], row['class'])}")
    return lines
def _run_daily_self_audit_post_actions() -> None:
    try:
        _build_adaptive_capture_feedback()
    except Exception as e:
        _swallow_exception(e)
    try:
        _build_stale_replay_penalty_profile()
    except Exception as e:
        _swallow_exception(e)
    try:
        escape_changes = _track_escape_aftermath()
        if escape_changes:
            for ec in escape_changes[:5]:
                _log_info_msg(f"  {ec}")
    except Exception as esc_e:
        _log_warn_msg(f"⚠️ 이탈 후속 추적 호출 오류: {esc_e}")
def run_daily_self_audit(stage: str = "krx") -> dict:
    """장마감 실제 상승 상위 종목 vs 포착/차단 결과를 자동 비교해 누락 패턴을 남긴다."""
    stage = "nxt" if str(stage).lower() == "nxt" else "krx"
    today = _now_kst().strftime("%Y%m%d")
    audit_key = f"{today}_{stage}_{BOT_VERSION}"
    if audit_key in _daily_self_audit_sent:
        return {}
    try:
        leaders = _load_daily_self_audit_leaders(stage)
        if not leaders:
            return {}
        today_detected = _load_daily_self_audit_detected(today)
        by_code_supp, by_code_shadow = _group_daily_self_audit_records(today)
        summary, details = _summarize_daily_self_audit(leaders, today_detected, by_code_shadow, by_code_supp)
        entry = _persist_daily_self_audit_entry(audit_key, today, stage, summary, details)
        send("\n".join(_build_daily_self_audit_lines(stage, summary, details)))
        _daily_self_audit_sent.add(audit_key)
        _run_daily_self_audit_post_actions()
        return entry
    except Exception as e:
        _log_error(f"run_daily_self_audit({stage})", e)
        return {}
# ============================================================
# v83: 외부 순위 소스 스크래핑 (KIS fallback 다변화)
# ============================================================
# v161.26: 섹터별 거래대금 집계 캐시
_sector_volume_cache: dict = {"ts": 0, "data": []}

def _fetch_sector_volume_rank(top_n: int = 10) -> list:
    """v161.26: 네이버 증권 업종별 시세에서 거래대금 순위 집계.
    반환: [{"sector": str, "amount_bn": float, "change_rate": float}, ...]
    amount_bn: 거래대금 (억원 단위)
    캐시 TTL: 3분
    """
    global _sector_volume_cache
    now = time.time()
    if now - _sector_volume_cache.get("ts", 0) < 180:
        return list(_sector_volume_cache.get("data", []))
    try:
        # 네이버 업종 시세 (kospi=0, kosdaq=1)
        results = {}
        for sosok, mkt in [("0", "코스피"), ("1", "코스닥")]:
            try:
                url = "https://finance.naver.com/sise/sise_group.naver"
                resp = requests.get(url, params={"type": "업종", "sosok": sosok},
                                    timeout=10, headers=_random_ua())
                resp.raise_for_status()
                apparent = (resp.apparent_encoding or "").strip()
                if apparent:
                    resp.encoding = apparent
                else:
                    resp.encoding = "euc-kr"
                soup = BeautifulSoup(resp.text, "html.parser")
                rows = soup.select("table.type_1 tr, table.group_list tr")
                if not rows:
                    rows = soup.select("tr")
                for row in rows:
                    tds = row.find_all("td")
                    if len(tds) < 5:
                        continue
                    a_tag = row.find("a")
                    if not a_tag:
                        continue
                    sector_name = a_tag.get_text(strip=True)
                    if not sector_name or len(sector_name) < 2:
                        continue
                    # 각 td에서 거래대금(억원) 추출 — 숫자가 큰 값이 거래대금
                    amounts = []
                    for td in tds:
                        txt = td.get_text(strip=True).replace(",", "")
                        try:
                            val = float(txt)
                            if val > 100:  # 100억 이상만 거래대금으로 간주
                                amounts.append(val)
                        except ValueError:
                            continue
                    if not amounts:
                        continue
                    amount = max(amounts)
                    # 등락률 추출
                    rate = 0.0
                    for td in tds:
                        txt = td.get_text(strip=True).replace(",", "").replace("+", "")
                        try:
                            val = float(txt)
                            if -15.0 < val < 15.0 and val != 0.0:
                                rate = val
                                break
                        except ValueError:
                            continue
                    key = sector_name
                    if key not in results or results[key]["amount_bn"] < amount:
                        results[key] = {
                            "sector": sector_name,
                            "amount_bn": amount,
                            "change_rate": rate,
                            "market": mkt,
                        }
            except Exception as e:
                _log_warn_msg(f"  ⚠️ 섹터 거래대금 {mkt} 스크래핑 실패: {e}")
                continue

        ranked = sorted(results.values(), key=lambda x: x["amount_bn"], reverse=True)[:top_n]
        _sector_volume_cache["ts"] = now
        _sector_volume_cache["data"] = ranked
        return ranked
    except Exception as e:
        _swallow_exception(e)
        return []
def _fetch_naver_rank(category: str = "rise", top_n: int = 30) -> list:
    """
    네이버 증권 순위 스크래핑.
    category: rise(상승률) | volume(거래량) | amount(거래대금)
    KIS API 불통 시 보조 소스로 사용.
    v85: 코스피 + 코스닥 합산으로 확대.
    v160.5: 코스닥 direct path 404를 피하기 위해 공통 URL + sosok 파라미터로 통일.
    """
    url_map = {
        "rise":   "https://finance.naver.com/sise/sise_rise.naver",
        "volume": "https://finance.naver.com/sise/sise_quant.naver",
        "amount": "https://finance.naver.com/sise/sise_quant.naver",  # v163.11 [#1]: sise_etf(404) → sise_quant
    }
    market_plan = [("KOSPI", "0"), ("KOSDAQ", "1")]

    def _parse_naver_rank_url(url: str, market_label: str, sosok: str) -> list:
        try:
            resp = requests.get(url, params={"sosok": sosok}, timeout=10, headers=_random_ua())
            resp.raise_for_status()
            apparent = (resp.apparent_encoding or "").strip()
            current = (resp.encoding or "").strip().lower()
            if apparent:
                resp.encoding = apparent
            elif not current or current == "iso-8859-1":
                resp.encoding = "euc-kr"
            soup = BeautifulSoup(resp.text, "html.parser")
            rows = soup.select("table.type_2 tr, table.type_5 tr")
            result = []
            for row in rows:
                tds = row.find_all("td")
                if len(tds) < 4:
                    continue
                a_tag = row.find("a", href=lambda h: h and "code=" in str(h))
                if not a_tag:
                    continue
                import re
                m = re.search(r"code=(\d{6})", a_tag.get("href", ""))
                if not m:
                    continue
                code = m.group(1)
                name = a_tag.get_text(strip=True)
                rate_td = None
                for td in tds:
                    txt = td.get_text(strip=True).replace(",", "").replace("+", "").replace("%", "")
                    try:
                        val = float(txt)
                        if -30 < val < 30 and val != 0:
                            rate_td = val
                            break
                    except ValueError:
                        continue
                if rate_td is None:
                    continue
                result.append({
                    "code": code, "name": name,
                    "change_rate": rate_td,
                    "source": f"naver_{category}",
                    "market": "KRX",
                    "market_detail": market_label,
                })
                if len(result) >= top_n:
                    break
            return result
        except Exception as e:
            _log_warn_msg(f"  ⚠️ 네이버 {market_label} {category} 순위 스크래핑 실패: {e}")
            return []

    base_url = url_map.get(category, url_map["rise"])
    merged = []
    for market_label, sosok in market_plan:
        merged.extend(_parse_naver_rank_url(base_url, market_label, sosok))

    seen = set()
    result = []
    for item in merged:
        code = item.get("code", "")
        if code and code not in seen:
            seen.add(code)
            result.append(item)
    result.sort(key=lambda x: float(x.get("change_rate", 0) or 0), reverse=True)
    return result[:top_n]
def _fetch_daum_rank(top_n: int = 30) -> list:
    """다음 증권 상승률 순위 스크래핑 (네이버 실패 시 2차 소스)
    v85: KOSPI + KOSDAQ 합산.
    """
    def _fetch_daum_market(market: str) -> list:
        try:
            url = f"https://finance.daum.net/api/quotes/ranks?market={market}&perPage=30&rankType=RISE"
            headers = {**_random_ua(), "Referer": "https://finance.daum.net/"}
            resp = requests.get(url, timeout=10, headers=headers)
            resp.raise_for_status()
            data = resp.json()
            items = data.get("data", [])
            result = []
            for item in items[:top_n]:
                code = str(item.get("code") or item.get("symbolCode") or "").replace("A", "")[:6]
                if not code:
                    continue
                result.append({
                    "code": code,
                    "name": item.get("name", ""),
                    "change_rate": float(item.get("changeRate", 0) or 0) * 100,
                    "price": int(item.get("tradePrice", 0) or 0),
                    "source": "daum_rise",
                    "market": "KRX",
                })
            return result
        except Exception as e:
            _log_warn_msg(f"  ⚠️ 다음 {market} 상승률 순위 스크래핑 실패: {e}")
            return []
    kospi_items = _fetch_daum_market("KOSPI")
    kosdaq_items = _fetch_daum_market("KOSDAQ")
    seen = set()
    result = []
    for item in kospi_items + kosdaq_items:
        code = item.get("code", "")
        if code and code not in seen:
            seen.add(code)
            result.append(item)
    result.sort(key=lambda x: float(x.get("change_rate", 0) or 0), reverse=True)
    return result[:top_n]
def _resolve_watchdog_market_basis() -> str:
    if is_nxt_open() and not is_market_open():
        return "NXT"
    return "KRX"
def _fetch_external_rank_top(min_change: float = COMMON_THRESHOLD_3P0, top_n: int = 30, market: str = "AUTO") -> list:
    """
    외부 소스(네이버→다음→유니버스) 순으로 시도해 상승 종목 목록 반환.
    v163.10 [#3]: 거래대금 상위도 병행 수집해 꾸준히 오르는 종목 커버.
    """
    market_basis = str(market or "AUTO").upper()
    if market_basis not in {"KRX", "NXT"}:
        market_basis = _resolve_watchdog_market_basis()
    items = []
    if market_basis == "NXT":
        raw = _rank_from_universe("NXT")
        items = [{**r, "source": "universe_nxt", "market": "NXT"} for r in raw]
        # v163.13 [#2]: universe_nxt 0건이면 KIS NXT volume-rank API 직접 재시도
        if not items:
            try:
                nxt_direct = get_nxt_surge_stocks()
                if nxt_direct:
                    items = [{**r, "source": "universe_nxt", "market": "NXT"} for r in nxt_direct]
                    _log_info_msg(f"  🔄 universe_nxt 0건 → NXT volume-rank 직접 재시도 {len(items)}건 확보")
            except Exception as _nxt_retry_e:
                _swallow_exception(_nxt_retry_e)
    else:
        items = _fetch_naver_rank("rise", top_n=top_n)
        if not items:
            items = _fetch_daum_rank(top_n=top_n)
        if not items:
            raw = _rank_from_universe("KRX")
            items = [{**r, "source": "universe", "market": "KRX"} for r in raw]
        # v163.10 [#3]: 거래대금 상위 30종목 병행 수집 (대한전선류 커버)
        try:
            seen_codes = {normalize_stock_code(r.get("code")) for r in items}
            amount_items = _fetch_naver_rank("amount", top_n=30)
            for r in amount_items:
                code = normalize_stock_code(r.get("code"))
                chg = float(r.get("change_rate", 0) or 0)
                if code and code not in seen_codes and chg >= min_change:
                    items.append(r)
                    seen_codes.add(code)
        except Exception as _ae:
            _swallow_exception(_ae)
    filtered = [r for r in items if float(r.get("change_rate", 0) or 0) >= min_change]
    filtered.sort(key=lambda x: float(x.get("change_rate", 0) or 0), reverse=True)
    return filtered[:top_n]
