# v83: 장중 워치독 — 침묵 감지 → 차단 사유 자동 진단 → 파라미터 완화
# ============================================================
_WATCHDOG_SILENCE_MIN   = int(os.getenv("WATCHDOG_SILENCE_MIN", "30"))    # 침묵 판정 기준(분)
_WATCHDOG_MIN_RISING    = int(os.getenv("WATCHDOG_MIN_RISING", "5"))      # 외부 상승 종목 최소 수
_WATCHDOG_RELAX_MIN     = int(os.getenv("WATCHDOG_RELAX_MIN", "30"))      # 완화 유지 시간(분)
_WATCHDOG_NOTIFY_CD_MIN = int(os.getenv("WATCHDOG_NOTIFY_CD_MIN", "20"))  # 텔레그램 알림 쿨다운(분)
_watchdog_last_notify_ts: float = 0.0
CODE_CHANGE_REQUEST_STATE_FILE = _state_path("code_change_request_state.json")
_CODE_CHANGE_REQUEST_CD_MIN = int(os.getenv("CODE_CHANGE_REQUEST_CD_MIN", "180"))
PUBLIC_STOCK_META_FILE = _state_path("public_stock_meta.json")
PUBLIC_STOCK_META_CACHE_TTL_SEC = int(os.getenv("PUBLIC_STOCK_META_CACHE_TTL_SEC", "21600") or "21600")
RUN_SCAN_REPAIR_RETRY_SEC = int(os.getenv("RUN_SCAN_REPAIR_RETRY_SEC", "120") or "120")
RUN_SCAN_REPAIR_MAX_ATTEMPTS = int(os.getenv("RUN_SCAN_REPAIR_MAX_ATTEMPTS", "3") or "3")
RUN_SCAN_REPAIR_ALERT_AFTER = int(os.getenv("RUN_SCAN_REPAIR_ALERT_AFTER", "2") or "2")
ENTRY_TERMINATION_STATE_FILE = _state_path("entry_termination_state.json")
ENTRY_TERMINATION_ALERT_COOLDOWN_SEC = int(os.getenv("ENTRY_TERMINATION_ALERT_COOLDOWN_SEC", "1800") or "1800")
ENTRY_TERMINATION_REARM_COOLDOWN_SEC = int(os.getenv("ENTRY_TERMINATION_REARM_COOLDOWN_SEC", "2400") or "2400")
_entry_termination_state_runtime = {}
_PUBLIC_STOCK_META_MEM = {"ts": 0.0, "items": {}}
_run_scan_repair_queue = {}
def _send_code_change_request_alert(issue_key: str, lines: list[str], cooldown_min: int | None = None) -> bool:
    """자동조정 불가 구조 문제를 별도 텔레그램 요청 알림으로 보낸다."""
    try:
        cd_sec = int((cooldown_min or _CODE_CHANGE_REQUEST_CD_MIN) * 60)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        cd_sec = 180 * 60
    now_ts = time.time()
    state = _read_json_safe(CODE_CHANGE_REQUEST_STATE_FILE, {})
    if not isinstance(state, dict):
        state = {}
    last_sent = state.get("last_sent", {})
    if not isinstance(last_sent, dict):
        last_sent = {}
    last_ts = float(last_sent.get(issue_key, 0) or 0)
    if last_ts and (now_ts - last_ts) < cd_sec:
        _log_info_msg(f"  🛠 코드수정 요청 쿨다운 중: {issue_key} ({int((now_ts-last_ts)/60)}분 경과)")
        return False
    send("\n".join([str(x) for x in lines if str(x).strip()]))
    last_sent[issue_key] = now_ts
    state["last_sent"] = last_sent
    state["last_issue_key"] = issue_key
    state["last_issue_text"] = "\n".join([str(x) for x in lines if str(x).strip()])
    _write_json_atomic(CODE_CHANGE_REQUEST_STATE_FILE, state, indent=2)
    _log_info_msg(f"  🛠 코드수정 요청 알림 발송: {issue_key}")
    return True
def _build_watchdog_code_change_request(main_reason: str, reasons: dict, rising: list, elapsed_since_alert: float, relax_changes: list[str], alert_baseline_label: str = "") -> dict | None:
    """워치독 결과 중 자동조정 불가 구조 문제를 코드수정 요청 알림 payload로 변환."""
    specs = {
        "candidate_miss": {
            "title": "후보군 미포착",
            "symptom": "외부 상승 종목은 있는데 후보군/포착 체인에 거의 안 올라옵니다.",
            "inspect": ["_fetch_external_rank_top", "_rank_api_fallback", "build_stock_universe", "analyze"],
            "route": "외부 상승 랭킹 → fallback 체인 → 유니버스 편입 → analyze 후보화",
            "request": "fallback 체인/유니버스 편입/후보화 조건 코드 점검 필요",
        },
    }
    spec = specs.get(main_reason)
    if not spec:
        return None
    silence_label = f"{int(elapsed_since_alert/60)}분"
    if alert_baseline_label:
        silence_label = f"{silence_label} ({alert_baseline_label})"
    top3 = ", ".join([f"{r.get('name','?')} {float(r.get('change_rate',0)):+.1f}%" for r in rising[:3]]) or "없음"
    lines = [
        "🛠 <b>[코드수정 요청]</b>",
        "━━━━━━━━━━━━━━━",
        f"📌 구조 문제: <b>{spec['title']}</b>",
        f"⏱ 알림 침묵: <b>{silence_label}</b>",
        f"📈 외부 상승 종목 예시: {top3}",
        "",
        "❌ 자동조정으로 해결 불가",
        f"증상: {spec['symptom']}",
        f"추정 경로: {spec['route']}",
        f"점검 함수: {', '.join(spec['inspect'])}",
        f"요청: {spec['request']}",
    ]
    if reasons:
        lines.append("")
        lines.append("참고 집계:")
        for k, v in sorted(reasons.items(), key=lambda x: -x[1]):
            lines.append(f"  • {k}: {v}건")
    if relax_changes:
        lines.append("")
        lines.append("자동 완화 시도:")
        for c in relax_changes:
            lines.append(f"  {c}")
    return {"issue_key": main_reason, "lines": lines}
def _watchdog_collect_block_reasons(since_ts: float) -> dict:
    """shadow_capture에서 since_ts 이후 차단 사유 집계"""
    counts: dict = {}
    try:
        data = _read_json_safe(SHADOW_CAPTURE_FILE, {})
        if not isinstance(data, dict):
            return counts
        for rec in data.values():
            if not isinstance(rec, dict):
                continue
            try:
                rec_ts = datetime.strptime(
                    str(rec.get("time") or ""), "%Y-%m-%d %H:%M:%S"
                ).timestamp()
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                continue
            if rec_ts < since_ts:
                continue
            reason = str(rec.get("reason") or rec.get("stage") or "기타")
            # 사유 정규화
            if "position_limit" in reason:
                key = "position_limit"
            elif "외부알림 억제" in reason or "grade_suppressed" in reason or "B등급" in reason or "C등급" in reason:
                key = "grade_suppressed"
            elif "no_ask_liquidity" in reason:
                key = "no_ask_liquidity"
            elif "candidate_miss" in reason or "후보 미포착" in reason:
                key = "candidate_miss"
            else:
                key = "기타"
            counts[key] = counts.get(key, 0) + 1
    except Exception as e:
        _log_warn_msg(f"  ⚠️ watchdog 사유 집계 오류: {e}")
    return counts
def _watchdog_apply_relax(main_reason: str) -> list:
    """
    주 차단 사유에 따라 _dynamic 파라미터 완화.
    코드 구조 문제(candidate_miss 등)는 파라미터로 못 고치므로 진단만 하고 알림.
    반환: 변경 내용 문자열 리스트
    """
    global _dynamic, _watchdog_relaxed_until
    changes = []
    relax_sec = _WATCHDOG_RELAX_MIN * 60
    if main_reason == "grade_suppressed":
        # A전용 외부알림 정책은 유지하고, 더 많은 종목이 A컷에 진입할 수 있게만 완화
        old_n = int(_dynamic.get("min_score_normal", 56))
        old_s = int(_dynamic.get("min_score_strict", 66))
        new_n = max(45, old_n - 8)
        new_s = max(52, old_s - 8)
        if new_n < old_n or new_s < old_s:
            _dynamic["min_score_normal"] = new_n
            _dynamic["min_score_strict"] = new_s
            _watchdog_relaxed_until = time.time() + relax_sec
            changes.append(f"min_score {old_n}/{old_s} → {new_n}/{new_s} (A전용 정책 유지 상태에서 A컷 진입 보조, {_WATCHDOG_RELAX_MIN}분 후 복원)")
    elif main_reason == "no_ask_liquidity":
        # 파라미터 완화로 대응 가능
        old_n = int(_dynamic.get("min_score_normal", 56))
        new_n = max(48, old_n - 5)
        if new_n < old_n:
            _dynamic["min_score_normal"] = new_n
            _watchdog_relaxed_until = time.time() + relax_sec
            changes.append(f"min_score_normal {old_n} → {new_n} (호가차단 완화, {_WATCHDOG_RELAX_MIN}분 후 복원)")
    elif main_reason == "candidate_miss":
        # v161.27: 파라미터로 부분 완화 가능한 항목 즉시 적용
        # ① RANK_SESSION_TOP_N 일시 확대 → 더 많은 종목이 랭킹후보로 편입
        old_top_n = int(_dynamic.get("rank_session_top_n_override", 0) or RANK_SESSION_TOP_N)
        new_top_n = min(old_top_n + 50, 150)
        _dynamic["rank_session_top_n_override"] = new_top_n
        # ② UNIVERSE_MAX_PER_THEME 일시 완화 → 테마 내 후순위 종목도 편입
        old_theme_cap = int(_dynamic.get("universe_max_per_theme_override", 0) or 8)
        new_theme_cap = min(old_theme_cap + 4, 15)
        _dynamic["universe_max_per_theme_override"] = new_theme_cap
        _watchdog_relaxed_until = time.time() + relax_sec
        changes.append(f"🔧 candidate_miss 완화: rank_top_n {old_top_n}→{new_top_n}, theme_cap {old_theme_cap}→{new_theme_cap} ({_WATCHDOG_RELAX_MIN}분 후 복원)")
        changes.append("🔴 구조 문제 병존: fallback 체인 점검 필요 (코드 수정 요망)")
    elif main_reason == "기타":
        # 원인 불명 — min_score만 소폭 완화
        old_n = int(_dynamic.get("min_score_normal", 56))
        new_n = max(48, old_n - 5)
        if new_n < old_n:
            _dynamic["min_score_normal"] = new_n
            _watchdog_relaxed_until = time.time() + relax_sec
            changes.append(f"min_score_normal {old_n} → {new_n} (원인불명 완화, {_WATCHDOG_RELAX_MIN}분 후 복원)")
    return changes
def _watchdog_restore_relax() -> bool:
    """완화 만료 시 원래 값으로 복원"""
    global _dynamic, _watchdog_relaxed_until
    if _watchdog_relaxed_until and time.time() >= _watchdog_relaxed_until:
        _watchdog_relaxed_until = 0.0
        # auto_tune 최신값으로 재로드 (동적 파라미터 파일 있으면 우선)
        try:
            saved = _read_json_safe(DYNAMIC_PARAMS_FILE, {})
            if isinstance(saved, dict) and saved:
                for k in ("min_score_normal", "min_score_strict"):
                    if k in saved:
                        _dynamic[k] = saved[k]
                _log_info_msg(f"  🔄 워치독 완화 만료 → 파라미터 복원")
                return True
        except Exception as e:
            _swallow_exception(e)
    return False
def _load_intraday_watchdog_rising() -> list:
    market_basis = _resolve_watchdog_market_basis()
    return _fetch_external_rank_top(min_change=WATCHDOG_RANK_MIN_CHANGE, top_n=WATCHDOG_RANK_TOP_N, market=market_basis)
def _collect_intraday_watchdog_state(now_ts: float) -> dict | None:
    rising = _load_intraday_watchdog_rising()
    n_rising = len(rising)
    if n_rising < _WATCHDOG_MIN_RISING:
        _log_info_msg(f"  🐕 워치독: 외부 상승 종목 {n_rising}개 — 침묵 판정 기준 미달, 스킵")
        return None
    silence_sec = _WATCHDOG_SILENCE_MIN * 60
    if _last_external_alert_ts > 0:
        baseline_ts = _last_external_alert_ts
        alert_baseline_label = "마지막 외부알림 기준"
    else:
        baseline_ts = _watchdog_process_start_ts
        alert_baseline_label = "부팅 후 외부알림 없음"
    elapsed_since_alert = max(0.0, now_ts - baseline_ts)
    if elapsed_since_alert < silence_sec:
        remaining = int((silence_sec - elapsed_since_alert) / 60)
        _log_info_msg(f"  🐕 워치독: {alert_baseline_label} {int(elapsed_since_alert/60)}분 경과 — 정상 (침묵 아님, {remaining}분 더 관찰)")
        return None
    since_ts = now_ts - silence_sec
    reasons = _watchdog_collect_block_reasons(since_ts)
    main_reason = max(reasons, key=reasons.get) if reasons else "candidate_miss"
    return {
        "rising": rising,
        "n_rising": n_rising,
        "elapsed_since_alert": elapsed_since_alert,
        "alert_baseline_label": alert_baseline_label,
        "reasons": reasons,
        "total_blocked": sum(reasons.values()),
        "main_reason": main_reason,
    }
def _build_intraday_watchdog_lines(state: dict, relax_changes: list[str]) -> list[str]:
    rising = state["rising"]
    n_rising = state["n_rising"]
    reasons = state["reasons"]
    total_blocked = state["total_blocked"]
    elapsed_since_alert = state["elapsed_since_alert"]
    alert_baseline_label = str(state.get("alert_baseline_label") or "")
    source_label = (rising[0].get("source", "?") if rising else "?")
    source_label = source_label.replace("naver_rise", "네이버").replace("daum_rise", "다음").replace("universe_nxt", "내부유니버스(NXT)").replace("universe", "내부유니버스")
    top3_rising = ", ".join([f"{r.get('name','?')} {float(r.get('change_rate',0)):+.1f}%" for r in rising[:3]])
    reason_labels = {
        "grade_suppressed": "A전용 정책 억제",
        "position_limit": "동시보유 제한(v82 제거됨)",
        "no_ask_liquidity": "호가 유동성 차단",
        "candidate_miss": "후보군 미포착",
        "기타": "기타/원인불명",
    }
    lines = [
        f"🐕 <b>[장중 워치독 자가진단]</b>",
        f"━━━━━━━━━━━━━━━",
        f"⏱ 알림 침묵: <b>{int(elapsed_since_alert/60)}분</b> (기준 {_WATCHDOG_SILENCE_MIN}분, {alert_baseline_label})",
        f"📈 외부 상승 종목: <b>{n_rising}개</b> [{source_label}]",
        f"🏷 감시 시장 기준: <b>{_resolve_watchdog_market_basis()}</b>",
        f"   {top3_rising} 등",
        f"",
        f"🔍 차단 사유 분석 ({total_blocked}건):",
    ]
    for k, v in sorted(reasons.items(), key=lambda x: -x[1]):
        lines.append(f"  • {reason_labels.get(k, k)}: {v}건")
    lines.append("")
    lines.append("⚙️ 자동 조치:")
    if relax_changes:
        lines.extend([f"  {c}" for c in relax_changes])
    else:
        lines.append("  없음 (이미 최소값)")
    return lines
def _maybe_send_intraday_watchdog_alert(now_ts: float, state: dict, relax_changes: list[str]) -> bool:
    global _watchdog_last_notify_ts
    notify_cd_sec = _WATCHDOG_NOTIFY_CD_MIN * 60
    if now_ts - _watchdog_last_notify_ts < notify_cd_sec:
        _log_info_msg(f"  🐕 워치독 알림 쿨다운 중 ({int((now_ts - _watchdog_last_notify_ts)/60)}분 경과)")
        return False
    _watchdog_last_notify_ts = now_ts
    send("\n".join(_build_intraday_watchdog_lines(state, relax_changes)))
    return True
def run_intraday_watchdog() -> None:
    """
    v83: 장중 침묵 감지 워치독.
    매 15분 실행. 다음 조건 모두 충족 시 자가진단 + 완화:
      ① 장 운영 중 (KRX or NXT)
      ② 외부 소스 기준 상승 종목 _WATCHDOG_MIN_RISING개 이상 존재
      ③ 지난 _WATCHDOG_SILENCE_MIN분간 외부 알림 0건
    """
    global _watchdog_last_run_ts
    if not is_any_market_open() or is_holiday():
        return
    _watchdog_restore_relax()
    now_ts = time.time()
    _watchdog_last_run_ts = now_ts
    state = _collect_intraday_watchdog_state(now_ts)
    if not state:
        return
    relax_changes = _watchdog_apply_relax(state["main_reason"])
    if _maybe_send_intraday_watchdog_alert(now_ts, state, relax_changes):
        code_req = _build_watchdog_code_change_request(state["main_reason"], state["reasons"], state["rising"], state["elapsed_since_alert"], relax_changes, state.get("alert_baseline_label", ""))
        if code_req:
            _send_code_change_request_alert(str(code_req.get("issue_key") or state["main_reason"]), list(code_req.get("lines") or []))
    _log_warn_msg(f"  🐕 워치독 자가진단 완료: 침묵 {int(state['elapsed_since_alert']/60)}분, 상승 {state['n_rising']}개, 주 차단사유={state['main_reason']}")
