def _read_json_safe(path: str, default):
    try:
        if not os.path.isfile(path):
            return default
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception as e:
        _warn_json_default_once(path, e)
        return default
def _load_runtime_state_bundle_unlocked() -> dict:
    raw = _read_json_unlocked(RUNTIME_STATE_BUNDLE_FILE, default={})
    return raw if isinstance(raw, dict) else {}
def _save_runtime_state_bundle_unlocked(bundle: dict) -> None:
    _write_json_atomic_unlocked(RUNTIME_STATE_BUNDLE_FILE, bundle if isinstance(bundle, dict) else {}, indent=2)
def _load_runtime_state_bundle() -> dict:
    with _file_lock:
        return _load_runtime_state_bundle_unlocked()
def _save_runtime_state_bundle(bundle: dict) -> None:
    with _file_lock:
        _save_runtime_state_bundle_unlocked(bundle)
def _read_legacy_state_json(path: str, default=None):
    default = {} if default is None else default
    return _read_json_safe(path, default)
def _runtime_state_get(key: str, default=None, legacy_path: str | None = None):
    bundle = _load_runtime_state_bundle()
    if key in bundle:
        value = bundle.get(key)
        return default if value is None else value
    if legacy_path:
        legacy = _read_legacy_state_json(legacy_path, default)
        return default if legacy is None else legacy
    return default
def _runtime_state_set(key: str, value, *, legacy_path: str | None = None) -> None:
    with _file_lock:
        bundle = _load_runtime_state_bundle_unlocked()
        bundle[key] = value
        _save_runtime_state_bundle_unlocked(bundle)
        if legacy_path and os.path.exists(legacy_path):
            try:
                os.remove(legacy_path)
            except Exception as e:
                _swallow_exception(e)
def _runtime_state_delete(key: str, *, legacy_path: str | None = None) -> None:
    with _file_lock:
        bundle = _load_runtime_state_bundle_unlocked()
        if key in bundle:
            bundle.pop(key, None)
            _save_runtime_state_bundle_unlocked(bundle)
        if legacy_path and os.path.exists(legacy_path):
            try:
                os.remove(legacy_path)
            except Exception as e:
                _swallow_exception(e)
def _save_preclose_gap_entry_watch() -> None:
    try:
        _write_json_atomic(PRECLOSE_GAP_ENTRY_WATCH_FILE, _preclose_gap_entry_watch if isinstance(_preclose_gap_entry_watch, dict) else {}, indent=2)
    except Exception as e:
        _swallow_exception(e)
def _load_preclose_gap_entry_watch() -> None:
    global _preclose_gap_entry_watch
    try:
        raw = _read_json_safe(PRECLOSE_GAP_ENTRY_WATCH_FILE, {})
        if not isinstance(raw, dict):
            _preclose_gap_entry_watch = {}
            return
        now_ts = time.time()
        restored = {}
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
        latest_by_code = _build_latest_tracking_by_code(siglog_data)
        for key, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            code = normalize_stock_code(watch.get("code"))
            deadline_ts = float(watch.get("deadline_ts", 0) or 0)
            if not code or (deadline_ts and now_ts >= deadline_ts):
                continue
            restored[str(key)] = watch
        _preclose_gap_entry_watch = restored
        if raw != restored:
            _save_preclose_gap_entry_watch()
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        _preclose_gap_entry_watch = {}
def _save_alert_history() -> None:
    """v161.15: _alert_history 쿨다운 상태파일 저장 — 재시작 후 당일 알람 중복 차단 유지."""
    try:
        today = _now_kst().strftime("%Y%m%d")
        now_ts = time.time()
        max_cooldown = 4 * 3600  # 최대 4시간치만 저장 (당일 범위)
        clean = {
            k: v for k, v in (_alert_history or {}).items()
            if isinstance(v, dict) and (now_ts - float(v.get("ts", 0) or 0)) < max_cooldown
        }
        _write_json_atomic(ALERT_HISTORY_FILE, {"date": today, "history": clean}, indent=2)
    except Exception as e:
        _swallow_exception(e)

def _load_alert_history() -> None:
    """v161.15: 재시작 시 _alert_history 쿨다운 복원 — 당일 날짜 기준, 익일 자동 무효화."""
    global _alert_history
    try:
        today = _now_kst().strftime("%Y%m%d")
        data = _read_json_safe(ALERT_HISTORY_FILE, {})
        if isinstance(data, dict) and data.get("date") == today:
            raw = data.get("history", {})
            if isinstance(raw, dict):
                now_ts = time.time()
                # 쿨다운 아직 유효한 항목만 복원
                _alert_history = {
                    k: v for k, v in raw.items()
                    if isinstance(v, dict) and (now_ts - float(v.get("ts", 0) or 0)) < get_regime_cooldown()
                }
                _log_info_msg(f"📂 알람 이력 복원 {len(_alert_history)}건 (쿨다운 유효)")
                return
        _alert_history = {}
    except Exception as e:
        _swallow_exception(e)
        _alert_history = {}

