def _load_reentry_watch() -> None:
    global _reentry_watch
    try:
        raw = _read_json_safe(REENTRY_WATCH_FILE, {})
        if not isinstance(raw, dict):
            _reentry_watch = {}
            return
        now_ts = time.time()
        restored = {}
        for code, watch in raw.items():
            if not isinstance(watch, dict):
                continue
            norm = normalize_stock_code(code or watch.get("code"))
            ts = float(watch.get("ts", 0) or 0)
            if not norm:
                continue
            if ts and now_ts - ts > 60 * 60 * 48:
                continue
            entry = int(watch.get("entry", 0) or 0)
            stop = int(watch.get("stop", 0) or 0)
            target = int(watch.get("target", 0) or 0)
            stop_price = int(watch.get("stop_price", 0) or 0)
            restored[norm] = {
                "name": str(watch.get("name", "") or ""),
                "stop_price": stop_price,
                "entry": entry,
                "stop": stop,
                "target": target,
                "signal_type": str(watch.get("signal_type", "") or ""),
                "ts": ts or now_ts,
                "nxt_listed": bool(watch.get("nxt_listed", is_nxt_listed(norm))),
                "market_basis": str(watch.get("market_basis", "NXT" if is_nxt_listed(norm) else "KRX") or ("NXT" if is_nxt_listed(norm) else "KRX")),
            }
        _reentry_watch = restored
        if raw != restored:
            _save_reentry_watch()
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        _reentry_watch = {}
def _clear_reentry_watch_all() -> None:
    _reentry_watch.clear()
    _stopped_priority_pool.clear()  # v163.13 [#5]: 손절후우선스캔 풀 함께 초기화
    _save_reentry_watch()
def _save_execution_setup_watch(force: bool = True) -> None:
    global _execution_setup_watch_last_persist_ts
    try:
        now_ts = time.time()
        min_interval = max(0, int(EXECUTION_SETUP_STATE_SAVE_MIN_INTERVAL_SEC or 0))
        if not force and min_interval > 0 and _execution_setup_watch_last_persist_ts:
            if now_ts - _execution_setup_watch_last_persist_ts < min_interval:
                return
        _write_json_atomic(EXECUTION_SETUP_WATCH_FILE, _execution_setup_watch if isinstance(_execution_setup_watch, dict) else {}, indent=2)
        _execution_setup_watch_last_persist_ts = now_ts
    except Exception as e:
        _swallow_exception(e)
def _load_execution_setup_watch() -> None:
    global _execution_setup_watch
