def _ws_get_approval_key() -> str:
    """KIS WebSocket 전용 approval_key 발급 (REST token과 별도)."""
    global _ws_approval_key, _ws_approval_key_ts
    now = time.time()
    # approval_key는 24시간 유효하지만 안전하게 12시간마다 갱신
    if _ws_approval_key and (now - _ws_approval_key_ts) < 43200:
        return _ws_approval_key
    try:
        url = f"{KIS_BASE_URL}/oauth2/Approval"
        body = {
            "grant_type": "client_credentials",
            "appkey": KIS_APP_KEY,
            "secretkey": KIS_APP_SECRET,
        }
        resp = requests.post(url, json=body, timeout=10)
        resp.raise_for_status()
        key = resp.json().get("approval_key", "")
        if key:
            _ws_approval_key = key
            _ws_approval_key_ts = now
            _log_info_msg(f"🔑 WebSocket approval_key 발급 완료")
        return key
    except Exception as e:
        _log_error_msg(f"❌ WebSocket approval_key 발급 실패: {e}")
        return ""


def _ws_build_subscribe_msg(tr_id: str, tr_key: str, tr_type: str = "1") -> str:
    """KIS WebSocket 구독/해제 메시지 생성."""
    return json.dumps({
        "header": {
            "approval_key": _ws_approval_key,
            "custtype": "P",
            "tr_type": tr_type,
            "content-type": "utf-8",
        },
        "body": {
            "input": {
                "tr_id": tr_id,
                "tr_key": tr_key,
            }
        }
    })


def _ws_parse_execution_data(raw_data: str) -> list[dict]:
    """H0STCNT0 체결 데이터 파싱 → _record_execution_snapshot 호환 dict 리스트 반환."""
    results = []
    try:
        parts = raw_data.split("|")
        if len(parts) < 4:
            return results
        tr_id = parts[1]
        if tr_id != "H0STCNT0":
            return results
        data_cnt = int(parts[2])
        fields_str = parts[3]
        values = fields_str.split("^")
        field_count = len(_WS_H0STCNT0_FIELDS)
        for i in range(data_cnt):
            offset = i * field_count
            if offset + field_count > len(values):
                break
            chunk = values[offset:offset + field_count]
            code = chunk[0].strip()
            if len(code) != 6 or not code.isdigit():
                continue
            try:
                price = int(chunk[2])
                acml_vol = int(chunk[13])
                if price <= 0 or acml_vol <= 0:
                    continue
                payload = {
                    "code": code,
                    "price": price,
                    "today_vol": acml_vol,
                    "change_rate": float(chunk[5]) if chunk[5] else 0.0,
                    "ask_qty": int(chunk[36]) if chunk[36] else 0,
                    "bid_qty": int(chunk[37]) if chunk[37] else 0,
                    "high": int(chunk[8]) if chunk[8] else 0,
                    "low": int(chunk[9]) if chunk[9] else 0,
                    "open": int(chunk[7]) if chunk[7] else 0,
                    # v162.4: F구간 VWAP 눌림반등 감지용 추가 필드
                    "weighted_avg": int(float(chunk[6])) if chunk[6] else 0,
                    "exec_vol": int(chunk[12]) if chunk[12] else 0,
                    "exec_strength": float(chunk[18]) if chunk[18] else 0.0,
                    "acml_tr_pbmn": int(chunk[14]) if chunk[14] else 0,
                    # v163: VI 발동 기준가 (정적VI, 0이면 미발동)
                    "vi_price": int(float(chunk[45])) if len(chunk) > 45 and chunk[45] else 0,
                }
                results.append({"code": code, "payload": payload})
            except (ValueError, IndexError):
                _ws_stats["parse_errors"] += 1
    except Exception:
        _ws_stats["parse_errors"] += 1
    return results


def _ws_on_message(data: str) -> None:
    """WebSocket 수신 메시지 처리 — 체결 데이터면 _record_execution_snapshot 호출."""
    global _ws_last_recv_ts
    _ws_last_recv_ts = time.time()

    if not data:
        return

    first_char = data[0] if data else ""

    # 실시간 데이터 (0=일반, 1=암호화)
    if first_char == "0":
        parsed = _ws_parse_execution_data(data)
        for item in parsed:
            try:
                # 시장 판별: NXT 시간대이고 KRX 미개장이면 NXT
                market = "KRX"
                if not is_market_open() and is_nxt_open():
                    market = "NXT"
                _record_execution_snapshot(item["code"], item["payload"], market=market)
                _ws_stats["recv_count"] += 1
            except Exception as e:
                _swallow_exception(e)
        return

    # JSON 응답 (구독 확인, 에러, PINGPONG)
    try:
        msg = json.loads(data)
        tr_id = msg.get("header", {}).get("tr_id", "")
        if tr_id == "PINGPONG":
            # PINGPONG 응답 — 동일 메시지를 돌려보내야 연결 유지
            return  # websocket-client ping_interval이 처리

        rt_cd = msg.get("body", {}).get("rt_cd", "")
        msg1 = msg.get("body", {}).get("msg1", "")
        if rt_cd == "0":
            _ws_stats["subscribe_ok"] += 1
        elif rt_cd == "1":
            _ws_stats["subscribe_fail"] += 1
            _log_warn_msg(f"⚠️ WebSocket 구독 에러: {msg1}")
    except (json.JSONDecodeError, Exception):
        pass


def _ws_subscribe(ws, code: str) -> bool:
    """종목 체결가 구독 등록."""
    # v163.12 [#1]: 연결 끊긴 상태에서 send 시도 차단 → Broken pipe 무한반복 방지
    if not _ws_connected:
        return False
    try:
        msg = _ws_build_subscribe_msg("H0STCNT0", code, "1")
        ws.send(msg)
        with _ws_lock:
            _ws_subscribed_codes[code] = time.time()
        return True
    except Exception as e:
        # v165.6 [#6]: Broken pipe 반복 WARNING 억제 — 종목별 최초 3회만 WARNING, 이후 무시
        err_str = str(e)
        with _ws_lock:
            _cnt = _ws_subscribe_fail_count.get(code, 0) + 1
            _ws_subscribe_fail_count[code] = _cnt
        if _cnt <= 3:
            _log_warn_msg(f"⚠️ WebSocket 구독 실패 [{code}]: {e}")
        return False


_ws_unsubscribe_fail_count: dict = {}  # v163.6: 구독해제 실패 횟수 추적
_ws_subscribe_fail_count:   dict = {}  # v165.6 [#6]: 구독 실패 횟수 — Broken pipe 반복 WARNING 억제
_nxt_eligible_cache: dict = {}         # v165.14: code → bool, NXT 거래가능 종목 캐시 (당일 유지)

def _ws_unsubscribe(ws, code: str) -> bool:
    """종목 체결가 구독 해제."""
    # v163.12 [#1]: 연결 끊긴 상태에서 send 시도 차단 → Broken pipe 무한반복 방지
    if not _ws_connected:
        with _ws_lock:
            _ws_subscribed_codes.pop(code, None)
            _ws_unsubscribe_fail_count.pop(code, None)
        return False
    try:
        msg = _ws_build_subscribe_msg("H0STCNT0", code, "2")
        ws.send(msg)
        with _ws_lock:
            _ws_subscribed_codes.pop(code, None)
            _ws_unsubscribe_fail_count.pop(code, None)
        return True
    except Exception as e:
        # v163.6: 실패 횟수 카운트 — 3회 초과 시 경고 없이 구독 목록에서 강제 제거
        with _ws_lock:
            fail_cnt = _ws_unsubscribe_fail_count.get(code, 0) + 1
            _ws_unsubscribe_fail_count[code] = fail_cnt
            if fail_cnt <= 3:
                _log_warn_msg(f"⚠️ WebSocket 구독해제 실패 [{code}]: {e}")
            else:
                # 3회 초과: 조용히 목록에서 제거하고 포기
                _ws_subscribed_codes.pop(code, None)
                _ws_unsubscribe_fail_count.pop(code, None)
        return False


def _ws_get_target_codes() -> list[str]:
    """현재 구독 대상 종목 코드 리스트 반환 — _entry_watch + _exec_speed_prewarm 기반."""
    targets = set()
    # 1순위: entry_watch 활성 종목
    try:
        for key, watch in dict(_entry_watch).items():
            code = normalize_stock_code(watch.get("code"))
            if code:
                targets.add(code)
    except Exception:
        pass
    # 2순위: prewarm 대상 종목
    try:
        for code in list(_exec_speed_prewarm.keys()):
            code = normalize_stock_code(code)
            if code:
                targets.add(code)
    except Exception:
        pass
    # 3순위: execution_setup_watch 종목
    try:
        for code in list(_execution_setup_watch.keys()):
            code = normalize_stock_code(code)
            if code:
                targets.add(code)
    except Exception:
        pass
    return list(targets)


def _ws_sync_subscriptions(ws) -> None:
    """구독 대상을 현재 _entry_watch/_exec_speed_prewarm과 동기화."""
    global _ws_last_sync_ts
    now = time.time()
    if now - _ws_last_sync_ts < WS_SYNC_INTERVAL_SEC:
        return
    _ws_last_sync_ts = now

    target_codes = _ws_get_target_codes()
    with _ws_lock:
        current_codes = set(_ws_subscribed_codes.keys())

    target_set = set(target_codes)

    # 구독 해제: 더 이상 필요 없는 종목
    for code in current_codes - target_set:
        _ws_unsubscribe(ws, code)

    # 신규 구독: 아직 구독 안 된 종목
    available_slots = WS_MAX_SUBSCRIPTIONS - len(_ws_subscribed_codes)
    codes_to_add = list(target_set - current_codes)

    if len(codes_to_add) > available_slots:
        # LRU 방식: 가장 오래된 구독 해제 후 새 종목 추가
        with _ws_lock:
            sorted_current = sorted(
                [(c, ts) for c, ts in _ws_subscribed_codes.items() if c not in target_set],
                key=lambda x: x[1]
            )
        evict_count = len(codes_to_add) - available_slots
        for c, _ in sorted_current[:evict_count]:
            _ws_unsubscribe(ws, c)
        codes_to_add = codes_to_add[:WS_MAX_SUBSCRIPTIONS - len(_ws_subscribed_codes)]

    for code in codes_to_add:
        if len(_ws_subscribed_codes) >= WS_MAX_SUBSCRIPTIONS:
            break
        _ws_subscribe(ws, code)
        time.sleep(0.05)  # 구독 요청 간 약간의 딜레이


def _ws_connect_loop() -> None:
    """WebSocket 수신 루프 — 별도 스레드에서 실행. 지수 백오프 재연결."""
    global _ws_connected, _ws_reconnect_count, _ws_last_sync_ts
    import websocket as _websocket_lib

    backoff = WS_RECONNECT_BASE_SEC

    while not _ws_stop_event.is_set():
        ws = None
        try:
            # 시장 미개장이면 대기
            if not is_any_market_open():
                _ws_connected = False
                with _ws_lock:
                    _ws_subscribed_codes.clear()
                _ws_stop_event.wait(30)
                continue

            # approval_key 발급
            approval_key = _ws_get_approval_key()
            if not approval_key:
                _ws_stop_event.wait(min(backoff, WS_RECONNECT_MAX_SEC))
                backoff = min(backoff * 2, WS_RECONNECT_MAX_SEC)
                continue

            _log_info_msg(f"🔌 WebSocket 연결 시도: {WS_URL}")
            ws = _websocket_lib.WebSocket()
            ws.connect(WS_URL, ping_interval=60, ping_timeout=30)
            _ws_connected = True
            backoff = WS_RECONNECT_BASE_SEC
            _ws_last_sync_ts = 0.0  # 즉시 동기화 트리거
            _ws_subscribe_fail_count.clear()    # v165.6 [#6]: 재연결 시 실패 카운트 초기화
            _log_info_msg(f"✅ WebSocket 연결 성공")

            # 초기 구독 동기화
            _ws_sync_subscriptions(ws)

            # 수신 루프
            while not _ws_stop_event.is_set():
                # 시장 폐장 확인
                if not is_any_market_open():
                    _log_info_msg("🔌 시장 폐장 — WebSocket 연결 해제")
                    break

                try:
                    ws.settimeout(5.0)
                    data = ws.recv()
                    if data:
                        # PINGPONG 처리
                        try:
                            if isinstance(data, str) and '"PINGPONG"' in data:
                                ws.send(data)
                                continue
                        except Exception:
                            pass
                        _ws_on_message(data)
                except _websocket_lib.WebSocketTimeoutException:
                    # 주기적 구독 동기화
                    _ws_sync_subscriptions(ws)
                    continue
                except _websocket_lib.WebSocketConnectionClosedException:
                    _log_warn_msg("⚠️ WebSocket 연결 종료됨 — 재연결 예정")
                    break
                except Exception as e:
                    _log_warn_msg(f"⚠️ WebSocket 수신 오류: {e}")
                    break

                # 주기적 구독 동기화
                _ws_sync_subscriptions(ws)

        except Exception as e:
            _log_warn_msg(f"⚠️ WebSocket 연결 실패: {e}")
        finally:
            _ws_connected = False
            with _ws_lock:
                _ws_subscribed_codes.clear()
            if ws:
                try:
                    ws.close()
                except Exception:
                    pass

        if _ws_stop_event.is_set():
            break

        # 재연결 대기 (지수 백오프)
        _ws_reconnect_count += 1
        _ws_stats["reconnects"] += 1
        wait_sec = min(backoff + random.uniform(0, 1), WS_RECONNECT_MAX_SEC)
        _log_info_msg(f"🔄 WebSocket 재연결 대기 {wait_sec:.1f}초 (#{_ws_reconnect_count})")
        _ws_stop_event.wait(wait_sec)
        backoff = min(backoff * 2, WS_RECONNECT_MAX_SEC)

    _log_info_msg("🔌 WebSocket 루프 종료")


def _ws_start() -> None:
    """WebSocket 스레드 시작 (이미 실행 중이면 skip)."""
    global _ws_thread
    if not WEBSOCKET_ENABLED:
        return
    if not KIS_APP_KEY or not KIS_APP_SECRET:
        _log_warn_msg("⚠️ WebSocket 시작 불가: KIS_APP_KEY/SECRET 누락")
        return
    if _ws_thread and _ws_thread.is_alive():
        return
    _ws_stop_event.clear()
    _ws_thread = threading.Thread(target=_ws_connect_loop, name="KIS-WebSocket", daemon=True)
    _ws_thread.start()
    _log_info_msg("🚀 WebSocket 스레드 시작")


def _ws_stop() -> None:
    """WebSocket 스레드 중지."""
    global _ws_thread
    _ws_stop_event.set()
    if _ws_thread:
        _ws_thread.join(timeout=10)
        _ws_thread = None
    _log_info_msg("🛑 WebSocket 스레드 중지")


def _ws_is_active() -> bool:
    """WebSocket이 활성 상태(연결 중 + 최근 데이터 수신)인지 확인."""
    if not WEBSOCKET_ENABLED or not _ws_connected:
        return False
    # 마지막 수신이 60초 이내면 활성
    return (time.time() - _ws_last_recv_ts) < 60.0


def _ws_get_status_summary() -> str:
    """WebSocket 상태 요약 문자열."""
    if not WEBSOCKET_ENABLED:
        return "WebSocket: 비활성"
    connected = "연결됨" if _ws_connected else "미연결"
    with _ws_lock:
        sub_count = len(_ws_subscribed_codes)
    age = int(time.time() - _ws_last_recv_ts) if _ws_last_recv_ts > 0 else -1
    return (f"WebSocket: {connected} | 구독 {sub_count}/{WS_MAX_SUBSCRIPTIONS} | "
            f"수신 {_ws_stats['recv_count']}건 | 재연결 {_ws_stats['reconnects']}회 | "
            f"마지막 수신 {age}초 전")

# ════════════════════════════════════════════════════════════════
_execution_setup_watch: dict = {}
_execution_setup_watch_last_persist_ts: float = 0.0
def _prune_execution_snapshots(code: str, now_ts: float | None = None) -> None:
    now_ts = float(now_ts or time.time())
    buf = _execution_snapshots.get(code)
    if not isinstance(buf, list):
        return
    cutoff = now_ts - max(EXEC_SPEED_WINDOW_SEC * 4, 360)
    _execution_snapshots[code] = [s for s in buf if float(s.get("ts", 0) or 0) >= cutoff][-80:]
def _get_exec_speed_micro_trade_threshold(price: int, market: str = "KRX", sample_ts: float | None = None) -> int:
    price = safe_int(price, 0)
    if price <= 0:
        return 0
    market_name = str(market or "KRX").upper()
    ts = float(sample_ts or time.time())
    try:
        local_dt = datetime.fromtimestamp(ts)
        afterhours_hint = (local_dt.hour > 15) or (local_dt.hour == 15 and local_dt.minute >= 30) or (local_dt.hour < 9)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        afterhours_hint = False
    relaxed = market_name == "NXT" or afterhours_hint
    share_multiplier = EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER_NXT if relaxed else EXEC_SPEED_MICRO_TRADE_SHARE_MULTIPLIER
    min_krw = EXEC_SPEED_MICRO_TRADE_MIN_KRW_NXT if relaxed else EXEC_SPEED_MICRO_TRADE_MIN_KRW
    return max(int(price * max(1, share_multiplier)), int(min_krw))
def _record_execution_snapshot(code: str, payload: dict, market: str = "KRX") -> None:
    code = normalize_stock_code(code)
    if not code or not isinstance(payload, dict):
        return
    price = safe_int(payload.get("price", 0))
    today_vol = safe_int(payload.get("today_vol", 0))
    if price <= 0 or today_vol <= 0:
        return
    now_ts = time.time()
    buf = _execution_snapshots.setdefault(code, [])
    prev = buf[-1] if buf else {}
    prev_vol = safe_int(prev.get("today_vol", 0))
    vol_delta = max(today_vol - prev_vol, 0)
    trade_value_delta = int(vol_delta * price)
    prev_ts = float(prev.get("ts", 0) or 0)
    elapsed_sec = max(now_ts - prev_ts, 1.0) if prev_ts > 0 else 0.0
    trade_value_per_sec = float(trade_value_delta / elapsed_sec) if trade_value_delta > 0 and elapsed_sec > 0 else 0.0
    micro_threshold = _get_exec_speed_micro_trade_threshold(price, market=market, sample_ts=now_ts)
    sample = {
        "ts": now_ts,
        "market": market,
        "price": price,
        "today_vol": today_vol,
        "change_rate": float(payload.get("change_rate", 0.0) or 0.0),
        "ask_qty": safe_int(payload.get("ask_qty", 0)),
        "bid_qty": safe_int(payload.get("bid_qty", 0)),
        "vol_delta": vol_delta,
        "trade_value_delta": trade_value_delta,
        "elapsed_sec": round(elapsed_sec, 2),
        "trade_value_per_sec": round(trade_value_per_sec, 2),
        "micro_trade": bool(vol_delta > 0 and trade_value_delta < micro_threshold),
        # v162.4: F구간 VWAP 눌림반등용 추가 저장
        "weighted_avg": safe_int(payload.get("weighted_avg", 0)),
        "exec_vol": safe_int(payload.get("exec_vol", 0)),
        "exec_strength": float(payload.get("exec_strength", 0.0) or 0.0),
        "acml_tr_pbmn": safe_int(payload.get("acml_tr_pbmn", 0)),
        "high": safe_int(payload.get("high", 0)),
        "low": safe_int(payload.get("low", 0)),
        # v163: VI 발동 기준가 저장
        "vi_price": safe_int(payload.get("vi_price", 0)),
    }
    if prev and prev.get("price") == price and prev.get("today_vol") == today_vol:
        return
    buf.append(sample)
    _prune_execution_snapshots(code, now_ts)
    # v163: VI 발동 감지 → 섹터별 VI 순서 기록
    # v163.5: get_stock_info 미정의 → get_stock_price 폴백으로 수정
    _vi_price_val = safe_int(payload.get("vi_price", 0))
    if _vi_price_val > 0:
        try:
            _stock_info = get_stock_price(code) or {}
            _vi_sector  = str(_stock_info.get("bstp_name", "") or _stock_info.get("sector", "") or "")
            _vi_name    = str(_stock_info.get("name", code) or code)
            _update_vi_sector_tracker(code, _vi_name, _vi_sector, _vi_price_val)
        except Exception as _ve:
            _swallow_exception(_ve)
def _build_execution_speed_metrics_base(current_price: int | None = None) -> dict:
    base_price = safe_int(current_price, 0)
    return {
        "ready": False,
        "provisional": False,
        "execution_speed_score": 0,
        "dip_resilience_score": 0,
        "micro_trade_filtered_ratio": 0.0,
        "pullback_pct": 0.0,
        "recent_peak_price": base_price,
        "suggested_entry_price": base_price,
        "valid_samples": 0,
        "window_samples": 0,
        "amount_per_active": 0,
        "active_ratio": 0.0,
        "avg_bid_ask_ratio": 0.0,
        "trade_value_per_sec": 0,
        "recent_trade_value_per_sec": 0,
        "prior_trade_value_per_sec": 0,
        "acceleration_ratio": 1.0,
        "freshness_score": 0,
        "last_active_age_sec": 999,
        "recent_valid_samples": 0,
        "flow_state": "중립",
        "summary": "샘플 부족",
    }
def _collect_execution_speed_window_samples(code: str, now_ts: float, window_sec: int, out: dict) -> tuple[list, list]:
    samples = [s for s in (_execution_snapshots.get(code) or []) if float(s.get("ts", 0) or 0) >= now_ts - window_sec]
    out["window_samples"] = len(samples)
    if len(samples) < 2:
        return samples, []
    positive = [s for s in samples if int(s.get("vol_delta", 0) or 0) > 0]
    valid = [s for s in positive if not s.get("micro_trade")]
    out["valid_samples"] = len(valid)
    if positive:
        out["micro_trade_filtered_ratio"] = round(max(0.0, 1.0 - len(valid) / max(len(positive), 1)), 2)
    if len(valid) < 2:
        out["summary"] = "유효 체결 부족"
    return samples, valid
def _calc_execution_speed_price_context(samples: list, valid: list, current_price: int | None, out: dict) -> tuple[int, int, float, float]:
    prices = [safe_int(s.get("price", 0), 0) for s in samples if safe_int(s.get("price", 0), 0) > 0]
    peak_price = max(prices) if prices else safe_int(current_price, 0)
    last_price = safe_int(current_price, 0) or safe_int(samples[-1].get("price", 0), 0)
    out["recent_peak_price"] = peak_price
    out["pullback_pct"] = round((peak_price - last_price) / peak_price * 100, 2) if peak_price else 0.0
    valid_amounts = [int(s.get("trade_value_delta", 0) or 0) for s in valid]
    mean_amount = sum(valid_amounts) / max(len(valid_amounts), 1)
    mean_abs_dev = sum(abs(v - mean_amount) for v in valid_amounts) / max(len(valid_amounts), 1)
    consistency = max(0.0, 1.0 - (mean_abs_dev / mean_amount)) if mean_amount > 0 else 0.0
    return peak_price, last_price, mean_amount, consistency
def _execution_speed_rate_from_sample(sample: dict, prev_ts: float | None) -> tuple[float, float]:
    ts = float(sample.get("ts", 0) or 0)
    elapsed = float(sample.get("elapsed_sec", 0) or 0)
    if elapsed <= 0 and prev_ts:
        elapsed = max(ts - prev_ts, 1.0)
    rate = float(int(sample.get("trade_value_delta", 0) or 0)) / max(elapsed, 1.0) if elapsed > 0 else 0.0
    return ts, rate
def _collect_execution_speed_flow_rates(valid: list) -> tuple[list[float], float]:
    flow_rates = []
    prev_ts = None
    for sample in valid:
        ts, rate = _execution_speed_rate_from_sample(sample, prev_ts)
        flow_rates.append(rate)
        prev_ts = ts or prev_ts
    mean_rate = sum(flow_rates) / max(len(flow_rates), 1)
    return flow_rates, mean_rate
def _collect_execution_speed_recent_profile(valid: list, now_ts: float, window_sec: int, mean_rate: float) -> dict:
    recent_window = max(15, min(window_sec, EXEC_SPEED_RECENT_WINDOW_SEC))
    recent_cutoff = now_ts - recent_window
    recent_rates, prior_rates = [], []
    recent_valid_samples = 0
    last_valid_ts = 0.0
    prev_ts = None
    for sample in valid:
        ts, rate = _execution_speed_rate_from_sample(sample, prev_ts)
        if ts >= recent_cutoff:
            recent_rates.append(rate)
            recent_valid_samples += 1
        else:
            prior_rates.append(rate)
        if ts > last_valid_ts:
            last_valid_ts = ts
        prev_ts = ts or prev_ts
    recent_rate = sum(recent_rates) / max(len(recent_rates), 1) if recent_rates else mean_rate
    prior_rate = sum(prior_rates) / max(len(prior_rates), 1) if prior_rates else mean_rate
    accel_ratio = recent_rate / max(prior_rate, 1.0) if recent_rate > 0 and prior_rate > 0 else 1.0
    return {
        "recent_rate": recent_rate,
        "prior_rate": prior_rate,
        "accel_ratio": accel_ratio,
        "recent_valid_samples": recent_valid_samples,
        "last_valid_ts": last_valid_ts,
        "prior_rates": prior_rates,
    }
def _score_execution_speed_freshness(last_active_age_sec: int) -> int:
    if last_active_age_sec <= 10:
        return 100
    if last_active_age_sec <= 20:
        return 85
    if last_active_age_sec <= 35:
        return 70
    if last_active_age_sec <= EXEC_SPEED_STALE_WARN_SEC:
        return 55
    if last_active_age_sec <= 70:
        return 35
    return 15
def _resolve_execution_speed_flow_state(last_active_age_sec: int, recent_valid_samples: int, accel_ratio: float, prior_rates: list[float]) -> str:
    if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC:
        return "정체"
    if recent_valid_samples >= 2 and accel_ratio >= 1.25:
        return "가속"
    if prior_rates and accel_ratio <= 0.80:
        return "둔화"
    return "유지"
def _calc_execution_speed_bid_context(valid: list, samples: list, out: dict, mean_amount: float) -> tuple[float, float]:
    bid_ratios = []
    for sample in valid:
        ask_qty = safe_int(sample.get("ask_qty", 0), 0)
        bid_qty = safe_int(sample.get("bid_qty", 0), 0)
        if ask_qty > 0 and bid_qty > 0:
            bid_ratios.append(min(bid_qty / ask_qty, COMMON_THRESHOLD_3P0))
    avg_bid_ratio = sum(bid_ratios) / len(bid_ratios) if bid_ratios else 1.0
    active_ratio = len(valid) / max(len(samples), 1)
    out["avg_bid_ask_ratio"] = round(avg_bid_ratio, 2)
    out["active_ratio"] = round(active_ratio, 2)
    out["amount_per_active"] = int(mean_amount)
    return avg_bid_ratio, active_ratio
def _calc_execution_speed_dip_score(valid: list, peak_price: int, mean_amount: float, pullback_pct: float) -> int:
    dip_samples = [
        s for s in valid
        if peak_price > 0 and safe_int(s.get("price", 0), 0) <= int(peak_price * (1 - EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT / 100.0))
    ]
    if dip_samples:
        dip_mean = sum(int(s.get("trade_value_delta", 0) or 0) for s in dip_samples) / max(len(dip_samples), 1)
        base_mean = mean_amount or 1.0
        dip_ratio = max(0.0, min(dip_mean / base_mean, 1.4))
        return int(min(100, max(0, round(dip_ratio * 100))))
    if pullback_pct >= EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT:
        return 45
    return 35
def _calc_execution_speed_score(mean_amount: float, mean_rate: float, valid_count: int, active_ratio: float, consistency: float, avg_bid_ratio: float, freshness_score: int, accel_ratio: float, last_active_age_sec: int) -> int:
    if mean_amount >= 100_000_000:
        amount_score = 40
    elif mean_amount >= 50_000_000:
        amount_score = 35
    elif mean_amount >= 20_000_000:
        amount_score = 30
    elif mean_amount >= 10_000_000:
        amount_score = 24
    elif mean_amount >= 5_000_000:
        amount_score = 18
    elif mean_amount >= 2_000_000:
        amount_score = 12
    elif mean_amount >= 1_000_000:
        amount_score = 8
    else:
        amount_score = 4
    if mean_rate >= 8_000_000:
        pace_score = 15
    elif mean_rate >= 4_000_000:
        pace_score = 12
    elif mean_rate >= 2_000_000:
        pace_score = 10
    elif mean_rate >= 1_000_000:
        pace_score = 8
    elif mean_rate >= 500_000:
        pace_score = 5
    elif mean_rate >= 200_000:
        pace_score = 3
    else:
        pace_score = 0
    depth_score = min(valid_count * 5, 15)
    active_score = min(int(active_ratio * 20), 20)
    consistency_score = min(int(consistency * 15), 15)
    bid_score = min(max(int((avg_bid_ratio - 0.8) * 8), 0), 10)
    freshness_bonus = min(max(int((freshness_score - 30) / 7), -3), 10)
    if accel_ratio >= 1.45:
        accel_bonus = 8
    elif accel_ratio >= 1.18:
        accel_bonus = 5
    elif accel_ratio <= 0.65:
        accel_bonus = -6
    elif accel_ratio <= 0.85:
        accel_bonus = -3
    else:
        accel_bonus = 0
    stale_penalty = -8 if last_active_age_sec > 60 else (-4 if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC else 0)
    return max(0, min(100, amount_score + pace_score + depth_score + active_score + consistency_score + bid_score + freshness_bonus + accel_bonus + stale_penalty))
def _finalize_execution_speed_metrics(out: dict, samples: list, valid: list, last_price: int, peak_price: int) -> dict:
    suggested_entry = safe_int(last_price, 0)
    if peak_price and last_price:
        if out["pullback_pct"] < EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT:
            suggested_entry = int(peak_price * (1 - EXEC_SPEED_CONFIRM_MIN_PULLBACK_PCT / 100.0))
        else:
            suggested_entry = min(last_price, int(peak_price * (1 - min(out["pullback_pct"], EXEC_SPEED_CONFIRM_MAX_PULLBACK_PCT) / 100.0)))
    out["suggested_entry_price"] = _round_price_down(max(suggested_entry, 0)) if suggested_entry else 0
    ready_window_min = max(2, EXEC_SPEED_MIN_SAMPLES)
    ready_valid_min = max(2, EXEC_SPEED_MIN_SAMPLES - 1)
    flow_hint = f" / 흐름 {out['flow_state']} / 최근체결 {out['last_active_age_sec']}초전"
    if len(samples) >= ready_window_min and len(valid) >= ready_valid_min:
        out["ready"] = True
        out["summary"] = f"속도 {out['execution_speed_score']}점 / 눌림유지 {out['dip_resilience_score']}점{flow_hint}"
    else:
        out["provisional"] = True
        out["summary"] = f"예비판단 {out['execution_speed_score']}점 / 눌림유지 {out['dip_resilience_score']}점{flow_hint}"
    return out
def get_execution_speed_metrics(code: str, current_price: int | None = None, window_sec: int = EXEC_SPEED_WINDOW_SEC) -> dict:
    code = normalize_stock_code(code)
    now_ts = time.time()
    out = _build_execution_speed_metrics_base(current_price)
    if not code:
        return out
    samples, valid = _collect_execution_speed_window_samples(code, now_ts, window_sec, out)
    if len(samples) < 2 or len(valid) < 2:
        return out
    peak_price, last_price, mean_amount, consistency = _calc_execution_speed_price_context(samples, valid, current_price, out)
    _, mean_rate = _collect_execution_speed_flow_rates(valid)
    recent_profile = _collect_execution_speed_recent_profile(valid, now_ts, window_sec, mean_rate)
    out["trade_value_per_sec"] = int(mean_rate)
    out["recent_trade_value_per_sec"] = int(recent_profile["recent_rate"])
    out["prior_trade_value_per_sec"] = int(recent_profile["prior_rate"])
    out["acceleration_ratio"] = round(recent_profile["accel_ratio"], 2)
    out["recent_valid_samples"] = recent_profile["recent_valid_samples"]
    last_active_age_sec = max(0, int(now_ts - recent_profile["last_valid_ts"])) if recent_profile["last_valid_ts"] > 0 else 999
    out["last_active_age_sec"] = last_active_age_sec
    out["freshness_score"] = _score_execution_speed_freshness(last_active_age_sec)
    out["flow_state"] = _resolve_execution_speed_flow_state(last_active_age_sec, recent_profile["recent_valid_samples"], recent_profile["accel_ratio"], recent_profile["prior_rates"])
    avg_bid_ratio, active_ratio = _calc_execution_speed_bid_context(valid, samples, out, mean_amount)
    out["dip_resilience_score"] = _calc_execution_speed_dip_score(valid, peak_price, mean_amount, out["pullback_pct"])
    out["execution_speed_score"] = int(_calc_execution_speed_score(mean_amount, mean_rate, len(valid), active_ratio, consistency, avg_bid_ratio, out["freshness_score"], recent_profile["accel_ratio"], last_active_age_sec))
    return _finalize_execution_speed_metrics(out, samples, valid, last_price, peak_price)
def _tick_exec_speed_prewarm() -> None:
    """포착 직후 등록된 종목의 체결속도 스냅샷을 사전 누적 (진입가 도달 시 샘플 부족 최소화).
    run_scan() 1사이클(20초)마다 호출되며, check_entry_watch() 직전에 실행해
    진입가 도달 판단 전 스냅샷 상태를 최신으로 유지한다.
    - 샘플이 EXEC_SPEED_MIN_SAMPLES 이상이면 해당 종목 워밍 해제.
    - EXEC_SPEED_PREWARM_MAX_SEC 초 경과 시 자동 해제 (방치 방지).
    - API 부담 제한: 가장 최근 등록 종목 기준 최대 EXEC_SPEED_PREWARM_MAX_CODES개만 처리.
    """
    global _exec_speed_prewarm
    if not _exec_speed_prewarm:
        return
    now_ts = time.time()
    # 만료 정리
    expired_codes = [c for c, ts in list(_exec_speed_prewarm.items())
                     if now_ts - ts > EXEC_SPEED_PREWARM_MAX_SEC]
    for c in expired_codes:
        _exec_speed_prewarm.pop(c, None)
    if not _exec_speed_prewarm:
        return
    krx_ok = is_market_open()
    nxt_ok = is_nxt_open()
    # 최근 등록 순으로 최대 N개만 처리
    targets = sorted(_exec_speed_prewarm.items(), key=lambda x: x[1], reverse=True)
    targets = targets[:EXEC_SPEED_PREWARM_MAX_CODES]
    for code, _reg_ts in targets:
        # 현재 유효 샘플 수 확인
        samples = _execution_snapshots.get(code) or []
        recent_samples = [
            s for s in samples
            if float(s.get("ts", 0) or 0) >= now_ts - EXEC_SPEED_WINDOW_SEC
        ]
        recent_count = len(recent_samples)
        recent_valid_count = sum(
            1 for s in recent_samples
            if int(s.get("vol_delta", 0) or 0) > 0 and not s.get("micro_trade")
        )
        if recent_count >= max(2, EXEC_SPEED_MIN_SAMPLES) and recent_valid_count >= max(2, EXEC_SPEED_MIN_SAMPLES - 1):
            # 충분히 쌓임 → 워밍 해제
            _exec_speed_prewarm.pop(code, None)
            continue
        # 스냅샷 1회 추가 수집 (시장 상태에 따라 KRX/NXT 선택)
        # v162: WebSocket 활성 시 REST 호출 skip — WebSocket이 실시간 갱신 중
        if _ws_is_active() and code in _ws_subscribed_codes:
            continue
        try:
            if krx_ok:
                get_stock_price(code)
            elif nxt_ok and is_nxt_listed(code):
                get_nxt_stock_price(code)
        except Exception as e:
            _swallow_exception(e)
def _execution_score_label(score: int) -> str:
    s = int(score or 0)
    if s >= 80:
        return "강함"
    if s >= 65:
        return "양호"
    if s >= 50:
        return "보통"
    return "약함"
def _entry_execution_judgement(metrics: dict | None = None) -> tuple[str, str]:
    metrics = metrics or {}
    speed_score = int(metrics.get("execution_speed_score", 0) or 0)
    dip_score = int(metrics.get("dip_resilience_score", 0) or 0)
    filtered_ratio = float(metrics.get("micro_trade_filtered_ratio", 0.0) or 0.0)
    freshness_score = int(metrics.get("freshness_score", 0) or 0)
    flow_state = str(metrics.get("flow_state", "중립") or "중립")
    last_active_age_sec = int(metrics.get("last_active_age_sec", 999) or 999)
    if not metrics.get("ready"):
        if metrics.get("provisional") and speed_score >= 68 and dip_score >= 55 and freshness_score >= 70 and flow_state in {"가속", "유지"}:
            return ("참고", f"🟡 예비판단상 체결 살아있음 — {flow_state}, 최근 유효체결 {last_active_age_sec}초 전")
        return ("참고", "⚠️ 체결속도 샘플 부족 — 진입 시 추가 확인")
    if last_active_age_sec > EXEC_SPEED_STALE_WARN_SEC or freshness_score < 40:
        return ("보류 우선", f"⚠️ 최근 체결이 끊김 — 마지막 유효체결 {last_active_age_sec}초 전")
    if speed_score >= 75 and dip_score >= 70 and filtered_ratio <= 0.60 and flow_state != "둔화":
        return ("진입 적합", f"✅ {flow_state} 흐름 유지 — 최근 유효체결 {last_active_age_sec}초 전")
    if speed_score < 40 or dip_score < 40 or filtered_ratio > 0.75:
        return ("보류 우선", "⚠️ 하락 중 체결 유지 약함 — 진입보류 우선")
    if flow_state == "둔화":
        return ("보통", f"🟡 체결은 이어지지만 둔화 중 — 최근 유효체결 {last_active_age_sec}초 전")
    return ("보통", f"🟡 체결속도는 보통 수준 — {flow_state}, 최근 유효체결 {last_active_age_sec}초 전")
# ── v41.66: 신호 강도 판정 ──
def _classify_signal_strength(watch: dict, exec_metrics: dict | None = None) -> str:
    """신호 강도를 '강한'/'보통'/'약한'으로 분류.
    기준: 등급(A/B/C) + 체결속도(진입적합/보통/보류) + 포착점수 종합."""
    grade = str(watch.get("grade", "B")).upper()
    score = int(watch.get("score", 0) or 0)
    exec_label, _ = _entry_execution_judgement(exec_metrics)
    # 등급 기반 기본 강도
    if grade == "A" and score >= 75:
        base = "강한"
    elif grade == "C" or score < 50:
        base = "약한"
    else:
        base = "보통"
    # 체결속도 보정
    if exec_label == "보류 우선" and base == "보통":
        base = "약한"
    elif exec_label == "진입 적합" and base == "보통":
        base = "강한"
    return base
_fi_turnaround_cache: dict[str, dict] = {}
def get_effective_volume_ratio(signal_type: str, current_time: str) -> float:
    """신호타입 × 시간대별 동적 거래량 기준.
    v66: NXT 장전(08시) 구간 추가 — 유동성이 적은 시간대이므로 기준 완화.
    """
    base_vol = {
        "UPPER_LIMIT": COMMON_THRESHOLD_3P0,
        "NEAR_UPPER": 5.0,
        "SURGE": 7.0,
        "EXECUTION_SPEED": 5.0,
        "DEFAULT": 5.0,
    }
    base = float(base_vol.get(str(signal_type or ""), base_vol["DEFAULT"]))
    time_str = str(current_time or "")
    if " " in time_str:
        time_str = time_str.split(" ")[-1]
    try:
        hour = int((time_str or "00:00:00").split(":")[0])
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        hour = datetime.now().hour
    if 8 <= hour < 9:
        # v66: NXT 장전 — 유동성 적어 거래량 배수가 높게 산출되므로 기준 완화
        time_adj = 0.7
    elif 9 <= hour < 10:
        time_adj = 1.3
    elif 10 <= hour < 14:
        time_adj = 1.0
    elif 14 <= hour < 15:
        time_adj = 0.85
    elif 15 <= hour < 16:
        # NXT 장후 초반 — 유동성 전환기
        time_adj = 0.8
    else:
        time_adj = 0.9
    required = max(2.0, min(base * time_adj, 10.0))
    return round(required, 1)
def _relax_opening_general_required_volume(required_vol: float, signal_type: str, change_rate: float,
                                           current_time: str, market: str = "") -> tuple[float, str]:
    """전 시간대 일반 포착 거래량 게이트를 시간대별로 현실화."""
    sig_type = str(signal_type or "").upper()
    orig_required = float(required_vol or 0.0)
    if sig_type not in ("EARLY_DETECT", "SURGE", "NEAR_UPPER", "UPPER_LIMIT"):
        return orig_required, ""
    profile = _get_full_session_capture_profile(current_time=current_time, market=market)
    stage = str(profile.get("stage", "other") or "other")
    if stage == "other":
        return orig_required, ""
    label = str(profile.get("label", "전시간대") or "전시간대")
    relaxed = orig_required
    mult_map = profile.get("required_vol_mult", {}) or {}
    try:
        base_mult = float(mult_map.get(sig_type, 1.0) or 1.0)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        base_mult = 1.0
    if base_mult < 1.0:
        relaxed = min(relaxed, round(orig_required * base_mult, 1))
    chg = safe_float(change_rate, 0.0)
    if sig_type == "SURGE":
        strong_cap = float(profile.get("surge_strong_cap", relaxed) or relaxed)
        base_cap = float(profile.get("surge_cap", relaxed) or relaxed)
        if chg >= max(8.0, float(profile.get("surge_min_change", 4.5) or 4.5) + COMMON_THRESHOLD_3P0):
            relaxed = min(relaxed, strong_cap)
        else:
            relaxed = min(relaxed, base_cap)
    elif sig_type == "NEAR_UPPER":
        relaxed = min(relaxed, float(profile.get("near_upper_cap", relaxed) or relaxed))
    elif sig_type == "UPPER_LIMIT":
        relaxed = min(relaxed, float(profile.get("upper_limit_cap", relaxed) or relaxed))
    elif sig_type == "EARLY_DETECT":
        relaxed = min(relaxed, max(1.2, round(orig_required * float(mult_map.get("EARLY_DETECT", 1.0) or 1.0), 1)))
    relaxed = round(max(1.2, min(relaxed, 10.0)), 1)
    if relaxed < orig_required:
        return relaxed, f"📊 {label} 거래량 기준 완화 ({orig_required:.1f}배→{relaxed:.1f}배)"
    return orig_required, ""
def get_dart_reliability_score(disclosure_type: str) -> int:
    score_map = {
        "회사합병결정": 3,
        "이사회의견서정정": 2,
        "첨부정정": 2,
        "자사주소각": 2,
        "주식소각": 2,
        "자기주식소각": 2,
        "유상증자": 1,
        "무상증자": 1,
        "기타": 0,
    }
    title = str(disclosure_type or "")
    for key, value in score_map.items():
        if key != "기타" and key in title:
            return value
    return score_map["기타"]
def detect_foreign_institution_turnaround(code: str) -> dict:
    now_ts = time.time()
    out = {"foreign_turnaround": False, "institution_buying": False, "score_bonus": 0}
    try:
        inv = get_investor_trend(code)
        foreign_now = safe_int(inv.get("foreign_net", 0), 0)
        institution_now = safe_int(inv.get("institution_net", 0), 0)
        prev = _fi_turnaround_cache.get(code, {}) if isinstance(_fi_turnaround_cache, dict) else {}
        prev_foreign = safe_int(prev.get("foreign_net", 0), 0)
        prev_ts = float(prev.get("ts", 0) or 0)
        foreign_turnaround = prev_ts > 0 and (now_ts - prev_ts) <= 1800 and prev_foreign < 0 < foreign_now
        institution_buying = institution_now > 0
        out = {
            "foreign_turnaround": foreign_turnaround,
            "institution_buying": institution_buying,
            "score_bonus": 10 if (foreign_turnaround and institution_buying) else 0,
            "foreign_net": foreign_now,
            "institution_net": institution_now,
        }
        _fi_turnaround_cache[code] = {"foreign_net": foreign_now, "institution_net": institution_now, "ts": now_ts}
    except Exception as e:
        _swallow_exception(e)
    return out
def check_liquidity(code: str, max_spread: int = 500, quote: dict | None = None) -> bool:
    try:
        q = dict(quote or {})
        if not q:
            q = get_stock_price(code)
        bid = safe_int(q.get("bid_price", 0), 0)
        ask = safe_int(q.get("ask_price", 0), 0)
        bid_qty = safe_int(q.get("bid_qty", 0), 0)
        ask_qty = safe_int(q.get("ask_qty", 0), 0)
        if bid and ask:
            spread = ask - bid
            if spread > max_spread or spread < 0:
                return False
            return True
        if bid_qty <= 0 and ask_qty <= 0:
            return True
        if bid_qty <= 0 or ask_qty <= 0:
            return False
        return True
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return True
def should_skip_expiration_for_dart_watch(watch: dict) -> bool:
    try:
        source = str(watch.get("source", "") or "")
        if source not in ("DART", "DART_MERGER", "MERGER_ANNOUNCEMENT"):
            return False
        shareholder_date = str(watch.get("shareholder_confirmation_date", "") or "")
        if not shareholder_date:
            return False
        target_date = datetime.strptime(shareholder_date, "%Y-%m-%d").date()
        return (target_date - datetime.now().date()).days >= 0
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def get_rsi_5min(code: str) -> float:
    try:
        mins = _get_minute_data(code, count=30)
        closes = [safe_int(x.get("close", 0), 0) for x in mins if safe_int(x.get("close", 0), 0) > 0]
        if len(closes) < 15:
            return float(calc_indicators(code).get("rsi", 50) or 50)
        gains, losses = [], []
        for prev, cur in zip(closes[:-1], closes[1:]):
            diff = cur - prev
            gains.append(max(diff, 0))
            losses.append(abs(min(diff, 0)))
        period = min(14, len(gains))
        avg_gain = sum(gains[-period:]) / max(period, 1)
        avg_loss = sum(losses[-period:]) / max(period, 1)
        if avg_loss <= 0:
            return 100.0 if avg_gain > 0 else 50.0
        rs = avg_gain / avg_loss
        return round(100 - (100 / (1 + rs)), 1)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 50.0
def get_current_volume(code: str) -> int:
    try:
        return safe_int(get_stock_price(code).get("today_vol", 0), 0)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 0
def get_macd_histogram(code: str) -> float:
    try:
        mins = _get_minute_data(code, count=60)
        closes = [float(safe_int(x.get("close", 0), 0)) for x in mins if safe_int(x.get("close", 0), 0) > 0]
        if len(closes) < 35:
            return 0.0
        def _ema(seq, period):
            k = 2 / (period + 1)
            ema = seq[0]
            out = []
            for val in seq:
                ema = val * k + ema * (1 - k)
                out.append(ema)
            return out
        ema12 = _ema(closes, 12)
        ema26 = _ema(closes, 26)
        macd = [a - b for a, b in zip(ema12, ema26)]
        signal = _ema(macd, 9)
        return round(macd[-1] - signal[-1], 4)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 0.0
def detect_hammer_or_bullish_engulfing(code: str) -> bool:
    try:
        mins = _get_minute_data(code, count=3)
        if len(mins) < 2:
            return False
        last = mins[-1]
        prev = mins[-2]
        prev_open = safe_int(prev.get("open", 0), 0)
        prev_close = safe_int(prev.get("close", 0), 0)
        last_open = safe_int(last.get("open", 0), 0)
        last_close = safe_int(last.get("close", 0), 0)
        body = abs(last_close - last_open)
        prev_body = abs(prev_close - prev_open)
        hammer_like = last_close >= last_open and body <= max(int(last_close * 0.01), 50)
        bullish_engulf = prev_close < prev_open and last_close > last_open and last_open <= prev_close and last_close >= prev_open and body >= prev_body
        return hammer_like or bullish_engulf
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def confirm_bottom_and_signal(watch: dict, current_price: int, current_data: dict) -> dict:
    result = {
        "is_bottom_confirmed": False,
        "should_send_signal": False,
        "signal_type": None,
        "reason": "",
    }
    try:
        volume_ratio = float(current_data.get("volume_ratio", watch.get("volume_ratio", 0)) or 0.0)
        exec_metrics = dict(current_data.get("execution_metrics") or watch.get("execution_metrics") or {})
        strength = _classify_signal_strength(watch, exec_metrics)
        low_price_time = watch.get("low_price_time") or ""
        if isinstance(low_price_time, datetime):
            low_dt = _coerce_kst_datetime(low_price_time) or _now_kst()
        else:
            low_dt = _parse_compact_datetime(low_price_time) or _now_kst()
        low_age_sec = _kst_seconds_since(low_dt)
        essential_check = {
            "volume": volume_ratio >= 2.5,
            "strength": strength in ("강한",),
            "time": low_age_sec is not None and low_age_sec <= 1800,
        }
        if not all(essential_check.values()):
            result["reason"] = "필수조건 미충족"
            return result
        result["is_bottom_confirmed"] = True
        bonus_score = 0
        sentiment = detect_foreign_institution_turnaround(watch.get("code", ""))
        if sentiment.get("foreign_turnaround") and sentiment.get("institution_buying"):
            bonus_score += 3
        if int(watch.get("dart_reliability_score", 0) or 0) > 0:
            bonus_score += 2
        if check_liquidity(watch.get("code", ""), max_spread=300, quote=current_data):
            bonus_score += 2
        if get_rsi_5min(watch.get("code", "")) <= 30:
            bonus_score += 2
        vol_now = get_current_volume(watch.get("code", ""))
        vol_prev_low = safe_int(watch.get("volume_at_low", vol_now), vol_now)
        if vol_now and vol_prev_low and vol_now < vol_prev_low * 0.7:
            bonus_score += 2
        if get_macd_histogram(watch.get("code", "")) > 0:
            bonus_score += 1
        if detect_hammer_or_bullish_engulfing(watch.get("code", "")):
            bonus_score += 1
        if bonus_score >= 3:
            result["should_send_signal"] = True
            result["signal_type"] = "entry_signal"
            result["reason"] = f"바닥 확인 + 재상승 신호 ({bonus_score}점)"
        else:
            result["should_send_signal"] = True
            result["signal_type"] = "watch_alert"
            result["reason"] = f"바닥 형성 확인, 재상승 대기중 ({bonus_score}점)"
        return result
    except Exception as e:
        result["reason"] = f"오류: {e}"
        return result
# ── v41.66: 1차/2차 분할 비중 규칙 ──
ENTRY_SPLIT_RULES = {
    "강한": {"phase1_pct": 45, "phase2_pct": 30, "reserve_pct": 25, "phase2_allowed": True},
    "보통": {"phase1_pct": 35, "phase2_pct": 25, "reserve_pct": 40, "phase2_allowed": True},
    "약한": {"phase1_pct": 0,  "phase2_pct": 0,  "reserve_pct": 100, "phase2_allowed": False},
}
def _get_entry_split_rule(strength: str) -> dict:
    """신호 강도별 분할진입 비중 규칙 반환."""
    return ENTRY_SPLIT_RULES.get(strength, ENTRY_SPLIT_RULES["보통"])
def _calc_avg_entry_price(phase1_price: int, phase2_price: int, phase1_pct: int, phase2_pct: int) -> int:
    """1차/2차 진입가 기반 평균단가 계산."""
    total_pct = phase1_pct + phase2_pct
    if total_pct <= 0:
        return phase1_price
    return int((phase1_price * phase1_pct + phase2_price * phase2_pct) / total_pct)
# ── v41.66: 2차 추가진입 판단 ──
def _judge_phase2_entry(watch: dict, cur: dict, price: int, exec_metrics: dict | None = None) -> dict:
    """2차 추가진입 가능/보류/금지 판단.
    반환: {"decision": "가능"/"보류"/"금지", "reasons": [...], "detail": str}
    4개 조건: 눌림유지 / 체결속도 / 손절여유 / 섹터모멘텀"""
    entry = watch.get("entry_price", 0)
    stop = watch.get("stop_loss", 0)
    reasons = []
    fail_count = 0
    if entry and price:
        drop_pct = (entry - price) / entry * 100
        if drop_pct <= 1.5:
            reasons.append("✅ 눌림 유지 (진입가 대비 -{:.1f}%)".format(drop_pct))
        elif drop_pct <= COMMON_THRESHOLD_3P0:
            reasons.append("🟡 소폭 하락 (진입가 대비 -{:.1f}%)".format(drop_pct))
        else:
            reasons.append("🔵 과도 하락 (진입가 대비 -{:.1f}%)".format(drop_pct))
            fail_count += 1
    exec_label, _ = _entry_execution_judgement(exec_metrics)
    flow_state = str((exec_metrics or {}).get("flow_state", "중립") or "중립")
    last_active_age_sec = int((exec_metrics or {}).get("last_active_age_sec", 999) or 999)
    if exec_label == "진입 적합":
        reasons.append(f"✅ 체결속도 양호 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
    elif exec_label == "보류 우선":
        reasons.append(f"🔵 체결속도 급약화 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
        fail_count += 1
    elif exec_label == "참고":
        reasons.append(f"🟡 체결속도 예비판단 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
    else:
        reasons.append(f"🟡 체결속도 보통 ({flow_state}, 최근 유효체결 {last_active_age_sec}초 전)")
    if stop and price and entry:
        stop_distance_pct = (price - stop) / price * 100
        if stop_distance_pct >= 2.0:
            reasons.append(f"✅ 손절가까지 여유 ({stop_distance_pct:.1f}%)")
        elif stop_distance_pct >= 1.0:
            reasons.append(f"🟡 손절가 접근 중 ({stop_distance_pct:.1f}%)")
        else:
            reasons.append(f"🔵 손절가 근접 ({stop_distance_pct:.1f}%)")
            fail_count += 1
    sector_ok = True
    try:
        _s_theme = watch.get("sector_theme", "")
        if _s_theme and _s_theme != "기타업종":
            for _tk, _ti in THEME_MAP.items():
                if _tk == _s_theme or _s_theme in _ti.get("desc", ""):
                    _chg_list = []
                    for _sc, _sn in _ti.get("stocks", [])[:5]:
                        try:
                            _sp = get_stock_price(_sc)
                            _cr = _sp.get("change_rate", 0)
                            if _cr is not None:
                                _chg_list.append(float(_cr))
                            time.sleep(0.03)
                        except Exception as e:
                            _swallow_exception(e)  # v105 structured silent-exception log
                            continue
                    if _chg_list and (sum(_chg_list) / len(_chg_list)) <= -1.0:
                        sector_ok = False
                    break
    except Exception as e:
        _swallow_exception(e)
    if sector_ok:
        reasons.append("✅ 섹터 모멘텀 유지")
    else:
        reasons.append("🔵 섹터 모멘텀 이탈")
        fail_count += 1
    if fail_count >= 2:
        decision = "금지"
        detail = "구조 악화 — 추가매수 금지, 기존 보유분 유지 또는 감축 검토"
    elif fail_count == 1:
        decision = "보류"
        detail = "일부 조건 미충족 — 추가매수 보류, 상황 관찰"
    else:
        decision = "가능"
        detail = "조건 충족 — 추가진입 가능"
    return {"decision": decision, "reasons": reasons, "detail": detail, "fail_count": fail_count}
