    if not _daily_trade_disable_notified:
        msg = f"⚠️ [KIS] inquire-daily-trade 비활성/대체 → 빈 데이터 반환 ({reason})"
        if code:
            msg += f" code={code}"
        if status not in (None, ""):
            msg += f" status={status}"
        if ct not in (None, ""):
            msg += f" ct={ct}"
        if body not in (None, ""):
            body_snip = str(body)[:120].replace("\n", " ")
            msg += f" body={body_snip}"
        _log_warn_msg(msg)
        _daily_trade_disable_notified = True
    return []
