def _rank_api_fallback(reason: str, *, status=None, ct=None, body=None, market: str = "KRX") -> list:
    """Fallback to universe ranking and (optionally) disable rank API for the rest of the day."""
    global _rank_api_disable_notified
    if reason != "disabled_today":
        _disable_rank_api_for_today(str(reason))
    elif not reason:
        reason = _get_rank_api_disable_reason() or "disabled_today"
    # v83: KIS 불통 시 외부 소스(네이버→다음)도 시도 후 유니버스와 합산
    items = _rank_from_universe(market)
    try:
        # v163.10 [#1]: top_n 30→80으로 확대 + 거래대금 상위도 병행 수집
        # 라이콤·머큐리·코위버 등 30위권 밖 소형주 누락 방지
        ext_rise = _fetch_external_rank_top(min_change=1.0, top_n=80)
        ext_codes = {normalize_stock_code(r.get("code")) for r in items}
        added_rise = 0
        for r in ext_rise:
            code = normalize_stock_code(r.get("code"))
            if code and code not in ext_codes:
                items.append(r)
                ext_codes.add(code)
                added_rise += 1
        # v163.10 [#1]: 거래대금 상위 30종목 병행 수집 (꾸준히 오르는 종목 커버)
        ext_amount = _fetch_naver_rank("amount", top_n=30)
        added_amount = 0
        for r in ext_amount:
            code = normalize_stock_code(r.get("code"))
            chg = float(r.get("change_rate", 0) or 0)
            if code and code not in ext_codes and chg >= 0:
                items.append(r)
                ext_codes.add(code)
                added_amount += 1
        if ext_rise or ext_amount:
            _log_info_msg(f"  🌐 외부 소스({ext_rise[0].get('source','?') if ext_rise else 'none'}) 상승{added_rise}건+거래대금{added_amount}건 보완")
    except Exception as e:
        _swallow_exception(e)
    if not _rank_api_disable_notified:
        msg = f"⚠️ [KIS] chgrate-pcls-100 비활성/대체 → {market} 유니버스+외부소스 사용 ({reason})"
        if status not in (None, ""):
            msg += f" status={status}"
        if ct not in (None, ""):
            msg += f" ct={ct}"
        if body not in (None, ""):
            body_snip = str(body)[:120].replace("\n", " ")
            msg += f" body={body_snip}"
        _log_info_msg(msg)
        _rank_api_disable_notified = True
    else:
        # v163.14 [#5]: 비활성 2시간 초과 시 추가 진단 알림 (장중 1회)
        try:
            obj = _runtime_state_get("rank_api_disable", {}, legacy_path=_RANK_API_DISABLE_FILE)
            _dis_ts = float((obj or {}).get("disabled_ts", 0) or 0)
            if _dis_ts and time.time() - _dis_ts > 7200:
                _warn_throttled_once(
                    "rank_api_inactive_alert",
                    f"🔴 [KIS] rank API 비활성 2시간 초과 — F존 미작동 가능. "
                    f"원인: {(obj or {}).get('reason','?')} / 유니버스 fallback 지속 중",
                    cooldown_sec=7200.0,
                )
        except Exception as _rdiag_e:
            _swallow_exception(_rdiag_e)
    _log_info_msg(f"  ↪ rank fallback[{market}] {len(items)}건")
    return items
def get_upper_limit_stocks() -> list:
    if _rank_api_disabled_today():
        return _rank_api_fallback(_get_rank_api_disable_reason() or 'disabled_today', market='KRX')
    url = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/chgrate-pcls-100"
    params = {
        "FID_COND_MRKT_DIV_CODE":"J","FID_COND_SCR_DIV_CODE":"20170","FID_INPUT_ISCD":"0000",
        "FID_RANK_SORT_CLS_CODE":"0","FID_INPUT_CNT_1":"30","FID_PRC_CLS_CODE":"0",
        "FID_INPUT_PRICE_1":"1000","FID_INPUT_PRICE_2":"","FID_VOL_CNT":"100000",
        "FID_TRGT_CLS_CODE":"0","FID_TRGT_EXLS_CLS_CODE":"0","FID_DIV_CLS_CODE":"0",
        "FID_RSFL_RATE1":"5","FID_RSFL_RATE2":"",
    }
    data, status, ct, body = _safe_get_meta(url, "FHPST01700000", params)
    if status == 404:
        return _rank_api_fallback("404", status=status, ct=ct, body=body, market="KRX")
    if status not in (None, 200):
        return _rank_api_fallback(f"status_{status}", status=status, ct=ct, body=body, market="KRX")
    if not isinstance(data, dict):
        return _rank_api_fallback("invalid_response", status=status, ct=ct, body=body, market="KRX")
    items = [{
        "code": i.get("mksc_shrn_iscd",""), "name": i.get("hts_kor_isnm",""),
        "price": int(i.get("stck_prpr",0)), "change_rate": float(i.get("prdy_ctrt",0)),
        "volume_ratio": float(i.get("vol_inrt",0) or 0), "market":"KRX"
    } for i in (data.get("output", []) if isinstance(data, dict) else [])]
    if not items and os.getenv("ENABLE_UNIVERSE_FALLBACK", "1") == "1":
        _log_warn_msg(f"⚠️ [KIS] 랭킹 응답 비어있음(status={status}, ct={ct}) → KRX 유니버스 후보군으로 대체")
        return _rank_api_fallback("empty_output", status=status, ct=ct, body=body, market="KRX")
    _log_info_msg(f"  ✅ [KIS] chgrate-pcls-100 응답 {len(items)}건 (status={status}, ct={ct or '-'})")
    return items
def _normalize_rank_candidate_item(item: dict, market: str = "KRX", desc: str = "") -> dict:
    item = item if isinstance(item, dict) else {}
    code = normalize_stock_code(item.get("code") or item.get("mksc_shrn_iscd") or item.get("stck_shrn_iscd") or "")
    if not code:
        return {}
    rec = {
        "code": code,
        "name": _resolve_stock_name(code, item.get("name") or item.get("hts_kor_isnm") or ""),
        "price": safe_int(item.get("price", item.get("stck_prpr", 0)), 0),
        "change_rate": safe_float(item.get("change_rate", item.get("prdy_ctrt", 0.0)), 0.0),
        "volume_ratio": safe_float(item.get("volume_ratio", item.get("vol_inrt", 0.0)), 0.0),
        "today_vol": safe_int(item.get("today_vol", item.get("acml_vol", 0)), 0),
        "trade_amount": safe_float(item.get("trade_amount", item.get("acml_tr_pbmn", 0.0)), 0.0),
        "market": "NXT" if str(market or "").upper() == "NXT" else "KRX",
    }
    if desc:
        rec["desc"] = desc
    return rec
def _extend_krx_volume_rank_items(items: list[dict], target_count: int) -> list[dict]:
    normalized: list[dict] = []
    seen: set[str] = set()
    for item in items or []:
        rec = _normalize_rank_candidate_item(item, "KRX", item.get("desc", "KIS거래량"))
        code = rec.get("code", "")
        if not code or code in seen:
            continue
        seen.add(code)
        normalized.append(rec)
    if len(normalized) >= target_count:
        return normalized[:target_count]
    sources = (("랭킹보강", _collect_market_rank_candidates("KRX", scan_limit=max(target_count, _get_rank_scan_limit()), force=False)),
               ("유니버스보강", _rank_from_universe("KRX")))
    for source_name, source_items in sources:
        for item in source_items:
            rec = _normalize_rank_candidate_item(item, "KRX", source_name)
            code = rec.get("code", "")
            if not code or code in seen:
                continue
            if rec.get("change_rate", 0.0) <= 0.0 and rec.get("volume_ratio", 0.0) < 1.0:
                continue
            seen.add(code)
            normalized.append(rec)
            if len(normalized) >= target_count:
                break
        if len(normalized) >= target_count:
            break
    normalized.sort(key=lambda x: (safe_float(x.get("volume_ratio", 0.0), 0.0), safe_float(x.get("change_rate", 0.0), 0.0), safe_float(x.get("trade_amount", 0.0), 0.0), safe_int(x.get("today_vol", 0), 0)), reverse=True)
    return normalized[:target_count]
def get_volume_surge_stocks() -> list:
    target_count = max(30, int(_get_krx_volume_rank_count() or 30))
    request_count = min(target_count, max(1, int(KIS_VOLUME_RANK_HARD_LIMIT or 30)))
    data = _safe_get(f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/volume-rank",
                     "FHPST01710000", {
        "FID_COND_MRKT_DIV_CODE":"J","FID_COND_SCR_DIV_CODE":"20171","FID_INPUT_ISCD":"0000",
        "FID_DIV_CLS_CODE":"0","FID_BLNG_CLS_CODE":"0","FID_TRGT_CLS_CODE":"111111111",
        "FID_TRGT_EXLS_CLS_CODE":"000000","FID_INPUT_PRICE_1":"1000",
        "FID_INPUT_PRICE_2":"","FID_VOL_CNT":str(request_count),"FID_INPUT_DATE_1":"",
    })
    items = [_normalize_rank_candidate_item(i, "KRX", "KIS거래량")
             for i in data.get("output",[]) if i.get("mksc_shrn_iscd")]
    items = [item for item in items if item.get("code")]
    if target_count > request_count:
        items = _extend_krx_volume_rank_items(items, target_count)
    # v163: 등락률 임계 초과 종목 → 섹터 최초 반응 tracker 업데이트
    try:
        for _it in items:
            _it_code = str(_it.get("code", "") or "")
            _it_chg  = float(_it.get("change_rate", 0.0) or 0.0)
            _it_sec  = str(_it.get("sector", "") or _it.get("theme", "") or "")
            _it_name = str(_it.get("name", _it_code) or _it_code)
            if _it_code and _it_chg >= SECTOR_FIRST_REACT_THRESHOLD:
                _update_sector_first_react(_it_code, _it_name, _it_sec, _it_chg)
    except Exception as _fre:
        _swallow_exception(_fre)
    return items
