def get_nxt_time_slot() -> str:
    """현재 시각 기준 NXT 시간대 구분 반환."""
    if not is_nxt_open():
        return ""
    n = datetime.now().time()
    if n < dtime(9, 0):
        return "pre"
    elif n <= dtime(15, 30):
        return "overlap"
    elif n <= dtime(17, 0):
        return "post_early"
    else:
        return "post_late"
def get_nxt_params() -> dict:
    """현재 NXT 시간대에 해당하는 파라미터 반환. NXT 아니면 빈 dict."""
    slot = get_nxt_time_slot()
    if not slot:
        return {}
    return NXT_TIME_PARAMS.get(slot, {})
def _is_nxt_postmarket_only_window(now_t: dtime | None = None) -> bool:
    now_t = now_t or datetime.now().time()
    return is_nxt_open() and (not is_market_open()) and now_t >= NXT_POSTMARKET_HELPER_START
def _is_nxt_premarket_window(now_t: dtime | None = None) -> bool:
    """v66: NXT 장전 시간대(08:00~08:59) 판별"""
    now_t = now_t or datetime.now().time()
    return is_nxt_open() and (not is_market_open()) and now_t < dtime(9, 0)
def _get_nxt_volume_rank_count() -> int:
    slot = get_nxt_time_slot()
    if slot == "post_late" and _is_nxt_postmarket_only_window():
        return max(20, NXT_POSTMARKET_VOLUME_RANK_LATE)
    if slot == "post_early" and _is_nxt_postmarket_only_window():
        return max(20, NXT_POSTMARKET_VOLUME_RANK_EARLY)
    return 20
def _get_krx_volume_rank_count() -> int:
    base = max(30, int(KRX_VOLUME_RANK_COUNT or 30))
    if _intraday_capture_mode_active(_get_intraday_capture_mode()):
        return max(base, 80)
    if is_strict_time():
        return max(base, 60)
    return base
def _is_nxt_postmarket_leader_candidate(item: dict | None) -> bool:
    if not isinstance(item, dict) or not _is_nxt_postmarket_only_window():
        return False
    try:
        change_rate = float(item.get("change_rate", 0.0) or 0.0)
        vol_ratio = float(item.get("volume_ratio", 0.0) or 0.0)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
    slot = get_nxt_time_slot()
    min_change = NXT_POSTMARKET_MIN_CHANGE + (0.0 if slot == "post_early" else 1.0)
    min_volume = NXT_POSTMARKET_MIN_VOLUME - (0.2 if slot == "post_late" else 0.0)
    return change_rate >= min_change and (vol_ratio >= min_volume or int(item.get("today_vol", 0) or 0) >= 100000)
def _collect_nxt_postmarket_candidates(existing_codes=None) -> list:
    if not _is_nxt_postmarket_only_window():
        return []
    existing = {str(c) for c in (existing_codes or [])}
    out, seen = [], set(existing)
    def _push_nxt_post_item(item: dict, desc: str):
        code = str(item.get("code", "") or "")
        if not code or code in seen:
            return
        name = _resolve_stock_name(code, item.get("name", ""))
        if not is_trade_candidate_name(name):
            return
        rec = dict(item)
        rec["code"] = code
        rec["name"] = name
        rec["market"] = "NXT"
        rec["desc"] = desc
        out.append(rec)
        seen.add(code)
    for item in get_nxt_surge_stocks():
        if _is_nxt_postmarket_leader_candidate(item):
            _push_nxt_post_item(item, "NXT장후리더")
    rank_limit = max(_get_rank_scan_limit(), NXT_POSTMARKET_EXTRA_RANK_LIMIT)
    for item in _collect_market_rank_candidates("NXT", scan_limit=rank_limit, force=False):
        if _is_nxt_postmarket_leader_candidate(item):
            _push_nxt_post_item(item, item.get("desc", "NXT랭킹후보") + " | NXT장후리더")
    for item in _collect_theme_peer_follow_candidates(existing_codes=seen):
        if str(item.get("market", "") or "") != "NXT":
            continue
        if _is_nxt_postmarket_leader_candidate(item):
            _push_nxt_post_item(item, item.get("desc", "테마동조") + " | NXT장후리더")
    out.sort(key=lambda x: (float(x.get("change_rate", 0) or 0), float(x.get("volume_ratio", 0) or 0), int(x.get("today_vol", 0) or 0)), reverse=True)
    return out
def _calc_nxt_postmarket_leader_bonus(code: str, name: str, theme: str, signal_type: str, *, change_rate: float, vol_ratio: float, market: str = "") -> tuple[int, list[str]]:
    if str(market or "") != "NXT" or not _is_nxt_postmarket_only_window():
        return 0, []
    slot = get_nxt_time_slot()
    min_change = NXT_POSTMARKET_MIN_CHANGE + (0.0 if slot == "post_early" else 1.0)
    if float(change_rate or 0.0) < min_change:
        return 0, []
    bonus = 0
    notes = []
    if vol_ratio >= COMMON_THRESHOLD_3P0:
        bonus += 8
    elif vol_ratio >= 2.0:
        bonus += 6
    elif vol_ratio >= max(1.2, NXT_POSTMARKET_MIN_VOLUME):
        bonus += 4
    if str(theme or "") not in ("", "기타업종", "unknown", "미분류"):
        bonus += 4
        notes.append(f"🌙 NXT 장후 리더 후보 [{theme}] +4점")
    if signal_type in ("NEAR_UPPER", "SURGE", "STRONG_BUY"):
        bonus += 4
    try:
        nxt = get_nxt_info(code)
        if float(nxt.get("vs_krx_pct", 0.0) or 0.0) >= 1.0:
            bonus += 4
            notes.append(f"🟡 NXT 종가 프리미엄 +{float(nxt.get('vs_krx_pct', 0.0) or 0.0):.1f}% +4점")
        if nxt.get("inv_bullish"):
            bonus += 4
            notes.append("🔴 NXT 수급 우호 (외인·기관 동시 유입) +4점")
    except Exception as e:
        _swallow_exception(e)
    if bonus > 0 and not notes:
        notes.append(f"🌙 NXT 장후 리더 가산 +{bonus}점")
    return bonus, notes[:2]
def is_nxt_open() -> bool:
    """NXT는 주말/공휴일 제외, 08:00~20:00"""
    if is_holiday(): return False
    return NXT_OPEN <= datetime.now().time() <= NXT_CLOSE
def get_nxt_surge_stocks() -> list:
    """NXT 급등/거래량 상위 종목 조회"""
    try:
        data = _safe_get(f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/volume-rank",
                         "FHPST01710000", {
            "FID_COND_MRKT_DIV_CODE":"NX","FID_COND_SCR_DIV_CODE":"20171",
            "FID_INPUT_ISCD":"0000","FID_DIV_CLS_CODE":"0","FID_BLNG_CLS_CODE":"0",
            "FID_TRGT_CLS_CODE":"111111111","FID_TRGT_EXLS_CLS_CODE":"000000",
            "FID_INPUT_PRICE_1":"1000","FID_INPUT_PRICE_2":"",
            "FID_VOL_CNT":str(_get_nxt_volume_rank_count()),"FID_INPUT_DATE_1":"",
        })
        items = [{"code":i.get("mksc_shrn_iscd",""),"name":i.get("hts_kor_isnm",""),
                  "price":int(i.get("stck_prpr",0)),"change_rate":float(i.get("prdy_ctrt",0)),
                  "volume_ratio":float(i.get("vol_inrt",0) or 0), "today_vol": int(i.get("acml_vol",0) or 0), "market":"NXT"}
                 for i in data.get("output",[]) if i.get("mksc_shrn_iscd")]
        if not items and os.getenv("ENABLE_UNIVERSE_FALLBACK", "1") == "1":
            _log_warn_msg("⚠️ [NXT] volume-rank 응답 비어있음 → NXT 유니버스 후보군으로 대체")
            return _rank_from_universe("NXT")
        # v163: NXT 종목도 최초 반응 tracker 업데이트
        # v163.5: get_stock_info 미정의 → 종목명은 items에서 직접 사용
        try:
            for _ni in items:
                _ni_code = str(_ni.get("code", "") or "")
                _ni_chg  = float(_ni.get("change_rate", 0.0) or 0.0)
                _ni_name = str(_ni.get("name", _ni_code) or _ni_code)
                if _ni_code and _ni_chg >= SECTOR_FIRST_REACT_THRESHOLD:
                    _ni_sec = str(_ni.get("bstp_name", "") or _ni.get("sector", "") or "")
                    _update_sector_first_react(_ni_code, _ni_name, _ni_sec, _ni_chg)
        except Exception as _nfre:
            _swallow_exception(_nfre)
        return items
    except Exception as e:
        _log_warn_msg(f"⚠️ NXT 조회 오류: {e}")
        return _rank_from_universe("NXT") if os.getenv("ENABLE_UNIVERSE_FALLBACK", "1") == "1" else []
def get_nxt_stock_price(code: str) -> dict:
    """NXT 개별 종목 현재가 조회"""
    url    = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-price"
    params = {"FID_COND_MRKT_DIV_CODE":"NX","FID_INPUT_ISCD":code}
    data   = _safe_get(url, "FHKST01010100", params)
    o      = data.get("output", {})
    price  = int(o.get("stck_prpr", 0))
    if not price: return {}
    payload = {
        "code": code, "name": o.get("hts_kor_isnm",""),
        "price": price, "change_rate": float(o.get("prdy_ctrt",0)),
        "volume_ratio": float(o.get("vol_inrt",0) or 0),
        "today_vol": int(o.get("acml_vol",0)),
        "ask_qty": int(o.get("askp_rsqn1",0) or 0),
        "bid_qty": int(o.get("bidp_rsqn1",0) or 0),
        "ask_price": int(o.get("askp1",0) or 0),
        "bid_price": int(o.get("bidp1",0) or 0),
        "open": int(o.get("stck_oprc",0) or 0),
        "market": "NXT",
        "bstp_name": o.get("bstp_kor_isnm","") or "동일업종",
        "vi_cls_code":  str(o.get("vi_cls_code","") or o.get("vi_yn","") or ""),  # v165.6 [#1]: trht_yn/halt_yn 분리 — VI발동 전용
        "raw_status_code": str(o.get("iscd_stat_cls_code","") or ""),  # v165.1: temp_stop_yn 분리
        "raw_temp_stop":   str(o.get("temp_stop_yn","") or ""),        # v165.1: VI임시정지 별도 필드
        "raw_trht_yn":     str(o.get("trht_yn","") or ""),             # v165.6 [#1]: 거래정지여부 별도 필드
        "raw_halt_yn":     str(o.get("halt_yn","") or ""),             # v165.6 [#1]: halt여부 별도 필드
        "mrkt_alrm_cls_code": str(o.get("mrkt_alrm_cls_code","") or ""),  # v163.2: 투자주의(01)/경고(02)/위험(03)
    }
    try:
        _record_execution_snapshot(code, payload, market="NXT")
    except Exception as e:
        _swallow_exception(e)
    try:
        _remember_public_stock_meta(code, payload.get("name", ""), payload.get("bstp_name", ""))
    except Exception as e:
        _swallow_exception(e)
    return payload
def _is_nxt_eligible(code: str) -> bool:
    """v165.14: 종목이 NXT 거래 가능한지 캐시 기반으로 판별.
    get_nxt_stock_price() 응답(price>0)이 있으면 NXT 가능, 없으면 KRX 전용.
    결과는 당일 캐시에 저장 — 반복 API 호출 방지."""
    if code in _nxt_eligible_cache:
        return _nxt_eligible_cache[code]
    try:
        cur = get_nxt_stock_price(code)
        eligible = bool(cur and safe_int(cur.get("price", 0), 0) > 0)
    except Exception as e:
        _swallow_exception(e)
        eligible = False  # 조회 실패 시 KRX 전용으로 보수적 처리
    _nxt_eligible_cache[code] = eligible
    return eligible
def get_nxt_investor_trend(code: str) -> dict:
    """NXT 외인·기관 순매수 조회"""
    data   = _safe_get(f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-investor",
                       "FHKST01010900", {"FID_COND_MRKT_DIV_CODE":"NX","FID_INPUT_ISCD":code})
    output = data.get("output", [])
    if not output: return {}
    return {
        "foreign_net":     safe_int(output[0].get('frgn_ntby_qty', 0)),
        "institution_net": safe_int(output[0].get('orgn_ntby_qty', 0)),
    }
def _kis_market_div_code(market: str = "") -> str:
    return "NX" if str(market or "").upper() == "NXT" else "J"
def _first_dict_output(data: dict, *keys: str) -> dict:
    raw = data if isinstance(data, dict) else {}
    for key in keys:
        obj = raw.get(key)
        if isinstance(obj, dict):
            return obj
        if isinstance(obj, list):
            for item in obj:
                if isinstance(item, dict):
                    return item
    return {}
def _pick_first_numeric(raw: dict, keys: list[str], default: float = 0.0) -> float:
    obj = raw if isinstance(raw, dict) else {}
    for key in keys:
        val = obj.get(key)
        if val in (None, ""):
            continue
        try:
            return float(str(val).replace(',', ''))
        except Exception as e:
            _swallow_exception(e)
    return float(default or 0.0)
def _quiet_snapshot_cache_key(kind: str, code: str, market: str) -> tuple[str, str, str]:
    return str(kind or ""), normalize_stock_code(code), "NXT" if str(market or "").upper() == "NXT" else "KRX"
def _reset_quiet_scan_cycle_state() -> None:
    budget = max(3, int(MARKET_FLOW_QUIET_DEEP_FETCH_LIMIT or 1) * 3)
    _quiet_scan_cycle_state.update({
        "started_ts": time.time(),
        "calls": 0,
        "budget": budget,
        "skipped_budget": 0,
    })
def _get_quiet_cached_snapshot(kind: str, code: str, market: str, loader) -> dict:
    key = _quiet_snapshot_cache_key(kind, code, market)
    now_ts = time.time()
    ttl = max(3, int(QUIET_SNAPSHOT_CACHE_TTL_SEC or 3))
    cached = _quiet_snapshot_cache.get(key)
    if cached and now_ts - float(cached.get("ts", 0.0) or 0.0) < ttl:
        return dict(cached.get("data") or {})
    if int(_quiet_scan_cycle_state.get("calls", 0) or 0) >= int(_quiet_scan_cycle_state.get("budget", 0) or 0):
        _quiet_scan_cycle_state["skipped_budget"] = int(_quiet_scan_cycle_state.get("skipped_budget", 0) or 0) + 1
        if cached and now_ts - float(cached.get("ts", 0.0) or 0.0) < ttl * 3:
            return dict(cached.get("data") or {})
        return {}
    data = loader() or {}
    _quiet_scan_cycle_state["calls"] = int(_quiet_scan_cycle_state.get("calls", 0) or 0) + 1
    if data:
        _quiet_snapshot_cache[key] = {"ts": now_ts, "data": dict(data)}
        return dict(data)
    if cached and now_ts - float(cached.get("ts", 0.0) or 0.0) < ttl * 3:
        return dict(cached.get("data") or {})
    return {}
def _get_quiet_investor_trend(code: str, market: str = "KRX") -> dict:
    market = "NXT" if str(market or "").upper() == "NXT" else "KRX"
    return _get_quiet_cached_snapshot(
        "investor", code, market,
        lambda: get_nxt_investor_trend(code) if market == "NXT" else get_investor_trend(code),
    )
def _get_quiet_orderbook_snapshot(code: str, market: str = "KRX") -> dict:
    return _get_quiet_cached_snapshot("orderbook", code, market, lambda: get_orderbook_depth_snapshot(code, market=market))
def _get_quiet_trade_snapshot(code: str, market: str = "KRX") -> dict:
    return _get_quiet_cached_snapshot("trade", code, market, lambda: get_trade_intensity_snapshot(code, market=market))

def _get_groq_scenario_for_code(code: str, name: str) -> dict:
    """Groq CoT 분석 결과에서 종목별 시나리오 필드 반환 (v165.0).
    gemini_stocks name 부분 매칭으로 조회.
    Returns: {today_reflected, tomorrow_continuation, scenario_confidence, counter_scenario} 또는 {}
    """
    try:
        rows = list(_groq_grounding_cache.get("rows") or [])
        name_clean = str(name or "").strip()
        code_clean = str(code or "").strip()
        for row in rows:
            for gs in (row.get("gemini_stocks") or []):
                gs_name = str(gs.get("name", "") or "")
                if not gs_name:
                    continue
                if gs_name in name_clean or name_clean in gs_name or gs_name == code_clean:
                    return {
                        "today_reflected":       row.get("_today_reflected", "partial"),
                        "tomorrow_continuation": row.get("_tomorrow_continuation", "moderate"),
                        "scenario_confidence":   row.get("_scenario_confidence", "medium"),
                        "counter_scenario":      row.get("_counter_scenario", ""),
                        "theme":                 gs.get("theme", ""),
                        "direction":             gs.get("direction", "neutral"),
                        "reason":                gs.get("reason", ""),
                    }
    except Exception as e:
        _swallow_exception(e)
    return {}

def _fetch_opening_expected_price(code: str) -> dict:
    """KIS FHKST01010200 output2 — 장전 동시호가 예상체결가 조회 (v165.0).
    08:30~09:00 동시호가 구간에서만 antc_cnpr 유효.
    Returns: {expected_price, expected_rate, bid_qty, ask_qty, bid_ask_ratio}
    """
    code = normalize_stock_code(code)
    if not code:
        return {}
    try:
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-asking-price-exp-ccn",
            "FHKST01010200",
            {"FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": code},
        )
        out2 = None
        if isinstance(data.get("output2"), dict):
            out2 = data["output2"]
        elif isinstance(data.get("output2"), list) and data["output2"]:
            out2 = data["output2"][0]
        out1 = None
        if isinstance(data.get("output1"), dict):
            out1 = data["output1"]
        elif isinstance(data.get("output1"), list) and data["output1"]:
            out1 = data["output1"][0]
        expected_price = 0
        expected_rate  = 0.0
        if out2:
            expected_price = safe_int(out2.get("antc_cnpr", 0), 0)
            try:
                expected_rate = float(out2.get("antc_cntg_vrss_prdy_ctrt", 0) or 0)
            except Exception:
                expected_rate = 0.0
        # 호가잔량은 output1에서
        bid_qty = ask_qty = 0
        if out1:
            bid_qty = safe_int(out1.get("bidp_rsqn1", 0), 0)
            ask_qty = safe_int(out1.get("askp_rsqn1", 0), 0)
        if expected_price <= 0:
            return {}
        bid_ask_ratio = round(bid_qty / max(ask_qty, 1), 2) if ask_qty > 0 else 0.0
        return {
            "expected_price": expected_price,
            "expected_rate":  round(expected_rate, 2),
            "bid_qty":        bid_qty,
            "ask_qty":        ask_qty,
            "bid_ask_ratio":  bid_ask_ratio,
        }
    except Exception as e:
        _swallow_exception(e)
        return {}

def _build_opening_gap_watch_pool() -> list:
    """시초가 진입 후보 풀 구성 (v165.0).
    1) signal_log PRECLOSE_GAP_ENTRY 어제·오늘 발송 종목
    2) _preclose_gap_entry_watch 현재 추적 종목
    3) Groq CoT today_reflected=not_yet + tomorrow_continuation=strong 종목
    Returns: list of {code, name, source}
    """
    pool = []
    seen = set()

    def _push(code, name, source):
        c = normalize_stock_code(code)
        if c and c not in seen:
            seen.add(c)
            pool.append({"code": c, "name": str(name or c), "source": source})

    # ① PRECLOSE_GAP_ENTRY 발송 이력
    try:
        today  = _now_kst().strftime("%Y%m%d")
        yest   = (_now_kst() - timedelta(days=1)).strftime("%Y%m%d")
        siglog = _read_json_safe(SIGNAL_LOG_FILE, {})
        recs   = list(siglog.values()) if isinstance(siglog, dict) else (siglog if isinstance(siglog, list) else [])
        for rec in recs:
            if not isinstance(rec, dict):
                continue
            if rec.get("signal_type") != PRECLOSE_GAP_SIGNAL_TYPE:
                continue
            det_date = str(rec.get("detect_date", "") or "")
            if det_date not in (today, yest):
                continue
            _push(rec.get("code", ""), rec.get("name", ""), "PRECLOSE_GAP")
    except Exception as e:
        _swallow_exception(e)

    # ② _preclose_gap_entry_watch 현재 추적 중
    try:
        with _state_lock:
            watch = dict(_preclose_gap_entry_watch or {})
        for v in watch.values():
            if isinstance(v, dict):
                _push(v.get("code", ""), v.get("name", ""), "PRECLOSE_WATCH")
    except Exception as e:
        _swallow_exception(e)

    # ③ Groq CoT 미반영·강세 지속 종목
    try:
        rows = list(_groq_grounding_cache.get("rows") or [])
        for row in rows:
            if row.get("_today_reflected") == "not_yet" and row.get("_tomorrow_continuation") == "strong":
                for gs in (row.get("gemini_stocks") or []):
                    gs_name = str(gs.get("name", "") or "")
                    if not gs_name:
                        continue
                    resolved = _resolve_stock_code_by_name(gs_name)
                    if resolved:
                        _push(resolved, gs_name, "GROQ_NOT_YET")
    except Exception as e:
        _swallow_exception(e)

    if pool:
        _log_info_msg(f"[OPENING_GAP] 후보 풀 구성: {len(pool)}건 (PRECLOSE:{sum(1 for p in pool if 'PRECLOSE' in p['source'])} / GROQ:{sum(1 for p in pool if 'GROQ' in p['source'])})")
    return pool[:OPENING_GAP_MAX_POOL]

def send_opening_gap_alert() -> None:
    """08:50 — 시초가 진입 알람 발송 (v165.0).
    KIS 예상체결가 조회 → 스코어링 → 조건 충족 시 텔레그램 알람.
    선진입(PRECLOSE_GAP_ENTRY)의 보완책 — 진입가가 더 높음을 알람에 명시.
    """
    if is_holiday():
        return
    now_t = _now_kst().time()
    # 08:30~09:05 사이에만 실행 (동시호가 구간)
    if not (dtime(8, 28) <= now_t <= dtime(9, 5)):
        return
    _log_info_msg("⚡ [시초가진입] 08:50 예상체결가 스캔 시작")
    pool = _build_opening_gap_watch_pool()
    if not pool:
        _log_info_msg("⚡ [시초가진입] 후보 풀 0건 — 종료")
        return
    us = get_us_market_signals() or {}
    candidates = []
    for item in pool:
        code = item["code"]
        name = item["name"]
        source = item["source"]
        try:
            exp = _fetch_opening_expected_price(code)
            if not exp:
                continue
            expected_rate  = float(exp.get("expected_rate", 0) or 0)
            bid_ask_ratio  = float(exp.get("bid_ask_ratio", 0) or 0)
            expected_price = int(exp.get("expected_price", 0) or 0)
            # 최소 조건: 예상 갭상승률 + 매수잔량 우위
            if expected_rate < OPENING_GAP_MIN_EXPECTED_GAP_PCT:
                continue
            if bid_ask_ratio < OPENING_GAP_MIN_BID_ASK_RATIO:
                continue
            # 스코어링
            score = 0
            reasons = []
            # 예상 갭상승률
            if expected_rate >= 8:
                score += 25; reasons.append(f"🔥 예상갭 {expected_rate:+.1f}% +25")
            elif expected_rate >= 5:
                score += 18; reasons.append(f"🔥 예상갭 {expected_rate:+.1f}% +18")
            elif expected_rate >= 3:
                score += 12; reasons.append(f"📈 예상갭 {expected_rate:+.1f}% +12")
            else:
                score += 6; reasons.append(f"📈 예상갭 {expected_rate:+.1f}% +6")
            # 매수잔량 비율
            if bid_ask_ratio >= 3.0:
                score += 15; reasons.append(f"💪 매수잔량 {bid_ask_ratio:.1f}배 +15")
            elif bid_ask_ratio >= 2.0:
                score += 10; reasons.append(f"💪 매수잔량 {bid_ask_ratio:.1f}배 +10")
            elif bid_ask_ratio >= 1.3:
                score += 5; reasons.append(f"💪 매수잔량 {bid_ask_ratio:.1f}배 +5")
            # RS 지속성 (전날 장중 스냅샷)
            try:
                consistency_pct, trend, snap_count = _get_momentum_consistency_score(code, "KRX")
                if snap_count >= 1:
                    if consistency_pct >= 80:
                        score += 8; reasons.append(f"📈 전일 RS 지속률 {consistency_pct:.0f}% +8")
                    elif consistency_pct >= 60:
                        score += 5; reasons.append(f"📈 전일 RS 지속률 {consistency_pct:.0f}% +5")
                    if trend == "improving":
                        score += 3; reasons.append("⬆️ RS 추세 개선 +3")
            except Exception as _e:
                _swallow_exception(_e)
            # Groq CoT 시나리오 점수
            try:
                gs = _get_groq_scenario_for_code(code, name)
                if gs:
                    tr = gs.get("today_reflected", "partial")
                    tc = gs.get("tomorrow_continuation", "moderate")
                    sc = gs.get("scenario_confidence", "medium")
                    if tr == "not_yet" and tc == "strong":
                        score += 12; reasons.append(f"🔥 Groq미반영·강세지속 +12")
                    elif tr == "not_yet":
                        score += 7; reasons.append(f"⭐ Groq미반영재료 +7")
                    elif tr == "already":
                        score -= 5; reasons.append("⚠️ Groq이미반영 -5")
                    if sc == "high":
                        score += 4; reasons.append("🎯 시나리오신뢰도高 +4")
            except Exception as _e:
                _swallow_exception(_e)
            # 미국시장 방향
            gap_signal = str(us.get("gap_signal", "flat") or "flat")
            if gap_signal == "gap_up":
                score += 5; reasons.append("🌐 미국 갭상승 +5")
            elif gap_signal == "gap_down":
                score -= 5; reasons.append("🌐 미국 갭하락 -5")
            # 외국인·기관 수급 (전일 가집계)
            try:
                inv = get_investor_provisional_trend(code, market="KRX")
                if isinstance(inv, dict) and inv:
                    if int(inv.get("frgn_ntby_qty", 0) or 0) > 0:
                        score += 5; reasons.append("🌐 외국인 순매수 +5")
                    if int(inv.get("orgn_ntby_qty", 0) or 0) > 0:
                        score += 4; reasons.append("🏦 기관 순매수 +4")
            except Exception as _e:
                _swallow_exception(_e)
            if score < OPENING_GAP_MIN_SCORE:
                continue
            candidates.append({
                "code": code, "name": name, "score": score,
                "expected_rate": expected_rate, "expected_price": expected_price,
                "bid_ask_ratio": bid_ask_ratio, "reasons": reasons[:4], "source": source,
            })
            time.sleep(0.08)
        except Exception as e:
            _swallow_exception(e)
    candidates.sort(key=lambda x: x["score"], reverse=True)
    if not candidates:
        _log_info_msg(f"⚡ [시초가진입] 조건 충족 종목 없음 (pool={len(pool)})")
        return
    _log_info_msg(f"⚡ [시초가진입] 알람 발송: {len(candidates)}건")
    for c in candidates[:3]:
        try:
            code  = c["code"]
            name  = c["name"]
            er    = c["expected_rate"]
            ep    = c["expected_price"]
            ba    = c["bid_ask_ratio"]
            sc    = c["score"]
            rsns  = "\n".join(f"  • {r}" for r in c["reasons"])
            src   = c["source"]
            src_tag = "📌 선진입 이월" if "PRECLOSE" in src else "🔍 Groq재료"
            msg = (
                f"⚡ [시초가 진입 대기] {name}({code})\n"
                f"━━━━━━━━━━━━━━━━━━━\n"
                f"예상 시초가: {ep:,}원 ({er:+.1f}%)\n"
                f"매수잔량비율: {ba:.1f}배\n"
                f"종합 점수: {sc}점\n"
                f"{rsns}\n"
                f"━━━━━━━━━━━━━━━━━━━\n"
                f"{src_tag} | ⚠️ 갭상승 후 진입으로 선진입 대비 진입가 높을 수 있음\n"
                f"📌 09:00 시초가 형성 후 매수잔량 유지 재확인 권장"
            )
            _send_telegram_message(msg)
        except Exception as e:
            _swallow_exception(e)

def get_orderbook_depth_snapshot(code: str, market: str = "KRX") -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    try:
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-asking-price-exp-ccn",
            "FHKST01010200",
            {"FID_COND_MRKT_DIV_CODE": _kis_market_div_code(market), "FID_INPUT_ISCD": code},
        )
    except Exception as e:
        _swallow_exception(e)
        return {}
    out = _first_dict_output(data, "output1", "output")
    if not out:
        return {}
    ask_total = 0
    bid_total = 0
    active_levels = 0
    support_levels = 0
    for idx in range(1, 11):
        ask_qty = safe_int(out.get(f"askp_rsqn{idx}", 0), 0)
        bid_qty = safe_int(out.get(f"bidp_rsqn{idx}", 0), 0)
        ask_total += ask_qty
        bid_total += bid_qty
        if ask_qty > 0 or bid_qty > 0:
            active_levels += 1
        if bid_qty > 0 and (ask_qty <= 0 or bid_qty >= ask_qty):
            support_levels += 1
    if ask_total <= 0 and bid_total <= 0:
        return {}
    bid_ask_ratio = round(min(bid_total / max(ask_total, 1), COMMON_THRESHOLD_3P0), 3)
    return {
        "ask_total": ask_total,
        "bid_total": bid_total,
        "bid_ask_ratio": bid_ask_ratio,
        "active_levels": active_levels,
        "support_levels": support_levels,
    }
def get_trade_intensity_snapshot(code: str, market: str = "KRX") -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    try:
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-ccnl",
            "FHKST01010300",
            {"FID_COND_MRKT_DIV_CODE": _kis_market_div_code(market), "FID_INPUT_ISCD": code},
        )
    except Exception as e:
        _swallow_exception(e)
        return {}
    out = _first_dict_output(data, "output", "output1")
    if not out:
        return {}
    strength = _pick_first_numeric(out, [
        "tday_rltv", "acml_cttr", "cttr", "trad_ints", "cntg_power", "cnqn",
    ])
    buy_qty = _pick_first_numeric(out, [
        "buy_cntg_qty", "totl_buy_cntg_qty", "total_buy_cntg_qty", "mspr_buy_qty",
    ])
    sell_qty = _pick_first_numeric(out, [
        "sell_cntg_qty", "totl_sell_cntg_qty", "total_sell_cntg_qty", "mspr_sell_qty",
    ])
    buy_ratio = round((buy_qty / max(buy_qty + sell_qty, 1.0)) * 100.0, 1) if (buy_qty > 0 or sell_qty > 0) else 0.0
    ccnl_vol = _pick_first_numeric(out, [
        "tday_ccld_qty", "acml_vol", "cntg_vol", "acml_tr_pbmn",
    ])
    if strength <= 0 and buy_ratio <= 0 and ccnl_vol <= 0:
        return {}
    return {
        "strength": round(strength, 2),
        "buy_qty": int(buy_qty or 0),
        "sell_qty": int(sell_qty or 0),
        "buy_ratio": buy_ratio,
        "ccnl_vol": int(ccnl_vol or 0),
    }
# NXT 데이터 캐시 (종목별 5분 유효)
_nxt_cache: dict = {}        # code → {data, ts}
_nxt_unavailable: set = set()  # NXT 비상장/거래없는 종목 (당일 재조회 안 함)
def get_nxt_info(code: str) -> dict:
    """
    NXT 종합 정보 (캐시 5분)
    NXT 비상장 종목은 _nxt_unavailable에 기록 → 당일 재조회 없음
    반환: {price, change_rate, volume_ratio, foreign_net, institution_net,
            vs_krx_pct, vol_surge, inv_bullish, inv_bearish}
    """
    if code in _nxt_unavailable: return {}   # 비상장 종목 빠르게 스킵
    cached = _nxt_cache.get(code)
    if cached and time.time() - cached["ts"] < 300:
        return cached["data"]
    if not is_nxt_open():
        return {}
    try:
        p = get_nxt_stock_price(code)
        if not p:
            _nxt_unavailable.add(code)       # 조회 실패 → 비상장으로 간주
            return {}
        inv = {}
        try: inv = get_nxt_investor_trend(code)
        except Exception as e:
            _swallow_exception(e)
        krx = get_stock_price(code)
        krx_price = krx.get("price", 0)
        vs_krx = round((p["price"] - krx_price) / krx_price * 100, 2) if krx_price else 0
        f_net = inv.get("foreign_net", 0)
        i_net = inv.get("institution_net", 0)
        result = {
            "price":           p["price"],
            "change_rate":     p["change_rate"],
            "volume_ratio":    p["volume_ratio"],
            "foreign_net":     f_net,
            "institution_net": i_net,
            "vs_krx_pct":      vs_krx,
            "vol_surge":       p["volume_ratio"] >= COMMON_THRESHOLD_3P0,
            "inv_bullish":     f_net > 0 and i_net > 0,
            "inv_bearish":     f_net < 0 and i_net < 0,
            "nxt_listed":      True,          # NXT 상장 확인됨
        }
        _nxt_cache[code] = {"data": result, "ts": time.time()}
        return result
    except Exception as e:
        _log_warn_msg(f"⚠️ NXT 정보 오류 ({code}): {e}")
        _nxt_unavailable.add(code)
        return {}
def nxt_score_bonus(code: str) -> tuple:
    """
    NXT 데이터 기반 신호 보정값 반환
    returns: (score_delta, reason_str)
    score_delta > 0 → 강화 / < 0 → 감점
    """
    if not is_nxt_open(): return 0, ""
    nxt = get_nxt_info(code)
    if not nxt: return 0, ""
    delta, reasons = 0, []
    if nxt["inv_bullish"]:
        delta += 15
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["foreign_net"] > 0:
        delta += 7
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["institution_net"] > 0:
        delta += 5
        reasons.append(_build_nxt_investor_label(nxt))
    if nxt["inv_bearish"]:
        delta -= 15
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["foreign_net"] < -3000:
        delta -= 10
        reasons.append("🔵 NXT 수급 약화 (외국인 이탈 확대)")
    if nxt["vol_surge"] and delta > 0:
        delta += 5
        reasons.append(f"🔴 NXT 거래량 급증 ({nxt['volume_ratio']:.1f}배)")
    if nxt["vs_krx_pct"] > 1.0:
        delta += 5
        reasons.append(f"🔴 NXT 프리미엄 +{nxt['vs_krx_pct']:.1f}% (내일 갭상 주목)")
    elif nxt["vs_krx_pct"] < -1.0:
        delta -= 5
        reasons.append(f"🔵 NXT 디스카운트 {nxt['vs_krx_pct']:.1f}%")
    return delta, "\n".join(reasons)
def get_investor_trend(code: str) -> dict:
    data   = _safe_get(f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-investor",
                       "FHKST01010900", {"FID_COND_MRKT_DIV_CODE":"J","FID_INPUT_ISCD":code})
    output = data.get("output",[])
    if not output: return {}
    return {
        "foreign_net":     safe_int(output[0].get('frgn_ntby_qty', 0)),
        "institution_net": safe_int(output[0].get('orgn_ntby_qty', 0)),
        "retail_net":      safe_int(output[0].get('prsn_ntby_qty', 0)),  # 개인 순매수
    }
def get_investor_provisional_trend(code: str, market: str = "KRX") -> dict:
    """v161.30 ⑤: KIS 기관·외국인 당일 가집계 조회 신규 함수.
    get_investor_trend()가 일별 누계를 반환하는 것과 달리,
    이 함수는 당일 장 중 실시간 잠정 집계(가집계)를 반환한다.
    - KRX: FHKST01010900 (FID_COND_MRKT_DIV_CODE=J), 당일 포함
    - NXT: FHKST01010900 (FID_COND_MRKT_DIV_CODE=NX)
    반환: {
        "foreign_net": 외국인 순매수(주),
        "institution_net": 기관 순매수(주),
        "retail_net": 개인 순매수(주),
        "foreign_net_amount": 외국인 순매수(원),
        "institution_net_amount": 기관 순매수(원),
        "is_provisional": True,   ← 가집계 플래그
        "market": "KRX" or "NXT",
    }
    """
    try:
        _mkt_div = "NX" if str(market or "").upper() == "NXT" else "J"
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-investor",
            "FHKST01010900",
            {"FID_COND_MRKT_DIV_CODE": _mkt_div, "FID_INPUT_ISCD": code},
        )
        output = data.get("output", [])
        if not output:
            return {"foreign_net": 0, "institution_net": 0, "retail_net": 0,
                    "foreign_net_amount": 0, "institution_net_amount": 0,
                    "is_provisional": True, "market": market}
        row = output[0] if isinstance(output, list) else output
        f_qty  = safe_int(row.get("frgn_ntby_qty",  0))
        i_qty  = safe_int(row.get("orgn_ntby_qty",  0))
        r_qty  = safe_int(row.get("prsn_ntby_qty",  0))
        f_amt  = safe_int(row.get("frgn_ntby_tr_pbmn", 0))  # 외국인 순매수 거래대금(원)
        i_amt  = safe_int(row.get("orgn_ntby_tr_pbmn", 0))  # 기관 순매수 거래대금(원)
        return {
            "foreign_net":             f_qty,
            "institution_net":         i_qty,
            "retail_net":              r_qty,
            "foreign_net_amount":      f_amt,
            "institution_net_amount":  i_amt,
            "is_provisional":          True,
            "market":                  market,
        }
    except Exception as e:
        _swallow_exception(e)
        return {"foreign_net": 0, "institution_net": 0, "retail_net": 0,
                "foreign_net_amount": 0, "institution_net_amount": 0,
                "is_provisional": True, "market": market}
