def _save_market_scenario_state(state: dict | None = None) -> None:
    global _market_scenario_state
    payload = dict(state or _market_scenario_state or {"items": [], "updated_ts": 0.0})
    _market_scenario_state = payload
    try:
        _write_json_atomic(MARKET_SCENARIO_STATE_FILE, payload, indent=2)
    except Exception as e:
        _swallow_exception(e)


def _load_market_scenario_state() -> dict:
    global _market_scenario_state
    if isinstance(_market_scenario_state, dict) and _market_scenario_state.get("items"):
        return _market_scenario_state
    raw = _read_json_safe(MARKET_SCENARIO_STATE_FILE, {"items": [], "updated_ts": 0.0})
    if isinstance(raw, dict):
        _market_scenario_state = raw
    return _market_scenario_state if isinstance(_market_scenario_state, dict) else {"items": [], "updated_ts": 0.0}


def _save_premarket_action_board(board: dict | None = None) -> None:
    global _premarket_action_board
    payload = dict(board or _premarket_action_board or {"items": [], "updated_ts": 0.0})
    _premarket_action_board = payload
    try:
        _write_json_atomic(PREMARKET_ACTION_BOARD_FILE, payload, indent=2)
    except Exception as e:
        _swallow_exception(e)


def _load_premarket_action_board() -> dict:
    global _premarket_action_board
    if isinstance(_premarket_action_board, dict) and _premarket_action_board.get("items"):
        return _premarket_action_board
    raw = _read_json_safe(PREMARKET_ACTION_BOARD_FILE, {"items": [], "updated_ts": 0.0})
    if isinstance(raw, dict):
        _premarket_action_board = raw
    return _premarket_action_board if isinstance(_premarket_action_board, dict) else {"items": [], "updated_ts": 0.0}


def _rebuild_premarket_action_board(scenarios: list[dict]) -> dict:
    items = []
    for row in list(scenarios or []):
        if not isinstance(row, dict):
            continue
        items.append({
            "event_name": str(row.get("event_name", "") or ""),
            "direction": str(row.get("direction", "neutral") or "neutral"),
            "cause": str(row.get("cause", "") or "")[:160],
            "source": str(row.get("source", "") or ""),
            "kr_sector_bull": list(row.get("kr_sector_bull", []) or []),
            "kr_sector_bear": list(row.get("kr_sector_bear", []) or []),
            "kr_stock_candidates_long": list(row.get("kr_stock_candidates_long", []) or []),
            "kr_stock_candidates_short": list(row.get("kr_stock_candidates_short", []) or []),
            "confirm_signal": str(row.get("confirm_signal", "") or ""),
            "invalidation": str(row.get("invalidation", "") or ""),
            "priority_score": int(row.get("priority_score", 0) or 0),
        })
    items = sorted(items, key=lambda item: (int(item.get("priority_score", 0) or 0), len(item.get("kr_stock_candidates_long", []) or []) + len(item.get("kr_stock_candidates_short", []) or [])), reverse=True)[:PREMARKET_ACTION_BOARD_MAX_ITEMS]
    board = {"items": items, "updated_ts": time.time()}
    _save_premarket_action_board(board)
    return board


def _build_material_signal_rows_from_scenarios() -> list[dict]:
    state = _load_market_scenario_state()
    rows = []
    for item in list((state or {}).get("items", []) or [])[:MARKET_SCENARIO_MAX_ITEMS]:
        if not isinstance(item, dict):
            continue
        direction_label = _scenario_direction_label(item.get("direction", "neutral"))
        focus_sectors = item.get("kr_sector_bull", []) if item.get("direction") == "up" else item.get("kr_sector_bear", [])
        focus_candidates = item.get("kr_stock_candidates_long", []) if item.get("direction") == "up" else item.get("kr_stock_candidates_short", [])
        rows.append({
            "title": (
                f"{item.get('event_name', '')} {direction_label} "
                f"원인 {str(item.get('cause', '') or '')[:60]} "
                f"한국섹터 {'/'.join(list(focus_sectors or [])[:3])} "
                f"한국후보 {'/'.join([str(v.get('name', '') or '') for v in list(focus_candidates or [])[:3]])}"
            ).strip(),
            "source": "SCENARIO",
            "published_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        })
    return rows


def _extract_overnight_event_keywords(headlines: list) -> dict:
    """
    야간/비장중 헤드라인에서 시나리오 객체를 추출.
    반환: {"event|direction": scenario_dict}
    """
    scenario_map = {}
    for raw in list(headlines or []):
        text = str(raw or "").strip()
        if not text:
            continue
        direction = _infer_scenario_direction_from_text(text)
        matched_any = False
        keyword_bull, keyword_bear = _collect_keyword_sector_effects(text)
        for event_name, keywords in OVERNIGHT_EVENT_KEYWORDS.items():
            matched = [kw for kw in keywords if kw and kw.lower() in text.lower()]
            if not matched:
                continue
            matched_any = True
            base_sectors = list(OVERNIGHT_EVENT_SECTOR_MAP.get(event_name, []) or [])
            bull = base_sectors + keyword_bull
            bear = keyword_bear
            item = _build_market_scenario_item(
                event_name=event_name,
                direction=direction,
                cause=text,
                source="HEADLINE",
                matched_keywords=matched,
                us_leaders=_extract_us_leader_keywords(text),
                kr_sector_bull=bull,
                kr_sector_bear=bear,
                priority_base=6,
                confidence="mid",
            )
            _merge_market_scenario_map(scenario_map, item)
        if matched_any:
            continue
        if keyword_bull or keyword_bear:
            generic_event = "거시/재료"
            if "환율" in text or "원달러" in text:
                generic_event = "환율"
            elif "금리" in text or "10년물" in text:
                generic_event = "금리"
            elif "유가" in text or "wti" in text.lower() or "oil" in text.lower():
                generic_event = "유가"
            elif "반도체" in text or "nvidia" in text.lower() or "엔비디아" in text:
                generic_event = "반도체/AI"
            item = _build_market_scenario_item(
                event_name=generic_event,
                direction=direction,
                cause=text,
                source="HEADLINE",
                matched_keywords=keyword_bull + keyword_bear,
                us_leaders=_extract_us_leader_keywords(text),
                kr_sector_bull=keyword_bull,
                kr_sector_bear=keyword_bear,
                priority_base=5,
                confidence="low",
            )
            _merge_market_scenario_map(scenario_map, item)
    return scenario_map


def _build_overnight_watchlist(detected_events: dict):
    """
    감지된 시나리오 → 상방 한국 종목 워치리스트 생성.
    detected_events: {scenario_key: scenario_dict}
    """
    global _overnight_watchlist
    try:
        watchlist = {}
        for scenario in list((detected_events or {}).values()):
            if not isinstance(scenario, dict):
                continue
            if str(scenario.get("direction", "neutral")) == "down":
                continue
            for cand in list(scenario.get("kr_stock_candidates_long", []) or [])[:6]:
                code = normalize_stock_code(cand.get("code"))
                if not code or code in watchlist:
                    continue
                watchlist[code] = {
                    "name": _resolve_stock_name(code, cand.get("name", "")),
                    "event": scenario.get("event_name", "기타"),
                    "keywords": list(scenario.get("matched_keywords", []) or []),
                    "sectors": list(scenario.get("kr_sector_bull", []) or []),
                    "cause": str(scenario.get("cause", "") or "")[:120],
                    "direction": str(scenario.get("direction", "up") or "up"),
                    "priority_score": int(scenario.get("priority_score", 0) or 0),
                    "confirm_signal": str(scenario.get("confirm_signal", "") or ""),
                    "ts": time.time(),
                    "source": str(scenario.get("source", "scenario") or "scenario"),
                }
                if len(watchlist) >= SCENARIO_WATCHLIST_MAX_CODES:
                    break
            if len(watchlist) >= SCENARIO_WATCHLIST_MAX_CODES:
                break
        _overnight_watchlist = watchlist
        try:
            _write_json_atomic(OVERNIGHT_WATCHLIST_FILE, watchlist, indent=2)
            if watchlist:
                _log_info_msg(f"  🌙 야간 시나리오 워치리스트 저장: {len(watchlist)}종목")
        except Exception as e:
            _swallow_exception(e)
    except Exception as e:
        _log_warn_msg(f"⚠️ _build_overnight_watchlist: {e}")


def collect_market_scenarios_24h(force: bool = False, external_headlines: dict | list | None = None, us: dict | None = None) -> dict:
    global _market_scenario_state
    now_ts = time.time()
    cached = _load_market_scenario_state()
    if not force and cached.get("items") and now_ts - float(cached.get("updated_ts", 0) or 0) < MARKET_SCENARIO_CACHE_TTL_SEC:
        return cached
    rows = []
    try:
        rows.extend(_get_material_signal_headline_rows(force=force))
    except Exception as e:
        _swallow_exception(e)
    if isinstance(external_headlines, dict):
        for source, titles in external_headlines.items():
            for title in list(titles or []):
                txt = str(title or "").strip()
                if txt:
                    rows.append({"title": txt, "source": str(source or "HEADLINE").upper(), "published_at": ""})
    elif isinstance(external_headlines, list):
        for title in external_headlines:
            txt = str(title or "").strip()
            if txt:
                rows.append({"title": txt, "source": "HEADLINE", "published_at": ""})
    scenario_map = {}
    headline_titles = [str((row or {}).get("title", "") or "").strip() for row in rows if str((row or {}).get("title", "") or "").strip()]
    for item in _extract_overnight_event_keywords(headline_titles).values():
        _merge_market_scenario_map(scenario_map, item)
    us_state = dict(us or get_us_market_signals() or {})
    for item in _build_macro_signal_scenarios(us_state):
        _merge_market_scenario_map(scenario_map, item)
    try:
        geo_state = _get_effective_geo_state() or {}
        if geo_state.get("active") and time.time() - float(geo_state.get("ts", 0) or 0) <= 3600 * 18:
            bull = []
            bear = []
            for row in list(geo_state.get("sector_directions", []) or []):
                direction = str((row or {}).get("direction", "") or "").lower()
                sector = str((row or {}).get("sector", "") or "").strip()
                if not sector:
                    continue
                if direction in ("상승", "up", "positive", "bull"):
                    bull.append(sector)
                elif direction in ("하락", "down", "negative", "bear"):
                    bear.append(sector)
            if not bull and geo_state.get("sectors"):
                bull = list(geo_state.get("sectors", []) or [])[:4]
            geo_item = _build_market_scenario_item(
                event_name="지정학/해외이슈",
                direction="down" if int(geo_state.get("score_adj", 0) or 0) <= -5 else "up",
                cause=str(geo_state.get("summary", "") or "")[:160],
                source="GEO",
                matched_keywords=list(geo_state.get("kws", []) or []),
                kr_sector_bull=bull,
                kr_sector_bear=bear,
                priority_base=7,
                confidence=str(geo_state.get("uncertainty", "mid") or "mid"),
            )
            _merge_market_scenario_map(scenario_map, geo_item)
    except Exception as e:
        _swallow_exception(e)
    items = sorted(scenario_map.values(), key=lambda item: (int(item.get("priority_score", 0) or 0), len(item.get("primary_candidates", []) or [])), reverse=True)
    items = items[:MARKET_SCENARIO_MAX_ITEMS]
    state = {"items": items, "updated_ts": now_ts}
    _save_market_scenario_state(state)
    _rebuild_premarket_action_board(items)
    _build_overnight_watchlist({f"{row.get('event_name','')}|{row.get('direction','neutral')}": row for row in items})
    return state


def run_market_scenario_collection_cycle(force: bool = False) -> None:
    try:
        if _bot_paused:
            return
        collect_market_scenarios_24h(force=force)
    except Exception as e:
        _log_error("run_market_scenario_collection_cycle", e)


def _format_premarket_action_board_block(max_events: int = 6, max_stocks: int = 4) -> str:
    board = _load_premarket_action_board()
    items = list((board or {}).get("items", []) or [])
    if not items:
        return ""
    bulls = [item for item in items if str(item.get("direction", "")) == "up"][:max_events]
    bears = [item for item in items if str(item.get("direction", "")) == "down"][:max_events]
    lines = ["🧭 <b>핵심 시나리오 액션보드</b>"]
    if bulls:
        lines.append("  🔴 <b>상방 시나리오</b>")
        for item in bulls[: max(1, max_events // 2 + 1)]:
            cand_names = "/".join([str(v.get("name", "") or "") for v in list(item.get("kr_stock_candidates_long", []) or [])[:max_stocks]])
            sec = ", ".join(list(item.get("kr_sector_bull", []) or [])[:3])
            lines.append(f"   • {item.get('event_name','')} — {str(item.get('cause','') or '')[:36]}")
            if sec:
                lines.append(f"     한국섹터: {sec}")
            if cand_names:
                lines.append(f"     후보: {cand_names}")
            if item.get("confirm_signal"):
                lines.append(f"     확인: {item.get('confirm_signal','')}")
    if bears:
        lines.append("  🔵 <b>하방 시나리오</b>")
        for item in bears[: max(1, max_events // 2 + 1)]:
            cand_names = "/".join([str(v.get("name", "") or "") for v in list(item.get("kr_stock_candidates_short", []) or [])[:max_stocks]])
            sec = ", ".join(list(item.get("kr_sector_bear", []) or [])[:3])
            lines.append(f"   • {item.get('event_name','')} — {str(item.get('cause','') or '')[:36]}")
            if sec:
                lines.append(f"     약세섹터: {sec}")
            if cand_names:
                lines.append(f"     회피/경계: {cand_names}")
            if item.get("confirm_signal"):
                lines.append(f"     확인: {item.get('confirm_signal','')}")
    return "\n".join(lines)


def _build_market_scenario_digest_text(force: bool = False) -> str:
    state = collect_market_scenarios_24h(force=force)
    items = list((state or {}).get("items", []) or [])
    if not items:
        return ""
    lines = ["🧭 <b>장후 시나리오 요약</b>", "━━━━━━━━━━━━━━━"]
    for item in items[:5]:
        direction_emoji = "🔴" if item.get("direction") == "up" else "🔵" if item.get("direction") == "down" else "🟡"
        focus_sectors = item.get("kr_sector_bull", []) if item.get("direction") == "up" else item.get("kr_sector_bear", [])
        focus_candidates = item.get("kr_stock_candidates_long", []) if item.get("direction") == "up" else item.get("kr_stock_candidates_short", [])
        cand_names = "/".join([str(v.get("name", "") or "") for v in list(focus_candidates or [])[:3]])
        lines.append(f"{direction_emoji} {item.get('event_name','')} | {_scenario_direction_label(item.get('direction','neutral'))}")
        lines.append(f"  원인: {str(item.get('cause','') or '')[:52]}")
        if focus_sectors:
            lines.append(f"  한국섹터: {', '.join(list(focus_sectors)[:3])}")
        if cand_names:
            lines.append(f"  후보: {cand_names}")
    return "\n".join(lines)


def _format_overnight_watchlist_block() -> str:
    """장전 브리핑용 야간 워치리스트 블록 생성"""
    if not _overnight_watchlist:
        return ""
    try:
        lines = ["🌙 <b>야간 시나리오 상방 후보</b>"]
        by_event: dict = {}
        for c, v in _overnight_watchlist.items():
            ev = v.get("event", "기타")
            by_event.setdefault(ev, []).append((c, v))
        for ev, items in list(by_event.items())[:4]:
            kws = items[0][1].get("keywords", [])[:3]
            cause = str(items[0][1].get("cause", "") or "")[:32]
            lines.append(f"  📌 <b>{ev}</b>  ({', '.join(kws)})")
            if cause:
                lines.append(f"    - {cause}")
            for c, v in items[:4]:
                lines.append(f"    • {v['name']} <code>{c}</code>")
        return "\n".join(lines)
    except Exception as e:
        _swallow_exception(e)
        return ""
def _default_market_flow_state() -> dict:
    return {"themes": {}, "updated_ts": 0.0}
def _prune_market_flow_state(state: dict | None) -> dict:
    raw = state if isinstance(state, dict) else {}
    cutoff_ts = time.time() - max(1, int(MARKET_FLOW_KEEP_HOURS or 72)) * 3600
    active = {}
    for theme_key, rec in (raw.get("themes") or {}).items():
        if not isinstance(rec, dict):
            continue
        theme_name = str(rec.get("theme") or rec.get("theme_key") or theme_key or "").strip()
        updated_ts = float(rec.get("updated_ts", 0) or 0)
        if _is_generic_sector_theme(theme_name) or updated_ts < cutoff_ts:
            continue
        active[theme_name] = {
            "theme": theme_name,
            "theme_key": str(rec.get("theme_key") or theme_name),
            "source": str(rec.get("source") or ""),
            "stage": str(rec.get("stage") or "event_watch"),
            "flow_score": int(rec.get("flow_score", 0) or 0),
            "leader_code": normalize_stock_code(rec.get("leader_code") or ""),
            "leader_name": str(rec.get("leader_name") or ""),
            "leader_change": round(safe_float(rec.get("leader_change", 0.0), 0.0), 2),
            "breadth_ratio": round(safe_float(rec.get("breadth_ratio", 0.0), 0.0), 4),
            "mention_count": int(rec.get("mention_count", 0) or 0),
            "headline": str(rec.get("headline") or ""),
            "quiet_codes": list(rec.get("quiet_codes") or [])[:6],
            "quiet_score": int(rec.get("quiet_score", 0) or 0),
            "quiet_summary": str(rec.get("quiet_summary") or ""),
            "bid_ask_ratio": round(safe_float(rec.get("bid_ask_ratio", 0.0), 0.0), 3),
            "trade_strength": round(safe_float(rec.get("trade_strength", 0.0), 0.0), 2),
            "foreign_net": safe_int(rec.get("foreign_net", 0), 0),
            "institution_net": safe_int(rec.get("institution_net", 0), 0),
            "updated_ts": updated_ts,
            "first_seen_ts": float(rec.get("first_seen_ts", updated_ts) or updated_ts),
            "market": str(rec.get("market") or "KRX"),
        }
    latest_ts = max([float(v.get("updated_ts", 0) or 0) for v in active.values()] + [0.0])
    return {"themes": active, "updated_ts": latest_ts}
def _save_market_flow_state() -> None:
    global _market_flow_state
    _market_flow_state = _prune_market_flow_state(_market_flow_state)
    _write_state_json(MARKET_FLOW_STATE_FILE, _market_flow_state)
def _load_market_flow_state() -> None:
    global _market_flow_state
    raw = _read_state_json(MARKET_FLOW_STATE_FILE, _default_market_flow_state())
    _market_flow_state = _prune_market_flow_state(raw)
    if raw != _market_flow_state:
        _save_market_flow_state()
def _collect_market_flow_theme_members(theme_name: str, seed_code: str = "", seed_name: str = "", max_members: int | None = None) -> tuple[str, list[tuple[str, str]]]:
    theme_name = str(theme_name or "").strip()
    max_members = max(1, int(max_members or MARKET_FLOW_MAX_MEMBERS or 1))
    members: list[tuple[str, str]] = []
    seen: set[str] = set()
    if seed_code:
        members.append((seed_code, seed_name or _resolve_stock_name(seed_code, seed_name)))
        seen.add(seed_code)
        try:
            resolved_theme, peers, _ = get_theme_sector_stocks(seed_code)
            if _is_generic_sector_theme(theme_name) and not _is_generic_sector_theme(resolved_theme):
                theme_name = resolved_theme
            for peer_code, peer_name in list(peers or [])[:max_members]:
                peer_code = normalize_stock_code(peer_code)
                if not peer_code or peer_code in seen:
                    continue
                seen.add(peer_code)
                members.append((peer_code, peer_name))
                if len(members) >= max_members:
                    break
        except Exception as e:
            _swallow_exception(e)
    theme_info = None
    if theme_name in THEME_MAP:
        theme_info = THEME_MAP.get(theme_name)
    else:
        for tk, ti in THEME_MAP.items():
            if theme_name == tk or theme_name in list(ti.get("sectors", []) or []):
                theme_info = ti
                break
    if isinstance(theme_info, dict):
        for c, n in list(theme_info.get("stocks", []) or [])[:max_members]:
            c = normalize_stock_code(c)
            if not c or c in seen:
                continue
            seen.add(c)
            members.append((c, n))
            if len(members) >= max_members:
                break
    return theme_name, members[:max_members]
def _build_market_flow_theme_record(theme_name: str, seed_code: str = "", seed_name: str = "", headlines: list[str] | None = None, source: str = "", market: str = "") -> dict:
    theme_name, members = _collect_market_flow_theme_members(theme_name, seed_code=seed_code, seed_name=seed_name)
    if _is_generic_sector_theme(theme_name) or not members:
        return {}
    market_basis = "NXT" if str(market or "").upper() == "NXT" else "KRX"
    quotes = []
    for member_code, member_name in members[:max(1, int(MARKET_FLOW_MAX_MEMBERS or 1))]:
        try:
            q = _get_live_quote_for_signal({"code": member_code, "name": member_name, "market": market_basis if market_basis == "NXT" else ""})
        except Exception as e:
            _swallow_exception(e)
            q = {}
        if not isinstance(q, dict) or not q.get("price"):
            continue
        quotes.append({
            "code": member_code,
            "name": _resolve_stock_name(member_code, member_name, q),
            "change_rate": round(safe_float(q.get("change_rate", 0.0), 0.0), 2),
            "volume_ratio": round(safe_float(q.get("volume_ratio", 0.0), 0.0), 2),
        })
        time.sleep(0.02)
    if not quotes:
        return {}
    quotes.sort(key=lambda x: (safe_float(x.get("change_rate", 0.0), 0.0), safe_float(x.get("volume_ratio", 0.0), 0.0)), reverse=True)
    leader = quotes[0]
    risers = [q for q in quotes if safe_float(q.get("change_rate", 0.0), 0.0) >= 2.0]
    quiet = [q for q in quotes if 0.4 <= safe_float(q.get("change_rate", 0.0), 0.0) < 4.2 and 0.6 <= safe_float(q.get("volume_ratio", 0.0), 0.0) <= 6.0]
    breadth_ratio = len(risers) / max(1, len(quotes))
    mention_count = len(list(headlines or []))
    leader_change = safe_float(leader.get("change_rate", 0.0), 0.0)
    stage = "event_watch"
    if leader_change >= 18.0 and breadth_ratio >= 0.34:
        stage = "leader_ignition"
    elif leader_change >= 8.0 and quiet:
        stage = "quiet_rotation"
    elif quiet and mention_count >= 1:
        stage = "quiet_absorption"
    flow_score = int(min(100, mention_count * 8 + max(0, round(leader_change * 1.5)) + len(risers) * 4 + len(quiet) * 3 + (6 if seed_code else 0)))
    now_ts = time.time()
    return {
        "theme": theme_name,
        "theme_key": theme_name,
        "source": str(source or ""),
        "stage": stage,
        "flow_score": flow_score,
        "leader_code": normalize_stock_code(leader.get("code", "")),
        "leader_name": str(leader.get("name", "")),
        "leader_change": round(leader_change, 2),
        "breadth_ratio": round(breadth_ratio, 4),
        "mention_count": mention_count,
        "headline": str((list(headlines or [""]) or [""])[0])[:90],
        "quiet_codes": [normalize_stock_code(q.get("code", "")) for q in quiet[:6] if normalize_stock_code(q.get("code", ""))],
        "updated_ts": now_ts,
        "first_seen_ts": now_ts,
        "market": market_basis,
    }
def _market_flow_stage_rank(stage: str) -> int:
    return {
        "event_watch": 0,
        "quiet_absorption": 1,
        "quiet_rotation": 2,
        "leader_ignition": 3,
    }.get(str(stage or "event_watch"), 0)
def _upsert_market_flow_record(record: dict) -> bool:
    global _market_flow_state
    if not isinstance(record, dict):
        return False
    theme_name = str(record.get("theme") or record.get("theme_key") or "").strip()
    if _is_generic_sector_theme(theme_name) or int(record.get("flow_score", 0) or 0) < int(MARKET_FLOW_MIN_SCORE or 0):
        return False
    state = _market_flow_state if isinstance(_market_flow_state, dict) else _default_market_flow_state()
    themes = state.setdefault("themes", {})
    prev = themes.get(theme_name) if isinstance(themes.get(theme_name), dict) else {}
    merged = dict(prev)
    merged.update(record)
    prev_stage = str(prev.get("stage") or "event_watch")
    new_stage = str(record.get("stage") or prev_stage or "event_watch")
    if _market_flow_stage_rank(prev_stage) > _market_flow_stage_rank(new_stage):
        merged["stage"] = prev_stage
    merged["flow_score"] = max(int(prev.get("flow_score", 0) or 0), int(record.get("flow_score", 0) or 0))
    merged["first_seen_ts"] = float(prev.get("first_seen_ts", record.get("first_seen_ts", time.time())) or record.get("first_seen_ts", time.time()))
    themes[theme_name] = merged
    state["updated_ts"] = float(record.get("updated_ts", time.time()) or time.time())
    _market_flow_state = _prune_market_flow_state(state)
    return True
def _refresh_market_flow_state_from_headlines(headlines: list[str] | None = None, source: str = "news") -> int:
    if not headlines:
        return 0
    updated = 0
    for theme_key, theme_info in THEME_MAP.items():
        matched = [
            h for h in list(headlines or [])
            if theme_key in h
            or any(sec in h for sec in list(theme_info.get("sectors", []) or [])[:4])
            or any(name in h for _c, name in list(theme_info.get("stocks", []) or [])[:4])
        ]
        if not matched:
            continue
        stocks = list(theme_info.get("stocks", []) or [])
        seed_code, seed_name = stocks[0] if stocks else ("", "")
        rec = _build_market_flow_theme_record(theme_key, seed_code=normalize_stock_code(seed_code), seed_name=str(seed_name or ""), headlines=matched, source=source)
        if _upsert_market_flow_record(rec):
            updated += 1
    if updated:
        _save_market_flow_state()
    return updated
def _register_market_flow_seed(seed: dict, source: str = "price_seed") -> bool:
    if not isinstance(seed, dict):
        return False
    seed_code = normalize_stock_code(seed.get("code", ""))
    seed_name = _resolve_stock_name(seed_code, seed.get("name", ""))
    if not seed_code or not is_trade_candidate_name(seed_name):
        return False
    theme_name, _, _ = get_theme_sector_stocks(seed_code)
    rec = _build_market_flow_theme_record(theme_name, seed_code=seed_code, seed_name=seed_name, source=source, market=seed.get("market", ""))
    if not _upsert_market_flow_record(rec):
        return False
    _save_market_flow_state()
    return True
def _score_quiet_absorption_context(seed: dict) -> dict:
    seed = seed if isinstance(seed, dict) else {}
    code = normalize_stock_code(seed.get("code", ""))
    market = "NXT" if str(seed.get("market", "")).upper() == "NXT" else "KRX"
    price = safe_int(seed.get("price", 0), 0)
    change_rate = safe_float(seed.get("change_rate", 0.0), 0.0)
    volume_ratio = safe_float(seed.get("volume_ratio", 0.0), 0.0)
    if not code or price <= 0:
        return {}
    if change_rate < MARKET_FLOW_QUIET_MIN_CHANGE or change_rate > MARKET_FLOW_QUIET_MAX_CHANGE:
        return {}
    if volume_ratio < MARKET_FLOW_QUIET_MIN_VOLUME_RATIO or volume_ratio > MARKET_FLOW_QUIET_MAX_VOLUME_RATIO:
        return {}
    inv = _get_quiet_investor_trend(code, market=market)
    orderbook = _get_quiet_orderbook_snapshot(code, market=market)
    trade = _get_quiet_trade_snapshot(code, market=market)
    exec_m = get_execution_speed_metrics(code, current_price=price) or {}
    foreign_net = safe_int(inv.get("foreign_net", 0), 0)
    institution_net = safe_int(inv.get("institution_net", 0), 0)
    investor_total = foreign_net + institution_net
    bid_ask_ratio = safe_float(orderbook.get("bid_ask_ratio", 0.0), 0.0)
    support_levels = safe_int(orderbook.get("support_levels", 0), 0)
    trade_strength = safe_float(trade.get("strength", 0.0), 0.0)
    buy_ratio = safe_float(trade.get("buy_ratio", 0.0), 0.0)
    exec_score = safe_int(exec_m.get("execution_speed_score", 0), 0)
    dip_score = safe_int(exec_m.get("dip_resilience_score", 0), 0)
    score = 0
    reasons: list[str] = []
    if change_rate >= 0.8:
        score += 2
        reasons.append(f"시세 {change_rate:+.1f}%")
    if change_rate >= 1.8:
        score += 1
    if 0.8 <= volume_ratio <= 4.8:
        score += 2
        reasons.append(f"거래량 {volume_ratio:.1f}배")
    elif volume_ratio > 4.8:
        score += 1
    if investor_total > 0:
        score += 2
        reasons.append("외인·기관 순유입")
    if foreign_net > 0 and institution_net > 0:
        score += 1
    if bid_ask_ratio >= 1.2:
        score += 2
        reasons.append(f"호가 {bid_ask_ratio:.1f}배")
    if bid_ask_ratio >= 1.6:
        score += 1
    if support_levels >= 6:
        score += 1
    if trade_strength >= 105:
        score += 2
        reasons.append(f"체결강도 {trade_strength:.0f}")
    if trade_strength >= 115:
        score += 1
    if buy_ratio >= 54.0:
        score += 1
    if exec_score >= 48:
        score += 2
        reasons.append(f"체결속도 {exec_score}점")
    if exec_score >= 60:
        score += 1
    if dip_score >= 55:
        score += 1
    summary = " / ".join(reasons[:5])
    return {
        "score": int(score),
        "summary": summary,
        "foreign_net": foreign_net,
        "institution_net": institution_net,
        "investor_total": investor_total,
        "bid_ask_ratio": round(bid_ask_ratio, 3),
        "support_levels": support_levels,
        "trade_strength": round(trade_strength, 2),
        "buy_ratio": round(buy_ratio, 1),
        "execution_speed_score": exec_score,
        "dip_resilience_score": dip_score,
    }
def _build_quiet_absorption_record(seed: dict, source: str = "quiet_absorption") -> dict:
    seed = seed if isinstance(seed, dict) else {}
    code = normalize_stock_code(seed.get("code", ""))
    name = _resolve_stock_name(code, seed.get("name", ""), seed)
    market = "NXT" if str(seed.get("market", "")).upper() == "NXT" else "KRX"
    if not code or not is_trade_candidate_name(name):
        return {}
    theme_name, peers, _ = get_theme_sector_stocks(code)
    if _is_generic_sector_theme(theme_name):
        return {}
    quiet_ctx = _score_quiet_absorption_context(seed)
    quiet_score = int(quiet_ctx.get("score", 0) or 0)
    if quiet_score < int(MARKET_FLOW_QUIET_MIN_SCORE or 0):
        return {}
    now_ts = time.time()
    member_count = max(2, min(len(list(peers or [])) + 1, int(MARKET_FLOW_MAX_MEMBERS or 6)))
    summary = str(quiet_ctx.get("summary", "") or "조용한 선매집 징후")
    return {
        "theme": theme_name,
        "theme_key": theme_name,
        "source": str(source or "quiet_absorption"),
        "stage": "quiet_absorption",
        "flow_score": max(int(MARKET_FLOW_MIN_SCORE or 0) + 2, int(MARKET_FLOW_MIN_SCORE or 0) + quiet_score - 1),
        "leader_code": code,
        "leader_name": name,
        "leader_change": round(safe_float(seed.get("change_rate", 0.0), 0.0), 2),
        "breadth_ratio": round(1.0 / max(member_count, 2), 4),
        "mention_count": 0,
        "headline": summary[:90],
        "quiet_codes": [code],
        "quiet_score": quiet_score,
        "quiet_summary": summary[:120],
        "bid_ask_ratio": round(safe_float(quiet_ctx.get("bid_ask_ratio", 0.0), 0.0), 3),
        "trade_strength": round(safe_float(quiet_ctx.get("trade_strength", 0.0), 0.0), 2),
        "foreign_net": safe_int(quiet_ctx.get("foreign_net", 0), 0),
        "institution_net": safe_int(quiet_ctx.get("institution_net", 0), 0),
        "updated_ts": now_ts,
        "first_seen_ts": now_ts,
        "market": market,
    }
def _register_quiet_absorption_seed(seed: dict, source: str = "quiet_absorption") -> bool:
    rec = _build_quiet_absorption_record(seed, source=source)
    if not rec:
        return False
    if not _upsert_market_flow_record(rec):
        return False
    _save_market_flow_state()
    return True
def _get_market_flow_hint(code: str, name: str = "", market: str = "", change_rate: float = 0.0, volume_ratio: float = 0.0) -> dict:
    code = normalize_stock_code(code)
    if not code or not isinstance(_market_flow_state, dict):
        return {}
    theme_name, _, _ = get_theme_sector_stocks(code)
    if _is_generic_sector_theme(theme_name):
        return {}
    rec = ((_market_flow_state.get("themes") or {}) if isinstance(_market_flow_state, dict) else {}).get(theme_name)
    if not isinstance(rec, dict):
        return {}
    leader_code = normalize_stock_code(rec.get("leader_code") or "")
    leader_name = str(rec.get("leader_name") or "")
    stage = str(rec.get("stage") or "event_watch")
    cr = safe_float(change_rate, 0.0)
    vr = safe_float(volume_ratio, 0.0)
    breadth_ratio = safe_float(rec.get("breadth_ratio", 0.0), 0.0)
    mention_count = int(rec.get("mention_count", 0) or 0)
    quiet_score = int(rec.get("quiet_score", 0) or 0)
    quiet_summary = str(rec.get("quiet_summary", rec.get("headline", "")) or "").strip()
    bonus = 0
    if stage == "quiet_absorption" and code == leader_code and 0.0 <= cr <= MARKET_FLOW_QUIET_MAX_CHANGE and 0.0 <= vr <= max(MARKET_FLOW_QUIET_MAX_VOLUME_RATIO, 7.0):
        bonus = max(3, MARKET_FLOW_FOLLOW_BONUS - 1)
    elif stage == "quiet_absorption" and code != leader_code and 0.0 <= cr < 4.5 and 0.5 <= vr <= 4.5:
        bonus = MARKET_FLOW_FOLLOW_BONUS + 1
    elif stage == "quiet_rotation" and code != leader_code and (cr >= 1.2 or vr >= 1.4):
        bonus = MARKET_FLOW_FOLLOW_BONUS
    elif stage == "leader_ignition" and code != leader_code and (cr >= 2.0 or vr >= 1.8):
        bonus = max(3, MARKET_FLOW_FOLLOW_BONUS - 1)
    elif stage == "leader_ignition" and code == leader_code:
        bonus = 2
    if mention_count >= 2:
        bonus += 1
    if breadth_ratio >= 0.34:
        bonus += 1
    if quiet_score >= max(0, int(MARKET_FLOW_QUIET_MIN_SCORE or 0) + 2) and stage == "quiet_absorption":
        bonus += 1
    bonus = int(min(bonus, MARKET_FLOW_EVENT_BONUS + MARKET_FLOW_FOLLOW_BONUS))
    if bonus <= 0:
        return {}
    stage_label = {
        "leader_ignition": "리더 점화",
        "quiet_rotation": "후속 순환",
        "quiet_absorption": "조용한 선매집",
        "event_watch": "이슈 감시",
    }.get(stage, stage)
    return {
        "theme": theme_name,
        "leader_name": leader_name or _resolve_stock_name(leader_code, leader_name),
        "leader_code": leader_code,
        "stage": stage,
        "stage_label": stage_label,
        "bonus": bonus,
        "headline": str(rec.get("headline") or ""),
        "flow_score": int(rec.get("flow_score", 0) or 0),
        "quiet_score": quiet_score,
        "summary": quiet_summary,
        "reason": f"시장 자금 이동 [{theme_name}] {stage_label}",
    }
def _default_sector_leader_follow_state() -> dict:
    return {"active": {}}
def _prune_sector_leader_follow_state(state: dict | None) -> dict:
    active = {}
    if isinstance(state, dict):
        active = state.get("active") if isinstance(state.get("active"), dict) else {}
    now_ts = time.time()
    keep_sec = max(1, int(SECTOR_LEADER_FOLLOW_KEEP_DAYS or 1)) * 86400
    pruned = {}
    for raw_code, rec in active.items():
        if not isinstance(rec, dict):
            continue
        code = normalize_stock_code(raw_code or rec.get("code"))
        if not code:
            continue
        try:
            expires_ts = float(rec.get("expires_ts", 0) or 0)
            last_seen_ts = float(rec.get("last_seen_ts", rec.get("registered_ts", 0)) or 0)
        except Exception as e:
            _swallow_exception(e)
            expires_ts = 0.0
            last_seen_ts = 0.0
        if expires_ts and expires_ts < now_ts:
            continue
        if last_seen_ts and now_ts - last_seen_ts > keep_sec:
            continue
        item = dict(rec)
        item["code"] = code
        item["name"] = _resolve_stock_name(code, rec.get("name", ""))
        item["theme"] = str(rec.get("theme", "") or "")
        item["leader_code"] = normalize_stock_code(rec.get("leader_code", ""))
        item["leader_name"] = str(rec.get("leader_name", "") or "")
        item["leader_change"] = round(float(rec.get("leader_change", 0.0) or 0.0), 2)
        item["leader_volume_ratio"] = round(float(rec.get("leader_volume_ratio", 0.0) or 0.0), 2)
        item["registered_ts"] = float(rec.get("registered_ts", last_seen_ts or now_ts) or (last_seen_ts or now_ts))
        item["last_seen_ts"] = float(last_seen_ts or item["registered_ts"])
        item["expires_ts"] = float(expires_ts or (item["registered_ts"] + keep_sec))
        item["seed_signal"] = str(rec.get("seed_signal", "SURGE") or "SURGE")
        item["peer_count"] = max(1, int(rec.get("peer_count", 1) or 1))
        market = str(rec.get("market", "") or "").upper()
        item["market"] = "NXT" if market == "NXT" else "KRX"
        pruned[code] = item
    return {"active": pruned}
def _save_sector_leader_follow_state() -> None:
    global _sector_leader_follow_watch
    _sector_leader_follow_watch = _prune_sector_leader_follow_state(_sector_leader_follow_watch)
    _write_state_json(SECTOR_LEADER_FOLLOW_FILE, _sector_leader_follow_watch)
def _load_sector_leader_follow_state() -> None:
    global _sector_leader_follow_watch
    raw = _read_state_json(SECTOR_LEADER_FOLLOW_FILE, _default_sector_leader_follow_state())
    _sector_leader_follow_watch = _prune_sector_leader_follow_state(raw)
    if raw != _sector_leader_follow_watch:
        _save_sector_leader_follow_state()
    active_cnt = len((_sector_leader_follow_watch.get("active") or {})) if isinstance(_sector_leader_follow_watch, dict) else 0
    if active_cnt:
        _log_info_msg(f"📂 섹터 대장 후속 강제감시 {active_cnt}개 복원")
def _get_sector_leader_follow_entry(code: str, market: str = "") -> dict:
    active = (_sector_leader_follow_watch.get("active") or {}) if isinstance(_sector_leader_follow_watch, dict) else {}
    rec = active.get(normalize_stock_code(code or ""))
    if not isinstance(rec, dict):
        return {}
    rec_market = str(rec.get("market", "") or "").upper()
    req_market = str(market or "").upper()
    if req_market == "NXT" and rec_market not in ("", "NXT"):
        return {}
    return rec
def _register_sector_leader_follow_seed(seed: dict) -> int:
    global _sector_leader_follow_watch
    if not isinstance(seed, dict):
        return 0
    seed_code = normalize_stock_code(seed.get("code", ""))
    seed_name = _resolve_stock_name(seed_code, seed.get("name", ""))
    if not seed_code or not is_trade_candidate_name(seed_name):
        return 0
    seed_change = safe_float(seed.get("change_rate", 0.0), 0.0)
    seed_vol = safe_float(seed.get("volume_ratio", 0.0), 0.0)
    upper_like = seed_change >= 29.0
    if not (upper_like or (seed_change >= SECTOR_LEADER_SEED_MIN_CHANGE and seed_vol >= SECTOR_LEADER_SEED_MIN_VOLUME)):
        return 0
    market = "NXT" if str(seed.get("market", "") or "").upper() == "NXT" else "KRX"
    touch_key = f"{datetime.now().strftime('%Y%m%d')}_{market}_{seed_code}"
    last_touch = float(_sector_leader_follow_seed_touched.get(touch_key, 0) or 0)
    if time.time() - last_touch < 1800:  # v163.14 [#4]: 600→1800초 (매 30분 재등록 로그 노이즈 제거)
        return 0
    theme_name, peers, _ = get_theme_sector_stocks(seed_code)
    if _is_generic_sector_theme(theme_name) or not peers:
        return 0
    now_ts = time.time()
    expires_ts = now_ts + max(2, int(SECTOR_LEADER_FOLLOW_KEEP_DAYS or 3)) * 86400
    active = (_sector_leader_follow_watch.get("active") or {}) if isinstance(_sector_leader_follow_watch, dict) else {}
    added = 0
    for peer_code, peer_name in list(peers or [])[:max(1, int(SECTOR_LEADER_FOLLOW_MAX_PEERS or 1))]:
        peer_code = normalize_stock_code(peer_code)
        if not peer_code or peer_code == seed_code:
            continue
        prev = active.get(peer_code) if isinstance(active.get(peer_code), dict) else {}
        if prev and prev.get("leader_code") == seed_code and now_ts - float(prev.get("last_seen_ts", 0) or 0) < 600:
            continue
        active[peer_code] = {
            "code": peer_code,
            "name": _resolve_stock_name(peer_code, peer_name),
            "theme": theme_name,
            "leader_code": seed_code,
            "leader_name": seed_name,
            "leader_change": round(seed_change, 2),
            "leader_volume_ratio": round(seed_vol, 2),
            "registered_ts": float(prev.get("registered_ts", now_ts) or now_ts),
            "last_seen_ts": now_ts,
            "expires_ts": max(float(prev.get("expires_ts", 0) or 0), expires_ts),
            "market": market,
            "seed_signal": "UPPER_LIMIT" if upper_like else "SURGE",
            "peer_count": max(1, len(peers or [])),
        }
        added += 1
    _sector_leader_follow_watch = _prune_sector_leader_follow_state({"active": active})
    if added:
        _save_sector_leader_follow_state()
        _register_market_flow_seed(seed, source="sector_leader_follow")
        _sector_leader_follow_seed_touched[touch_key] = now_ts
        _log_info_msg(f"🧭 섹터 대장 후속 강제감시 등록: {seed_name} [{theme_name}] → {added}개")
    return added
def _collect_sector_leader_follow_candidates(existing_codes: set | None = None, limit_total: int | None = None) -> list:
    # v161.31: active 원본 대신 얕은 복사본으로 순회 — 순회 중 외부에서 키 추가돼도 RuntimeError 방지
    active = (_sector_leader_follow_watch.get("active") or {}) if isinstance(_sector_leader_follow_watch, dict) else {}
    if not active:
        return []
    active_snapshot = dict(active)  # 순회용 스냅샷 (원본과 분리)
    existing = {normalize_stock_code(c) for c in (existing_codes or set()) if c}
    limit_total = max(1, int(limit_total or SECTOR_LEADER_FOLLOW_SCAN_LIMIT or 1))
    rows = []
    ts_updates: dict = {}  # 순회 완료 후 일괄 반영
    ordered = sorted(active_snapshot.values(), key=lambda rec: (float((rec or {}).get("leader_change", 0.0) or 0.0), float((rec or {}).get("registered_ts", 0.0) or 0.0)), reverse=True)
    for rec in ordered:
        if len(rows) >= limit_total:
            break
        code = normalize_stock_code((rec or {}).get("code", ""))
        if not code or code in existing:
            continue
        market = str((rec or {}).get("market", "") or "").upper()
        try:
            q = _get_live_quote_for_signal({"code": code, "name": rec.get("name", ""), "market": market if market == "NXT" else ""})
        except Exception as e:
            _swallow_exception(e)
            q = {}
        if not isinstance(q, dict) or not q.get("price"):
            continue
        chg = safe_float(q.get("change_rate", 0.0), 0.0)
        vol = safe_float(q.get("volume_ratio", 0.0), 0.0)
        if chg < SECTOR_LEADER_FOLLOW_MIN_CHANGE and vol < SECTOR_LEADER_FOLLOW_MIN_VOLUME:
            continue
        cand = dict(q)
        cand["code"] = code
        cand["name"] = _resolve_stock_name(code, rec.get("name", ""), q)
        cand["desc"] = f"sector_leader_follow[{rec.get('theme', '기타')}]"
        cand["_sector_leader_follow"] = dict(rec)
        cand["_force_news_recheck"] = True  # v161.31: 상승 중 재료 즉시 재평가 강제
        if market == "NXT":
            cand["market"] = "NXT"
        rows.append(cand)
        existing.add(code)
        ts_updates[code] = time.time()  # 순회 완료 후 일괄 반영
        time.sleep(0.03)
    # 순회 완료 후 last_seen_ts 일괄 반영 (순회 중 dict 수정 방지)
    if ts_updates:
        try:
            live_active = (_sector_leader_follow_watch.get("active") or {}) if isinstance(_sector_leader_follow_watch, dict) else {}
            for code, ts in ts_updates.items():
                if code in live_active and isinstance(live_active[code], dict):
                    live_active[code]["last_seen_ts"] = ts
            _save_sector_leader_follow_state()
        except Exception as e:
            _swallow_exception(e)
    return rows
# ============================================================
# 🏗️ 실질 섹터 분류 (4레이어 가중 스코어)
# ============================================================
_dart_related_cache: dict = {}   # code → {related: [...], ts}
_real_sector_cache:  dict = {}   # code → {sector_id, score, peers, ts}
def get_dart_related_stocks(code: str) -> list:
    """
    DART 지분공시에서 모자/관계회사 종목 조회.
    반환: [(code, name, reason)] 
    예: [("005930", "삼성전자", "최대주주")]
    캐시 24시간 (지분관계는 자주 안 바뀜)
    """
    if not DART_API_KEY:
        return []
    cached = _dart_related_cache.get(code)
    if cached and time.time() - cached["ts"] < 86400:
        return cached["related"]
    try:
        # DART 기업개황에서 corp_code 조회
        url = "https://opendart.fss.or.kr/api/company.json"
        resp = _session.get(url, params={"crtfc_key": DART_API_KEY, "stock_code": code}, timeout=10)
        if resp.status_code != 200:
            _dart_related_cache[code] = {"related": [], "ts": time.time()}
            return []
        corp_code = resp.json().get("corp_code", "")
        if not corp_code:
            _dart_related_cache[code] = {"related": [], "ts": time.time()}
            return []
        # 최대주주 현황 조회 (대표적 지분 공시)
        url2  = "https://opendart.fss.or.kr/api/hyslrSttus.json"
        year  = datetime.now().strftime("%Y")
        resp2 = _session.get(url2, params={
            "crtfc_key": DART_API_KEY, "corp_code": corp_code,
            "bsns_year": year, "reprt_code": "11011"  # 사업보고서
        }, timeout=10)
        items = resp2.json().get("list", []) if resp2.status_code == 200 else []
        related = []
        for item in items:
            relate_stock = item.get("stock_code", "").strip()
            relate_name  = item.get("nm", "").strip()
            relate_type  = item.get("relate", "").strip()
            if relate_stock and relate_stock != code:
                related.append((relate_stock, relate_name, relate_type or "관계회사"))
        _dart_related_cache[code] = {"related": related[:10], "ts": time.time()}
        return related[:10]
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        _dart_related_cache[code] = {"related": [], "ts": time.time()}
        return []
def calc_real_sector_score(code_a: str, code_b: str,
                            name_a: str = "", name_b: str = "") -> dict:
    """
    두 종목 간 실질 섹터 연관성 스코어 (0~100).
    4가지 레이어 가중 합산:
      ① 주가 상관계수 0.7↑  → 40점
      ② 당일 동반 상승 중   → 30점
      ③ DART 지분 연결      → 20점
      ④ 뉴스 동시 언급      → 10점
    반환: {"score": int, "layers": dict, "label": str}
    """
    score   = 0
    layers  = {}
    # ① 주가 상관계수 (60일)
    try:
        corr = calc_price_correlation(code_a, code_b)
        if corr >= 0.7:
            pts = int(40 * min((corr - 0.7) / 0.3 + 0.5, 1.0))  # 0.7→20점, 1.0→40점
            score += pts
            layers["상관계수"] = f"{corr:.2f} (+{pts}점)"
        elif corr >= 0.5:
            score += 10
            layers["상관계수"] = f"{corr:.2f} (+10점)"
    except Exception as e:
        _swallow_exception(e)
    # ② 당일 동반 상승 (실시간)
    try:
        pa = get_stock_price(code_a)
        pb = get_stock_price(code_b)
        cr_a = pa.get("change_rate", 0)
        cr_b = pb.get("change_rate", 0)
        if cr_a >= 2.0 and cr_b >= 2.0:
            score += 30
            layers["동반상승"] = f"+{cr_a:.1f}%/+{cr_b:.1f}% (+30점)"
        elif cr_a >= 1.0 and cr_b >= 1.0:
            score += 15
            layers["동반상승"] = f"+{cr_a:.1f}%/+{cr_b:.1f}% (+15점)"
    except Exception as e:
        _swallow_exception(e)
    # ③ DART 지분 관계
    try:
        related = get_dart_related_stocks(code_a)
        dart_hit = next((r for r in related if r[0] == code_b), None)
        if dart_hit:
            score += 20
            layers["DART지분"] = f"{dart_hit[2]} (+20점)"
    except Exception as e:
        _swallow_exception(e)
    # ④ 뉴스 동시 언급
    try:
        cooccur_a = _news_cooccur.get(code_a, {}).get("peers", {})
        if code_b in cooccur_a and cooccur_a[code_b] >= 2:
            score += 10
            layers["뉴스동시언급"] = f"{cooccur_a[code_b]}회 (+10점)"
    except Exception as e:
        _swallow_exception(e)
    if score >= 60:   label = "🔵 강한 연관"
    elif score >= 40: label = "🟡 보통 연관"
    elif score >= 20: label = "🟡 약한 연관"
    else:             label = "연관 없음"
    return {"score": score, "layers": layers, "label": label}
def get_theme_sector_stocks(code: str) -> tuple:
    """
    종목 코드 → (테마명, [(peer_code, peer_name)]) 반환
    우선순위:
      1. 하드코딩 THEME_MAP
      2. 동적 테마맵
      3. KIS 업종코드 / 공용 업종 fallback
    """
    peers_all = {}
    theme_name = "기타업종"
    for tk, ti in THEME_MAP.items():
        if code in [c for c, _ in ti["stocks"]]:
            theme_name = tk
            for c, n in ti["stocks"]:
                if c != code:
                    peers_all[c] = (n, "테마", tk)
            break
    for tk, ti in _dynamic_theme_map.items():
        if code in [c for c, _ in ti["stocks"]]:
            if theme_name == "기타업종":
                theme_name = ti.get("desc", tk)
            for c, n in ti["stocks"]:
                if c != code and c not in peers_all:
                    peers_all[c] = (n, "동적테마", ti.get("desc", tk))
            break
    base_ctx = _load_sector_stock_base_context(code) if code else {}
    kis_sector_name = str((base_ctx or {}).get("bstp_name", "") or "").strip()
    public_meta = _get_public_stock_meta(code)
    public_sector = _normalize_public_sector_name((public_meta or {}).get("sector", ""))
    if theme_name == "기타업종" and kis_sector_name not in ("", "동일업종", "업종미상", "미분류", "unknown"):
        theme_name = kis_sector_name
    if _is_generic_sector_theme(theme_name) and public_sector not in ("", "기타업종", "기타"):
        theme_name = public_sector
    kis_peers = get_sector_stocks_from_kis(code)
    for c, n in kis_peers:
        if c not in peers_all:
            peers_all[c] = (n, "업종코드", kis_sector_name or theme_name)
    if public_sector not in ("", "기타업종", "기타"):
        for c, n in _collect_public_sector_peers(code, public_sector):
            if c not in peers_all:
                peers_all[c] = (n, "공용업종", public_sector)
    peers = [(c, n) for c, (n, _src, _rsn) in peers_all.items()]
    return theme_name, peers, peers_all
# ════════════════════════════════════════════════════════════
# 🌍 J: 해외 선물→섹터 연동 (v39.0)
# ════════════════════════════════════════════════════════════
# 원자재/금리 변동이 직접 영향을 주는 한국 섹터 매핑
COMMODITY_SECTOR_MAP = {
    # (지표키, 임계값, 방향) → [(섹터명, 보정점수)]
    # 유가 급등 → 에너지/석유화학 호재, 항공/해운 악재
    "oil_up":    {"threshold": COMMON_THRESHOLD_3P0, "sectors": {"석유화학": +5, "에너지": +5, "정유": +5,
                                                 "항공": -4, "해운": -3, "운수": -3}},
    "oil_down":  {"threshold": -COMMON_THRESHOLD_3P0, "sectors": {"석유화학": -4, "에너지": -4,
                                                   "항공": +3, "해운": +2}},
    # 금 급등 → 안전자산 선호 = 방산/귀금속 호재, 성장주 약세
    "gold_up":   {"threshold": 1.5, "sectors": {"방산": +4, "금": +3, "귀금속": +3}},
    "gold_down": {"threshold": -1.5, "sectors": {"방산": -2}},
    # 국채 수익률 상승 → 금융 호재, 건설/성장주 악재
    "tnx_high":  {"threshold": 4.5, "sectors": {"은행": +3, "보험": +3, "금융": +3,
                                                  "건설": -3, "바이오": -3}},
    "tnx_low":   {"threshold": 3.5, "sectors": {"건설": +2, "바이오": +2,
                                                  "은행": -2}},
}
def _get_commodity_sector_adj(theme_name: str) -> int:
    """v39.0-J: 해외 선물 데이터 기반 섹터별 점수 보정."""
    if not theme_name:
        return 0
    try:
        us = _us_cache  # get_us_market_signals()의 캐시
        if not us or time.time() - us.get("ts", 0) > 7200:
            return 0
        oil_chg  = float(us.get("oil_chg", 0) or 0)
        gold_chg = float(us.get("gold_chg", 0) or 0)
        tnx      = float(us.get("tnx", 0) or 0)
        adj = 0
        theme_lower = theme_name.lower()
        # 유가
        if oil_chg >= COMMODITY_SECTOR_MAP["oil_up"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["oil_up"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif oil_chg <= COMMODITY_SECTOR_MAP["oil_down"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["oil_down"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        # 금
        if gold_chg >= COMMODITY_SECTOR_MAP["gold_up"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["gold_up"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif gold_chg <= COMMODITY_SECTOR_MAP["gold_down"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["gold_down"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        # 국채
        if tnx >= COMMODITY_SECTOR_MAP["tnx_high"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["tnx_high"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif tnx > 0 and tnx <= COMMODITY_SECTOR_MAP["tnx_low"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["tnx_low"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        return adj
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 0
def _empty_sector_momentum(theme_name: str) -> dict:
    return {"bonus": 0, "theme": theme_name, "summary": "", "rising": [], "flat": [], "detail": [], "sources": {}, "leader": None}
def _resolve_geo_sector_bias(theme_name: str) -> int:
    try:
        geo_meta = _find_geo_sector_evidence(theme_name)
        if geo_meta and not geo_meta.get("is_actionable"):
            return 0
        return int(globals().get('GEO_SECTOR_BIAS', {}).get(theme_name, 0) or 0)
    except Exception as e:
        _swallow_exception(e)
        return 0
def _collect_sector_momentum_results(peers: list, peers_all: dict) -> list:
    results = []
    for peer_code, peer_name in peers[:8]:
        try:
            cur = get_stock_price(peer_code)
            if not cur:
                continue
            safe_peer_name = _resolve_stock_name(peer_code, peer_name, cur)
            cr, vr = cur.get("change_rate", 0), cur.get("volume_ratio", 0)
            price = cur.get("price", 0)
            today_vol = cur.get("today_vol", 0)
            trade_amt = price * today_vol if price and today_vol else 0
            src, rsn = peers_all.get(peer_code, (safe_peer_name, "업종코드", ""))[1:]
            results.append({
                "code": peer_code,
                "name": safe_peer_name,
                "price": price,
                "change_rate": cr,
                "volume_ratio": vr,
                "trade_amount": trade_amt,
                "strong": cr >= 2.0 and vr >= 2.0,
                "weak": cr >= 2.0,
                "source": src,
                "reason": rsn,
            })
            time.sleep(GEO_PREWATCH_POLL_DELAY_SEC)
        except Exception as e:
            _swallow_exception(e)
    return results
def _calc_sector_momentum_score_bundle(results: list) -> dict:
    total = len(results)
    react_cnt = sum(1 for r in results if r["weak"])
    strong_cnt = sum(1 for r in results if r["strong"])
    react_ratio = react_cnt / total if total else 0.0
    avg_vr = sum(r["volume_ratio"] for r in results) / total if total else 1.0
    avg_cr = sum(r["change_rate"] for r in results) / total if total else 0.0
    sector_score = round(0.5 * min(avg_vr / COMMON_THRESHOLD_3P0, 1.0) + 0.3 * react_ratio + 0.2 * min(avg_cr / 5.0, 1.0), 2)
    bonus = (15 if react_ratio >= 1.0 else 10 if react_ratio >= 0.5 else 5 if react_cnt >= 1 else 0)
    if strong_cnt >= 2:
        bonus += 5
    if sector_score >= 0.7:
        bonus += 8
    elif sector_score >= 0.5:
        bonus += 4
    return {
        "total": total,
        "react_cnt": react_cnt,
        "strong_cnt": strong_cnt,
        "react_ratio": react_ratio,
        "sector_score": sector_score,
        "bonus": bonus,
    }
def _apply_sector_leader_scores(results: list) -> dict | None:
    if not results:
        return None
    cr_sorted = sorted(range(len(results)), key=lambda i: -results[i]["change_rate"])
    vr_sorted = sorted(range(len(results)), key=lambda i: -results[i]["volume_ratio"])
    amt_sorted = sorted(range(len(results)), key=lambda i: -results[i]["trade_amount"])
    n = len(results)
    for i, row in enumerate(results):
        cr_rank = cr_sorted.index(i) / max(n - 1, 1)
        vr_rank = vr_sorted.index(i) / max(n - 1, 1)
        amt_rank = amt_sorted.index(i) / max(n - 1, 1)
        row["leader_score"] = round(
            0.35 * (1 - cr_rank) +
            0.30 * (1 - vr_rank) +
            0.25 * (1 - amt_rank) +
            0.10 * (1.0 if row["change_rate"] > 0 and row["price"] > 0 else 0),
            2,
        )
    leader_row = max(results, key=lambda r: r.get("leader_score", 0))
    if leader_row.get("leader_score", 0) < 0.5:
        return None
    return {
        "code": leader_row["code"],
        "name": leader_row["name"],
        "score": leader_row["leader_score"],
        "cr": leader_row["change_rate"],
        "vr": leader_row["volume_ratio"],
    }
def _build_sector_momentum_summary(theme_name: str, metrics: dict, leader: dict | None) -> tuple[str, list, list]:
    results = metrics["results"]
    rising = [r for r in results if r["weak"]]
    flat = [r for r in results if not r["weak"]]
    bonus = metrics["bonus"]
    react_ratio = metrics["react_ratio"]
    react_cnt = metrics["react_cnt"]
    total = metrics["total"]
    sector_score = metrics["sector_score"]
    if bonus == 0:
        summary = f"📉 섹터 반응 없음 ({theme_name}: {react_cnt}/{total})"
    elif react_ratio >= 1.0:
        summary = f"🔥 섹터 전체 동반 상승! ({theme_name}: {react_cnt}/{total})"
    elif react_ratio >= 0.5:
        summary = f"✅ 섹터 절반 이상 반응 ({theme_name}: {react_cnt}/{total})"
    else:
        summary = f"🟡 섹터 일부 반응 ({theme_name}: {react_cnt}/{total})"
    if sector_score >= 0.5:
        summary += f"  💰 자금집중도 {sector_score:.0%}"
    if leader:
        summary += f"  👑 대장 {leader['name']}({leader['cr']:+.1f}%)"
    return summary, rising, flat
def _apply_nxt_sector_momentum_alignment(results: list, bonus: int, summary: str) -> tuple[int, str]:
    if not (is_nxt_open() and results):
        return bonus, summary
    nxt_bullish_cnt = 0
    nxt_bearish_cnt = 0
    for row in results[:4]:
        try:
            nxt = get_nxt_info(row["code"])
            if nxt.get("inv_bullish"):
                nxt_bullish_cnt += 1
            elif nxt.get("inv_bearish"):
                nxt_bearish_cnt += 1
            time.sleep(0.1)
        except Exception as e:
            _swallow_exception(e)
    if nxt_bullish_cnt >= 2:
        bonus = min(bonus + 10, 30)
        summary += f"  🔴 NXT {nxt_bullish_cnt}종목 외인+기관 매수"
    elif nxt_bearish_cnt >= 2:
        bonus = max(bonus - 10, 0)
        summary += f"  🔵 NXT {nxt_bearish_cnt}종목 외인+기관 매도"
    return bonus, summary
def _build_sector_momentum_sources(results: list) -> dict:
    sources = {}
    for row in results:
        src = row.get("source", "업종코드")
        sources.setdefault(src, []).append(row["name"])
    return sources
def calc_sector_momentum(code: str, name: str) -> dict:
    theme_name, peers, peers_all = get_theme_sector_stocks(code)
    geo_bias = _resolve_geo_sector_bias(theme_name)
    if not peers:
        return _empty_sector_momentum(theme_name)
    results = _collect_sector_momentum_results(peers, peers_all)
    if not results:
        return _empty_sector_momentum(theme_name)
    metrics = _calc_sector_momentum_score_bundle(results)
    metrics["results"] = results
    leader = _apply_sector_leader_scores(results)
    summary, rising, flat = _build_sector_momentum_summary(theme_name, metrics, leader)
    bonus, summary = _apply_nxt_sector_momentum_alignment(results, metrics["bonus"], summary)
    sources = _build_sector_momentum_sources(results)
    bonus = int(bonus + geo_bias)
    commodity_bias = _get_commodity_sector_adj(theme_name)
    bonus = int(bonus + commodity_bias)
    if commodity_bias != 0:
        summary += f"  🌐 원자재연동 {commodity_bias:+d}점"
    return {
        "bonus": bonus,
        "theme": theme_name,
        "summary": summary,
        "rising": rising,
        "flat": flat,
        "detail": results,
        "sources": sources,
        "leader": leader,
        "sector_score": metrics["sector_score"],
    }
