SIGNAL_LOG_MAX_RECORDS = int(os.getenv("SIGNAL_LOG_MAX_RECORDS", "5000") or "5000")  # v38.3: 50000→5000
SIGNAL_LOG_ARCHIVE_DAYS = int(os.getenv("SIGNAL_LOG_ARCHIVE_DAYS", "90") or "90")
STRICT_ENTRY_CLEANUP_MARKER = os.path.join(DATA_DIR, "strict_entry_cleanup_v37_25.done")
def _strict_cleanup_legacy_entry_hits() -> None:
    """엄격 진입가 도달 체계 전환용 1회성 마이그레이션.
    과거 허용오차 기반으로 기록됐을 수 있는 비실진입 entry_hit를 초기화한다.
    새 strict hit가 재시작 때 지워지지 않도록 marker 파일로 1회만 수행한다.
    """
    try:
        if os.path.exists(STRICT_ENTRY_CLEANUP_MARKER):
            return
        if not os.path.exists(SIGNAL_LOG_FILE):
            with open(STRICT_ENTRY_CLEANUP_MARKER, "w", encoding="utf-8") as f:
                f.write(datetime.now().strftime("%Y-%m-%d %H:%M:%S"))
            return
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict):
            return
        changed = 0
        now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        backup_path = os.path.join(DATA_DIR, f"signal_log.before_strict_cleanup_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json")
        for _k, rec in data.items():
            if not isinstance(rec, dict):
                continue
            if rec.get("actual_entry") is True:
                continue
            if rec.get("entry_hit") is True:
                rec["legacy_entry_hit"] = True
                rec["legacy_entry_hit_time"] = rec.get("entry_hit_time")
                rec["legacy_entry_hit_price"] = rec.get("entry_hit_price")
                rec["legacy_entry_hit_date"] = rec.get("entry_hit_date")
                rec["legacy_entry_hit_clock"] = rec.get("entry_hit_clock")
                rec["legacy_entry_hit_reset_at"] = now_s
                rec["legacy_entry_hit_reset_reason"] = "strict_cleanup_non_actual_entry"
                rec["entry_hit"] = False
                rec["entry_hit_time"] = None
                changed += 1
        if changed > 0:
            original = _read_json_locked(SIGNAL_LOG_FILE)
            _write_json_atomic(backup_path, original, indent=2)
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
            _log_info_msg(f"🧹 strict cleanup: 과거 비실진입 entry_hit {changed}건 초기화, 백업={os.path.basename(backup_path)}")
        else:
            _log_info_msg("🧹 strict cleanup: 초기화할 과거 비실진입 entry_hit 없음")
        with open(STRICT_ENTRY_CLEANUP_MARKER, "w", encoding="utf-8") as f:
            f.write(now_s)
    except Exception as e:
        _log_warn_msg(f"⚠️ strict cleanup 오류: {e}")
TUNE_LOOKBACK_DAYS = int(os.getenv("TUNE_LOOKBACK_DAYS", "30") or "30")
TUNE_MIN_SAMPLES   = int(os.getenv("TUNE_MIN_SAMPLES", "30") or "30")
TUNE_ALPHA         = float(os.getenv("TUNE_ALPHA", "0.35") or "0.35")  # 0~1, 클수록 빠르게 반영
ROUND_TRIP_COST_PCT = float(os.getenv("ROUND_TRIP_COST_PCT", "0.30") or "0.30")  # 왕복 수수료+슬리피지 공통 합산(%)
def _safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        return float(x)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return default
def safe_float(x, default=0.0):
    """하위 호환용 float 변환 helper."""
    return _safe_float(x, default)
def _is_manual_pnl_record(rec: dict) -> bool:
    try:
        if not isinstance(rec, dict):
            return False
        if rec.get("signal_type") == "MANUAL":
            return True
        if rec.get("exit_reason") == "수동입력":
            return True
        return False
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def _calc_net_pnl_pct(gross_pnl_pct, round_trip_cost_pct=None, *, is_manual: bool = False) -> float:
    gross = _safe_float(gross_pnl_pct, 0.0)
    if is_manual:
        return round(gross, 2)
    cost = _safe_float(ROUND_TRIP_COST_PCT if round_trip_cost_pct is None else round_trip_cost_pct, ROUND_TRIP_COST_PCT)
    return round(gross - cost, 2)
def _effective_pnl_pct(rec: dict, default: float = 0.0) -> float:
    try:
        if not isinstance(rec, dict):
            return default
        is_manual = _is_manual_pnl_record(rec)
        net = rec.get("net_pnl_pct")
        if net is not None:
            return round(_safe_float(net, default), 2)
        gross = rec.get("gross_pnl_pct")
        if gross is not None:
            return _calc_net_pnl_pct(gross, rec.get("round_trip_cost_pct"), is_manual=is_manual)
        pnl = rec.get("pnl_pct")
        if pnl is not None:
            return _calc_net_pnl_pct(pnl, rec.get("round_trip_cost_pct"), is_manual=is_manual)
        return default
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return default
def _sync_record_pnl_fields(rec: dict) -> bool:
    try:
        if not isinstance(rec, dict):
            return False
        changed = False
        is_manual = _is_manual_pnl_record(rec)
        completed = rec.get("status") in ("수익", "손실", "본전") or bool(rec.get("exit_reason"))
        desired_cost = 0.0 if is_manual else ROUND_TRIP_COST_PCT
        cur_cost = rec.get("round_trip_cost_pct")
        if cur_cost is None or abs(_safe_float(cur_cost, desired_cost) - desired_cost) > 1e-9:
            rec["round_trip_cost_pct"] = round(desired_cost, 4)
            changed = True
        if completed:
            gross_val = rec.get("gross_pnl_pct")
            if gross_val is None:
                src = rec.get("pnl_pct")
                if src is None:
                    src = rec.get("net_pnl_pct", 0.0)
                gross_val = _safe_float(src, 0.0)
                rec["gross_pnl_pct"] = round(gross_val, 2)
                changed = True
            else:
                gross_val = _safe_float(gross_val, 0.0)
            desired_net = _calc_net_pnl_pct(gross_val, rec.get("round_trip_cost_pct"), is_manual=is_manual)
            cur_net = rec.get("net_pnl_pct")
            if cur_net is None or abs(_safe_float(cur_net, desired_net) - desired_net) > 1e-9:
                rec["net_pnl_pct"] = desired_net
                changed = True
            cur_pnl = rec.get("pnl_pct")
            if cur_pnl is None or abs(_safe_float(cur_pnl, desired_net) - desired_net) > 1e-9:
                rec["pnl_pct"] = desired_net
                changed = True
        else:
            if rec.get("gross_pnl_pct") is None:
                rec["gross_pnl_pct"] = 0.0
                changed = True
            if rec.get("net_pnl_pct") is None:
                rec["net_pnl_pct"] = 0.0
                changed = True
            if rec.get("pnl_pct") is None:
                rec["pnl_pct"] = 0.0
                changed = True
        return changed
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def _normalize_signal_log_pnl_fields(data: dict) -> int:
    if not isinstance(data, dict):
        return 0
    changed = 0
    for rec in data.values():
        if _sync_record_pnl_fields(rec):
            changed += 1
        if _ensure_record_stats_meta(rec):
            changed += 1
    return changed
def migrate_signal_log_pnl_fields() -> None:
    """기존 signal_log에 gross/net/cost 필드를 1회 보강해 net 기준 통계를 유지한다."""
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict) or not data:
            return
        changed = _normalize_signal_log_pnl_fields(data)
        if changed <= 0:
            return
        data = _prune_signal_log(data)
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        try:
            _history_cache["data"] = data
            _history_cache["ts"] = time.time()
        except Exception as e:
            _swallow_exception(e)
        _log_info_msg(f"💸 signal_log pnl 정규화 완료: {changed}건 (왕복비용 {ROUND_TRIP_COST_PCT:.2f}%)")
    except Exception as e:
        _log_warn_msg(f"⚠️ signal_log pnl 정규화 오류: {e}")
def _prune_signal_log(data: dict) -> dict:
    """v38.3-P1-7: signal_log 크기 관리 — 90일 아카이브 + 건수 제한."""
    try:
        if not isinstance(data, dict):
            return data
        # 1단계: 90일 초과 완료건 아카이브
        cutoff = (datetime.now() - timedelta(days=SIGNAL_LOG_ARCHIVE_DAYS)).strftime("%Y%m%d")
        archive, keep = {}, {}
        for k, v in data.items():
            if not isinstance(v, dict):
                keep[k] = v; continue
            if v.get("status") in ("수익","손실","본전") and str(v.get("detect_date","")) < cutoff:
                archive[k] = v
            else:
                keep[k] = v
        if archive:
            try:
                arch_path = _state_path("signal_log_archive.json")
                existing = _read_json_locked(arch_path)
                if not isinstance(existing, dict): existing = {}
                existing.update(archive)
                _write_json_atomic(arch_path, existing, indent=1)
                _log_info_msg(f"📦 signal_log 아카이브: {len(archive)}건")
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                keep.update(archive)  # 실패 시 원본 유지
        data = keep
        # 2단계: 건수 제한
        if len(data) <= SIGNAL_LOG_MAX_RECORDS:
            return data
        def _k(item):
            k, v = item
            d = str(v.get("detect_date","")) if isinstance(v,dict) else ""
            t = str(v.get("detect_time","")) if isinstance(v,dict) else ""
            return (d + t.replace(":","")[:6]) if len(d)==8 and len(t)>=5 else k
        items = sorted(data.items(), key=_k)
        return dict(items[-SIGNAL_LOG_MAX_RECORDS:])
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return data
def _get_params_snapshot() -> dict:
    """신호 당시 '조건'을 최소 핵심만 스냅샷(최적화용)."""
    try:
        # 너무 많은 키를 저장하면 튜닝 데이터가 지저분해짐 → 핵심만
        keys = [
            "min_score_normal", "min_score_strict",
            "atr_stop_mult", "atr_target_mult",
            "early_price_min", "early_volume_min",
            "mid_surge_min_pct", "mid_pullback_min", "mid_pullback_max",
            "mid_pullback_bucket_a_confirm_min", "mid_pullback_bucket_b_confirm_min",
            "mid_pullback_close_window_min_krx", "mid_pullback_close_window_min_nxt",
            "mid_pullback_close_gate_level",
            "themed_score_bonus",
            # 가중치(기여도 튜닝용)
            "feat_w_rsi", "feat_w_ma", "feat_w_bb", "feat_w_sector", "feat_w_nxt", "feat_w_geo",
        ]
        snap = {k: _dynamic.get(k) for k in keys if k in _dynamic}
        snap["_v"] = BOT_VERSION
        return snap
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"_v": BOT_VERSION}
def _tune_score(records: list) -> float:
    """
    파라미터 후보의 성능 점수.
    - 평균 수익률(+)을 중심으로, 손실/드로우다운(MAE)을 페널티로 반영.
    """
    if not records:
        return -1e9
    pnls = [_effective_pnl_pct(r, 0.0) for r in records]
    maes = [_safe_float(r.get("mae_pct"), 0.0) for r in records]  # 음수(손실폭)
    # MAE는 보통 음수이므로 abs로 페널티
    avg = sum(pnls) / len(pnls)
    win = sum(1 for p in pnls if p > 0)
    wr  = win / len(pnls)
    avg_abs_mae = (sum(abs(x) for x in maes) / len(maes)) if maes else 0.0
    # 점수: 평균수익 + (승률-0.5)*2 보너스 - MAE 페널티
    return avg + (wr - 0.5) * 2.0 - avg_abs_mae * 0.35
def _select_best_params(completed: list) -> dict:
    """최근 lookback 구간에서 params_snapshot별 성능 비교 → best snapshot 반환."""
    if not completed:
        return {}
    # lookback filter
    try:
        cutoff = datetime.now() - timedelta(days=TUNE_LOOKBACK_DAYS)
        filtered = []
        for r in completed:
            d = r.get("exit_date") or r.get("detect_date")
            t = r.get("exit_time") or r.get("detect_time") or "00:00:00"
            if d and len(str(d)) == 8:
                try:
                    dt = datetime.strptime(str(d) + str(t)[:8], "%Y%m%d%H:%M:%S")
                except Exception as e:
                    _swallow_exception(e)  # v105 structured silent-exception log
                    try:
                        dt = datetime.strptime(str(d), "%Y%m%d")
                    except Exception as e:
                        _swallow_exception(e)  # v105 structured silent-exception log
                        dt = None
                if dt and dt >= cutoff:
                    filtered.append(r)
            else:
                filtered.append(r)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        filtered = completed
    groups = {}
    for r in filtered:
        snap = r.get("params_snapshot")
        if not isinstance(snap, dict):
            continue
        # signature (핵심 값만)
        sig = (
            snap.get("min_score_normal"),
            snap.get("min_score_strict"),
            snap.get("atr_stop_mult"),
            snap.get("atr_target_mult"),
        )
        groups.setdefault(sig, []).append(r)
    # 충분한 샘플만
    scored = []
    for sig, recs in groups.items():
        if len(recs) < TUNE_MIN_SAMPLES:
            continue
        scored.append((_tune_score(recs), sig, recs))
    if not scored:
        return {}
    scored.sort(key=lambda x: x[0], reverse=True)
    best_score, best_sig, best_recs = scored[0]
    # best snapshot은 대표 1개를 사용
    best_snap = dict(best_recs[0].get("params_snapshot", {}))
    best_snap["_score"] = round(best_score, 4)
    best_snap["_n"] = len(best_recs)
    return best_snap
def _apply_result_labels(rec: dict):
    """추적 결과를 최적화/튜닝에 쓰기 좋게 라벨링(MFE/MAE/보유기간 등)."""
    try:
        entry = _safe_float(rec.get("entry_price"), 0.0)
        if entry <= 0:
            return
        max_p = _safe_float(rec.get("max_price"), entry)
        min_p = _safe_float(rec.get("min_price"), entry)
        rec["mfe_pct"] = round((max_p - entry) / entry * 100, 2)
        rec["mae_pct"] = round((min_p - entry) / entry * 100, 2)  # 보통 음수
        # 보유 기간(분) — detect_date/time 또는 log_key 기반
        try:
            d = str(rec.get("detect_date", ""))
            t = str(rec.get("detect_time", "00:00:00"))
            dt0 = datetime.strptime(d + t[:8], "%Y%m%d%H:%M:%S")
            d2 = str(rec.get("exit_date", ""))
            t2 = str(rec.get("exit_time", "00:00:00"))
            dt1 = datetime.strptime(d2 + t2[:8], "%Y%m%d%H:%M:%S")
            rec["hold_minutes"] = int((dt1 - dt0).total_seconds() // 60)
        except Exception as e:
            _swallow_exception(e)
        _sync_record_pnl_fields(rec)
        pnl = _effective_pnl_pct(rec, 0.0)
        if pnl > 0:
            rec["outcome"] = "win"
        elif pnl < 0:
            rec["outcome"] = "loss"
        else:
            rec["outcome"] = "flat"
        # v163.19: 결과 확정 시 동적테마·종목 프로파일 성과 자동 반영
        try:
            code = str(rec.get("code", "") or "")
            if code and pnl != 0.0:
                _auto_reinforce_dynamic_theme(code, pnl)
        except Exception as _re:
            _swallow_exception(_re)
    except Exception as e:
        _swallow_exception(e)
TRACK_ACTIVE_STATUSES = {"추적중", "진입준비"}
TRACK_EPISODE_CANDIDATE_KEEP = int(os.getenv("TRACK_EPISODE_CANDIDATE_KEEP", "12") or "12")
TRACK_ENTRY_UPDATE_HISTORY_KEEP = int(os.getenv("TRACK_ENTRY_UPDATE_HISTORY_KEEP", "8") or "8")
# [v41.85] 고아 추적 판별 및 정리
def _is_orphan_tracking(rec: dict) -> bool:
    """entry/stop/target이 모두 0인 '추적중' 레코드인지 판별."""
    if rec.get("status") != "추적중":
        return False
    return _is_empty_tracking_price_triplet(
        rec.get("entry_price", 0),
        rec.get("stop_price", 0),
        rec.get("target_price", 0),
    )
def _get_valid_tracking(data: dict) -> list:
    """signal_log에서 고아/만료 예정 레코드를 제외한 유효 추적중 레코드만 반환."""
    today = datetime.now().strftime("%Y%m%d")
    out = []
    for rec in _iter_signal_log_records(data):
        if rec.get("status") != "추적중":
            continue
        if _is_orphan_tracking(rec):
            continue
        if _is_tracking_display_expired(rec, today):
            continue
        out.append(rec)
    return out
def _drop_tracking_runtime_artifacts(codes: set[str]) -> None:
    normalized = set()
    for code in codes or set():
        norm = normalize_stock_code(code)
        if norm:
            normalized.add(norm)
    codes = normalized
    if not codes:
        return
    detected_changed = False
    entry_changed = False
    execution_changed = False
    try:
        with _state_lock:
            for code in list(codes):
                if _detected_stocks.pop(code, None) is not None:
                    detected_changed = True
            for key in list(_entry_watch.keys()):
                watch = _entry_watch.get(key)
                if not isinstance(watch, dict):
                    continue
                if normalize_stock_code(watch.get("code")) in codes:
                    _entry_watch.pop(key, None)
                    entry_changed = True
            for key in list(_execution_setup_watch.keys()):
                watch = _execution_setup_watch.get(key)
                if not isinstance(watch, dict):
                    continue
                if normalize_stock_code(watch.get("code")) in codes:
                    _execution_setup_watch.pop(key, None)
                    execution_changed = True
    except Exception as e:
        _swallow_exception(e)
    if detected_changed:
        save_carry_stocks()
    if entry_changed:
        _save_entry_watch_active()
    if execution_changed:
        _save_execution_setup_watch(force=True)
    try:
        build_next_open_watchlist(max_codes=30)
    except Exception as e:
        _swallow_exception(e)
def purge_orphan_tracking(notify: bool = False) -> int:
    """signal_log 전체에서 고아 추적 종목을 일괄 만료 처리. 봇 시작 시 호출."""
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 0
    today = datetime.now().strftime("%Y%m%d")
    purged = 0
    purged_codes: set[str] = set()
    for log_key, rec in data.items():
        if not isinstance(rec, dict):
            continue
        if not _is_orphan_tracking(rec):
            continue
        elapsed = _get_tracking_elapsed_days(rec, today)
        if elapsed >= TRACK_MAX_DAYS:
            rec["status"] = TRACK_TIMEOUT_RESULT
            rec["exit_date"] = today
            rec["exit_reason"] = "고아추적_자동만료"
            rec["pnl_pct"] = 0.0
            purged += 1
            code = normalize_stock_code(rec.get("code"))
            if code:
                purged_codes.add(code)
            _log_info_msg(f"  🗑 고아 추적 만료: {rec.get('name', rec.get('code', log_key))} ({elapsed}일 경과)")
    if purged:
        try:
            _write_json_atomic(SIGNAL_LOG_FILE, data)
        except Exception as e:
            _swallow_exception(e)
        _drop_tracking_runtime_artifacts(purged_codes)
        if notify:
            _log_info_msg(f"  🗑 고아 추적 총 {purged}건 자동 만료")
    return purged
def _extract_signal_detect_datetime(stock: dict | None) -> datetime:
    stock = stock or {}
    detected_at = stock.get("detected_at")
    if isinstance(detected_at, datetime):
        return detected_at
    return datetime.now()
def _build_tracking_episode_candidate(stock: dict | None, reason: str = "신호포착") -> dict:
    stock = stock or {}
    detected_at = _extract_signal_detect_datetime(stock)
    return {
        "recorded_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(reason or "신호포착"),
        "detect_date": detected_at.strftime("%Y%m%d"),
        "detect_time": detected_at.strftime("%H:%M:%S"),
        "signal_type": str(stock.get("signal_type", "") or ""),
        "entry_price": safe_int(stock.get("entry_price", stock.get("price", 0)), 0),
        "stop_price": safe_int(stock.get("stop_loss", 0), 0),
        "target_price": safe_int(stock.get("target_price", 0), 0),
        "detect_price": safe_int(stock.get("price", 0), 0),
        "change_rate": safe_float(stock.get("change_rate", 0.0), 0.0),
        "volume_ratio": safe_float(stock.get("volume_ratio", 0.0), 0.0),
        "score": safe_int(stock.get("score", 0), 0),
        "grade": str(stock.get("grade", "") or ""),
    }
def _append_tracking_episode_candidate(rec: dict | None, candidate: dict | None) -> None:
    if not isinstance(rec, dict) or not isinstance(candidate, dict):
        return
    items = list(rec.get("episode_candidates") or [])
    items.append(candidate)
    keep = max(2, TRACK_EPISODE_CANDIDATE_KEEP)
    rec["episode_candidates"] = items[-keep:]
    rec["episode_candidate_count"] = len(rec["episode_candidates"])
    rec["episode_last_signal_time"] = f"{candidate.get('detect_date', '')} {candidate.get('detect_time', '')}".strip()
def _append_tracking_entry_update(rec: dict | None, old_entry: int, new_entry: int, reason: str = "재포착대표진입갱신") -> None:
    if not isinstance(rec, dict):
        return
    old_entry = safe_int(old_entry, 0)
    new_entry = safe_int(new_entry, 0)
    if old_entry <= 0 or new_entry <= 0 or old_entry == new_entry:
        return
    hist = list(rec.get("entry_update_history") or [])
    hist.append({
        "updated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(reason or "재포착대표진입갱신"),
        "old_entry": old_entry,
        "new_entry": new_entry,
    })
    keep = max(2, TRACK_ENTRY_UPDATE_HISTORY_KEEP)
    rec["entry_update_history"] = hist[-keep:]
    rec["entry_update_count"] = len(rec["entry_update_history"])
    rec["last_entry_update_time"] = rec["entry_update_history"][-1].get("updated_at", "")
def _calc_pullback_reclaim_ratio(peak_price: int, pullback_low: int, price: int) -> float:
    peak_price = safe_int(peak_price, 0)
    pullback_low = safe_int(pullback_low, 0)
    price = safe_int(price, 0)
    if peak_price <= 0 or pullback_low <= 0 or peak_price <= pullback_low or price <= 0:
        return 0.0
    return round(max(0.0, min(1.0, (price - pullback_low) / (peak_price - pullback_low))), 3)
def _calc_resurge_entry_price(current_price: int, pullback_low: int, reclaim_ratio: float = 0.0) -> int:
    current_price = safe_int(current_price, 0)
    pullback_low = safe_int(pullback_low, 0)
    reclaim_ratio = max(0.0, min(1.0, float(reclaim_ratio or 0.0)))
    if current_price <= 0:
        return 0
    discount_pct = MID_RESURGE_ENTRY_DISCOUNT_PCT + (0.5 if reclaim_ratio >= 0.7 else 0.0)
    base_entry = _round_price_down(current_price * (1 - discount_pct / 100.0))
    if pullback_low > 0:
        floor_entry = _round_price_down(pullback_low * (1 + 0.025 + min(reclaim_ratio, 0.8) * 0.03))
        if floor_entry > 0:
            base_entry = max(base_entry, floor_entry) if base_entry > 0 else floor_entry
    if base_entry <= 0 or base_entry >= current_price:
        base_entry = _round_price_down(current_price * 0.99)
    if base_entry <= 0 or base_entry >= current_price:
        base_entry = _round_price_down(current_price)
    return int(base_entry)
def _select_representative_entry_price(prev_entry: int, next_entry: int, signal_type: str = "",
                                       detect_date: str = "", miss_count: int = 0) -> tuple[int, str]:
    prev_entry = safe_int(prev_entry, 0)
    next_entry = safe_int(next_entry, 0)
    sig_type = str(signal_type or "")
    if prev_entry <= 0:
        return next_entry, "신규등록"
    if next_entry <= 0:
        return prev_entry, "기존유지"
    if next_entry < prev_entry:
        return next_entry, "하향갱신"
    if next_entry > prev_entry and sig_type in NO_CHASE_ENTRY_SIGNAL_TYPES:
        if sig_type in _get_dynamic_relaxable_no_chase_signal_types():
            try:
                if detect_date:
                    elapsed = (datetime.strptime(datetime.now().strftime("%Y%m%d"), "%Y%m%d") -
                               datetime.strptime(detect_date, "%Y%m%d")).days
                else:
                    elapsed = 0
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                elapsed = 0
            gap_pct = (next_entry - prev_entry) / prev_entry * 100 if prev_entry else 0.0
            recovery = _get_capture_watch_recovery_state({"signal_type": sig_type, "miss_count": safe_int(miss_count, 0)})
            if elapsed >= 2 or safe_int(miss_count, 0) >= 3 or gap_pct >= 15.0:
                reason = f"경과완화({elapsed}일/{safe_int(miss_count, 0)}회/괴리{gap_pct:.0f}%)"
                return next_entry, reason
            if recovery.get("active") and (elapsed >= 1 or safe_int(miss_count, 0) >= 1 or gap_pct >= 6.0):
                reason = f"회복완화({elapsed}일/{safe_int(miss_count, 0)}회/괴리{gap_pct:.0f}%)"
                return next_entry, reason
            # v165.6 [#5]: NXT 장후 시간대 miss 1회 이상 + 괴리 3% 이상이면 상향 갱신 허용
            # 이유: NXT 15:30~20:00 구간에서 종목이 진입가 위에서 계속 유지 시
            #        기존 기준(miss 3회/괴리 15%)이 너무 엄격 → 7회 미도달 반복
            _now_t = datetime.now().time()
            _is_nxt_after = dtime(15, 30) <= _now_t < dtime(20, 0)
            if _is_nxt_after and safe_int(miss_count, 0) >= 1 and gap_pct >= 3.0:
                reason = f"NXT장후완화({safe_int(miss_count,0)}회/괴리{gap_pct:.0f}%)"
                return next_entry, reason
        return prev_entry, "고점추격방지유지"
    return next_entry, "상향갱신" if next_entry > prev_entry else "기존유지"
def _apply_entry_price_guard(stock: dict | None, prev_entry: int = 0, detect_date: str = "", miss_count: int = 0) -> tuple[int, str]:
    stock = stock if isinstance(stock, dict) else {}
    current_entry = safe_int(stock.get("entry_price", stock.get("price", 0)), 0)
    _det_date = detect_date or str(stock.get("first_detect_date", stock.get("detect_date", "")) or "")
    _miss_cnt = miss_count or safe_int(stock.get("miss_count", 0), 0)
    chosen_entry, mode = _select_representative_entry_price(
        prev_entry, current_entry, stock.get("signal_type", ""),
        detect_date=_det_date, miss_count=_miss_cnt
    )
    if chosen_entry > 0:
        stock["entry_price"] = chosen_entry
        planned_prev = safe_int(stock.get("planned_entry_price", current_entry or chosen_entry), 0)
        if planned_prev <= 0 or mode == "고점추격방지유지":
            stock["planned_entry_price"] = chosen_entry
        else:
            stock["planned_entry_price"] = min(planned_prev, chosen_entry)
        try:
            stop_price, target_price, stop_pct, target_pct, atr_used = calc_stop_target(stock.get("code"), chosen_entry, signal_type=stock.get("signal_type"))
            if stop_price > 0 and target_price > chosen_entry:
                stock["stop_loss"] = int(stop_price)
                stock["target_price"] = int(target_price)
                stock["stop_pct"] = float(stop_pct)
                stock["target_pct"] = float(target_pct)
                stock["atr_used"] = bool(atr_used)
        except Exception as e:
            _swallow_exception(e)
    stock["entry_guard_mode"] = mode
    return chosen_entry, mode
def _get_dynamic_entry_reach_slack_pct(watch: dict | None = None) -> float:
    watch = watch if isinstance(watch, dict) else {}
    recovery = _get_capture_watch_recovery_state(watch)
    if not recovery.get("active"):
        return 0.0
    grade = str(watch.get("execution_grade") or watch.get("grade") or watch.get("execution_grade_at_detect") or watch.get("grade_at_detect") or "").upper()
    score = safe_int(watch.get("score", 0), 0)
    strength = str(watch.get("signal_strength") or watch.get("signal_strength_at_detect") or "")
    sig_type = str(watch.get("signal_type") or "").upper()
    if grade == "A" or strength == "강한" or score >= 85 or sig_type in {"MID_PULLBACK", "ENTRY_POINT", "STRONG_BUY", "SURGE"}:
        return 0.012
    if grade == "B" or score >= 78:
        return 0.006
    return 0.0
def _should_soft_allow_no_ask_liquidity(cur: dict, signal: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    sig_type = str(signal.get("signal_type") or "")
    ask_qty = safe_int(cur.get("ask_qty", 0), 0)
    bid_qty = safe_int(cur.get("bid_qty", 0), 0)
    if ask_qty > 0:
        return False
    change_rate = float(cur.get("change_rate", 0.0) or signal.get("change_rate", 0.0) or 0.0)
    if bid_qty > 0 and change_rate >= 29.0:
        return False
    # v163.15 [#1]: NXT A등급 SURGE/EARLY_DETECT/STRONG_BUY soft allow 추가
    # entry_watch 경로 no_ask_liquidity 186건 hard block 원인 — MID_PULLBACK만 허용하던 조건 확대
    if sig_type in ("SURGE", "EARLY_DETECT", "STRONG_BUY"):
        grade = str(signal.get("execution_grade") or signal.get("grade") or "").upper()
        score = int(signal.get("score", 0) or 0)
        market = str(signal.get("market") or "").upper()
        if market == "NXT" and grade == "A" and score >= 72 and change_rate >= 5.0:
            return True
        # 직접뉴스 확인된 경우 KRX도 soft allow
        if grade == "A" and (signal.get("direct_news_hit") or signal.get("direct_news_theme")):
            return True
        return False
    # MID_PULLBACK 기존 로직 유지
    if sig_type != "MID_PULLBACK":
        return False
    if signal.get("entry_soft_block_allowed"):
        return True
    if signal.get("resurge_mode"):
        return True
    if signal.get("direct_news_theme"):
        return True
    return int(signal.get("score", 0) or 0) >= MID_SOFT_ALLOW_MIN_SCORE
def _enrich_mid_pullback_direct_news(signal: dict | None) -> dict:
    signal = signal if isinstance(signal, dict) else {}
    if str(signal.get("signal_type") or "") != "MID_PULLBACK":
        return signal
    if signal.get("direct_news_hit") or signal.get("direct_news_theme"):
        return signal
    code = normalize_stock_code(signal.get("code"))
    if not code:
        return signal
    name = _resolve_stock_name(code, signal.get("name", code))
    direct = _infer_direct_news_theme(code, name)
    theme = str(direct.get("theme", "") or "").strip()
    if not theme:
        return signal
    signal["direct_news_hit"] = True
    signal["direct_news_theme"] = theme
    signal["direct_news_bonus"] = int(direct.get("bonus", 0) or 0)
    sector_info = signal.get("sector_info") if isinstance(signal.get("sector_info"), dict) else {}
    if not sector_info:
        sector_info = {}
        signal["sector_info"] = sector_info
    if str(sector_info.get("theme", "") or "") in ("", "기타업종", "unknown", "미분류"):
        sector_info["theme"] = theme
        sector_info["theme_key"] = theme
        signal["sector_theme"] = theme
    matched = ", ".join((direct.get("matched") or [])[:3])
    signal.setdefault("reasons", []).append(
        f"📰 직접뉴스 예외 허용 [{theme}] — {direct.get('reason', '')}"
        + (f" ({matched})" if matched else "")
    )
    return signal
def _should_suppress_mid_pullback_c_alert(signal: dict | None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    if str(signal.get("signal_type") or "") != "MID_PULLBACK":
        return False
    if str(signal.get("grade") or "").upper() != "C":
        return False
    if signal.get("resurge_mode"):
        return False
    if signal.get("direct_news_hit") or signal.get("direct_news_theme"):
        return False
    return True
def _tracking_active_items(data: dict | None, code: str = "") -> list[tuple[str, dict]]:
    data = data or {}
    code = normalize_stock_code(code)
    items = []
    for _k, _rec in data.items():
        if not isinstance(_rec, dict):
            continue
        if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
            continue
        if code and normalize_stock_code(_rec.get("code")) != code:
            continue
        items.append((_k, _rec))
    return items
def _find_representative_tracking_log_key(data: dict | None, code: str, preferred_key: str = "") -> str:
    code = normalize_stock_code(code)
    if not code:
        return ""
    data = data or {}
    if preferred_key:
        pref = data.get(preferred_key)
        if isinstance(pref, dict) and pref.get("status") in TRACK_ACTIVE_STATUSES and normalize_stock_code(pref.get("code")) == code:
            return preferred_key
    items = _tracking_active_items(data, code)
    if not items:
        return ""
    best_key, _ = max(items, key=lambda kv: _tracking_record_sort_key(kv[1]))
    return best_key
def _merge_tracking_episode_records(data: dict | None, code: str, representative_key: str, reason: str = "대표레코드통합") -> bool:
    data = data or {}
    code = normalize_stock_code(code)
    if not code or not representative_key or representative_key not in data:
        return False
    changed = False
    for _k, _rec in data.items():
        if _k == representative_key or not isinstance(_rec, dict):
            continue
        if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
            continue
        if normalize_stock_code(_rec.get("code")) != code:
            continue
        _rec["status"] = "대표진입승계"
        _rec["exit_reason"] = str(reason or "대표레코드통합")
        _rec["pnl_pct"] = 0.0
        _rec["merged_into_log_key"] = representative_key
        _rec["episode_representative"] = False
        changed = True
    rep = data.get(representative_key)
    if isinstance(rep, dict):
        rep["episode_representative"] = True
    return changed
def _load_signal_log_data() -> dict:
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if isinstance(data, dict):
            _normalize_signal_log_pnl_fields(data)
        return data if isinstance(data, dict) else {}
    except Exception as e:
        _swallow_exception(e)
        return {}
