def save_signal_log(stock: dict):
    """
    알림 발송된 모든 신호를 로그에 저장
    - UPPER_LIMIT / NEAR_UPPER / SURGE / EARLY_DETECT / MID_PULLBACK / ENTRY_POINT / PRECLOSE_GAP_ENTRY / FZONE_VWAP_BOUNCE
    - 이후 track_signal_results()가 목표가·손절가 도달 여부를 자동 체크
    """
    try:
        # v161.28: 최후 방어 — stop_loss=0 또는 target_price=0이면 entry 기반 재계산
        _entry = safe_int(stock.get("entry_price", 0), 0)
        if _entry > 0:
            _stop = safe_int(stock.get("stop_loss", 0), 0)
            _tgt  = safe_int(stock.get("target_price", 0), 0)
            if _stop <= 0 or _stop >= _entry:
                stock["stop_loss"]    = int(_entry * 0.93 / 10) * 10
                stock["stop_pct"]     = 7.0
            if _tgt <= _entry:
                stock["target_price"] = int(_entry * 1.10 / 10) * 10
                stock["target_pct"]   = 10.0
        data = _load_signal_log_data()
        ctx = _build_signal_log_context(stock)
        if _update_representative_signal_log_record(data, stock, ctx):
            return
        data[ctx["log_key"]] = _build_new_signal_log_record(stock, ctx)
        stock["signal_log_key"] = ctx["log_key"]
        data = _prune_signal_log(data)
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _record_capture_funnel_event("saved", stock, {"mode": "new"})
        _log_info_msg(f"  💾 신호 저장: {stock['name']} [{ctx['sig_type']}] 진입{stock.get('entry_price',0):,} 손절{stock.get('stop_loss',0):,} 목표{stock.get('target_price',0):,}")
    except Exception as e:
        _log_error_msg(f"⚠️ 신호 저장 오류: {e}")
# 하위 호환성 유지 (기존 EARLY_LOG_FILE도 동시에 저장)
def save_early_detect(stock: dict):
    save_signal_log(stock)
    try:
        data = {}
        try:
            data = _read_json_safe(EARLY_LOG_FILE, {}) or {}
        except Exception as e:
            _swallow_exception(e)
        code = stock["code"]
        if code not in data:
            data[code] = {
                "code": code, "name": stock["name"],
                "detect_time":  datetime.now().strftime("%H:%M"),
                "detect_date":  datetime.now().strftime("%Y%m%d"),
                "detect_price": stock["price"],
                "change_at_detect": stock["change_rate"],
                "volume_ratio": stock["volume_ratio"],
                "entry_price":  stock["entry_price"],
                "stop_price":   stock["stop_loss"],
                "target_price": stock["target_price"],
                "signal_type":  stock.get("signal_type", "EARLY_DETECT"),
                "sector_bonus": stock.get("sector_info", {}).get("bonus", 0),
                "status": "추적중", "pnl_pct": 0, "exit_price": 0, "exit_date": "",
            }
            _write_json_atomic(EARLY_LOG_FILE, data, indent=2)
    except Exception as e:
        _log_warn_msg(f"⚠️ EARLY 저장 오류: {e}")
