WIN_STREAK_THRESHOLD       = 4     # 연속 수익 N회 → 공격 모드 진입
def _check_and_restore_emergency_score_boost():
    """v163.13 [#4]: 연속손절 강제 min_score 상향 후 3시간 경과 시 원래값으로 복원"""
    boost_ts = float(_dynamic.get("_emergency_score_boost_ts") or 0)
    if boost_ts <= 0:
        return
    elapsed = time.time() - boost_ts
    if elapsed >= 10800:  # 3시간 = 10800초
        orig_n = int(_dynamic.get("_emergency_score_boost_n") or 56)
        orig_s = int(_dynamic.get("_emergency_score_boost_s") or 66)
        cur_n = int(_dynamic.get("min_score_normal", 56))
        cur_s = int(_dynamic.get("min_score_strict", 66))
        _dynamic["min_score_normal"] = orig_n
        _dynamic["min_score_strict"] = orig_s
        _dynamic.pop("_emergency_score_boost_ts", None)
        _dynamic.pop("_emergency_score_boost_n", None)
        _dynamic.pop("_emergency_score_boost_s", None)
        _log_info_msg(
            f"  ✅ 긴급 min_score 강화 복원: {cur_n}/{cur_s} → {orig_n}/{orig_s} (3시간 경과)"
        )

def _save_dynamic_params():
    """
    현재 _dynamic 값을 파일에 저장
    → Railway 재시작 후에도 조정값 유지
    """
    try:
        _write_json_atomic(DYNAMIC_PARAMS_FILE, _dynamic, indent=2)
    except Exception as e:
        _log_warn_msg(f"dynamic_params 저장 실패: {e}")
def _load_dynamic_params():
    """
    저장된 _dynamic 값을 불러와서 현재 세션에 복원
    파일 없으면 기본값 유지
    """
    global _dynamic, _early_price_min_dynamic, _early_volume_min_dynamic
    try:
        saved = _read_json_safe(DYNAMIC_PARAMS_FILE, {})
        # 저장된 값 중 유효한 키만 덮어씀 (새로 추가된 키는 기본값 유지)
        # v37.0: 타입 강제 변환 (JSON str→int/float 오류 방지)
        for k, v in saved.items():
            if k in _dynamic:
                default = _dynamic[k]
                try:
                    if isinstance(default, int) and not isinstance(default, bool):
                        _dynamic[k] = int(v)
                    elif isinstance(default, float):
                        _dynamic[k] = float(v)
                    elif isinstance(default, dict) and isinstance(v, dict):
                        _dynamic[k] = v
                    elif isinstance(default, str):
                        _dynamic[k] = str(v)
                    else:
                        _dynamic[k] = v
                except (ValueError, TypeError):
                    pass  # 변환 실패 시 기본값 유지
        _log_info_msg(
            f"동적 파라미터 복원 완료 (min_score={_dynamic['min_score_normal']}점, "
            f"atr_stop={_dynamic['atr_stop_mult']})"
        )
        # v165.10 [#1] / v165.13 수정: boost_ts 기준 긴급 강화 복원
        # v165.10 원래 로직: boost_ts 없고 min_score>56 → 기본값 복원
        # 문제: auto_tune이 정상적으로 올린 값(65점 등)도 날려버림
        # v165.13 수정: boost_ts 있고 3시간 경과 시에만 복원 (boost_ts 없으면 auto_tune 값 유지)
        boost_ts = float(_dynamic.get("_emergency_score_boost_ts") or 0)
        if boost_ts > 0 and (time.time() - boost_ts) >= 10800:
            # boost_ts 있고 3시간 이미 경과 → 즉시 복원
            orig_n = int(_dynamic.get("_emergency_score_boost_n") or 56)
            orig_s = int(_dynamic.get("_emergency_score_boost_s") or 66)
            _dynamic["min_score_normal"] = orig_n
            _dynamic["min_score_strict"] = orig_s
            _dynamic.pop("_emergency_score_boost_ts", None)
            _dynamic.pop("_emergency_score_boost_n", None)
            _dynamic.pop("_emergency_score_boost_s", None)
            _log_info_msg(f"  🔄 min_score 긴급 복원: 재시작 후 3시간 경과 → {orig_n}/{orig_s}")
            _save_dynamic_params()
    except FileNotFoundError:
        _log_info_msg("dynamic_params.json 없음 → 기본값 사용")
        # 저장 파일이 없으면 기본값을 즉시 저장해 다음 재시작부터 복원되도록 한다
        try:
            _save_dynamic_params()
            _log_info_msg("dynamic_params.json 기본값 저장 완료")
        except Exception as se:
            _log_warn_msg(f"dynamic_params 기본값 저장 실패: {se}")
    except Exception as e:
        _log_warn_msg(f"dynamic_params 복원 실패: {e}")
def _reset_stats_runtime_controls():
    global _dynamic, _early_price_min_dynamic, _early_volume_min_dynamic
    global _consecutive_loss_count, _consecutive_win_count
    _dynamic.clear()
    _dynamic.update(json.loads(json.dumps(_DEFAULT_DYNAMIC_PARAMS, ensure_ascii=False)))
    _early_price_min_dynamic = _dynamic["early_price_min"]
    _early_volume_min_dynamic = _dynamic["early_volume_min"]
    _consecutive_loss_count = 0
    _consecutive_win_count = 0
    state = _default_auto_tune_state()
    state["last_emergency_reason"] = "reset_stats"
    state["last_emergency_ts"] = time.time()
    _save_auto_tune_state(state)
    _clear_emergency_tune_state("reset_stats")
    _save_dynamic_params()
    return {
        "min_score_normal": _dynamic.get("min_score_normal", 0),
        "min_score_strict": _dynamic.get("min_score_strict", 0),
        "consecutive_loss_count": _consecutive_loss_count,
        "consecutive_win_count": _consecutive_win_count,
    }


def load_tracker_feedback():
    """기존 함수 — 하위 호환용. auto_tune()을 호출"""
    auto_tune(notify=False)
def _get_timeslot(detect_time: str) -> str:
    """
    신호 발생 시간(HH:MM:SS 또는 HH:MM)을 4개 구간으로 분류
    장초반 09:00~10:00 / 오전 10:00~12:00 / 오후 12:00~14:00 / 장후반 14:00~15:30
    """
    try:
        t = detect_time[:5]   # "HH:MM"
        h, m = int(t[:2]), int(t[3:])
        minutes = h * 60 + m
        if minutes < 10 * 60:              return "장초반"   # ~10:00
        elif minutes < 12 * 60:            return "오전"     # 10:00~12:00
        elif minutes < 14 * 60:            return "오후"     # 12:00~14:00
        else:                              return "장후반"   # 14:00~
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return "기타"
def analyze_timeslot_winrate(completed: list) -> dict:
    """
    완료 신호를 시간대별로 분류해 승률·평균 수익률 반환
    반환: {"장초반": {"win":N,"total":N,"avg":F}, ...}
    """
    slots = {"장초반": [], "오전": [], "오후": [], "장후반": [], "기타": []}
    for r in completed:
        t = r.get("detect_time", r.get("detected_at", ""))
        slot = _get_timeslot(t)
        slots[slot].append(r["pnl_pct"])
    result = {}
    for slot, pnls in slots.items():
        if not pnls: continue
        result[slot] = {
            "win":   sum(1 for p in pnls if p > 0),
            "total": len(pnls),
            "avg":   round(sum(pnls) / len(pnls), 1),
            "rate":  round(sum(1 for p in pnls if p > 0) / len(pnls) * 100, 0),
        }
    return result
def _feature_change_bucket(change_rate: float) -> str:
    try:
        cr = float(change_rate or 0)
        if cr >= 20:
            return "extreme"
        elif cr >= 8:
            return "strong"
        return "mild"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return "mild"
def _feature_volume_bucket(volume_ratio: float) -> str:
    try:
        vr = float(volume_ratio or 0)
        if vr >= 8:
            return "extreme"
        elif vr >= 3:
            return "high"
        return "normal"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return "normal"
def _safe_nested_dict(base: dict, key: str, default: dict) -> dict:
    try:
        val = base.get(key, default)
        return val if isinstance(val, dict) else dict(default)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return dict(default)
def analyze_loss_pattern(completed: list) -> str:
    """
    손실 종목들의 공통 패턴 분석 → 텍스트 요약 반환
    분석 항목: 손절 이유 분포 / 시간대 / 신호유형 / 테마여부
    """
    losses = [r for r in completed if r.get("pnl_pct", 0) <= 0]
    if len(losses) < 3:
        return ""
    lines = [f"🔵 <b>손실 패턴 분석</b>  ({len(losses)}건)"]
    # 손절 이유 분포
    reasons = {}
    for r in losses:
        ex = r.get("exit_reason", "?")
        reasons[ex] = reasons.get(ex, 0) + 1
    reason_str = "  ".join([f"{k}:{v}건" for k, v in sorted(reasons.items(), key=lambda x: -x[1])])
    lines.append(f"  청산 이유: {reason_str}")
    # 시간대별 손실 집중도
    slot_counts = {}
    for r in losses:
        t = r.get("detect_time", r.get("detected_at", ""))
        slot = _get_timeslot(t)
        slot_counts[slot] = slot_counts.get(slot, 0) + 1
    worst_slot = max(slot_counts, key=slot_counts.get) if slot_counts else None
    if worst_slot:
        lines.append(f"  손실 집중 시간대: {worst_slot} ({slot_counts[worst_slot]}건)")
    # 신호 유형별 손실
    type_counts = {}
    for r in losses:
        t = r.get("signal_type", "기타")
        type_counts[t] = type_counts.get(t, 0) + 1
    worst_type = max(type_counts, key=type_counts.get) if type_counts else None
    if worst_type:
        type_labels = {"UPPER_LIMIT":"상한가","NEAR_UPPER":"상한가근접","SURGE":"급등",
                       "EARLY_DETECT":"조기포착","MID_PULLBACK":"눌림목",
                       "ENTRY_POINT":"눌림목","STRONG_BUY":"강력매수"}
        lines.append(f"  손실 많은 신호: {type_labels.get(worst_type, worst_type)} ({type_counts[worst_type]}건)")
    # 단독 vs 테마 손실 비율
    solo_loss   = sum(1 for r in losses if not r.get("sector_bonus", 0))
    themed_loss = sum(1 for r in losses if r.get("sector_bonus", 0))
    if solo_loss + themed_loss > 0:
        lines.append(f"  단독:{solo_loss}건  테마동반:{themed_loss}건")
    return "\n".join(lines)
# ============================================================
# 📊 v41.63: signal_log 피드백 루프 — KPI 자동 분석 + 전략 건강도 판정
# ============================================================
KPI_MIN_SAMPLES = int(os.getenv("KPI_MIN_SAMPLES", "10") or "10")
def _load_completed_signal_kpi_records(completed: list | None) -> list:
    if completed is not None:
        return [row for row in completed if row.get("status") in ["수익", "손실", "본전"] and _record_matches_stats_scope(row)]
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)
        data = {}
    return [v for v in data.values() if v.get("status") in ["수익", "손실", "본전"] and _record_matches_stats_scope(v)]
def _empty_signal_kpi() -> dict:
    return {
        "win_rate": 0,
        "avg_pnl": 0,
        "profit_factor": 0,
        "payoff_ratio": 0,
        "expectancy": 0,
        "n": 0,
    }
def _calc_signal_kpi(recs: list, pnl_field: str) -> dict:
    if not recs:
        return _empty_signal_kpi()
    pnls = []
    for row in recs:
        try:
            pnls.append(float(row.get(pnl_field, 0) or 0))
        except Exception as e:
            _swallow_exception(e)
            pnls.append(0.0)
    n = len(pnls)
    if not n:
        return _empty_signal_kpi()
    wins = [p for p in pnls if p > 0]
    losses = [p for p in pnls if p < 0]
    win_rate = len(wins) / n * 100 if n else 0
    avg_pnl = sum(pnls) / n if n else 0
    avg_win = sum(wins) / len(wins) if wins else 0
    avg_loss = abs(sum(losses) / len(losses)) if losses else 1
    payoff_ratio = round(avg_win / avg_loss, 2) if avg_loss > 0 else 99.0
    profit_factor = round(sum(wins) / abs(sum(losses)), 2) if losses and sum(losses) != 0 else 99.0
    loss_rate = 1 - len(wins) / n if n else 0
    expectancy = round((len(wins) / n * avg_win - loss_rate * avg_loss) if n else 0, 2)
    return {
        "win_rate": round(win_rate, 1),
        "avg_pnl": round(avg_pnl, 2),
        "profit_factor": profit_factor,
        "payoff_ratio": payoff_ratio,
        "expectancy": expectancy,
        "n": n,
    }
def _group_signal_kpi_records(completed: list, key_fn) -> dict:
    grouped = {}
    for row in completed:
        grouped.setdefault(key_fn(row), []).append(row)
    return grouped
def _build_mid_pullback_bucket_kpi(by_bucket: dict, pnl_field: str) -> dict:
    bucket_result = {}
    for bucket, recs in by_bucket.items():
        entry = _calc_signal_kpi(recs, pnl_field)
        grade_dist = {"A": 0, "B": 0, "C": 0}
        for row in recs:
            grade = str(row.get("execution_grade") or row.get("grade") or "").upper()
            if grade in grade_dist:
                grade_dist[grade] += 1
        entry["execution_grade_dist"] = grade_dist
        bucket_result[bucket] = entry
    return bucket_result
def _calc_consecutive_signal_losses(sorted_recs: list, pnl_field: str) -> int:
    consec = 0
    for row in reversed(sorted_recs):
        try:
            pnl_val = float(row.get(pnl_field, 0) or 0)
        except Exception as e:
            _swallow_exception(e)
            pnl_val = 0.0
        if pnl_val < 0:
            consec += 1
        else:
            break
    return consec
def compute_signal_kpi(completed: list | None = None, pnl_field: str = "pnl_pct") -> dict:
    """
    signal_log 기반 승률/손익비/기대수익 KPI 자동 계산.
    v41.63 #1: 신호유형별·레짐별·시간대별 세분화 KPI.
    v41.93/v41.95: 눌림목 bucket 및 실진입(actual_pnl) KPI 지원.
    """
    completed = _load_completed_signal_kpi_records(completed)
    result = {"overall": _calc_signal_kpi(completed, pnl_field)}
    by_type = _group_signal_kpi_records(completed, lambda row: row.get("signal_type", "기타"))
    result["by_type"] = {name: _calc_signal_kpi(recs, pnl_field) for name, recs in by_type.items()}
    by_regime = _group_signal_kpi_records(completed, lambda row: row.get("regime", row.get("market_regime_mode", "normal")))
    result["by_regime"] = {name: _calc_signal_kpi(recs, pnl_field) for name, recs in by_regime.items()}
    by_slot = _group_signal_kpi_records(completed, lambda row: _get_timeslot(row.get("time", "10:00:00")))
    result["by_slot"] = {name: _calc_signal_kpi(recs, pnl_field) for name, recs in by_slot.items()}
    bucket_rows = [row for row in completed if str(row.get("mid_pullback_bucket", "") or "")]
    by_bucket = _group_signal_kpi_records(bucket_rows, lambda row: str(row.get("mid_pullback_bucket", "") or ""))
    result["by_mid_pullback_bucket"] = _build_mid_pullback_bucket_kpi(by_bucket, pnl_field)
    sorted_recs = sorted(completed, key=lambda row: row.get("exit_date", "") + row.get("exit_time", ""))
    result["consecutive_loss"] = _calc_consecutive_signal_losses(sorted_recs, pnl_field)
    return result
def _check_strategy_health(kpi: dict, notify: bool = True) -> list:
    """
    v41.63 #2: KPI 기반 전략 건강도 자동 판정.
    문제 있는 신호유형을 감지하고 자동 기준 강화 또는 경고 발송.
    반환: 변경사항 리스트 (auto_tune changes에 합류)
    """
    changes = []
    try:
        overall = kpi.get("overall", {})
        if overall.get("n", 0) < KPI_MIN_SAMPLES:
            return changes
        # ── 전체 건강도 체크 ──
        if overall["win_rate"] < 35:
            changes.append(
                f"⚠️ <b>전체 승률 경고</b>: {overall['win_rate']:.0f}% "
                f"(목표 40%↑)  n={overall['n']}"
            )
        if overall.get("payoff_ratio", 1) < 1.0 and overall["n"] >= 20:
            changes.append(
                f"⚠️ <b>손익비 경고</b>: {overall['payoff_ratio']:.2f} "
                f"(목표 1.0↑)  — 평균 수익 < 평균 손실"
            )
        # ── 연속 손절 긴급 경고 ──
        consec = kpi.get("consecutive_loss", 0)
        if consec >= 5:
            changes.append(
                f"🚨 <b>연속 손절 {consec}회</b> — 긴급 기준 강화 권고"
            )
            if notify:
                send(
                    f"🚨 <b>전략 긴급 경고</b>\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"연속 손절 <b>{consec}회</b> 발생!\n"
                    f"승률: {overall['win_rate']:.0f}%  손익비: {overall.get('payoff_ratio',0):.2f}\n"
                    f"기대수익: {overall.get('expectancy',0):+.2f}%\n\n"
                    f"💡 자동 튜닝이 기준을 강화합니다.\n"
                    f"/stats 로 상세 확인"
                )
        # ── 신호유형별 건강도 체크 ──
        for sig_type, sig_kpi in kpi.get("by_type", {}).items():
            if sig_kpi.get("n", 0) < max(KPI_MIN_SAMPLES // 2, 5):
                continue
            if sig_kpi["win_rate"] < 30:
                changes.append(
                    f"📉 {sig_type} 승률 {sig_kpi['win_rate']:.0f}% "
                    f"(n={sig_kpi['n']}) → 기준 강화 필요"
                )
            elif sig_kpi["win_rate"] > 70 and sig_kpi.get("payoff_ratio", 1) >= 1.5:
                changes.append(
                    f"🌟 {sig_type} 고성과: 승률 {sig_kpi['win_rate']:.0f}% "
                    f"손익비 {sig_kpi['payoff_ratio']:.1f} → 기준 완화 가능"
                )
        # ── 레짐별 건강도 체크 ──
        for regime, reg_kpi in kpi.get("by_regime", {}).items():
            if reg_kpi.get("n", 0) < max(KPI_MIN_SAMPLES // 2, 5):
                continue
            if reg_kpi["win_rate"] < 25 and regime in ("bear", "crash"):
                changes.append(
                    f"⚠️ {regime} 레짐 승률 {reg_kpi['win_rate']:.0f}% "
                    f"(n={reg_kpi['n']}) — 해당 레짐 진입 축소 권고"
                )
    except Exception as e:
        _log_error("_check_strategy_health", e)
    return changes
def _auto_tune_mid_pullback_bucket_params(mid_recs: list) -> list:
    changes = []
    if len(mid_recs) < max(MIN_SAMPLES, 6):
        return changes
    base_a = {
        "weekly_monthly_trend": 2,
        "daily_trend": 3,
        "gap_first_pullback": 3,
        "intraday_reclaim": 4,
    }
    base_b = {
        "weekly_monthly_trend": 1,
        "daily_trend": 2,
        "gap_first_pullback": 2,
        "intraday_reclaim": 2,
    }
    labels = MID_PULLBACK_BUCKET_LABELS
    a_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_a_confirm_min", base_a)
    b_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_b_confirm_min", base_b)
    for bucket, label in labels.items():
        subset = [r for r in mid_recs if str(r.get("mid_pullback_bucket", "") or "daily_trend") == bucket]
        if len(subset) < 4:
            continue
        win = sum(1 for r in subset if r.get("pnl_pct", 0) > 0) / len(subset)
        avg = sum(float(r.get("pnl_pct", 0) or 0) for r in subset) / len(subset)
        old_a = int(a_map.get(bucket, base_a.get(bucket, 3)) or base_a.get(bucket, 3))
        old_b = int(b_map.get(bucket, base_b.get(bucket, 1)) or base_b.get(bucket, 1))
        new_a, new_b = old_a, old_b
        if win < 0.40 or avg < -0.5:
            new_a = min(old_a + 1, 5)
            new_b = min(old_b + 1, max(4, new_a))
        elif win > 0.68 and avg > 0.8:
            new_a = max(old_a - 1, 1)
            new_b = max(old_b - 1, 0)
        if (new_a, new_b) != (old_a, old_b):
            a_map[bucket] = new_a
            b_map[bucket] = new_b
            changes.append(
                f"🏷️ 눌림목 유형[{label}] A/B 게이트 조정: {old_a}/{old_b}→{new_a}/{new_b} "
                f"(승률 {win*100:.0f}%, 평균 {avg:+.1f}%, n={len(subset)})"
            )
    _dynamic["mid_pullback_bucket_a_confirm_min"] = a_map
    _dynamic["mid_pullback_bucket_b_confirm_min"] = b_map
    close_rows = [r for r in mid_recs if bool((r.get("feature_snapshot") or {}).get("mid_close_window"))]
    for stage, key, default_window in (("KRX", "mid_pullback_close_window_min_krx", 20), ("NXT", "mid_pullback_close_window_min_nxt", 25)):
        subset = [r for r in close_rows if str((r.get("feature_snapshot") or {}).get("mid_close_stage", "") or "") == stage]
        if len(subset) < 4:
            continue
        win = sum(1 for r in subset if r.get("pnl_pct", 0) > 0) / len(subset)
        avg = sum(float(r.get("pnl_pct", 0) or 0) for r in subset) / len(subset)
        old_window = int(_dynamic.get(key, default_window) or default_window)
        new_window = old_window
        old_gate = int(_dynamic.get("mid_pullback_close_gate_level", 1) or 1)
        new_gate = old_gate
        if win < 0.40 or avg < -0.7:
            new_window = min(old_window + 5, 45)
            new_gate = min(old_gate + 1, 3)
        elif win > 0.68 and avg > 0.8:
            new_window = max(old_window - 5, 5)
            new_gate = max(old_gate - 1, 0)
        if new_window != old_window:
            _dynamic[key] = new_window
            changes.append(f"🕒 눌림목 마감보수[{stage}] 윈도우 조정: {old_window}→{new_window}분 (승률 {win*100:.0f}%, n={len(subset)})")
        if new_gate != old_gate:
            _dynamic["mid_pullback_close_gate_level"] = new_gate
            changes.append(f"🕒 눌림목 마감보수 게이트: {old_gate}→{new_gate} (stage {stage}, 평균 {avg:+.1f}%)")
    return changes
def _signal_feedback_sort_key(rec: dict | None = None) -> tuple:
    rec = dict(rec or {})
    exit_ts = f"{rec.get('exit_date','')} {rec.get('exit_time','')}".strip()
    detect_ts = f"{rec.get('detect_date','')} {rec.get('detect_time','')}".strip()
    hit_ts = str(rec.get('entry_hit_time') or '').strip()
    return (exit_ts, hit_ts, detect_ts, str(rec.get('code') or ''), str(rec.get('signal_type') or ''))
def _auto_tune_entry_pullback_ratio_feedback(data: dict, completed: list, tune_state: dict) -> list:
    """상승이탈 누적 시 entry_pullback_ratio 완화, 손실 악화 시 보수 복원."""
    changes = []
    try:
        if not isinstance(data, dict):
            return changes
        cur_ratio = round(float(_dynamic.get('entry_pullback_ratio', ENTRY_PULLBACK_RATIO) or ENTRY_PULLBACK_RATIO), 2)
        base_ratio = round(float(get_regime_pullback_ratio() or ENTRY_PULLBACK_RATIO), 2)
        miss_all = []
        for rec in data.values():
            if not isinstance(rec, dict):
                continue
            if str(rec.get('status') or '') != '진입미달':
                continue
            miss_all.append(dict(rec))
        miss_all.sort(key=_signal_feedback_sort_key)
        recent_miss = miss_all[-ENTRY_PULLBACK_MISS_LOOKBACK:]
        surge_miss = [r for r in recent_miss if '상승이탈' in str(r.get('exit_reason', '') or '')]
        expire_miss = [r for r in recent_miss if '기간만료' in str(r.get('exit_reason', '') or '')]
        if len(recent_miss) >= ENTRY_PULLBACK_MISS_MIN_SAMPLES:
            surge_share = len(surge_miss) / len(recent_miss) if recent_miss else 0.0
            avg_surge_away = 0.0
            if surge_miss:
                avg_surge_away = sum(float(r.get('entry_miss_away', 0) or 0) for r in surge_miss) / len(surge_miss)
            if (len(surge_miss) >= max(4, len(expire_miss) + 2)
                    and surge_share >= 0.45
                    and cur_ratio > ENTRY_PULLBACK_RATIO_MIN):
                new_ratio = round(max(ENTRY_PULLBACK_RATIO_MIN, cur_ratio - ENTRY_PULLBACK_ADJUST_STEP), 2)
                if new_ratio != cur_ratio:
                    _dynamic['entry_pullback_ratio'] = new_ratio
                    tune_state['last_entry_pullback_reason'] = f'surge_miss_{len(surge_miss)}of{len(recent_miss)}'
                    tune_state['last_entry_pullback_ts'] = time.time()
                    changes.append(
                        f"🎯 진입가 비율 완화: {cur_ratio:.2f}→{new_ratio:.2f} "
                        f"(최근 진입미달 {len(recent_miss)}건 중 상승이탈 {len(surge_miss)}건, 평균 {avg_surge_away:+.1f}%)"
                    )
                    cur_ratio = new_ratio
        recent_completed = sorted([dict(r) for r in completed if isinstance(r, dict)], key=_signal_feedback_sort_key)[-ENTRY_PULLBACK_RESULT_LOOKBACK:]
        if len(recent_completed) >= ENTRY_PULLBACK_RESULT_MIN_SAMPLES and cur_ratio < base_ratio:
            losses = [r for r in recent_completed if float(r.get('pnl_pct', 0) or 0) <= 0]
            loss_rate = len(losses) / len(recent_completed) if recent_completed else 0.0
            avg_pnl = sum(float(r.get('pnl_pct', 0) or 0) for r in recent_completed) / len(recent_completed) if recent_completed else 0.0
            stop_hits = sum(1 for r in recent_completed if str(r.get('exit_reason') or '') == '손절가')
            stop_ratio = stop_hits / len(recent_completed) if recent_completed else 0.0
            if loss_rate >= 0.60 or avg_pnl <= -1.0 or stop_ratio >= 0.35:
                restore_to = round(min(base_ratio, cur_ratio + ENTRY_PULLBACK_ADJUST_STEP), 2)
                if restore_to != cur_ratio:
                    _dynamic['entry_pullback_ratio'] = restore_to
                    tune_state['last_entry_pullback_reason'] = f'loss_guard_{len(recent_completed)}'
                    tune_state['last_entry_pullback_ts'] = time.time()
                    changes.append(
                        f"🛡 진입가 비율 보수 복원: {cur_ratio:.2f}→{restore_to:.2f} "
                        f"(최근 완료 {len(recent_completed)}건 손실비중 {loss_rate*100:.0f}% / 평균 {avg_pnl:+.1f}%)"
                    )
                    cur_ratio = restore_to
                old_min = int(_dynamic.get('min_score_normal', 56) or 56)
                new_min = min(old_min + 2, 85)
                if new_min != old_min:
                    _dynamic['min_score_normal'] = new_min
                    changes.append(f"🛡 손실 가드 최소점수 강화: {old_min}→{new_min}점")
                if stop_ratio >= 0.35:
                    old_atr = round(float(_dynamic.get('atr_stop_mult', ATR_STOP_MULT) or ATR_STOP_MULT), 2)
                    new_atr = round(min(old_atr + 0.1, 2.5), 1)
                    if new_atr != old_atr:
                        _dynamic['atr_stop_mult'] = new_atr
                        changes.append(f"🛡 손실 가드 ATR 손절배수 확대: {old_atr}→{new_atr}")
    except Exception as e:
        _log_error('_auto_tune_entry_pullback_ratio_feedback', e)
    return changes
def _auto_tune_load_completed_records():
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return None, []
    completed = [
        v for v in (data or {}).values()
        if v.get("status") in ["수익", "손실", "본전"]
    ]
    return data or {}, completed
def _auto_tune_group_by_signal_type(completed):
    by_type = {}
    for v in completed:
        t = v.get("signal_type", "기타")
        by_type.setdefault(t, []).append(v)
    return by_type
def _auto_tune_apply_params_snapshot_tuning(completed, changes):
    best = _select_best_params(completed)
    if not best:
        return
    try:
        cur_min_n = int(_dynamic.get("min_score_normal", 60))
        cur_min_s = int(_dynamic.get("min_score_strict", 70))
        cur_atr_s = _safe_float(_dynamic.get("atr_stop_mult", 1.5), 1.5)
        cur_atr_t = _safe_float(_dynamic.get("atr_target_mult", COMMON_THRESHOLD_3P0), COMMON_THRESHOLD_3P0)
        cand_min_n = int(best.get("min_score_normal", cur_min_n))
        cand_min_s = int(best.get("min_score_strict", cur_min_s))
        cand_atr_s = _safe_float(best.get("atr_stop_mult", cur_atr_s), cur_atr_s)
        cand_atr_t = _safe_float(best.get("atr_target_mult", cur_atr_t), cur_atr_t)
        new_min_n = int(round(cur_min_n * (1 - TUNE_ALPHA) + cand_min_n * TUNE_ALPHA))
        new_min_s = int(round(cur_min_s * (1 - TUNE_ALPHA) + cand_min_s * TUNE_ALPHA))
        new_atr_s = round(cur_atr_s * (1 - TUNE_ALPHA) + cand_atr_s * TUNE_ALPHA, 2)
        new_atr_t = round(cur_atr_t * (1 - TUNE_ALPHA) + cand_atr_t * TUNE_ALPHA, 2)
        new_min_n = max(45, min(new_min_n, 80))
        new_min_s = max(55, min(new_min_s, 90))
        new_atr_s = max(0.8, min(new_atr_s, 3.5))
        new_atr_t = max(1.5, min(new_atr_t, 6.0))
        if (new_min_n, new_min_s, new_atr_s, new_atr_t) == (cur_min_n, cur_min_s, cur_atr_s, cur_atr_t):
            return
        _dynamic["min_score_normal"] = new_min_n
        _dynamic["min_score_strict"] = new_min_s
        _dynamic["atr_stop_mult"] = new_atr_s
        _dynamic["atr_target_mult"] = new_atr_t
        changes.append(
            f"🧠 <b>성능 기반 튜닝</b> (최근 {TUNE_LOOKBACK_DAYS}일 / n={best.get('_n','?')})\n"
            f"- score {best.get('_score','?')} 기준 best params로 스무딩 적용\n"
            f"- min_score: {cur_min_n}/{cur_min_s} → {new_min_n}/{new_min_s}\n"
            f"- atr_stop/target: {cur_atr_s} / {cur_atr_t} → {new_atr_s} / {new_atr_t}"
        )
    except Exception as te:
        _log_error("auto_tune.params_snapshot", te)
def _auto_tune_apply_emergency_tuning(completed, overall, tune_state, changes, notify: bool = False):
    recent = sorted(completed, key=lambda x: x.get("exit_date","") + x.get("exit_time",""))[-5:]
    recent_loss_streak = 0
    for r in reversed(recent):
        if r.get("pnl_pct", 0) <= 0:
            recent_loss_streak += 1
        else:
            break
    cur_stage = _emergency_stage(recent_loss_streak)
    prev_stage = int(tune_state.get("emergency_stage", 0) or 0)
    if cur_stage <= 0:
        if tune_state.get("emergency_active") or prev_stage > 0:
            tune_state["emergency_active"] = False
            tune_state["emergency_stage"] = 0
            tune_state["last_emergency_reason"] = "streak_cleared"
            tune_state["last_emergency_ts"] = time.time()
        return
    tune_state["emergency_active"] = True
    if cur_stage > prev_stage:
        old_n = _dynamic["min_score_normal"]
        old_s = _dynamic["min_score_strict"]
        bump = {1: 8, 2: 5, 3: 5}.get(cur_stage, 4)
        _dynamic["min_score_normal"] = min(old_n + bump, 85)
        _dynamic["min_score_strict"] = min(old_s + bump, 90)
        changes.append(
            f"🚨 <b>긴급 튜닝[{_emergency_stage_label(cur_stage)}]</b>: 연속 손절 {recent_loss_streak}회\n"
            f"   최소점수 즉시 강화: {old_n}→{_dynamic['min_score_normal']}점"
        )
        tune_state["emergency_stage"] = cur_stage
        tune_state["last_emergency_reason"] = f"loss_streak_{recent_loss_streak}"
        tune_state["last_emergency_ts"] = time.time()
        alert_hash = _payload_hash({
            "stage": cur_stage,
            "consecutive_loss": recent_loss_streak,
            "min_score_normal": _dynamic["min_score_normal"],
            "min_score_strict": _dynamic["min_score_strict"],
        })
        if notify and (int(tune_state.get("last_emergency_alert_stage", 0) or 0) != cur_stage or str(tune_state.get("last_emergency_alert_hash") or "") != alert_hash):
            send(_build_emergency_tuning_alert(recent_loss_streak, overall or {}, cur_stage, old_n, _dynamic["min_score_normal"], old_s, _dynamic["min_score_strict"]))
            tune_state["last_emergency_alert_stage"] = cur_stage
            tune_state["last_emergency_alert_hash"] = alert_hash
        return
    tune_state["emergency_stage"] = max(prev_stage, cur_stage)
def _auto_tune_apply_signal_type_tuning(by_type, data, completed, tune_state, changes):
    global _early_price_min_dynamic, _early_volume_min_dynamic
    early_recs = by_type.get("EARLY_DETECT", [])
    if len(early_recs) >= MIN_SAMPLES:
        rate = sum(1 for r in early_recs if r["pnl_pct"] > 0) / len(early_recs)
        old_p = _dynamic["early_price_min"]
        old_v = _dynamic["early_volume_min"]
        if rate < 0.40:
            _dynamic["early_price_min"] = min(old_p + 2.0, 18.0)
            _dynamic["early_volume_min"] = min(old_v + 2.0, 18.0)
            changes.append(
                f"🔍 조기포착 조건 강화 (승률 {rate*100:.0f}%)\n"
                f"   가격 {old_p}→{_dynamic['early_price_min']}%  거래량 {old_v}→{_dynamic['early_volume_min']}배"
            )
        elif rate > 0.70:
            _dynamic["early_price_min"] = max(old_p - 1.0, 7.0)
            _dynamic["early_volume_min"] = max(old_v - 1.0, 7.0)
            changes.append(
                f"🔍 조기포착 조건 완화 (승률 {rate*100:.0f}%)\n"
                f"   가격 {old_p}→{_dynamic['early_price_min']}%  거래량 {old_v}→{_dynamic['early_volume_min']}배"
            )
        _early_price_min_dynamic = _dynamic["early_price_min"]
        _early_volume_min_dynamic = _dynamic["early_volume_min"]
    mid_recs = by_type.get("MID_PULLBACK", [])
    if len(mid_recs) >= MIN_SAMPLES:
        rate = sum(1 for r in mid_recs if r["pnl_pct"] > 0) / len(mid_recs)
        old_surge = _dynamic["mid_surge_min_pct"]
        old_min = _dynamic["mid_pullback_min"]
        old_max = _dynamic["mid_pullback_max"]
        if rate < 0.40:
            _dynamic["mid_surge_min_pct"] = min(old_surge + COMMON_THRESHOLD_3P0, 25.0)
            _dynamic["mid_pullback_min"] = min(old_min + 2.0, 16.0)
            _dynamic["mid_pullback_max"] = max(old_max - 4.0, 24.0)
            changes.append(
                f"🏆 눌림목 조건 강화 (승률 {rate*100:.0f}%)\n"
                f"   1차급등 {old_surge}→{_dynamic['mid_surge_min_pct']}%\n"
                f"   눌림범위 {old_min}~{old_max}→{_dynamic['mid_pullback_min']}~{_dynamic['mid_pullback_max']}%"
            )
        elif rate > 0.70:
            _dynamic["mid_surge_min_pct"] = max(old_surge - 2.0, 12.0)
            _dynamic["mid_pullback_min"] = max(old_min - 1.0, 12.0)
            _dynamic["mid_pullback_max"] = min(max(old_max, 24.0), 28.0)
            changes.append(
                f"🏆 눌림목 조건 완화 제한 (승률 {rate*100:.0f}%)\n"
                f"   1차급등 {old_surge}→{_dynamic['mid_surge_min_pct']}%\n"
                f"   눌림범위 하한 유지 {old_min}→{_dynamic['mid_pullback_min']}% / 상한 {old_max}→{_dynamic['mid_pullback_max']}%"
            )
        changes.extend(_auto_tune_mid_pullback_bucket_params(mid_recs))
    # v162.4: FZONE_VWAP_BOUNCE 학습 — 목표가%/VWAP허용범위/체결강도/손익비 자동조정
    fzone_recs = by_type.get("FZONE_VWAP_BOUNCE", [])
    if len(fzone_recs) >= MIN_SAMPLES:
        fzone_win = sum(1 for r in fzone_recs if r["pnl_pct"] > 0)
        fzone_rate = fzone_win / len(fzone_recs)
        # 목표가 % 조정 (승률 낮으면 목표가 낮춰 도달률↑, 승률 높으면 목표가↑)
        old_tgt = float(_dynamic.get("fzone_target_pct", 100.0))
        old_tol = float(_dynamic.get("fzone_vwap_tol_pct", 3.0))
        old_str = float(_dynamic.get("fzone_min_exec_strength", 100.0))
        old_rr  = float(_dynamic.get("fzone_min_rr", 1.2))
        changed = []
        if fzone_rate < 0.40:
            # 승률 40% 미만 → 조건 강화: 목표가 낮추고(도달 쉽게), VWAP 허용 좁히고, 체결강도 올리고, 손익비 높이기
            _dynamic["fzone_target_pct"] = round(max(old_tgt - 2.0, 92.0), 1)
            _dynamic["fzone_vwap_tol_pct"] = round(max(old_tol - 0.3, 1.0), 1)
            _dynamic["fzone_min_exec_strength"] = round(min(old_str + 5.0, 130.0), 1)
            _dynamic["fzone_min_rr"] = round(min(old_rr + 0.1, 2.0), 1)
            changed.append(f"⚡ F구간 조건 강화 (승률 {fzone_rate*100:.0f}%, {len(fzone_recs)}건)")
            changed.append(f"   목표가 {old_tgt:.0f}%→{_dynamic['fzone_target_pct']:.0f}%")
            changed.append(f"   VWAP허용 {old_tol:.1f}%→{_dynamic['fzone_vwap_tol_pct']:.1f}%")
            changed.append(f"   체결강도 {old_str:.0f}→{_dynamic['fzone_min_exec_strength']:.0f}")
        elif fzone_rate > 0.65:
            # 승률 65% 초과 → 조건 완화: 목표가 올리고, VWAP 허용 넓히고, 체결강도 낮추기
            _dynamic["fzone_target_pct"] = round(min(old_tgt + 1.0, 100.0), 1)
            _dynamic["fzone_vwap_tol_pct"] = round(min(old_tol + 0.3, 5.0), 1)
            _dynamic["fzone_min_exec_strength"] = round(max(old_str - 3.0, 90.0), 1)
            _dynamic["fzone_min_rr"] = round(max(old_rr - 0.05, 1.0), 1)
            changed.append(f"⚡ F구간 조건 완화 (승률 {fzone_rate*100:.0f}%, {len(fzone_recs)}건)")
            changed.append(f"   목표가 {old_tgt:.0f}%→{_dynamic['fzone_target_pct']:.0f}%")
            changed.append(f"   VWAP허용 {old_tol:.1f}%→{_dynamic['fzone_vwap_tol_pct']:.1f}%")
        # 손절 빈도 체크
        fzone_stops = sum(1 for r in fzone_recs if r.get("exit_reason") == "손절가")
        if fzone_stops / max(len(fzone_recs), 1) > 0.55:
            _dynamic["fzone_min_exec_strength"] = round(min(old_str + 8.0, 140.0), 1)
            changed.append(f"   손절빈발({fzone_stops}건) → 체결강도 기준 강화")
        if changed:
            changes.extend(changed)
    changes.extend(_auto_tune_entry_pullback_ratio_feedback(data, completed, tune_state))
    rate = sum(1 for r in completed if r["pnl_pct"] > 0) / len(completed)
    old_n = _dynamic["min_score_normal"]
    old_s = _dynamic["min_score_strict"]
    if rate < 0.40:
        _dynamic["min_score_normal"] = min(old_n + 5, 80)
        _dynamic["min_score_strict"] = min(old_s + 5, 85)
        changes.append(f"⭐ 최소 점수 강화: {old_n}→{_dynamic['min_score_normal']}점")
    elif rate > 0.70:
        _dynamic["min_score_normal"] = max(old_n - 3, 50)
        _dynamic["min_score_strict"] = max(old_s - 3, 60)
        changes.append(f"⭐ 최소 점수 완화: {old_n}→{_dynamic['min_score_normal']}점")
    stop_hits = sum(1 for r in completed if r.get("exit_reason") == "손절가")
    timeout_hit = sum(1 for r in completed if r.get("exit_reason") in ["만료", "timeout", TRACK_TIMEOUT_RESULT])
    old_atr = _dynamic["atr_stop_mult"]
    stop_ratio = stop_hits / len(completed)
    timeout_ratio = timeout_hit / len(completed)
    if stop_ratio > 0.50 and old_atr < 2.5:
        _dynamic["atr_stop_mult"] = round(min(old_atr + 0.2, 2.5), 1)
        changes.append(f"📐 ATR 손절배수 확대: {old_atr}→{_dynamic['atr_stop_mult']} (손절 너무 빈번)")
    elif timeout_ratio > 0.40 and old_atr > 1.0:
        _dynamic["atr_stop_mult"] = round(max(old_atr - 0.2, 1.0), 1)
        changes.append(f"📐 ATR 손절배수 축소: {old_atr}→{_dynamic['atr_stop_mult']} (손절 너무 느슨)")
def _auto_tune_apply_timeslot_context(completed, changes) -> None:
    slot_stats = analyze_timeslot_winrate(completed)
    new_slot_adj = dict(_dynamic["timeslot_score_adj"])
    slot_changes = []
    for slot, st in slot_stats.items():
        if st["total"] < 3:
            continue
        old_adj = new_slot_adj.get(slot, 0)
        if st["rate"] < 35 and old_adj < 20:
            new_slot_adj[slot] = old_adj + 5
            slot_changes.append(f"{slot}(승률{st['rate']:.0f}%→+{new_slot_adj[slot]}점)")
        elif st["rate"] > 70 and old_adj > 0:
            new_slot_adj[slot] = max(old_adj - 3, 0)
            slot_changes.append(f"{slot}(승률{st['rate']:.0f}%→점수 완화)")
    if slot_changes:
        _dynamic["timeslot_score_adj"] = new_slot_adj
        changes.append(f"🕐 시간대별 점수 조정: {', '.join(slot_changes)}")
def _auto_tune_apply_themed_bonus_context(completed, changes) -> None:
    solo_recs = [r for r in completed if not r.get("sector_bonus", 0)]
    themed_recs = [r for r in completed if r.get("sector_bonus", 0)]
    if len(solo_recs) < 3 or len(themed_recs) < 3:
        return
    solo_rate = sum(1 for r in solo_recs if r["pnl_pct"] > 0) / len(solo_recs)
    themed_rate = sum(1 for r in themed_recs if r["pnl_pct"] > 0) / len(themed_recs)
    gap = themed_rate - solo_rate
    old_bonus = _dynamic["themed_score_bonus"]
    if gap > 0.20:
        _dynamic["themed_score_bonus"] = min(old_bonus + 5, 25)
        changes.append(f"🏭 테마 보너스 강화: {old_bonus}→{_dynamic['themed_score_bonus']}점")
    elif gap < -0.10 and old_bonus > 5:
        _dynamic["themed_score_bonus"] = max(old_bonus - 3, 5)
        changes.append(f"🏭 테마 보너스 축소: {old_bonus}→{_dynamic['themed_score_bonus']}점")
def _auto_tune_apply_overnight_context(completed, changes) -> None:
    overnight_recs = [r for r in completed if r.get("feature_flags", {}).get("gap_signal") in ["gap_up", "gap_down", "flat"]]
    if len(overnight_recs) < 5:
        return
    gap_groups = {}
    for rec in overnight_recs:
        gap_label = rec.get("feature_flags", {}).get("gap_signal", "flat")
        gap_groups.setdefault(gap_label, []).append(rec)
    for gap_label, dyn_key in (("gap_up", "overnight_gapup_bonus"), ("gap_down", "overnight_gapdown_penalty")):
        grp = gap_groups.get(gap_label, [])
        if len(grp) < 3:
            continue
        win_rate = sum(1 for r in grp if r.get("pnl_pct", 0) > 0) / len(grp)
        avg_pnl = sum(r.get("pnl_pct", 0) for r in grp) / len(grp)
        old_v = int(_dynamic.get(dyn_key, 0) or 0)
        new_v = old_v
        if gap_label == "gap_up":
            if win_rate > 0.70 and avg_pnl > 1.5:
                new_v = min(old_v + 2, 8)
            elif win_rate < 0.40 or avg_pnl < -1.0:
                new_v = max(old_v - 2, -2)
        else:
            if win_rate < 0.40 or avg_pnl < -1.0:
                new_v = min(old_v + 2, 10)
            elif win_rate > 0.60 and avg_pnl > 0.5:
                new_v = max(old_v - 1, 0)
        if new_v != old_v:
            _dynamic[dyn_key] = new_v
            changes.append(f"🌙 오버나이트[{gap_label}] 보정: {old_v:+d}→{new_v:+d}점 (승률 {win_rate*100:.0f}% / 평균 {avg_pnl:+.1f}%)")
def _auto_tune_apply_earnings_risk_context(completed, changes) -> None:
    risk_recs = [r for r in completed if r.get("feature_flags", {}).get("earnings_risk") in ["warn", "high", "none"]]
    if len(risk_recs) < MIN_SAMPLES:
        return
    for risk_key, dyn_key, base_default, floor_v in (("warn", "earnings_warn_mult", 0.85, 0.60), ("high", "earnings_high_mult", 0.72, 0.40)):
        with_risk = [r for r in risk_recs if r.get("feature_flags", {}).get("earnings_risk") == risk_key]
        base_recs = [r for r in risk_recs if r.get("feature_flags", {}).get("earnings_risk") == "none"]
        if len(with_risk) < 3 or len(base_recs) < 3:
            continue
        win_with = sum(1 for r in with_risk if r.get("pnl_pct", 0) > 0) / len(with_risk)
        win_base = sum(1 for r in base_recs if r.get("pnl_pct", 0) > 0) / len(base_recs)
        avg_with = sum(r.get("pnl_pct", 0) for r in with_risk) / len(with_risk)
        avg_base = sum(r.get("pnl_pct", 0) for r in base_recs) / len(base_recs)
        edge = (win_with - win_base) + (avg_with - avg_base) / 20.0
        old_mult = float(_dynamic.get(dyn_key, base_default) or base_default)
        new_mult = old_mult
        if edge < -0.10:
            new_mult = round(max(old_mult - 0.05, floor_v), 2)
        elif edge > 0.10:
            new_mult = round(min(old_mult + 0.03, 1.00), 2)
        if new_mult != old_mult:
            _dynamic[dyn_key] = new_mult
            changes.append(f"📅 실적 리스크[{risk_key}] 배율 조정: {old_mult:.2f}→{new_mult:.2f} (승률 {win_with*100:.0f}% vs 무리스크 {win_base*100:.0f}%)")
def _auto_tune_apply_feature_snapshot_context(completed, changes) -> None:
    snap_recs = [r for r in completed if isinstance(r.get("feature_snapshot"), dict)]
    if len(snap_recs) < MIN_SAMPLES * 2:
        return
    for dyn_key, bucket_fn, source_key, label in (
        ("feature_change_adj", _feature_change_bucket, "change_rate", "변동률"),
        ("feature_volume_adj", _feature_volume_bucket, "volume_ratio", "거래량"),
    ):
        cur_map = _safe_nested_dict(_dynamic, dyn_key, {})
        bucket_groups = {}
        for rec in snap_recs:
            fs = rec.get("feature_snapshot") or {}
            bucket = bucket_fn(fs.get(source_key, 0))
            bucket_groups.setdefault(bucket, []).append(rec)
        for bucket, group in bucket_groups.items():
            other = [r for b, rs in bucket_groups.items() if b != bucket for r in rs]
            if len(group) < 3 or len(other) < 3:
                continue
            win_g = sum(1 for r in group if r.get("pnl_pct", 0) > 0) / len(group)
            win_o = sum(1 for r in other if r.get("pnl_pct", 0) > 0) / len(other)
            avg_g = sum(r.get("pnl_pct", 0) for r in group) / len(group)
            avg_o = sum(r.get("pnl_pct", 0) for r in other) / len(other)
            edge = (win_g - win_o) + (avg_g - avg_o) / 18.0
            old_adj = int(cur_map.get(bucket, 0) or 0)
            new_adj = old_adj
            if edge < -0.10:
                new_adj = max(old_adj - 2, -10)
            elif edge > 0.10:
                new_adj = min(old_adj + 2, 10)
            if new_adj != old_adj:
                cur_map[bucket] = new_adj
                changes.append(f"🧪 {label} 학습[{bucket}] 보정: {old_adj:+d}→{new_adj:+d}점 (승률 {win_g*100:.0f}% vs 타구간 {win_o*100:.0f}%)")
        _dynamic[dyn_key] = cur_map
def _auto_tune_apply_geo_sector_weight_context(completed, changes) -> None:
    geo_recs = [r for r in completed if r.get("feature_flags", {}).get("geo_active") and isinstance(r.get("geo_sector_bias"), dict)]
    if len(geo_recs) < MIN_SAMPLES:
        return
    geo_weights = _safe_nested_dict(_dynamic, "geo_sector_weights", {})
    sector_perf = {}
    for rec in geo_recs:
        bias = rec.get("geo_sector_bias") or {}
        for sec, raw in bias.items():
            try:
                raw_v = float(raw or 0)
            except Exception as e:
                _swallow_exception(e)
                raw_v = 0.0
            if abs(raw_v) < 1:
                continue
            sector_perf.setdefault(sec, []).append(rec.get("pnl_pct", 0))
    global_avg = sum(r.get("pnl_pct", 0) for r in geo_recs) / len(geo_recs)
    for sec, pnls in sector_perf.items():
        if len(pnls) < 3:
            continue
        avg_sec = sum(pnls) / len(pnls)
        old_w = float(geo_weights.get(sec, 1.0) or 1.0)
        new_w = old_w
        if avg_sec < global_avg - 1.5:
            new_w = round(max(old_w - 0.10, 0.6), 2)
        elif avg_sec > global_avg + 1.5:
            new_w = round(min(old_w + 0.08, 1.4), 2)
        if new_w != old_w:
            geo_weights[sec] = new_w
            changes.append(f"🌍 지정학 섹터[{sec}] 배율 조정: {old_w:.2f}→{new_w:.2f} (평균 {avg_sec:+.1f}% vs 전체 {global_avg:+.1f}%)")
    _dynamic["geo_sector_weights"] = geo_weights
def _auto_tune_apply_feature_weight_context(completed, changes) -> None:
    feat_recs = [r for r in completed if r.get("feature_flags")]
    if len(feat_recs) < MIN_SAMPLES * 2:
        return
    feat_analyses = {
        "feat_w_rsi": ("rsi", lambda r: r.get("feature_flags", {}).get("indic_score_adj", 0) != 0),
        "feat_w_ma": ("ma_aligned", lambda r: r.get("feature_flags", {}).get("ma_aligned") is True),
        "feat_w_bb": ("bb_breakout", lambda r: r.get("feature_flags", {}).get("bb_breakout") is True),
        "feat_w_sector": ("sector", lambda r: r.get("feature_flags", {}).get("sector_bonus", 0) > 0),
        "feat_w_nxt": ("nxt", lambda r: r.get("feature_flags", {}).get("nxt_delta", 0) != 0),
        "feat_w_geo": ("geo", lambda r: r.get("feature_flags", {}).get("geo_active", False)),
    }
    for feat_key, (feat_name, feat_filter) in feat_analyses.items():
        with_feat = [r for r in feat_recs if feat_filter(r)]
        without_feat = [r for r in feat_recs if not feat_filter(r)]
        if len(with_feat) < 3 or len(without_feat) < 3:
            continue
        win_with = sum(1 for r in with_feat if r["pnl_pct"] > 0) / len(with_feat)
        win_without = sum(1 for r in without_feat if r["pnl_pct"] > 0) / len(without_feat)
        avg_with = sum(r["pnl_pct"] for r in with_feat) / len(with_feat)
        avg_without = sum(r["pnl_pct"] for r in without_feat) / len(without_feat)
        old_w = _dynamic.get(feat_key, 1.0)
        contribution = (win_with - win_without) + (avg_with - avg_without) / 20
        if contribution < -0.15 and old_w > 0.3:
            new_w = round(max(old_w - 0.2, 0.2), 1)
            _dynamic[feat_key] = new_w
            changes.append(f"🔻 [{feat_name}] 기여도 저조 → 가중치 {old_w}→{new_w} (있을때 승률{win_with*100:.0f}% vs 없을때 {win_without*100:.0f}%)")
        elif contribution > 0.15 and old_w < 1.5:
            new_w = round(min(old_w + 0.1, 1.5), 1)
            _dynamic[feat_key] = new_w
            changes.append(f"🔺 [{feat_name}] 기여도 양호 → 가중치 {old_w}→{new_w} (있을때 승률{win_with*100:.0f}% vs 없을때 {win_without*100:.0f}%)")
def _auto_tune_apply_rsi_context(completed, changes) -> None:
    if len(completed) < MIN_SAMPLES * 2:
        return
    all_rsi_high = [r for r in completed if r.get("rsi_at_signal", 50) >= 65]
    if len(all_rsi_high) < 3:
        return
    rsi_high_rate = sum(1 for r in all_rsi_high if r["pnl_pct"] > 0) / len(all_rsi_high)
    old_ob = _dynamic["rsi_overbuy"]
    if rsi_high_rate > 0.65 and old_ob < 80:
        _dynamic["rsi_overbuy"] = min(old_ob + 2, 80)
        changes.append(f"📊 RSI 과매수 기준 완화: {old_ob:.0f}→{_dynamic['rsi_overbuy']:.0f} (고RSI 성공률 {rsi_high_rate*100:.0f}%)")
    elif rsi_high_rate < 0.35 and old_ob > 60:
        _dynamic["rsi_overbuy"] = max(old_ob - 2, 60)
        changes.append(f"📊 RSI 과매수 기준 강화: {old_ob:.0f}→{_dynamic['rsi_overbuy']:.0f} (고RSI 성공률 저조)")
def _auto_tune_apply_context_tuning(completed, changes):
    _auto_tune_apply_timeslot_context(completed, changes)
    _auto_tune_apply_themed_bonus_context(completed, changes)
    _auto_tune_apply_overnight_context(completed, changes)
    _auto_tune_apply_earnings_risk_context(completed, changes)
    _auto_tune_apply_feature_snapshot_context(completed, changes)
    _auto_tune_apply_geo_sector_weight_context(completed, changes)
    _auto_tune_apply_feature_weight_context(completed, changes)
    _auto_tune_apply_rsi_context(completed, changes)
def _auto_tune_apply_kpi_feedback(completed, changes, notify):
    try:
        kpi = compute_signal_kpi(completed)
        health_changes = _check_strategy_health(kpi, notify=notify)
        changes.extend(health_changes)
        if kpi["overall"].get("n", 0) < KPI_MIN_SAMPLES:
            return
        exp = kpi["overall"].get("expectancy", 0)
        if exp < -0.5:
            old_n = _dynamic["min_score_normal"]
            bump = 3 if exp < -1.0 else 2
            _dynamic["min_score_normal"] = min(old_n + bump, 85)
            changes.append(f"📉 기대수익 {exp:+.2f}% → 최소점수 +{bump}점 ({old_n}→{_dynamic['min_score_normal']})")
        elif exp > 1.5 and _dynamic["min_score_normal"] > 55:
            _dynamic["min_score_normal"] = max(_dynamic["min_score_normal"] - 2, 50)
            changes.append(f"🌟 기대수익 {exp:+.2f}% → 최소점수 완화 (→{_dynamic['min_score_normal']})")
    except Exception as _kpi_err:
        _log_error("auto_tune.kpi_feedback", _kpi_err)
def _auto_tune_finalize_changes(changes, completed, before_hash, tune_state, notify):
    after_sig = _current_dynamic_signature()
    after_hash = _payload_hash(after_sig)
    if after_hash == before_hash:
        _save_auto_tune_state(tune_state)
        _log_info_msg(f"  🧠 자동 조정: 유효 파라미터 변경 없음 ({len(completed)}건 분석)")
        return
    tune_log = {}
    try:
        tune_log = _read_json_safe(AUTO_TUNE_FILE, {}) or {}
    except Exception as e:
        _swallow_exception(e)
    ts_key = datetime.now().strftime("%Y%m%d_%H%M%S")
    while ts_key in tune_log:
        ts_key = datetime.now().strftime("%Y%m%d_%H%M%S") + f"_{random.randint(10,99)}"
    tune_log[ts_key] = {
        "changes": changes,
        "params": {k: v for k, v in _dynamic.items() if k != "timeslot_score_adj"},
        "samples": len(completed),
        "effective_hash": after_hash,
        "instance_id": _INSTANCE_ID,
    }
    _write_json_atomic(AUTO_TUNE_FILE, tune_log, indent=2)
    notify_hash = _payload_hash({
        "effective_hash": after_hash,
        "changes": changes,
        "samples": len(completed),
    })
    if notify:
        if tune_state.get("last_notify_hash") == notify_hash:
            _log_info_msg("  📨 조건 자동 조정 알림 중복 생략 (동일 변경)")
        else:
            change_text = "\n".join(changes)
            send(
                f"🔧 <b>조건 자동 조정 완료</b>\n"
                f"근거: {len(completed)}건 결과 분석\n"
                f"━━━━━━━━━━━━━━━\n"
                f"{change_text}\n\n"
                f"/stats 로 전체 통계 확인"
            )
            tune_state["last_notify_hash"] = notify_hash
    tune_state["last_effective_hash"] = after_hash
    _save_auto_tune_state(tune_state)
    _save_dynamic_params()
def auto_tune(notify: bool = True):
    """
    signal_log.json 기반으로 신호 유형별 성과를 분석해서
    조건을 자동으로 조정. 장 마감마다 호출.
    """
    global _consecutive_loss_count
    if not _try_acquire_leader_lock():
        _log_info_msg("  ⏸ auto_tune 생략 — 현재 replica는 리더 아님")
        return
    # v163.13 [#4]: 3시간 경과 시 긴급 min_score 강화 자동 복원
    _check_and_restore_emergency_score_boost()
    try:
        before_hash = _payload_hash(_current_dynamic_signature())
        tune_state = _get_auto_tune_state()
        data, completed = _auto_tune_load_completed_records()
        if data is None or len(completed) < MIN_SAMPLES:
            return
        changes = []
        changes.extend(_auto_tune_korea_etf_weights(completed))
        _auto_tune_apply_params_snapshot_tuning(completed, changes)
        by_type = _auto_tune_group_by_signal_type(completed)
        overall_kpi = compute_signal_kpi(completed).get("overall", {})
        _auto_tune_apply_emergency_tuning(completed, overall_kpi, tune_state, changes, notify=notify)
        _auto_tune_apply_signal_type_tuning(by_type, data, completed, tune_state, changes)
        _auto_tune_apply_context_tuning(completed, changes)
        _auto_tune_apply_kpi_feedback(completed, changes, notify)
        _auto_tune_finalize_changes(changes, completed, before_hash, tune_state, notify)
    except Exception as e:
        _log_error("auto_tune", e, critical=True)
