def _normalize_geo_sector_name(sector_name: str) -> str:
    text = str(sector_name or "").strip()
    if not text:
        return ""
    text = text.replace("ㆍ", "·").replace("&", "·").replace("+", "·")
    text = _re.sub(r"\s*/\s*", "·", text)
    text = _re.sub(r"\s*(및|와|과)\s*", "·", text)
    text = _re.sub(r"\s+", " ", text).strip(" ·")
    return text
def _split_geo_sector_tokens(sector_name: str) -> list:
    normalized = _normalize_geo_sector_name(sector_name)
    if not normalized:
        return []
    clean = _re.sub(r"[\(\)\[\]]", "·", normalized)
    parts = [p.strip() for p in clean.split("·") if p.strip()]
    out = []
    seen = set()
    for token in [normalized] + parts:
        token = token.strip()
        if token and token not in seen:
            seen.add(token)
            out.append(token)
    return out
def _derive_geo_sector_stocks(sector_name: str, reason: str = "", max_n: int = 5) -> list:
    normalized = _normalize_geo_sector_name(sector_name)
    tokens = _split_geo_sector_tokens(normalized)
    if not tokens:
        return []
    seen_codes = set()
    results = []
    def _add_stock(code, name):
        code = str(code or "").strip()
        name = str(name or "").strip()
        if not code or not name or code in seen_codes:
            return
        seen_codes.add(code)
        results.append((code, name))
    for token in tokens:
        for c, n in _GEO_SECTOR_STOCKS.get(token, []):
            _add_stock(c, n)
    for key, stocks in _GEO_SECTOR_STOCKS.items():
        if any(key in token or token in key for token in tokens):
            for c, n in stocks:
                _add_stock(c, n)
    for theme_key, theme_info in THEME_MAP.items():
        sectors = [str(s) for s in theme_info.get("sectors", [])]
        hay = [theme_key, str(theme_info.get("desc", ""))] + sectors
        if any(any(token in h or h in token for h in hay if h) for token in tokens):
            for c, n in theme_info.get("stocks", []):
                _add_stock(c, n)
    for tk, ti in _dynamic_theme_map.items():
        sectors = [str(s) for s in ti.get("sectors", [])]
        hay = [tk, str(ti.get("desc", "")), str(ti.get("reason", ""))] + sectors
        if any(any(token in h or h in token for h in hay if h) for token in tokens):
            for item in ti.get("stocks", []):
                if isinstance(item, (list, tuple)) and len(item) >= 2:
                    _add_stock(item[0], item[1])
    reason_text = str(reason or "")
    if reason_text:
        candidate_pool = []
        for stocks in _GEO_SECTOR_STOCKS.values():
            candidate_pool.extend(stocks)
        for ti in THEME_MAP.values():
            candidate_pool.extend(ti.get("stocks", []))
        for ti in _dynamic_theme_map.values():
            candidate_pool.extend([tuple(x[:2]) for x in ti.get("stocks", []) if isinstance(x, (list, tuple)) and len(x) >= 2])
        seen_names = set()
        for c, n in candidate_pool:
            if n in seen_names:
                continue
            seen_names.add(n)
            if n and n in reason_text:
                _add_stock(c, n)
    return results[:max_n]
def _remember_geo_sector_candidates(sec_dirs: list):
    global _dynamic_theme_map
    if not sec_dirs:
        return
    today = datetime.now().strftime("%m%d")
    changed = False
    for sd in sec_dirs:
        sector = _normalize_geo_sector_name(sd.get("sector", ""))
        if not sector:
            continue
        reason = str(sd.get("reason", "") or "")
        stocks = _derive_geo_sector_stocks(sector, reason=reason, max_n=8)
        if not stocks:
            continue
        theme_key = f"geo_{today}_{_re.sub(r'[^0-9A-Za-z가-힣]+', '_', sector)[:40]}"
        existing = _dynamic_theme_map.get(theme_key, {})
        merged = []
        seen = set()
        for item in list(existing.get("stocks", [])) + stocks:
            if not isinstance(item, (list, tuple)) or len(item) < 2:
                continue
            c, n = str(item[0]), str(item[1])
            if not c or c in seen:
                continue
            seen.add(c)
            merged.append((c, n))
        sectors = []
        for token in _split_geo_sector_tokens(sector):
            if token not in sectors:
                sectors.append(token)
        _dynamic_theme_map[theme_key] = {
            "desc": f"{sector} 연관 지정학 테마",
            "reason": reason or str(sd.get("direction", "") or "지정학 섹터"),
            "stocks": merged,
            "sectors": sectors,
            "ts": time.time(),
            "source": "geo_sector",
        }
        changed = True
    if changed:
        try:
            _write_json_atomic(DYNAMIC_THEME_FILE, {k: {**v, "stocks": v.get("stocks", [])} for k, v in _dynamic_theme_map.items()}, indent=2)
        except Exception as e:
            _swallow_exception(e)
def _get_geo_sector_stocks(sector_name: str, max_n: int = 3) -> list:
    """
    섹터명으로 관련 종목 조회.
    _GEO_SECTOR_STOCKS 직접 매핑 + THEME_MAP + 동적 지정학 테마까지 단계적으로 반영.
    returns: [(code, name), ...]
    """
    return _derive_geo_sector_stocks(sector_name, max_n=max_n)
def _get_geo_direction_sign(direction: str) -> int:
    d = str(direction or "").strip().lower()
    if d in ("상승", "up", "bull", "positive"):
        return 1
    if d in ("하락", "down", "bear", "negative"):
        return -1
    return 0
def _classify_geo_sector_evidence(total: int, aligned_rate: int, aligned_avg: float) -> str:
    if total < 8:
        return "insufficient"
    if aligned_rate >= 55 and aligned_avg >= 0.5:
        return "actionable"
    if aligned_rate < 40 or aligned_avg <= 0:
        return "weak"
    return "mixed"
def _collect_geo_sector_history_stats(sector_name: str, stock_list: list, direction: str = "중립") -> dict:
    """지정학 섹터별 과거 완료 신호를 방향 기준(상승/하락)으로 집계한다."""
    default = {
        "total": 0,
        "wins": 0,
        "avg_pnl": 0.0,
        "aligned_hits": 0,
        "aligned_rate": 0,
        "aligned_avg": 0.0,
        "grade": "insufficient",
        "recent": [],
    }
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return dict(default)
    if not data or not stock_list:
        return dict(default)
    stock_codes = {code for code, _name in stock_list}
    expected_sign = _get_geo_direction_sign(direction)
    matched = []
    for _log_key, rec in data.items():
        if rec.get("status") == "추적중":
            continue
        pnl = rec.get("pnl_pct", 0)
        if pnl == 0 and not rec.get("exit_price"):
            continue
        code = rec.get("code", "")
        s_theme = rec.get("sector_theme", "")
        is_direct = code in stock_codes
        is_sector = (sector_name and s_theme and (sector_name in s_theme or s_theme in sector_name))
        is_geo = rec.get("feature_flags", {}).get("geo_active", False)
        if is_direct or (is_sector and is_geo):
            matched.append({
                "code": code,
                "name": rec.get("name", ""),
                "pnl": round(float(pnl or 0), 1),
                "date": rec.get("detect_date", ""),
                "geo": bool(is_geo),
            })
    if not matched:
        return dict(default)
    total = len(matched)
    wins = sum(1 for m in matched if m["pnl"] > 0)
    avg_pnl = round(sum(m["pnl"] for m in matched) / total, 1) if total else 0.0
    if expected_sign == 0:
        aligned_hits = wins
        aligned_avg = avg_pnl
    else:
        aligned_hits = sum(1 for m in matched if m["pnl"] * expected_sign > 0)
        aligned_avg = round(sum(m["pnl"] * expected_sign for m in matched) / total, 1) if total else 0.0
    aligned_rate = round(aligned_hits / total * 100) if total else 0
    recent = sorted(matched, key=lambda x: x["date"], reverse=True)[:3]
    grade = _classify_geo_sector_evidence(total, aligned_rate, aligned_avg)
    return {
        "total": total,
        "wins": wins,
        "avg_pnl": avg_pnl,
        "aligned_hits": aligned_hits,
        "aligned_rate": aligned_rate,
        "aligned_avg": aligned_avg,
        "grade": grade,
        "recent": recent,
    }
def _get_geo_sector_history(sector_name: str, stock_list: list, direction: str = "중립") -> str:
    """상승/하락 공통으로 방향 일치 기준 통계를 반환한다."""
    stats = _collect_geo_sector_history_stats(sector_name, stock_list, direction=direction)
    total = int(stats.get("total", 0) or 0)
    if total <= 0:
        return ""
    grade = stats.get("grade", "insufficient")
    grade_emoji = {
        "actionable": "🟢",
        "mixed": "🟡",
        "weak": "🔵",
        "insufficient": "⚪",
    }.get(grade, "⚪")
    line1 = (
        f"│  {grade_emoji} 방향 일치: {total}건 중 {int(stats.get('aligned_hits', 0) or 0)}건 "
        f"({int(stats.get('aligned_rate', 0) or 0)}%) / 방향기대값 {float(stats.get('aligned_avg', 0) or 0):+.1f}%"
    )
    examples = []
    for r in stats.get("recent", [])[:3]:
        d_str = ""
        if r.get("date") and len(str(r.get("date"))) == 8:
            d_str = f"({str(r['date'])[4:6]}/{str(r['date'])[6:8]})"
        pnl_str = f"{float(r.get('pnl', 0) or 0):+.1f}%"
        geo_mark = "🌍" if r.get("geo") else ""
        examples.append(f"{_resolve_stock_name(r.get('code',''), r.get('name',''))}{geo_mark} {pnl_str}{d_str}")
    line2 = "│     최근: " + " | ".join(examples) if examples else ""
    return line1 + ("\n" + line2 if line2 else "")
def _build_geo_sector_evidence_map(sec_dirs: list) -> dict:
    evidence = {}
    for sd in sec_dirs or []:
        sec_name = str(sd.get("sector", "") or "").strip()
        if not sec_name:
            continue
        stocks = _get_geo_sector_stocks(sec_name, max_n=GEO_PREWATCH_MAX_STOCKS)
        stats = _collect_geo_sector_history_stats(sec_name, stocks, direction=sd.get("direction", "중립")) if stocks else {
            "total": 0,
            "aligned_hits": 0,
            "aligned_rate": 0,
            "aligned_avg": 0.0,
            "grade": "insufficient",
        }
        evidence[sec_name] = {
            "direction": sd.get("direction", "중립"),
            "score_adj": int(sd.get("score_adj", 0) or 0),
            "total": int(stats.get("total", 0) or 0),
            "aligned_hits": int(stats.get("aligned_hits", 0) or 0),
            "aligned_rate": int(stats.get("aligned_rate", 0) or 0),
            "aligned_avg": float(stats.get("aligned_avg", 0) or 0),
            "grade": stats.get("grade", "insufficient"),
            "is_actionable": stats.get("grade") == "actionable",
        }
    return evidence
def _get_geo_sector_evidence_map(refresh: bool = False) -> dict:
    sec_dirs = _geo_event_state.get("sector_directions", []) or []
    evidence = _geo_event_state.get("sector_evidence", {}) or {}
    if refresh or (not evidence and sec_dirs):
        evidence = _build_geo_sector_evidence_map(sec_dirs)
        _geo_event_state["sector_evidence"] = evidence
    return evidence or {}
def _find_geo_sector_evidence(sector_name: str) -> dict:
    sector_name = str(sector_name or "").strip()
    if not sector_name:
        return {}
    evidence_map = _get_geo_sector_evidence_map()
    best_meta = {}
    best_len = -1
    for sec_name, meta in evidence_map.items():
        if not sec_name:
            continue
        if sec_name in sector_name or sector_name in sec_name:
            match_len = min(len(sec_name), len(sector_name))
            if match_len > best_len:
                best_len = match_len
                best_meta = meta
    return best_meta or {}
def _render_geo_sector_block(sec_dirs: list) -> str:
    sec_dirs = list(sec_dirs or [])
    if not sec_dirs:
        return ""
    evidence_map = _build_geo_sector_evidence_map(sec_dirs)
    _geo_event_state["sector_evidence"] = evidence_map
    lines = [
        "<b>📊 실전형 섹터 후보</b>",
        "(표시 점수는 내부보정치, 방향 일치 근거가 약한 섹터는 숨김)",
    ]
    shown = 0
    hidden = []
    for sd in sec_dirs:
        sec_name = str(sd.get("sector", "") or "").strip()
        if not sec_name:
            continue
        meta = evidence_map.get(sec_name, {})
        if not meta.get("is_actionable"):
            hidden.append(sec_name)
            continue
        _dir = sd.get("direction", "중립")
        _icon = _DIR_DISPLAY.get(_dir, "▶")
        _adj = int(sd.get("score_adj", 0) or 0)
        _adj_str = f"  <b>내부보정 {_adj:+d}점</b>" if _adj != 0 else ""
        _stocks = _get_geo_sector_stocks(sec_name, max_n=3)
        _stk_str = "  ".join(f"<code>{n}</code>" for _c, n in _stocks) if _stocks else ""
        _hist_str = _get_geo_sector_history(sec_name, _stocks, direction=_dir) if _stocks else ""
        lines.append(
            f"┌ {_icon} <b>{sec_name}</b>{_adj_str}\n"
            f"│  {sd.get('reason','')}\n"
            + (f"│  📌 {_stk_str}\n" if _stk_str else "")
            + (f"{_hist_str}\n" if _hist_str else "")
            + "└─────────────"
        )
        shown += 1
    if shown == 0:
        lines.append("• 실전형 섹터 후보 없음 — 방향 일치 근거가 약한 섹터는 외부 표시/점수/프리워치에서 제외")
    if hidden:
        sample = ", ".join(hidden[:5])
        more = "" if len(hidden) <= 5 else f" 외 {len(hidden)-5}"
        lines.append(f"⚪ 숨김 {len(hidden)}개: {sample}{more}")
    return "\n".join(lines) + "\n"
_GEO_SECTOR_MAP = {
    "전쟁|전투|공습|미사일|폭격|침공|교전|충돌|군사": ["방산", "항공우주"],
    "이란|OPEC|유가|원유|석유|천연가스|LNG|감산|증산|호르무즈": ["정유", "에너지", "화학", "방산"],
    "러시아|우크라이나": ["방산", "에너지", "곡물"],
    "중국|대만|반도체|수출통제": ["반도체", "IT", "전자"],
    "제재|봉쇄|관세|무역전쟁|금수": ["수출주", "화학", "철강"],
    "이스라엘|팔레스타인|가자|중동|홍해|수에즈": ["방산", "정유", "해운"],
    "북한": ["방산", "건설"],
}
_geo_cache: dict = {}  # keyword_hash → {result, ts}
def _strip_html(text: str) -> str:
    try:
        # 매우 단순한 HTML 제거 (RSS description에 종종 포함)
        text = _re.sub(r"<[^>]+>", " ", text or "")
        text = _re.sub(r"\s+", " ", text).strip()
        return text
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return (text or "").strip()
def _parse_rss_xml_titles(xml_text: str, max_items: int) -> list:
    root = ET.fromstring(xml_text)
    items = root.findall(".//{*}item") or root.findall(".//{*}entry")
    titles = []
    for it in items[:max_items]:
        t = it.find(".//{*}title")
        d = it.find(".//{*}description")
        if d is None:
            d = it.find(".//{*}summary")
        if d is None:
            d = it.find(".//{*}content")
        title = _strip_html((t.text or "").strip()) if t is not None else ""
        desc = _strip_html((d.text or "").strip()) if d is not None else ""
        if not title:
            continue
        if desc and desc != title:
            desc = desc[:140] + ("…" if len(desc) > 140 else "")
            titles.append(f"{title} — {desc}")
        else:
            titles.append(title)
    return titles
def _parse_rss_regex_titles(xml_text: str, max_items: int) -> list:
    items = _re.findall(r"<item[^>]*>.*?</item>", xml_text, flags=_re.I | _re.S)
    if not items:
        items = _re.findall(r"<entry[^>]*>.*?</entry>", xml_text, flags=_re.I | _re.S)
    titles = []
    for blk in items[:max_items]:
        mt = _re.search(r"<title[^>]*>(.*?)</title>", blk, flags=_re.I | _re.S)
        md = _re.search(r"<description[^>]*>(.*?)</description>", blk, flags=_re.I | _re.S)
        if md is None:
            md = _re.search(r"<summary[^>]*>(.*?)</summary>", blk, flags=_re.I | _re.S)
        if md is None:
            md = _re.search(r"<content[^>]*>(.*?)</content>", blk, flags=_re.I | _re.S)
        title_raw = _re.sub(r"^<!\[CDATA\[|\]\]>$", "", (mt.group(1) if mt else "").strip()).strip()
        desc_raw = _re.sub(r"^<!\[CDATA\[|\]\]>$", "", (md.group(1) if md else "").strip()).strip()
        title = _strip_html(title_raw)
        desc = _strip_html(desc_raw)
        if not title:
            continue
        if desc and desc != title:
            desc = desc[:140] + ("…" if len(desc) > 140 else "")
            titles.append(f"{title} — {desc}")
        else:
            titles.append(title)
    return titles
def _fetch_rss_headlines(url: str, max_items: int = 10) -> list:
    """RSS 피드에서 헤드라인 수집 (title + description 요약 포함)."""
    try:
        resp = requests.get(url, timeout=12, headers=_random_ua())
        if resp.status_code != 200:
            return []
        xml_text = (resp.text or "").strip()
        if not xml_text:
            return []
        try:
            return _parse_rss_xml_titles(xml_text, max_items)
        except Exception as e:
            _swallow_exception(e)
            try:
                return _parse_rss_regex_titles(xml_text, max_items)
            except Exception as e:
                _swallow_exception(e)
                return []
    except Exception as e:
        _swallow_exception(e)
        return []
def _fetch_multi_source_headlines() -> dict:
    """
    국내외 다중 소스에서 헤드라인 수집.
    반환: {source_name: [headline, ...]}
    """
    sources = {
        # ── 해외 (지정학·경제 핵심) ──
        "BBC":        "https://feeds.bbci.co.uk/news/world/rss.xml",
        "Al_Jazeera": "https://www.aljazeera.com/xml/rss/all.xml",
        "CNBC":       "https://www.cnbc.com/id/100003114/device/rss/rss.html",
        "Guardian":   "https://www.theguardian.com/world/rss",
        "DW_World":    "https://rss.dw.com/rdf/rss-en-world",
        "DefenseNews_Global": "https://www.defensenews.com/arc/outboundfeeds/rss/category/global/?outputType=xml",
        "NPR_World":   "https://feeds.npr.org/1004/rss.xml",
        "G뉴스_해운":   "https://news.google.com/rss/search?q=shipping+Red+Sea+Hormuz+freight&hl=en&gl=US&ceid=US:en",
        "G뉴스_원자재": "https://news.google.com/rss/search?q=gold+safe+haven+commodities&hl=en&gl=US&ceid=US:en",
        "G뉴스_환율":   "https://news.google.com/rss/search?q=dollar+yen+won+fx+geopolitics&hl=en&gl=US&ceid=US:en",
        "G뉴스_지정학": "https://news.google.com/rss/search?q=geopolitics+war+sanctions&hl=en&gl=US&ceid=US:en",
        "G뉴스_에너지": "https://news.google.com/rss/search?q=oil+price+OPEC+energy&hl=en&gl=US&ceid=US:en",
        "G뉴스_무역":   "https://news.google.com/rss/search?q=trade+war+tariff+sanctions&hl=en&gl=US&ceid=US:en",
        # ── 국내 (한국 증시 직결) ──
        "한경":       "https://www.hankyung.com/feed/economy",
        "G뉴스_매경":     "https://news.google.com/rss/search?q=site:mk.co.kr+경제&hl=ko&gl=KR&ceid=KR:ko",
        "G뉴스_한국경제": "https://news.google.com/rss/search?q=한국+증시+경제&hl=ko&gl=KR&ceid=KR:ko",
        "G뉴스_유가":     "https://news.google.com/rss/search?q=유가+원유+중동&hl=ko&gl=KR&ceid=KR:ko",
        "G뉴스_반도체":   "https://news.google.com/rss/search?q=반도체+수출규제+미중&hl=ko&gl=KR&ceid=KR:ko",
    }
    results = {}
    errors  = []
    def _fetch_one(name, url):
        try:
            headlines = _fetch_rss_headlines(url, max_items=15)
            if headlines:
                results[name] = headlines
            else:
                errors.append(f"{name}:0건")
        except Exception as e:
            errors.append(f"{name}:{e}")
    # v37.0: ThreadPoolExecutor로 전환 (max_workers=6, 동시 연결 제한)
    from concurrent.futures import ThreadPoolExecutor, as_completed
    with ThreadPoolExecutor(max_workers=6) as executor:
        futures = {executor.submit(_fetch_one, n, u): n for n, u in sources.items()}
        try:
            for f in as_completed(futures, timeout=20):
                pass  # _fetch_one이 결과를 results에 직접 저장
        except Exception as e:
            _swallow_exception(e, note="rss_as_completed_timeout")  # 타임아웃 시 수집된 것만 사용
    if errors:
        _log_warn_msg(f"  ⚠️ RSS 수집 실패: {', '.join(errors)}")
    # 모두 실패 시 기존 fetch_all_news (국내) fallback
    if not results:
        domestic = fetch_all_news()
        if domestic:
            results["국내뉴스"] = domestic[:20]
    return results
def _detect_geo_keywords(headlines_flat: list) -> list:
    """헤드라인 목록에서 지정학 키워드 감지 → 감지된 키워드 반환"""
    detected = []
    for h in headlines_flat:
        for kw in _GEO_KEYWORDS:
            if kw in h and kw not in detected:
                detected.append(kw)
    return detected
def _map_geo_sectors(detected_kws: list) -> list:
    """감지된 키워드 → 관련 섹터 자동 매핑"""
    sectors = []
    for pattern, sec_list in _GEO_SECTOR_MAP.items():
        for kw in detected_kws:
            if _re.search(pattern, kw):
                for s in sec_list:
                    s = _normalize_geo_sector_name(s)
                    if s and s not in sectors:
                        sectors.append(s)
    return sectors
def _build_fallback_sector_directions(detected_kws: list, sectors: list) -> list:
    """
    API 없을 때 감지 키워드 + 섹터 기반으로 기본 방향/이유 생성.
    전쟁/군사 → 방산 상승 / 정유·에너지 상승 / 나머지 하락 기본값.
    """
    # 키워드 패턴으로 이벤트 유형 추론
    war_kws    = {"전쟁","전투","공습","미사일","폭격","침공","교전","충돌","군사","핵","대피","동원","군비","방공"}
    oil_kws    = {"이란","OPEC","유가","원유","석유","천연가스","LNG","감산","증산","호르무즈","홍해","수에즈","해협"}
    trade_kws  = {"제재","관세","무역전쟁","금수","봉쇄","수출통제","블랙리스트","덤핑","규제","칩","반도체규제"}
    ship_kws   = {"홍해","수에즈","호르무즈","해운","운임","선박","컨테이너","항만","물류","해협","보험료"}
    fx_kws     = {"달러","환율","원달러","엔화","위안","통화","금리","채권","리스크오프"}
    metal_kws  = {"금","은","구리","니켈","리튬","원자재","귀금속"}
    grain_kws  = {"곡물","밀","옥수수","대두","비료","식량","흉작","수출금지"}
    power_kws  = {"전력","원전","원자력","우라늄","전기요금","가스발전","발전"}
    cyber_kws  = {"사이버","해킹","랜섬웨어","공격","통신","위성","GPS","전파교란"}
    kw_set     = set(detected_kws)
    is_war   = bool(kw_set & war_kws)
    is_oil   = bool(kw_set & oil_kws)
    is_trade = bool(kw_set & trade_kws)
    is_ship  = bool(kw_set & ship_kws)
    is_fx    = bool(kw_set & fx_kws)
    is_metal = bool(kw_set & metal_kws)
    is_grain = bool(kw_set & grain_kws)
    is_power = bool(kw_set & power_kws)
    is_cyber = bool(kw_set & cyber_kws)
    # 섹터별 기본 방향 규칙
    SECTOR_RULES = {
        "방산":      ("상승",  "군사 긴장 → 방위산업 수혜",          +8),
        "항공우주":  ("상승",  "지정학 위기 → 방산·항공 수요 증가",   +6),
        "정유":      ("상승",  "지정학 위기 → 유가 상승 수혜",        +6) if is_oil or is_war else ("중립", "유가 변동 제한적", 0),
        "에너지":    ("상승",  "원유·가스 가격 상승 기대",             +5) if is_oil or is_war else ("중립", "유가 변동 제한적", 0),
        "화학":      ("하락",  "원자재 비용 증가 → 마진 악화",        -5),
        "항공":      ("하락",  "유가 상승 → 연료비 부담",             -6),
        "자동차":    ("하락",  "원자재 비용 상승 + 소비심리 위축",    -4),
        "조선":      ("상승",  "방위산업 수주 기대",                   +4) if is_war else ("중립", "직접 영향 제한적", 0),
        "반도체":    ("하락",  "수출통제·공급망 불확실성",            -5) if is_trade else ("중립", "직접 영향 제한적", 0),
        "IT":        ("하락",  "무역제재 → 글로벌 수요 위축",        -4) if is_trade else ("중립", "직접 영향 제한적", 0),
        "수출주":    ("하락",  "무역전쟁 → 수출 타격",               -6) if is_trade else ("중립", "제한적", 0),
        "금융·보험": ("하락",  "불확실성 → 투자심리 위축",           -4),
        "철강":      ("하락",  "원자재 수급 불안 + 수요 둔화",       -3),
        "곡물":      ("상승",  "공급망 차질 → 식품 가격 상승",        +5),
        "해운·물류": ("상승",  "해상 리스크/우회운항 → 운임 상승 수혜",    +6) if is_ship else ("중립", "직접 영향 제한적", 0),
        "물류":      ("상승",  "공급망 차질 → 운임/창고 수요 증가",        +4) if is_ship else ("중립", "직접 영향 제한적", 0),
        "보험":      ("하락",  "사고/리스크 확대 → 손해율 악화 우려",      -3) if is_ship or is_war else ("중립","제한적",0),
        "원전·전력": ("상승",  "에너지 안보 이슈 → 원전/전력 투자 확대",    +5) if is_power or is_oil else ("중립", "제한적", 0),
        "우라늄":    ("상승",  "원전 확대 기대 → 우라늄 수요",            +5) if is_power else ("중립","제한적",0),
        "금·귀금속": ("상승",  "리스크오프 → 안전자산 선호",              +5) if (is_war or is_fx or is_metal) else ("중립","제한적",0),
        "달러·환율": ("상승",  "달러 강세/변동성 확대",                    +3) if is_fx else ("중립","제한적",0),
        "여행":      ("하락",  "불확실성/유가 상승 → 수요 둔화",          -4) if (is_war or is_oil) else ("중립","제한적",0),
        "통신·위성": ("상승",  "통신/위성 인프라 수요",                    +3) if is_cyber else ("중립","제한적",0),
        "사이버보안": ("상승",  "사이버 공격 증가 → 보안 수요 확대",       +6) if is_cyber else ("중립","제한적",0),
        "건설":      ("중립",  "국내 수요 변화 제한적",               0),
    }
    result = []
    for sec in sectors:
        # 섹터명 부분 매칭 (예: "에너지·정유" → "정유" 규칙 사용)
        matched_rule = None
        for key, rule in SECTOR_RULES.items():
            if key in sec or sec in key:
                matched_rule = rule
                break
        if matched_rule:
            direction, reason, score_adj = matched_rule
        else:
            direction, reason, score_adj = "중립", "영향 분석 중", 0
        result.append({
            "sector":    sec,
            "direction": direction,
            "reason":    reason,
            "score_adj": score_adj,
        })
    return result
def _build_geo_analysis_cache_key(detected_kws: list[str]) -> str:
    return ",".join(sorted(detected_kws[:5]))
def _get_cached_geo_analysis_result(cache_key: str) -> dict | None:
    cached = _geo_cache.get(cache_key) or _geo_cache.get("fb_" + cache_key)
    if not cached:
        return None
    ttl = 7200 if _geo_cache.get("fb_" + cache_key) else 3600
    return cached if time.time() - cached.get("ts", 0) < ttl else None
def _build_geo_fallback_result(detected_kws: list[str], *, score_adj: int, summary_prefix: str, cache_key: str | None = None) -> dict:
    sectors = _map_geo_sectors(detected_kws)
    sec_dirs_fb = _build_fallback_sector_directions(detected_kws, sectors)
    _remember_geo_sector_candidates(sec_dirs_fb)
    result_fb = {
        "detected": True,
        "uncertainty": "mid",
        "sectors": sectors,
        "sector_directions": sec_dirs_fb,
        "score_adj": score_adj,
        "summary": f"{summary_prefix}: {', '.join(detected_kws[:3])}",
        "entities": [],
        "ts": time.time(),
    }
    if cache_key:
        _geo_cache["fb_" + cache_key] = result_fb
    return result_fb
def _build_geo_analysis_source_text(headlines_by_source: dict) -> str:
    blocks = []
    for src, hl_list in headlines_by_source.items():
        if hl_list:
            blocks.append(f"[{src}]\n" + "\n".join(f"- {headline}" for headline in hl_list[:8]))
    return "\n\n".join(blocks)
def _build_geo_analysis_prompt(source_text: str, detected_kws: list[str]) -> str:
    return f"""다음은 여러 언론 소스의 최신 헤드라인입니다.
{source_text}
감지된 지정학 키워드: {', '.join(detected_kws[:10])}
다음을 분석해서 JSON으로만 답하세요 (다른 텍스트 없이):
{{
  "entities": [
{{"name": "주체명(국가/기업/기구)", "stance": "긍정/부정/중립", "reason": "한 줄 이유"}}
  ],
  "uncertainty": "high/mid/low",
  "uncertainty_reason": "소스 간 입장 충돌 여부",
  "sector_directions": [
{{
  "sector": "한국 주식 섹터명",
  "direction": "상승/하락/중립",
  "reason": "한 줄 이유",
  "score_adj": -10~+10 사이 정수
}}
  ],
  "score_adj": -15~+10 사이 정수 (전체 시장 불확실성 기준),
  "summary": "한국 투자자용 한 줄 요약"
}}
주의:
- uncertainty는 소스들이 서로 다른 입장을 보이면 high, 비슷하면 low
- sector_directions는 이 이슈로 인해 직접 영향받는 한국 섹터만 포함 (3~6개)
- direction은 해당 섹터 주가 방향 예측 (상승/하락/중립)
- score_adj는 섹터별 점수 보정값 (상승이면 양수, 하락이면 음수)"""
def _request_geo_ai_analysis(api_key: str, prompt: str) -> tuple[dict | None, str]:
    resp = requests.post(
        "https://api.anthropic.com/v1/messages",
        headers={"x-api-key": api_key, "anthropic-version": "2024-10-22", "content-type": "application/json"},
        json={"model": "claude-haiku-4-5-20251001", "max_tokens": 1000, "messages": [{"role": "user", "content": prompt}]},
        timeout=15,
    )
    resp_json = safe_json_response(resp)
    raw = extract_ai_text(resp_json) if resp_json else ""
    return resp_json, raw.replace("```json", "").replace("```", "").strip()
def _sync_geo_sector_bias_from_ai(sec_dirs: list[dict]) -> None:
    bias = {}
    for sd in sec_dirs or []:
        sec = sd.get("sector")
        direction = sd.get("direction")
        if not sec or not direction:
            continue
        if direction in ("up", "bull", "positive", "상승"):
            bias[sec] = int(sd.get("score_adj", 3) or 3)
        elif direction in ("down", "bear", "negative", "하락"):
            bias[sec] = int(sd.get("score_adj", -3) or -3)
    GEO_SECTOR_BIAS.clear()
    GEO_SECTOR_BIAS.update(bias)
def _normalize_geo_ai_result(data: dict, detected_kws: list[str], cache_key: str) -> dict:
    sec_dirs = data.get("sector_directions", [])
    sectors = [sd["sector"] for sd in sec_dirs] if sec_dirs else _map_geo_sectors(detected_kws)
    _remember_geo_sector_candidates(sec_dirs)
    result = {
        "detected": True,
        "entities": data.get("entities", []),
        "uncertainty": data.get("uncertainty", "mid"),
        "sectors": sectors,
        "sector_directions": sec_dirs,
        "score_adj": max(-15, min(data.get("score_adj", 0), 10)),
        "summary": data.get("summary", ""),
        "kws": detected_kws[:5],
        "ts": time.time(),
    }
    _geo_cache[cache_key] = result
    try:
        _sync_geo_sector_bias_from_ai(sec_dirs)
    except Exception as e:
        _swallow_exception(e)
    return result
def analyze_geopolitical_event(headlines_by_source: dict) -> dict:
    all_headlines = [headline for hl in headlines_by_source.values() for headline in hl]
    detected_kws = _detect_geo_keywords(all_headlines)
    if not detected_kws:
        return {"detected": False, "uncertainty": "low", "sectors": [], "score_adj": 0, "summary": "", "entities": []}
    cache_key = _build_geo_analysis_cache_key(detected_kws)
    cached = _get_cached_geo_analysis_result(cache_key)
    if cached:
        return cached
    api_key = os.environ.get("ANTHROPIC_API_KEY", "")
    if not api_key:
        score_adj = -5 if len(detected_kws) >= 3 else 0
        return _build_geo_fallback_result(detected_kws, score_adj=score_adj, summary_prefix="⚠️ 지정학 이벤트 감지")
    try:
        prompt = _build_geo_analysis_prompt(_build_geo_analysis_source_text(headlines_by_source), detected_kws)
        resp_json, raw = _request_geo_ai_analysis(api_key, prompt)
        if not resp_json:
            _warn_throttled_once("geo_api_empty_response", "🌍 지정학 API: HTTP 빈 응답 → 키워드 fallback", cooldown_sec=3600.0)
            return _build_geo_fallback_result(detected_kws, score_adj=-3, summary_prefix="⚠️ 지정학 키워드 감지", cache_key=cache_key)
        if not raw:
            _warn_throttled_once("geo_api_blank_text", "🌍 지정학 API: 텍스트 비어있음 → 키워드 fallback", cooldown_sec=3600.0)
            return _build_geo_fallback_result(detected_kws, score_adj=-3, summary_prefix="⚠️ 지정학 키워드 감지", cache_key=cache_key)
        result = _normalize_geo_ai_result(json.loads(raw), detected_kws, cache_key)
        _log_info_msg(f"🌍 지정학 분석: {result['uncertainty']} 불확실성 / 섹터: {result['sectors']}")
        return result
    except Exception as e:
        _warn_throttled_once("geo_api_analysis_error", f"🌍 지정학 분석 실패 → 키워드 fallback ({type(e).__name__})", cooldown_sec=1800.0)
        return _build_geo_fallback_result(detected_kws, score_adj=-5, summary_prefix="⚠️ 지정학 이벤트")
def _load_detected_geo_event(headlines_by_source: dict) -> dict:
    if not headlines_by_source:
        return {}
    geo = analyze_geopolitical_event(headlines_by_source)
    return geo if geo.get("detected") else {}
def _store_geo_event_state(geo: dict) -> None:
    _geo_prev = _load_geo_active_state()
    _geo_history = list(_geo_prev.get("history_lines") or [])
    _geo_line = f"[{_now_kst().strftime('%H:%M')}] {geo.get('uncertainty','low').upper()} — {geo.get('summary','')}"
    if _geo_line not in _geo_history:
        _geo_history.append(_geo_line)
    _geo_history = _geo_history[-10:]
    _sec_dirs_for_state = list(geo.get("sector_directions", []) or [])
    _sector_evidence = _build_geo_sector_evidence_map(_sec_dirs_for_state) if _sec_dirs_for_state else {}
    _geo_event_state.update({
        "active": True,
        "uncertainty": geo["uncertainty"],
        "sectors": geo["sectors"],
        "sector_directions": _sec_dirs_for_state,
        "score_adj": geo["score_adj"],
        "summary": geo["summary"],
        "entities": geo["entities"],
        "kws": geo.get("kws", []),
        "history_lines": _geo_history,
        "sector_evidence": _sector_evidence,
        "ts": time.time(),
        "last_sent_ts": float(_geo_prev.get("last_sent_ts", 0) or 0),
        "last_sent_msg": str(_geo_prev.get("last_sent_msg", "") or ""),
    })
    _save_geo_active_state(dict(_geo_event_state))
def _build_geo_event_message(geo: dict, headlines_by_source: dict) -> str:
    unc_emoji = {"high": "🔵", "mid": "🟡", "low": "🔴"}
    msg = (
        f"🌍 <b>지정학 이벤트 감지</b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{unc_emoji.get(geo['uncertainty'],'🟡')} 불확실성: <b>{geo['uncertainty'].upper()}</b>\n\n"
    )
    if geo.get("entities"):
        msg += "<b>주체별 입장</b>\n"
        for e in geo["entities"][:5]:
            stance_emoji = {"긍정":"🔴","부정":"🔵","중립":"🟡"}.get(e.get("stance","중립"),"🟡")
            msg += f"  {stance_emoji} {e.get('name','')} — {e.get('stance','')} ({e.get('reason','')})\n"
        msg += "\n"
    sec_dirs = geo.get("sector_directions", [])
    if not sec_dirs and geo.get("sectors"):
        sec_dirs = _build_fallback_sector_directions(
            geo.get("kws", []) or _detect_geo_keywords([h for hl in headlines_by_source.values() for h in hl]),
            geo["sectors"],
        )
    if sec_dirs:
        msg += _render_geo_sector_block(sec_dirs) + "\n"
    elif geo.get("sectors"):
        msg += f"📊 관련 섹터: {', '.join(geo['sectors'])}\n"
    if geo.get("summary"):
        msg += f"\n💡 {geo['summary']}"
    return msg
def _maybe_send_geo_event_message(msg: str) -> None:
    if is_holiday():
        _log_info_msg(f"  🌍 지정학 감지(대기모드): {_geo_event_state.get('uncertainty','')} — 내부 저장만")
        return
    last_sent = _geo_event_state.get("last_sent_ts", 0)
    if time.time() - last_sent < 3600:
        return
    if is_any_market_open():
        last_sent_msg = str(_geo_event_state.get("last_sent_msg", "") or "")
        msg_compare = "\n".join(line.rstrip() for line in msg.strip().splitlines())
        if last_sent_msg == msg_compare:
            _log_info_msg("🌍 지정학 이벤트 감지 — 장중 동일 내용 재발송 생략")
            return
        send(msg)
        _geo_event_state["last_sent_ts"] = time.time()
        _geo_event_state["last_sent_msg"] = msg_compare
    else:
        _log_info_msg("🌍 지정학 이벤트 감지 — 장외 시간 텔레그램 발송 비활성화")
def _maybe_refresh_geo_overnight_watchlist(headlines_by_source: dict) -> None:
    try:
        now_h = _now_kst().hour
        if now_h >= 20 or now_h < 7:
            all_headlines = [h for hl in headlines_by_source.values() for h in hl]
            if all_headlines:
                detected_events = _extract_overnight_event_keywords(all_headlines)
                if detected_events:
                    _build_overnight_watchlist(detected_events)
                    _log_info_msg(f"  🌙 geo→야간 이벤트 {len(detected_events)}건 → 워치리스트 갱신")
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ geo→야간 워치리스트 연결 오류: {_e}")
def _maybe_register_geo_issue_prewatch(geo: dict) -> None:
    try:
        if not is_any_market_open():
            return
        sec_dirs = geo.get("sector_directions", [])
        geo_evidence_map = _get_geo_sector_evidence_map()
        for sd in sec_dirs:
            if sd.get("direction") not in ("상승", "up"):
                continue
            sec_name = sd.get("sector", "")
            if not sec_name:
                continue
            sec_meta = geo_evidence_map.get(sec_name) or _find_geo_sector_evidence(sec_name)
            if sec_meta and not sec_meta.get("is_actionable"):
                continue
            if not sec_meta and geo_evidence_map:
                continue
            sec_stocks = _get_geo_sector_stocks(sec_name, max_n=GEO_PREWATCH_MAX_STOCKS)
            if not sec_stocks:
                continue
            pw_key = f"geo_{sec_name}"
            if pw_key in _news_issue_prewatch or pw_key in _news_prewatch_fired:
                continue
            stock_status_geo = []
            for code_g, name_g in sec_stocks:
                try:
                    cur_g = get_stock_price(code_g)
                    if not cur_g:
                        continue
                    stock_status_geo.append({
                        "code": code_g,
                        "name": name_g,
                        "price": cur_g.get("price", 0),
                        "change_rate": cur_g.get("change_rate", 0),
                        "volume_ratio": cur_g.get("volume_ratio", 0),
                    })
                    time.sleep(GEO_PREWATCH_POLL_DELAY_SEC)
                except Exception as e:
                    _swallow_exception(e)
                    continue
            if stock_status_geo:
                _news_issue_prewatch[pw_key] = {
                    "stocks": stock_status_geo,
                    "headline": geo.get("summary", sec_name)[:60],
                    "theme_desc": f"지정학 수혜섹터: {sec_name}",
                    "ts": time.time(),
                }
                _log_info_msg(f"  🌍 geo prewatch 등록: [{pw_key}] {len(stock_status_geo)}종목 대기")
    except Exception as _e2:
        _log_warn_msg(f"  ⚠️ geo prewatch 등록 오류: {_e2}")
def run_geo_news_scan():
    """
    지정학 뉴스 스캔 (1시간마다).
    이벤트 감지 시 관련 섹터 알림 + 신호 점수 자동 보정 등록.
    """
    try:
        headlines_by_source = _fetch_multi_source_headlines()
        geo = _load_detected_geo_event(headlines_by_source)
        if not geo:
            return
        _store_geo_event_state(geo)
        collect_market_scenarios_24h(force=True, external_headlines=headlines_by_source)
        msg = _build_geo_event_message(geo, headlines_by_source)
        _maybe_send_geo_event_message(msg)
        _maybe_refresh_geo_overnight_watchlist(headlines_by_source)
        _maybe_register_geo_issue_prewatch(geo)
        if is_any_market_open():
            # v161.46: 장중 지정학 이벤트 감지 시 뉴스테마 포착 체인 연결
            # geo_prewatch(check_issue_prewatch)와 보완 관계 — 테마별 종목 A급 즉시 dispatch
            try:
                all_headlines = [h for lines in headlines_by_source.values() for h in lines]
                if all_headlines:
                    for signal in analyze_news_theme(headlines=all_headlines):
                        send_news_theme_alert(signal)
            except Exception as _e2:
                _log_error("run_geo_news_scan/analyze_news_theme", _e2)
            try:
                check_issue_prewatch()
            except Exception as _e3:
                _log_error("run_geo_news_scan/check_issue_prewatch", _e3)
    except Exception as e:
        _log_error("run_geo_news_scan", e)
def _build_retail_signal_result(score_adj: int, label: str, detail: str, confidence: str) -> dict:
    return {
        "score_adj": score_adj,
        "label": label,
        "detail": detail,
        "confidence": confidence,
    }
def _get_retail_signal_stock_trend(code: str) -> str:
     stock_trend = "unknown"
     try:
         daily = get_daily_data(code, 10)
         closes = [int(d.get("stck_clpr", 0)) for d in daily if d.get("stck_clpr")]
         if len(closes) >= 6:
             chg_5d = (closes[-1] - closes[-6]) / closes[-6] * 100
             if chg_5d >= 5.0:
                 stock_trend = "rally"
             elif chg_5d >= 1.0:
                 stock_trend = "uptrend"
             elif chg_5d >= -COMMON_THRESHOLD_3P0:
                 stock_trend = "sideways"
             elif chg_5d >= -7.0:
                 stock_trend = "pullback"
             else:
                 stock_trend = "downtrend"
     except Exception as e:
         _swallow_exception(e)
     return stock_trend
 
 
def _classify_retail_signal_context(regime: str, stock_trend: str, cap_size: str, r_abs: int, f_net: int, i_net: int) -> dict:
     if (regime in ("bull", "normal") and cap_size in ("large", "mid") and stock_trend in ("uptrend", "pullback", "sideways", "rally")):
         label = "💡 개인 저점 매수 (대/중형 조정)" if stock_trend != "rally" else "💡 개인 급등 후 조정 매수 (대/중형)"
         return _build_retail_signal_result(+5, label, f"bull/normal 국면 + {cap_size}cap 조정 중 개인 +{r_abs:,}주 — 기관 리밸런싱 매도 가능성, 단기 지지 효과 기대", "mid")
     if regime in ("bull", "normal") and cap_size == "small" and stock_trend in ("rally", "uptrend"):
         return _build_retail_signal_result(-5, "⚠️ 개인 고점 추격 (소형 급등)", f"소형주 급등 후 개인 +{r_abs:,}주 — 기관 차익실현 물량 받아내는 구도 가능성", "mid")
     if regime in ("bull", "normal") and cap_size == "small" and stock_trend in ("sideways", "pullback"):
         return _build_retail_signal_result(0, "📊 소형주 개인 매수 (조정중, 판단 보류)", f"소형주 조정 구간 개인 +{r_abs:,}주 — 기관+외국인 이탈 지속 여부 확인 필요", "low")
     if regime in ("bear", "crash") and cap_size in ("large", "mid"):
         return _build_retail_signal_result(0, "❓ 하락장 대형/중형주 개인 매수 (낙폭과대 판단 보류)", f"약세장에도 {cap_size}cap 개인 +{r_abs:,}주 — 낙폭과대 저점 가능성 vs 추가하락 위험 공존 (판단 보류)", "low")
     if regime in ("bear", "crash") and cap_size == "small":
         return _build_retail_signal_result(-12, "🔵 개인만 매수 / 기관+외국인 이탈 (약세장+소형주)", f"약세장 소형주 + 외국인 {f_net:,}주 + 기관 {i_net:,}주 동시 매도 — 개인 역방향 수급, 추가 하락 위험", "high")
     if stock_trend == "downtrend":
         return _build_retail_signal_result(-8, "⚠️ 하락추세 중 개인 역방향 매수", f"5일 추세 하락 중 개인 +{r_abs:,}주 — 기관+외국인 이탈 지속 시 지지력 약화 우려", "mid")
     return _build_retail_signal_result(0, "📊 개인 매수 (맥락 불분명)", f"개인 +{r_abs:,}주 / 기관+외국인 이탈 — 국면:{regime}, 추세:{stock_trend}, 규모:{cap_size} — 판단 보류", "low")
 
 
def eval_retail_signal(code: str,
                        f_net: int, i_net: int, r_net: int,
                        cap_size: str = "unknown") -> dict:
     """
     "개인만 매수" 신호를 맥락에 따라 다르게 해석.
 
     고려 요소:
       ① 시장 국면 (bull/normal/bear/crash)
       ② 종목 5일 추세 (상승조정 vs 하락전환)
       ③ 종목 규모 (대형/중형/소형)
 
     반환:
       score_adj: int
       label: str
       detail: str
       confidence: str
     """
     if not (r_net > 0 and f_net < 0 and i_net < 0):
         return {}
     regime = get_market_regime().get("mode", "normal")
     r_abs = abs(r_net)
     stock_trend = _get_retail_signal_stock_trend(code)
     return _classify_retail_signal_context(regime, stock_trend, cap_size, r_abs, f_net, i_net)
