# ============================================================
# 📊 매물대/지지저항선 자동 계산 (Volume Profile)
# ============================================================
_vp_cache: dict = {}  # code → {levels, ts}
def calc_volume_profile(code: str, entry: int) -> dict:
    """
    일봉 데이터로 가격별 거래량 집계 → 매물대/지지저항선 계산.
    진입가 근처에 강한 저항선 있으면 감점, 지지선 위면 가중.
    반환: {score_adj: int, reason: str, support: int, resistance: int}
    """
    cached = _vp_cache.get(code)
    if cached and time.time() - cached.get("ts", 0) < 3600:
        return cached
    result = {"score_adj": 0, "reason": "", "support": 0, "resistance": 0, "ts": time.time()}
    try:
        items = get_daily_data(code, 60)
        if len(items) < 20 or not entry:
            return result
        # 가격 구간별 거래량 집계 (50개 구간)
        prices = [i["close"] for i in items if i.get("close")]
        vols   = [i["vol"]   for i in items if i.get("vol")]
        if not prices: return result
        price_min, price_max = min(prices), max(prices)
        if price_max == price_min: return result
        bucket_size = (price_max - price_min) / 50
        buckets     = {}
        for i, item in enumerate(items):
            if not item.get("close") or not item.get("vol"): continue
            bucket = int((item["close"] - price_min) / bucket_size)
            bucket = max(0, min(bucket, 49))
            buckets[bucket] = buckets.get(bucket, 0) + item["vol"]
        # 상위 10% 거래량 구간 → 매물대
        sorted_buckets = sorted(buckets.items(), key=lambda x: -x[1])
        top_n          = max(1, len(sorted_buckets) // 10)
        heavy_buckets  = [b for b, v in sorted_buckets[:top_n]]
        # 매물대 가격 계산
        heavy_prices = [price_min + (b + 0.5) * bucket_size for b in heavy_buckets]
        # 진입가 기준 ±10% 범위 내 매물대 찾기
        near_range    = entry * 0.10
        above_levels  = sorted([p for p in heavy_prices if entry < p <= entry + near_range])
        below_levels  = sorted([p for p in heavy_prices if entry - near_range <= p < entry], reverse=True)
        resistance = int(above_levels[0])  if above_levels else 0
        support    = int(below_levels[0])  if below_levels else 0
        score_adj = 0
        reasons   = []
        if resistance:
            gap_pct = (resistance - entry) / entry * 100
            if gap_pct < COMMON_THRESHOLD_3P0:
                score_adj -= 8
                reasons.append(f"🧱 진입가 +{gap_pct:.1f}%에 강한 저항선 ({resistance:,}원) -8점")
            elif gap_pct < 6.0:
                score_adj -= 3
                reasons.append(f"⚠️ 진입가 +{gap_pct:.1f}%에 저항선 ({resistance:,}원) -3점")
        if support:
            gap_pct = (entry - support) / entry * 100
            if gap_pct < COMMON_THRESHOLD_3P0:
                score_adj += 5
                reasons.append(f"✅ 진입가 -{gap_pct:.1f}%에 강한 지지선 ({support:,}원) +5점")
        result.update({
            "score_adj":  score_adj,
            "reason":     "  ".join(reasons),
            "support":    support,
            "resistance": resistance,
        })
        _vp_cache[code] = result
    except Exception as e:
        _log_error(f"calc_volume_profile({code})", e)
    return result
def analyze_news_sentiment(headlines: list, stock_name: str = "") -> dict:
    """
    뉴스 헤드라인 목록에서 감성 점수 계산.
    stock_name이 있으면 해당 종목 관련 헤드라인만 필터.
    반환: {score: -20~+20, label: str, pos: int, neg: int, matched: list}
    """
    if not headlines:
        return {"score": 0, "label": "중립", "pos": 0, "neg": 0, "matched": []}
    # 종목명 필터
    targets = [h for h in headlines if not stock_name or stock_name in h] if stock_name else headlines
    pos = sum(1 for h in targets for kw in _POSITIVE_KEYWORDS if kw in h)
    neg = sum(1 for h in targets for kw in _NEGATIVE_KEYWORDS if kw in h)
    # 정규화 (-20 ~ +20)
    total = pos + neg
    if total == 0:
        raw_score = 0
    else:
        raw_score = int((pos - neg) / total * 20)
    raw_score = max(-20, min(raw_score, 20))
    if   raw_score >= 10: label = "매우 긍정"
    elif raw_score >= 4:  label = "긍정"
    elif raw_score <= -10: label = "매우 부정"
    elif raw_score <= -4:  label = "부정"
    else:                  label = "중립"
    matched = [h for h in targets if
               any(kw in h for kw in _POSITIVE_KEYWORDS + _NEGATIVE_KEYWORDS)][:3]
    return {"score": raw_score, "label": label, "pos": pos, "neg": neg, "matched": matched}
def _is_material_first_extended_window(now: datetime | None = None) -> bool:
    now = now or _now_kst()
    if is_holiday():
        return False
    now_t = now.time()
    return MATERIAL_FIRST_OFFHOURS_START <= now_t <= MATERIAL_FIRST_OFFHOURS_END


def _get_theme_scenario_bonus(theme_key: str) -> int:
    theme_key = str(theme_key or "").strip()
    theme_info = THEME_MAP.get(theme_key, {}) if isinstance(THEME_MAP, dict) else {}
    theme_tokens = {theme_key.lower()}
    for sector in list(theme_info.get("sectors", []) or []):
        token = str(sector or "").strip().lower()
        if token:
            theme_tokens.add(token)
    score = 0
    board = _load_premarket_action_board()
    for item in list((board or {}).get("items", []) or [])[:PREMARKET_ACTION_BOARD_MAX_ITEMS]:
        sectors = [str(v or "").strip().lower() for v in list(item.get("kr_sector_bull", []) or []) + list(item.get("kr_sector_bear", []) or [])]
        if any(tok and (tok in sec or sec in tok) for tok in theme_tokens for sec in sectors if sec):
            score += 1
    return min(3, score)


def _score_material_seed_quality(theme_key: str, matched: list, stock_status: list[dict]) -> dict:
    matched_cnt = len(matched or [])
    reacted_cnt = sum(1 for s in stock_status if safe_float(s.get("change_rate", 0.0), 0.0) >= ISSUE_PREWATCH_REACTION_MIN_CHANGE)
    vol_on_cnt = sum(1 for s in stock_status if safe_float(s.get("volume_ratio", 0.0), 0.0) >= ISSUE_PREWATCH_REACTION_MIN_VOLUME)
    leader_cnt = sum(1 for s in stock_status if safe_float(s.get("change_rate", 0.0), 0.0) >= 2.5 and safe_float(s.get("volume_ratio", 0.0), 0.0) >= 1.5)
    scenario_bonus = _get_theme_scenario_bonus(theme_key)
    score = min(3, matched_cnt) + min(2, reacted_cnt) + min(2, vol_on_cnt) + min(2, leader_cnt) + min(3, scenario_bonus)
    passes = score >= MATERIAL_PREWATCH_SEED_SCORE_MIN and matched_cnt >= MATERIAL_PREWATCH_HEADLINE_MIN
    return {
        "theme_key": theme_key,
        "matched_cnt": matched_cnt,
        "reacted_cnt": reacted_cnt,
        "vol_on_cnt": vol_on_cnt,
        "leader_cnt": leader_cnt,
        "scenario_bonus": scenario_bonus,
        "score": score,
        "passes": passes,
        "strong": score >= MATERIAL_PREWATCH_STRONG_SEED_SCORE,
    }


def _material_first_stock_alert_key(code: str, theme_key: str = "") -> str:
    code = normalize_stock_code(code or "")
    theme_key = str(theme_key or "").strip()
    return f"{theme_key}:{code}" if theme_key else code


def _is_material_first_stock_cooldown(code: str, theme_key: str = "") -> bool:
    key = _material_first_stock_alert_key(code, theme_key)
    if not key:
        return False
    return (time.time() - float(_news_stock_alert_history.get(key, 0) or 0)) < MATERIAL_PREWATCH_STOCK_COOLDOWN_SEC


def _mark_material_first_stock_alerted(code: str, theme_key: str = "") -> None:
    key = _material_first_stock_alert_key(code, theme_key)
    if key:
        _news_stock_alert_history[key] = time.time()


def _summarize_material_reaction(reacted: list[dict], pw: dict | None = None) -> dict:
    reacted = list(reacted or [])
    pw = dict(pw or {})
    reacted_cnt = len(reacted)
    strong_cnt = sum(1 for item in reacted if safe_float(item.get("change_rate", 0.0), 0.0) >= 2.0 and safe_float(item.get("volume_ratio", 0.0), 0.0) >= 1.8)
    leader_cnt = sum(1 for item in reacted if safe_float(item.get("change_rate", 0.0), 0.0) >= COMMON_THRESHOLD_3P0)
    seed_score = safe_int(pw.get("quality_score", 0), 0)
    passes = reacted_cnt >= 1 and (strong_cnt >= 1 or leader_cnt >= 1 or seed_score >= MATERIAL_PREWATCH_STRONG_SEED_SCORE)
    return {
        "reacted_cnt": reacted_cnt,
        "strong_cnt": strong_cnt,
        "leader_cnt": leader_cnt,
        "seed_score": seed_score,
        "passes": passes,
        "strong": strong_cnt >= 2 or leader_cnt >= 1 or seed_score >= MATERIAL_PREWATCH_STRONG_SEED_SCORE,
    }


def _material_reacted_priority_score(item: dict, pw: dict | None = None, summary: dict | None = None) -> float:
    pw = dict(pw or {})
    summary = dict(summary or {})
    change_rate = safe_float(item.get("change_rate", 0.0), 0.0)
    vol_ratio = safe_float(item.get("volume_ratio", 0.0), 0.0)
    seed_score = safe_int(summary.get("seed_score", pw.get("quality_score", 0)), 0)
    return round(change_rate * 10.0 + vol_ratio * 8.0 + seed_score * 6.0 + safe_int(summary.get("strong_cnt", 0), 0) * 4.0, 2)


def _register_material_seed_prewatch(headlines: list, source_label: str = "material_first") -> int:
    added = 0
    if not headlines:
        return 0
    now_ts = time.time()
    for theme_key, theme_info in THEME_MAP.items():
        try:
            if theme_key in _news_issue_prewatch:
                continue
            if now_ts - _news_prewatch_fired.get(theme_key, 0) < 14400:
                continue
            matched = [h for h in headlines if theme_key in h or any(s in h for s in theme_info.get("sectors", []))]
            if not matched:
                continue
            stock_status = []
            for code, name in theme_info.get("stocks", [])[:10]:
                try:
                    cur = get_stock_price(code) or {}
                    stock_status.append({
                        "code": code,
                        "name": name,
                        "price": int(cur.get("price", 0) or 0),
                        "change_rate": float(cur.get("change_rate", 0) or 0),
                        "volume_ratio": float(cur.get("volume_ratio", 0) or 0),
                        "source": source_label,
                    })
                    time.sleep(0.1)
                except Exception as e:
                    _swallow_exception(e)
                    continue
            if not stock_status:
                continue
            quality = _score_material_seed_quality(theme_key, matched, stock_status)
            if not quality.get("passes"):
                continue
            _news_issue_prewatch[theme_key] = {
                "stocks": stock_status,
                "headline": matched[0][:60],
                "theme_desc": theme_info.get("desc", theme_key),
                "ts": now_ts,
                "source": source_label,
                "quality_score": quality.get("score", 0),
                "headline_count": quality.get("matched_cnt", 0),
                "reacted_count": quality.get("reacted_cnt", 0),
            }
            added += 1
        except Exception as e:
            _swallow_exception(e)
    return added


def run_material_first_scan() -> None:
    if _bot_paused or is_holiday():
        return
    live_market = is_any_market_open()
    if not live_market and not _is_material_first_extended_window():
        return
    now_ts = time.time()
    if not live_market and now_ts - float(_material_first_state.get("last_offhours_ts", 0) or 0) < MATERIAL_FIRST_OFFHOURS_MIN_SEC:
        return
    if not _material_first_scan_lock.acquire(blocking=False):
        return
    try:
        _log_info_msg(f"\n[{datetime.now().strftime('%H:%M:%S')}] 재료-first 스캔{' [실시간]' if live_market else ' [장외/장전]'}...")
        collect_market_scenarios_24h(force=not live_market)
        headlines = _get_material_signal_headlines(force=not live_market)
        if not headlines:
            return
        threading.Thread(target=update_news_cooccur, args=(headlines,), daemon=True).start()

        # v163.4: F구간 무재료 종목 우선 뉴스 검색
        # F존에 마킹됐지만 재료가 없는 종목들을 헤드라인과 대조하여 재료 확인 시 마킹 업데이트
        try:
            _fz_no_mat = _get_fzone_no_material_codes()
            if _fz_no_mat:
                _log_info_msg(f"  🔍 F구간 무재료 종목 재료 추적 중: {len(_fz_no_mat)}종목")
                _headlines_lower = [h.lower() for h in headlines]
                for _fz_code in _fz_no_mat:
                    _fz_name = _resolve_stock_name(_fz_code, _fz_code)
                    _fz_name_lower = _fz_name.lower()
                    # 종목명 또는 코드가 헤드라인에 포함되면 재료 확인으로 간주
                    _hit = any(
                        _fz_name_lower in h or _fz_code in h
                        for h in _headlines_lower
                    )
                    if _hit:
                        _log_info_msg(f"  ✅ F구간 재료 확인: {_fz_name}({_fz_code}) — 헤드라인 매칭")
                        _mark_f_zone(_fz_code, has_material=True)
                    else:
                        _log_info_msg(f"  ⏳ F구간 재료 미확인: {_fz_name}({_fz_code})")
        except Exception as _fz_e:
            _swallow_exception(_fz_e)

        # v163.4: F구간 재료 확인 후속 알람 처리 (material_confirmed_pending 종목)
        try:
            _check_fzone_material_confirmed_and_alert()
        except Exception as _fa_e:
            _swallow_exception(_fa_e)

        if live_market:
            for signal in analyze_news_theme(headlines=headlines):
                send_news_theme_alert(signal)
            try:
                check_issue_prewatch()
            except Exception as e:
                _log_error("run_material_first_scan/check_issue_prewatch", e)
        else:
            added = _register_material_seed_prewatch(headlines, source_label="offhours")
            _material_first_state["last_offhours_ts"] = now_ts
            _material_first_state["last_seed_cnt"] = added
            if added > 0:
                _log_info_msg(f"  👁 장외 재료-first prewatch seed 등록: {added}개")
    except Exception as e:
        _log_warn_msg(f"⚠️ 재료-first 스캔 오류: {e}")
    finally:
        _material_first_scan_lock.release()


def analyze_news_theme(headlines: list = None) -> list:
    signals = []
    if headlines is None:
        headlines = _get_material_signal_headlines()
    if not headlines:
        return []
    _log_info_msg(f"  📰 뉴스 {len(headlines)}건 ({len(DOMESTIC_NEWS_SOURCE_FUNCS)}개 소스)")
    _refresh_market_flow_state_from_headlines(headlines, source="news_theme")
    for theme_key, theme_info in THEME_MAP.items():
        if time.time() - _news_alert_history.get(theme_key, 0) < 14400:
            continue
        matched = [h for h in headlines if theme_key in h or any(s in h for s in theme_info.get("sectors", []))]
        if not matched:
            continue
        stock_status = []
        for code, name in theme_info["stocks"]:
            try:
                cur = get_stock_price(code)
                if not cur:
                    continue
                cr, vr = cur.get("change_rate", 0), cur.get("volume_ratio", 0)
                stock_status.append({
                    "code": code, "name": name, "price": cur["price"],
                    "change_rate": cr, "volume_ratio": vr,
                    "rising": cr >= 2.0, "surging": cr >= 5.0, "vol_on": vr >= 2.0, "not_yet": cr < 2.0,
                })
                time.sleep(0.2)
            except Exception as e:
                _swallow_exception(e)
                continue
        if not stock_status:
            continue
        rising_stocks = [s for s in stock_status if s["rising"]]
        if not rising_stocks:
            now_ts = time.time()
            quality = _score_material_seed_quality(theme_key, matched, stock_status)
            if time.time() - _news_prewatch_fired.get(theme_key, 0) < 14400 or theme_key in _news_issue_prewatch:
                _log_info_msg(f"  ⏭ [{theme_key}] 뉴스 있지만 주가 반응 없음 → 스킵")
            elif not quality.get("passes"):
                _log_info_msg(f"  ⏭ [{theme_key}] material seed 품질 미달({quality.get('score', 0)}점/{quality.get('matched_cnt', 0)}헤드라인)")
            else:
                _news_issue_prewatch[theme_key] = {
                    "stocks": stock_status,
                    "headline": matched[0][:60],
                    "theme_desc": theme_info["desc"],
                    "ts": now_ts,
                    "quality_score": quality.get("score", 0),
                    "headline_count": quality.get("matched_cnt", 0),
                    "reacted_count": quality.get("reacted_cnt", 0),
                }
                _log_info_msg(f"  👁 [{theme_key}] 뉴스 감지 → prewatch 등록 ({len(stock_status)}종목 대기, {quality.get('score', 0)}점)")
            continue
        total = len(stock_status)
        react_ratio = len(rising_stocks) / total
        sector_bonus = 15 if react_ratio >= 1.0 else 10 if react_ratio >= 0.5 else 5
        if sum(1 for s in rising_stocks if s["vol_on"]) >= 2:
            sector_bonus += 5
        strength = "매우강함" if [s for s in stock_status if s["surging"]] and react_ratio >= 0.5 else "강함" if react_ratio >= 0.5 else "보통"
        _news_alert_history[theme_key] = time.time()
        signals.append({
            "theme_key": theme_key, "theme_desc": theme_info["desc"],
            "headline": matched[0][:60], "rising": rising_stocks,
            "surging": [s for s in stock_status if s["surging"]],
            "not_yet": [s for s in stock_status if s["not_yet"]][:6],
            "react_ratio": react_ratio, "sector_bonus": sector_bonus,
            "signal_strength": strength, "total": total,
        })
    return signals
def _get_theme_chain_strength_profile(signal: dict | None = None) -> dict:
    signal = signal if isinstance(signal, dict) else {}
    strength = str(signal.get("signal_strength") or "").strip()
    rising = list(signal.get("rising") or [])
    react_ratio = safe_float(signal.get("react_ratio", 0.0), 0.0)
    return {
        "strong": strength in ("매우강함", "강함"),
        "very_strong": strength == "매우강함",
        "react_ratio": react_ratio,
        "rising_count": len(rising),
        "theme_desc": str(signal.get("theme_desc") or signal.get("theme_key") or ""),
    }

def _build_theme_chain_execution_plan(item: dict | None = None, signal: dict | None = None) -> dict:
    item = item if isinstance(item, dict) else {}
    signal = signal if isinstance(signal, dict) else {}
    price = safe_int(item.get("price", 0), 0)
    profile = _get_theme_chain_strength_profile(signal)
    stop_ratio = 0.06 if profile.get("very_strong") else 0.065
    target_ratio = 0.18 if profile.get("very_strong") else 0.16
    return {
        "entry_price": price,
        "stop_loss": int(round(price * (1.0 - stop_ratio))) if price > 0 else 0,
        "target_price": int(round(price * (1.0 + target_ratio))) if price > 0 else 0,
    }

def _should_force_theme_chain_direct(analyzed: dict | None = None, item: dict | None = None, signal: dict | None = None) -> bool:
    analyzed = analyzed if isinstance(analyzed, dict) else {}
    item = item if isinstance(item, dict) else {}
    profile = _get_theme_chain_strength_profile(signal)
    if not profile.get("strong"):
        return False
    score = safe_int(analyzed.get("score", 0), 0)
    grade = str(analyzed.get("execution_grade") or analyzed.get("grade") or "C").upper()
    chg = safe_float(item.get("change_rate", analyzed.get("change_rate", 0.0)), 0.0)
    if grade == "A" and score >= 70:
        return True
    return bool(profile.get("very_strong") and profile.get("react_ratio", 0.0) >= 0.8 and chg >= 3.0 and score >= 60)

def _build_theme_chain_direct_candidate(analyzed: dict | None = None, item: dict | None = None, signal: dict | None = None, source_label: str = "") -> dict:
    analyzed = dict(analyzed if isinstance(analyzed, dict) else {})
    item = item if isinstance(item, dict) else {}
    signal = signal if isinstance(signal, dict) else {}
    plan = _build_theme_chain_execution_plan(item, signal)
    analyzed.setdefault("code", item.get("code"))
    analyzed.setdefault("name", item.get("name"))
    analyzed.setdefault("price", safe_int(item.get("price", 0), 0))
    analyzed["entry_price"] = safe_int(analyzed.get("entry_price", 0), 0) or plan["entry_price"]
    analyzed["stop_loss"] = safe_int(analyzed.get("stop_loss", 0), 0) or plan["stop_loss"]
    analyzed["target_price"] = safe_int(analyzed.get("target_price", 0), 0) or plan["target_price"]
    analyzed["grade"] = "A"
    analyzed["execution_grade"] = "A"
    analyzed["force_external_capture_alert"] = True
    analyzed["theme_chain_force_hit"] = True
    analyzed["direct_news_hit"] = True
    analyzed.setdefault("reasons", []).append(f"🧩 테마체인 직승격: {str(signal.get('theme_desc') or signal.get('theme_key') or '')[:30]}")
    analyzed.setdefault("sector_info", {}).setdefault("theme", str(signal.get("theme_desc") or analyzed.get("sector_theme") or ""))
    analyzed["first_entry_reached"] = analyzed.get("price", 0) <= analyzed.get("entry_price", 0) if analyzed.get("entry_price", 0) else False
    return analyzed

def _apply_theme_chain_capture_adjustment(analyzed: dict | None = None, item: dict | None = None, signal: dict | None = None, source_label: str = "") -> dict:
    analyzed = dict(analyzed if isinstance(analyzed, dict) else {})
    item = item if isinstance(item, dict) else {}
    if _should_force_theme_chain_direct(analyzed, item, signal):
        return _build_theme_chain_direct_candidate(analyzed, item, signal, source_label=source_label)
    if safe_int(analyzed.get("entry_price", 0), 0) <= 0 and _get_theme_chain_strength_profile(signal).get("strong"):
        plan = _build_theme_chain_execution_plan(item, signal)
        analyzed["entry_price"] = plan["entry_price"]
        analyzed["stop_loss"] = plan["stop_loss"]
        analyzed["target_price"] = plan["target_price"]
    return analyzed

def send_news_theme_alert(signal: dict):
    emoji = {"매우강함":"🔥","강함":"✅","보통":"🟡"}.get(signal["signal_strength"],"📢")
    react_pct = int(signal["react_ratio"]*100)
    rising_lines = []
    for s in signal.get("rising", []):
        wsuf = _watch_suffix(s.get("code",""), safe_int(s.get("price", 0)))
        marker = '🟩' if s['change_rate'] > 0 else ('🟥' if s['change_rate'] < 0 else '')
        rising_lines.append(
            f"  {marker} <b>{s['name']}</b> {s['change_rate']:+.1f}%"
            + (f" 🔊{s['volume_ratio']:.0f}x" if s.get("vol_on") else "")
            + (" 🚀" if s.get("surging") else "")
            + wsuf
        )
    rising_block = ("\n".join(rising_lines) + ("\n" if rising_lines else ""))
    not_yet_lines = []
    for s in signal.get("not_yet", []):
        wsuf = _watch_suffix(s.get("code",""), safe_int(s.get("price", 0)))
        marker = '🟩' if s['change_rate'] > 0 else ('🟥' if s['change_rate'] < 0 else '')
        not_yet_lines.append(f"  {marker} {s['name']} {s['change_rate']:+.1f}%{wsuf}")
    not_yet_block = ("\n".join(not_yet_lines) + ("\n" if not_yet_lines else ""))
    send(f"{emoji} <b>[뉴스+주가 연동]</b>  {signal['signal_strength']}\n"
         f"🕐 {datetime.now().strftime('%H:%M:%S')}\n\n"
         f"📰 <b>{signal['theme_desc']}</b>\n💬 {signal['headline']}...\n\n"
         f"━━━━━━━━━━━━━━━\n"
         f"🏭 섹터 반응: <b>{len(signal['rising'])}/{signal['total']}개</b> ({react_pct}%)  +{signal['sector_bonus']}점\n\n"
         +(f"🔥 <b>실제 상승 중</b>\n{rising_block}\n" if rising_block else "")
         +(f"🎯 <b>아직 안 오른 종목 (추격 기회)</b>\n{not_yet_block}\n" if not_yet_block else "")
         +"━━━━━━━━━━━━━━━")
    # v81 #1: rising 종목 A급 진입 체인 연결
    # 정보 알람 발송 후 각 상승 종목에 대해 analyze() → A급이면 _dispatch_general_alert_signal()
    _nxt_only = not is_market_open() and is_nxt_open()  # v161.45: KRX 장마감 후 NXT 전용 시간대 판단
    for r in signal.get("rising", []):
        try:
            # v161.45: NXT 전용 시간대에 KRX 전용 종목 A급 진입 체인 차단 (정보성 메시지는 이미 발송됨)
            if _nxt_only and not is_nxt_listed(r.get("code", "")):
                _log_info_msg(f"  ⏭ NXT전용 시간대 비NXT 종목 진입체인 차단(뉴스테마): {r.get('name', r.get('code', ''))}")
                continue
            cur = get_stock_price(r["code"])
            if not cur:
                continue
            stock_input = {
                "code":         r["code"],
                "name":         r["name"],
                "price":        cur.get("price", r.get("price", 0)),
                "change_rate":  cur.get("change_rate", r.get("change_rate", 0)),
                "volume_ratio": cur.get("volume_ratio", r.get("volume_ratio", 0)),
                "today_vol":    cur.get("today_vol", 0),
                "ask_qty":      cur.get("ask_qty", 0),
                "bid_qty":      cur.get("bid_qty", 0),
                "prev_close":   cur.get("prev_close", 0),
                "high":         cur.get("high", 0),
                "open":         cur.get("open", 0),
                "cap_size":     cur.get("cap_size", "small"),
                "mktcap":       cur.get("mktcap", 0),
            }
            analyzed = analyze(stock_input)
            # v165.11 [#1]: 뉴스테마 경로는 이미 뉴스 필터 통과 → direct_news_hit=True 강제 주입
            # 기존: analyze() 내부에서 Gemini/Groq 결과 없으면 direct_news_hit=False → support_count 손해
            # 수정: 뉴스테마 경로 진입 자체가 뉴스 hit 증거 → direct_news_hit=True + grade 재판정
            if analyzed:
                analyzed["direct_news_hit"] = True
                _cur_grade = str(analyzed.get("execution_grade") or analyzed.get("grade") or "C").upper()
                if _cur_grade != "A":
                    _re_grade = _derive_general_signal_grade(
                        str(analyzed.get("signal_type") or "SURGE"),
                        int(analyzed.get("score") or 0),
                        change_rate=float(analyzed.get("change_rate") or 0),
                        vol_ratio=float(analyzed.get("volume_ratio") or 0),
                        sector_info=analyzed.get("sector_info") or {},
                        direct_news_hit=True,
                        nxt_delta=int((analyzed.get("nxt") or {}).get("vs_krx_pct") or 0),
                        market=str(analyzed.get("market") or ""),
                        reasons=analyzed.get("reasons") or [],
                    )
                    if _re_grade == "A":
                        analyzed["grade"] = "A"
                        analyzed["execution_grade"] = "A"
                        analyzed.setdefault("reasons", []).append("📰 뉴스테마 경로 direct_news_hit 보정 → A급 승격")
            analyzed = _apply_theme_chain_capture_adjustment(analyzed, stock_input, signal, source_label="뉴스테마 상승")
            if analyzed and str(analyzed.get("execution_grade") or analyzed.get("grade") or "C").upper() == "A" and analyzed.get("entry_price", 0) > 0:
                analyzed.setdefault("reasons", []).append(
                    f"📰 뉴스+주가 연동: {signal['theme_desc'][:25]}"
                )
                dispatched = _dispatch_general_alert_signal(
                    analyzed,
                    source_label="뉴스테마 상승"
                )
                if dispatched:
                    _log_info_msg(f"  📰 뉴스테마→A급 진입 체인: {r['name']} {r['change_rate']:+.1f}%")
            else:
                _log_info_msg(f"  ⏭ 뉴스테마 A급 미달: {r['name']} {r.get('change_rate',0):+.1f}% — 내부 기록만")
            time.sleep(0.2)
        except Exception as _e:
            _log_error(f"send_news_theme_alert/analyze({r.get('name','')})", _e)
# ============================================================
# v78 #3: 이슈 선감지 prewatch 체크 — 주가 변동 시 즉시 알람
# ============================================================
def _should_expire_issue_prewatch(theme_key: str, pw: dict, now: float) -> bool:
    if now - pw.get("ts", 0) > ISSUE_PREWATCH_TTL_SEC:
        return True
    if theme_key in _news_prewatch_fired:
        return True
    stocks = pw.get("stocks", [])
    return not stocks
def _get_issue_prewatch_reaction_thresholds(stock: dict, pw: dict | None = None) -> dict:
    pw = pw if isinstance(pw, dict) else {}
    min_change = float(ISSUE_PREWATCH_REACTION_MIN_CHANGE)
    min_volume = float(ISSUE_PREWATCH_REACTION_MIN_VOLUME)
    quality_score = safe_int(pw.get("quality_score", 0), 0)
    headline_count = safe_int(pw.get("headline_count", 0), 0)
    strong_seed = bool(quality_score >= ISSUE_PREWATCH_STRONG_SEED_SCORE or headline_count >= ISSUE_PREWATCH_STRONG_HEADLINE_COUNT)
    if strong_seed and is_market_open():
        min_change = min(min_change, float(ISSUE_PREWATCH_STRONG_REACTION_MIN_CHANGE))
        min_volume = min(min_volume, float(ISSUE_PREWATCH_STRONG_REACTION_MIN_VOLUME))
    return {"min_change": round(min_change, 2), "min_volume": round(min_volume, 2), "strong_seed": strong_seed}

def _collect_issue_prewatch_reacted(stocks: list[dict], pw: dict | None = None) -> list[dict]:
    reacted = []
    thresholds = _get_issue_prewatch_reaction_thresholds({}, pw)
    min_change = safe_float(thresholds.get("min_change", ISSUE_PREWATCH_REACTION_MIN_CHANGE), ISSUE_PREWATCH_REACTION_MIN_CHANGE)
    min_volume = safe_float(thresholds.get("min_volume", ISSUE_PREWATCH_REACTION_MIN_VOLUME), ISSUE_PREWATCH_REACTION_MIN_VOLUME)
    strong_seed = bool(thresholds.get("strong_seed"))
    for stock in stocks:
        try:
            cur = get_stock_price(stock["code"])
            if not cur:
                continue
            cr = cur.get("change_rate", 0)
            vr = cur.get("volume_ratio", 0)
            reacts = bool(cr >= min_change and (vr >= min_volume or (strong_seed and cr >= min_change + 1.0)))
            if reacts:
                reacted.append({
                    "code": stock["code"],
                    "name": stock["name"],
                    "change_rate": cr,
                    "volume_ratio": vr,
                    "price": cur.get("price", 0),
                    "today_vol": cur.get("today_vol", 0),
                    "ask_qty": cur.get("ask_qty", 0),
                    "bid_qty": cur.get("bid_qty", 0),
                    "prev_close": cur.get("prev_close", 0),
                    "high": cur.get("high", 0),
                    "open": cur.get("open", 0),
                    "cap_size": cur.get("cap_size", "small"),
                    "mktcap": cur.get("mktcap", 0),
                    "issue_prewatch_min_change": min_change,
                    "issue_prewatch_min_volume": min_volume,
                    "issue_prewatch_strong_seed": strong_seed,
                })
            time.sleep(GEO_PREWATCH_POLL_DELAY_SEC)
        except Exception as e:
            _swallow_exception(e)
    return reacted
def _dispatch_issue_prewatch_reacted(pw: dict, reacted: list[dict]) -> set[str]:
    dispatched_codes = set()
    theme_key = str((pw or {}).get("theme_key") or "")
    summary = _summarize_material_reaction(reacted, pw)
    reacted_sorted = sorted(reacted, key=lambda item: _material_reacted_priority_score(item, pw, summary), reverse=True)
    for item in reacted_sorted[:ISSUE_PREWATCH_REACT_LIMIT]:
        code = item["code"]
        name = item["name"]
        if _is_material_first_stock_cooldown(code, theme_key):
            continue
        try:
            analyzed = analyze(item)
            analyzed = _apply_theme_chain_capture_adjustment(analyzed, item, pw, source_label="이슈 선감지")
            if analyzed and str(analyzed.get("execution_grade") or analyzed.get("grade") or "C").upper() == "A" and analyzed.get("entry_price", 0) > 0:
                analyzed.setdefault("reasons", []).append(f"👁 이슈 선감지: {pw['theme_desc'][:30]}")
                analyzed["material_first_hint"] = True
                analyzed["material_first_priority_hit"] = bool(summary.get("strong"))
                dispatched = _dispatch_general_alert_signal(analyzed, source_label="이슈 선감지")
                if dispatched:
                    dispatched_codes.add(code)
                    _mark_material_first_stock_alerted(code, theme_key)
                    _log_info_msg(f"  👁 이슈→A급 진입 체인: {name} {item['change_rate']:+.1f}% 등급A")
                    continue
        except Exception as e:
            _log_error(f"check_issue_prewatch/analyze({name})", e)
        _log_info_msg(f"  ⏭ 이슈 선감지 A급 미달: {name} {item['change_rate']:+.1f}% — 내부 기록만")
    return dispatched_codes
def check_issue_prewatch() -> None:
    """이슈 prewatch 감시."""
    if not is_any_market_open() or _bot_paused:
        return
    now = time.time()
    expired_keys = []
    for theme_key, pw in list(_news_issue_prewatch.items()):
        if _should_expire_issue_prewatch(theme_key, pw, now):
            expired_keys.append(theme_key)
            continue
        try:
            pw = dict(pw)
            pw.setdefault("theme_key", theme_key)
            reacted = _collect_issue_prewatch_reacted(pw.get("stocks", []), pw)
            if not reacted:
                continue
            _news_prewatch_fired[theme_key] = now
            expired_keys.append(theme_key)
            dispatched_codes = _dispatch_issue_prewatch_reacted(pw, reacted)
            if dispatched_codes:
                _log_info_msg(f"  👁 이슈 선감지 A급 진입 체인: {len(dispatched_codes)}종목")
        except Exception as e:
            _log_error("check_issue_prewatch", e)
    for k in expired_keys:
        _news_issue_prewatch.pop(k, None)
    for k in [k2 for k2, ts in list(_news_prewatch_fired.items()) if now - ts > ISSUE_PREWATCH_FIRED_TTL_SEC]:
        _news_prewatch_fired.pop(k, None)
